-- compat shim: util.toast does not exist in Lexis, use GTA native notifications
if not util.toast then
    util.toast = function(msg, _flag)
        pcall(function()
            invoker.call(0xB87A37EEF25AD7BD) -- BEGIN_TEXT_COMMAND_THEFEED_POST
            invoker.call(0x6C188BE134E074AA, tostring(msg), true, false) -- ADD_TEXT_COMPONENT_SUBSTRING_PLAYER_NAME
            invoker.call(0x2ED7843F8F801023) -- END_TEXT_COMMAND_THEFEED_POST_TICKER
        end)
    end
end

