-- MODDER OVERLAY STATE
-- =========================================================================
local modder_overlay = {
    enabled  = false,
    -- Overlay position (0‥1 relative to screen, default top-right)
    pos_x    = 0.72,
    pos_y    = 0.04,
    -- Internal: detected modders table  { [id] = {name, reasons={}, first_seen} }
    detected = {},
    -- Spectate alert
    spectated_by        = {},   -- { [player_id] = name }
    spectate_notified   = {},   -- avoid repeat toasts
}

local function modder_overlay_get_reasons(p)
    -- Returns a list of human-readable reason strings for why p is flagged.
    -- Uses only data already present in the player entry built by update_player_list().
    local reasons = {}
    if p.god   then reasons[#reasons+1] = "God Mode" end
    if p.modder then reasons[#reasons+1] = "Lexis Flagged" end
    if p.rank  and p.rank  >= 1000       then reasons[#reasons+1] = "Rank " .. p.rank end
    if p.money and p.money > 500000000   then reasons[#reasons+1] = "Money $" .. math.floor(p.money/1e6) .. "M" end
    if p.bank  and p.bank  > 500000000   then reasons[#reasons+1] = "Bank $"  .. math.floor(p.bank /1e6) .. "M" end
    -- health above max (god mode variant)
    if p.health and p.max_health and p.health > p.max_health + 5 then
        reasons[#reasons+1] = "Over-health"
    end
    -- negative wanted (exploit)
    if p.wanted and p.wanted < 0 then reasons[#reasons+1] = "Neg Wanted" end
    return reasons
end

local function draw_modder_overlay()
    if not modder_overlay.enabled then return end
    if not (gui and gui.rect and gui.text and vec2 and color) then return end
    if not (game and game.resolution) then return end
    local res = game.resolution()
    local sw = res and res.x or 1920
    local sh = res and res.y or 1080

    local s       = math.max(0.5, sh / 1080)
    local pad     = math.floor(8 * s)
    local row_h   = math.floor(20 * s)
    local font_h  = math.floor(13 * s)
    local w       = math.floor(280 * s)

    -- Build rows: collect detected modders
    local rows = {}
    for _, p in ipairs(player_state and player_state.player_list or {}) do
        if p.id ~= (player_state and player_state.my_id or -1) then
            local reasons = modder_overlay_get_reasons(p)
            if #reasons > 0 then
                rows[#rows+1] = { name = p.name or "?", reasons = reasons }
            end
        end
    end

    if #rows == 0 then return end

    -- Header + rows
    local header_h = math.floor(22 * s)
    local h = header_h + pad + total_rows * (row_h + 2) + pad

    local ox = math.floor(modder_overlay.pos_x * sw)
    local oy = math.floor(modder_overlay.pos_y * sh)

    -- Clamp to screen
    ox = math.max(0, math.min(sw - w, ox))
    oy = math.max(0, math.min(sh - h, oy))

    -- Background
    gui.rect(vec2(ox, oy), vec2(w, h), color(14, 14, 18, 210), math.floor(5 * s))
    -- Header bar
    gui.rect(vec2(ox, oy), vec2(w, header_h), color(114, 137, 218, 220), math.floor(5 * s))
    gui.text("⚠  Modder Detection (" .. #rows .. ")",
        vec2(ox + pad, oy + math.floor(5 * s)), font_h, color(255,255,255,255))

    local ry = oy + header_h + pad

    for _, row in ipairs(rows) do
        -- row background
        gui.rect(vec2(ox + pad, ry), vec2(w - pad*2, row_h), color(40, 40, 46, 140), math.floor(3*s))
        -- name
        gui.text(row.name, vec2(ox + pad + math.floor(4*s), ry + math.floor(3*s)),
            font_h, color(255, 90, 90, 255))
        -- reasons on same line, dimmer
        local reason_str = table.concat(row.reasons, "  |  ")
        gui.text(reason_str, vec2(ox + pad + math.floor(4*s), ry + math.floor(3*s) + font_h + 1),
            math.floor(10*s), color(200, 170, 80, 220))
        ry = ry + row_h + 2
    end

end



local function set_crash_cam(active)
    pcall(function()
        if active and not kyron_crash_cam.active then
            -- CREATE_CAM (0xC3981DCE61D9E13F)
            local cam = invoker.call(0xC3981DCE61D9E13F, "DEFAULT_SCRIPTED_CAMERA", true).int
            if cam and cam ~= 0 then
                -- SET_CAM_POS - 10000 units above world (0x4D41783FB745E42E)
                invoker.call(0x4D41783FB745E42E, cam, 0.0, 0.0, 10000.0)
                -- POINT_CAM_AT_COORD - look at world center (0xF75497BB865F0803)
                invoker.call(0xF75497BB865F0803, cam, 0.0, 0.0, 100.0)
                -- SET_CAM_ACTIVE (0x026FB97D0A425F84)
                invoker.call(0x026FB97D0A425F84, cam, true)
                -- RENDER_SCRIPT_CAMS (0x07E5B515DB0636FC)
                invoker.call(0x07E5B515DB0636FC, true, true, 1000, true, true, true)
                kyron_crash_cam.cam_id = cam
                kyron_crash_cam.active = true
            end
        elseif not active and kyron_crash_cam.active then
            -- RENDER_SCRIPT_CAMS off
            invoker.call(0x07E5B515DB0636FC, false, false, 1000, false, false, false)
            -- DESTROY_ALL_CAMS (0x8E5FB15663F79120)
            invoker.call(0x8E5FB15663F79120, false)
            kyron_crash_cam.cam_id = nil
            kyron_crash_cam.active = false
        end
    end)
end

