-- -------------------------------------------------------------------------
-- PROTECTION LOG (writes to your existing DEBUG LOG)
-- -------------------------------------------------------------------------
local function protection_log(msg)
    pcall(function()
        local log_dir = (debug.getinfo(1,"S").source:match("@(.*)[\\/]") or ".") .. "/Kyron/Debug"
        local log_path = log_dir .. "/DEBUG LOG.txt"
        local f = io.open(log_path, "a")
        if f then
            f:write(os.date("%Y-%m-%d %H:%M:%S") .. " [PROTECTION] " .. tostring(msg) .. "\n")
            f:flush()
            f:close()
        end
    end)
end

-- =========================================================================
-- KYRON TARGETED PROTECTION
-- Players added here get ALL script events blocked + freeze counter + alert
-- Format: { ["name_lowercase"] = true }
-- =========================================================================
local KYRON_WATCHLIST = {}
local kyron_watch_state = {
    -- tracks how many SEs we've eaten from each player this session
    se_count   = {},   -- [player_id] = number
    alerted    = {},   -- [player_id] = true  (suppress repeat toasts)
    last_seen  = {},   -- [player_id] = os.clock()
    freeze_hit = false,
    freeze_tick = 0,
}

local function kyron_watchlist_add(name)
    if not name or name == "" then return end
    KYRON_WATCHLIST[name:lower()] = true
    protection_log("WATCHLIST ADD: " .. name)
end

local function kyron_is_watched(sender_id)
    local name = ""
    pcall(function() name = (players.get_name(sender_id) or ""):lower() end)
    return KYRON_WATCHLIST[name] == true, name
end

