-- -------------------------------------------------------------------------
-- SCRIPT EVENT HANDLER
-- -------------------------------------------------------------------------
local se_handler_ok = pcall(function()
    util.register_script_event_handler(function(sender_id, event_args)
        if not event_args or type(event_args) ~= "table" then return end

        -- ── TARGETED PROTECTION: block ALL SEs from watchlisted players ──
        local watched, wname = kyron_is_watched(sender_id)
        if watched then
            kyron_watch_state.se_count[sender_id] = (kyron_watch_state.se_count[sender_id] or 0) + 1
            kyron_watch_state.last_seen[sender_id] = os.clock()
            local cnt = kyron_watch_state.se_count[sender_id]

            -- Alert on first hit each session
            if not kyron_watch_state.alerted[sender_id] then
                kyron_watch_state.alerted[sender_id] = true
                safe_toast("[KYRON] ⛔ WATCHLIST PLAYER IN SESSION: " .. wname .. "\nAll attacks blocked.")
                protection_log("WATCHLIST ACTIVE: " .. wname .. " (id=" .. tostring(sender_id) .. ")")
            end

            -- Extra toast if they're flooding (freeze attempt = many SEs fast)
            if cnt == 30 then
                safe_toast("[KYRON] ⚠ " .. wname .. " is flooding SEs (" .. cnt .. ") — freeze attempt blocked.")
                protection_log("WATCHLIST FLOOD: " .. wname .. " sent " .. cnt .. " SEs")
                kyron_watch_state.freeze_hit = true
                kyron_watch_state.freeze_tick = os.clock()
            end

            return true  -- BLOCK every single SE from this player
        end

        -- ── MENU DETECTION: fingerprint via SE hash ──
        local hash = event_args[1]
        if type(hash) == "number" then
        end
        if hash == nil then return end

        -- Block known crash hashes
        if BLOCKED_SCRIPT_EVENTS[hash] then
            blocked_count = blocked_count + 1
            local reason = BLOCKED_SCRIPT_EVENTS[hash]
            local sender_name = "Unknown"
            pcall(function() sender_name = players.get_name(sender_id) or tostring(sender_id) end)
            last_attacker = sender_name
            protection_log("BLOCKED [" .. reason .. "] from=" .. sender_name .. " hash=" .. tostring(hash))
            util.toast("[KYRON SHIELD] Blocked: " .. reason .. "\nFrom: " .. sender_name, TOAST_ALL)
            return true  -- BLOCK IT
        end

        -- Block arg overflow crash (sending 100s of args to overflow engine)
        if #event_args > 100 then
            blocked_count = blocked_count + 1
            protection_log("BLOCKED [Arg Overflow] sender=" .. tostring(sender_id) .. " args=" .. #event_args)
            util.toast("[KYRON SHIELD] Blocked arg overflow crash!", TOAST_ALL)
            return true
        end

        -- Block NaN / Infinity in args (triggers engine crash)
        for _, v in ipairs(event_args) do
            if type(v) == "number" and (v ~= v or v == math.huge or v == -math.huge) then
                blocked_count = blocked_count + 1
                protection_log("BLOCKED [NaN/Inf Arg] sender=" .. tostring(sender_id))
                return true
            end
        end
    end)
end)

