local ne_handler_ok = pcall(function()
    if util.register_net_event_handler then
        util.register_net_event_handler(function(event_type, sender_id, args)
            if args and args.model and BLOCKED_NET_OBJ_MODELS[args.model] then
                blocked_count = blocked_count + 1
                protection_log("BLOCKED [Bad Model=" .. tostring(args.model) .. "] sender=" .. tostring(sender_id))
                return true
            end
        end)
    end
end)

-- -------------------------------------------------------------------------
-- PASSIVE PROTECTION THREAD (native guards, runs every frame)
-- -------------------------------------------------------------------------
util.create_thread(function()
    -- Try to enable every Lexis built-in protection flag
    pcall(function()
        if protections then
            local flags = {
                "script_event_crash","net_object_crash","ped_crash","vehicle_crash",
                "object_crash","kick_protection","ceo_kick","bad_sport",
                "transaction_error","idle_kick","spectate","teleport",
                "explosion","wanted_level","bounty","mugger","mercenary",
                "airstrike","ragdoll",
            }
            for _, flag in ipairs(flags) do
                pcall(function() protections[flag] = true end)
                pcall(function() protections.set(flag, true) end)
                pcall(function() protections.enable(flag) end)
            end
        end
    end)

    while true do
        pcall(function()
            local pid  = invoker.call(0x4F8644AF03D0E0D6).int
            local pped = invoker.call(0x43A66C31C68491C0, pid).int

            -- Block fake "lost connection" kick
            invoker.call(0xA03085F5B918F3B9, false)

            -- Protect player ped from remote attacks
            if pped and pped ~= 0 then
                invoker.call(0x45BB4184AE4E977A, pped, false)  -- SET_PED_SUFFERS_CRITICAL_HITS(false)
                invoker.call(0xDB3338C9B4187A6B, pped, false)  -- STOP_PED_WEAPON_FIRING_WHEN_DROPPED
            end
        end)
        util.yield(0)
    end
end)

-- -------------------------------------------------------------------------
-- STARTUP TOAST - confirms protection is active
-- -------------------------------------------------------------------------
do
    local hash_count = 0
    for _ in pairs(BLOCKED_SCRIPT_EVENTS) do hash_count = hash_count + 1 end
    local status = {}
    table.insert(status, se_handler_ok and "ScriptEvent OK" or "ScriptEvent FAILED (update Lexis!)")
    if ne_handler_ok then table.insert(status, "NetEvent OK") end
    util.toast(
        "[KYRON SHIELD] PROTECTION ACTIVE\n" ..
        table.concat(status, " | ") .. "\n" ..
        "Blocking " .. hash_count .. " crash hashes",
        TOAST_ALL
    )
end

local function casino_debug_log(msg)
    local timestamp = os.date("%Y-%m-%d %H:%M:%S")
    local formatted = timestamp .. " [CASINO] " .. tostring(msg) .. "\n"
    pcall(function()
        local dir_cmd = 'if not exist "' .. DEBUG_DIR:gsub("/", "\\") .. '" mkdir "' .. DEBUG_DIR:gsub("/", "\\") .. '"'
        os.execute(dir_cmd)
    end)
    pcall(function()
        local f = io.open(DEBUG_LOG_PATH, "a")
        if f then f:write(formatted) f:flush() f:close() end
    end)
end

