local joaat = _G.joaat or util.joaat
local request = {}
function request.model(hash)
    if not STREAMING.IS_MODEL_IN_CDIMAGE(hash) or not STREAMING.IS_MODEL_VALID(hash) then
        return false
    end
    STREAMING.REQUEST_MODEL(hash)
    local start = util.get_tick_count()
    while not STREAMING.HAS_MODEL_LOADED(hash) do
        if util.get_tick_count() - start > 1000 then return false end
        util.yield(0)
    end
    return true
end
function request.control(entity, force_ownership)
    if not ENTITY.DOES_ENTITY_EXIST(entity) then return false end
    -- Lexis v10: game.update_net_obj_owner forces ownership without needing host/script host
    if force_ownership and game and game.update_net_obj_owner then
        local my_id = players.me and players.me().id or invoker.call(0x4F8644AF03D0E0D6).int
        pcall(game.update_net_obj_owner, entity, my_id)
    end
    local attempts = 0
    while not NETWORK.NETWORK_HAS_CONTROL_OF_ENTITY(entity) and attempts < 15 do
        NETWORK.NETWORK_REQUEST_CONTROL_OF_ENTITY(entity)
        attempts = attempts + 1
        util.yield(0)
    end
    return NETWORK.NETWORK_HAS_CONTROL_OF_ENTITY(entity)
end
function request.dict(dict)
    STREAMING.REQUEST_ANIM_DICT(dict)
    local start = util.get_tick_count()
    while not STREAMING.HAS_ANIM_DICT_LOADED(dict) do
        if util.get_tick_count() - start > 1000 then return false end
        util.yield(0)
    end
    return true
end
function request.weapon(hash)
    WEAPON.REQUEST_WEAPON_ASSET(hash, 31, 0)
    local start = util.get_tick_count()
    while not WEAPON.HAS_WEAPON_ASSET_LOADED(hash) do
        if util.get_tick_count() - start > 1000 then return false end
        util.yield(0)
    end
    return true
end
function request.particle(ptfx)
    STREAMING.REQUEST_NAMED_PTFX_ASSET(ptfx)
    local start = util.get_tick_count()
    while not STREAMING.HAS_NAMED_PTFX_ASSET_LOADED(ptfx) do
        if util.get_tick_count() - start > 1000 then return false end
        util.yield(0)
    end
    return true
end
local function get_coords(entity)
    return invoker.call(0x3FEF770D40960D5A, entity, false).scr_vec3
end
local function get_target()
    if players.is_target_session() then
        notify.push("Test", "Select a specific player first.", { icon = notify.icon.info })
        return nil
    end
    return players.target()
end
local function get_offset_from_coords(pos, heading, dist)
    local rad = math.rad(heading)
    return {
        x = pos.x + (math.sin(-rad) * dist),
        y = pos.y + (math.cos(-rad) * dist),
        z = pos.z
    }
end
local function get_rel_coords(pos, heading, right, fwd, up)
    local rad = math.rad(heading)
    local c = math.cos(rad)
    local s = math.sin(rad)
    return {
        x = pos.x + (c * right) - (s * fwd),
        y = pos.y + (s * right) + (c * fwd),
        z = pos.z + up
    }
end
