-- GLOBAL CASINO STATE (accessible by both UI and monitoring threads)
-- =========================================================================
casino_state = {
    roulette_outcome = 7,
    roulette_active = false,
    slots_symbol = 6,
    slots_active = false,
    blackjack_dealer_bust = false,
    lucky_wheel_prize = 18,
}

-- =========================================================================
-- CASINO MONITORING THREAD (TOP LEVEL - EXACT COPY OF WORKING SCRIPTS)
-- =========================================================================
util.create_thread(function()
    casino_debug_log("Casino monitoring thread started (TOP LEVEL)")

    while true do
        -- ROULETTE RIG
        if casino_state.roulette_active and script.running("casinoroulette") then
            for i = 0, 5 do
                local win_local = script.locals("casinoroulette", 1659 + i)
                local state_local = script.locals("casinoroulette", 1506 + i)

                if win_local and state_local then
                    local current_val = win_local.int32
                    local current_phase = state_local.int32
                    if current_phase >= 2 and current_val ~= -1 and current_val ~= casino_state.roulette_outcome then
                        win_local.int32 = casino_state.roulette_outcome
                        util.yield(10)
                    end
                end
            end
        end

        -- SLOTS RIG
        if casino_state.slots_active and script.running("casino_slots") then
            local current_machine = script.locals("casino_slots", 2151).int32
            if current_machine >= 0 and current_machine <= 53 then
                for slots_iter = 3, 196, 1 do
                    if slots_iter ~= 67 and slots_iter ~= 132 then
                        script.locals("casino_slots", 1374 + slots_iter).int32 = casino_state.slots_symbol
                    end
                end
            end
        end

        -- BLACKJACK RIG
        if casino_state.blackjack_dealer_bust and script.running("blackjack") then
            local player_id = players.me().id
            local current_table_local = script.locals("blackjack", 1800 + 1 + (player_id * 8) + 4)
            local current_table = current_table_local.int32

            if current_table ~= -1 then
                local dealer_offset = 140 + 846 + 1 + (current_table * 13)
                local first_card = script.locals("blackjack", dealer_offset + 1)
                local second_card = script.locals("blackjack", dealer_offset + 2)
                local third_card = script.locals("blackjack", dealer_offset + 3)
                local visible_cards = script.locals("blackjack", 140 + 846 + 12 + (current_table * 13))

                if first_card.int32 ~= 11 then first_card.int32 = 11 end
                if second_card.int32 ~= 12 then second_card.int32 = 12 end
                if third_card.int32 ~= 13 then third_card.int32 = 13 end
                if visible_cards.int32 ~= 3 then visible_cards.int32 = 3 end
            end
        end

        util.yield()
    end
end)

