local function get_char_lines(c) return font_3d[c] or {} end

-- Draw 3D text using line segments (global scope to avoid 200 local limit)
local function draw_3d_text(text, world_x, world_y, world_z, cam_coords, distance, r, g, b)
    if not text or not cam_coords or not cam_coords.scr_vec3 then return end
    local to_x = world_x - cam_coords.scr_vec3.x
    local to_y = world_y - cam_coords.scr_vec3.y
    local to_len = math.sqrt(to_x*to_x + to_y*to_y)
    if to_len < 0.01 then return end
    to_x, to_y = to_x/to_len, to_y/to_len
    local rx, ry = to_y, -to_x
    local scale = math.min(math.max(distance/40, 0.15), 1.5)
    local cw, ch, cs = 0.15*scale, 0.25*scale, 0.25*scale
    local start_off = -(#text-1)*cs/2
    for i=1,#text do
        local lines = get_char_lines(text:sub(i,i):upper())
        local off = start_off+(i-1)*cs
        for _,ln in ipairs(lines) do
            local x1,y1,x2,y2 = ln[1],ln[2],ln[3],ln[4]
            invoker.call(0x6B7256074AE34680,
                world_x+rx*((x1-0.5)*cw+off), world_y+ry*((x1-0.5)*cw+off), world_z+(1-y1)*ch,
                world_x+rx*((x2-0.5)*cw+off), world_y+ry*((x2-0.5)*cw+off), world_z+(1-y2)*ch,
                r,g,b,255)
        end
    end
end

if not MOUSE then MOUSE={x=0,y=0,scroll_up=false,scroll_down=false,just_pressed=false,down=false} end
function is_hovering(x,y,w,h) return MOUSE.x>=x and MOUSE.x<=x+w and MOUSE.y>=y and MOUSE.y<=y+h end

-- =========================================================================
-- SHARED world-to-screen (module-level, visible to ALL threads)
-- Avoids GET_SCREEN_COORD_FROM_WORLD_COORD (crashes on Enhanced).
-- Uses correct GTA ZXY Euler order: yaw=Z then pitch=X.
-- =========================================================================
function kyron_w2s(world_x, world_y, world_z)
    local ok, a, b, c = pcall(function()
        local cc  = invoker.call(0x14D6F5678D8F1B37)       -- GET_GAMEPLAY_CAM_COORD
        local cr  = invoker.call(0x837765A25378F0BB, 2)     -- GET_GAMEPLAY_CAM_ROT
        local fv  = invoker.call(0x65019750A0324133)        -- GET_GAMEPLAY_CAM_FOV
        local cam = cc and (cc.scr_vec3 or cc.vec3)
        local rot = cr and (cr.scr_vec3 or cr.vec3)
        local fov = fv and fv.float
        if not (cam and rot and fov) then return false, 0.5, 0.5 end

        local dx = world_x - cam.x
        local dy = world_y - cam.y
        local dz = world_z - cam.z

        -- Yaw (rotate around world Z)
        local cz = math.cos(-math.rad(rot.z))
        local sz = math.sin(-math.rad(rot.z))
        local rx1 = dx * cz - dy * sz
        local ry1 = dx * sz + dy * cz
        local rz1 = dz

        -- Pitch (rotate around camera X)
        local cx2 = math.cos(-math.rad(rot.x))
        local sx2 = math.sin(-math.rad(rot.x))
        local cam_right   = rx1
        local cam_forward = ry1 * cx2 - rz1 * sx2
        local cam_up      = ry1 * sx2 + rz1 * cx2

        -- Behind camera?
        if cam_forward <= 0.001 then return false, 0.5, 0.5 end

        local ok_ar, ar_r = pcall(invoker.call, 0xF1307EF624A80D87, true)
        local aspect = (ok_ar and ar_r and ar_r.float and ar_r.float > 0.5) and ar_r.float or (16.0/9.0)
        local f = 1.0 / math.tan(math.rad(fov) * 0.5)

        local sx3 = 0.5 + (cam_right / cam_forward) * (f / (2.0 * aspect))
        local sy3 = 0.5 - (cam_up    / cam_forward) * (f / 2.0)

        return (sx3 >= 0.0 and sx3 <= 1.0 and sy3 >= 0.0 and sy3 <= 1.0), sx3, sy3
    end)
    if not ok then return false, 0.5, 0.5 end
    return a, b, c
end

-- Start main thread (EXACTLY like ClickUI)
