            screen_w = res.x or 1920
            screen_h = res.y or 1080
        end
    end

    -- Wallpaper loaded via gui.load_image (same method as Aurox AIO)
    -- Place Kyron_wallpaper.png in: scripts\Kyron\kyron_ui\Kyron_wallpaper.png
    local wallpaper_tex = nil
    local wallpaper_attempted = false
    local function try_load_wallpaper()
        if wallpaper_attempted then return end
        wallpaper_attempted = true
        if not (gui and gui.load_image) then return end
        local candidates = {}
        if SCRIPT_DIR then
            candidates[#candidates+1] = SCRIPT_DIR .. [[\kyron_ui\Kyron_wallpaper.png]]
            candidates[#candidates+1] = SCRIPT_DIR .. [[\Kyron_wallpaper.png]]
        end
        if paths and paths.script then
            candidates[#candidates+1] = paths.script .. [[\Kyron\kyron_ui\Kyron_wallpaper.png]]
            candidates[#candidates+1] = paths.script .. [[\kyron_ui\Kyron_wallpaper.png]]
        end
        for _, p in ipairs(candidates) do
            local ok, tex = pcall(gui.load_image, p)
            if ok and tex then
                wallpaper_tex = tex
                safe_toast("Kyron: Wallpaper loaded!")
                return
            end
        end
        safe_toast("Kyron: Wallpaper not found - check kyron_ui folder")
    end

