        INFO  = {level = 2, name = "INFO",  color = color(255, 255, 255, 255)},
        WARN  = {level = 3, name = "WARN",  color = color(255, 200, 0, 255)},
        ERROR = {level = 4, name = "ERROR", color = color(255, 50, 50, 255)},
        }
    }

    -- Core logging function
    local function debug_log(level_data, module, message, data)
        if not DEBUG.enabled then return end
        if level_data.level < DEBUG.log_level then return end

        local parts = {}

        -- Timestamp
        if DEBUG.show_timestamp then
            local time = os.date and os.date("%H:%M:%S") or "00:00:00"
            table.insert(parts, "[" .. time .. "]")
        end

        -- Level
        table.insert(parts, "[" .. level_data.name .. "]")

        -- Module
        if module and module ~= "" then
            table.insert(parts, "[" .. module .. "]")
        end

        -- Message
        table.insert(parts, tostring(message))

        -- Data
        if data then
            table.insert(parts, "-> " .. tostring(data))
        end

        -- Memory
        if DEBUG.show_memory then
            local now = os.clock()
            if now - DEBUG.last_mem_check >= 1.0 then
                DEBUG.last_mem_check = now
                local mem_kb = collectgarbage("count")
                table.insert(parts, string.format("[Mem: %d KB]", math.floor(mem_kb)))
            end
        end

        local formatted = table.concat(parts, " ")

        -- Add to circular buffer
        local entry = {
            level = level_data.name,
            color = level_data.color,
            message = formatted,
            time = os.clock(),
        }

        if DEBUG.log_count < DEBUG.max_logs then
            DEBUG.log_count = DEBUG.log_count + 1
            table.insert(DEBUG.logs, entry)
        else
            DEBUG.logs[DEBUG.log_head] = entry
            DEBUG.log_head = (DEBUG.log_head % DEBUG.max_logs) + 1
        end

        -- Show toast for errors
        if level_data.level >= 4 then
            safe_toast(message)
        end
    end

    -- Public logging functions
    local function debug_debug(module, message, data)
        debug_log(DEBUG.log_levels.DEBUG, module, message, data)
    end

    local function debug_info(module, message, data)
        debug_log(DEBUG.log_levels.INFO, module, message, data)
    end

    local function debug_warn(module, message, data)
        debug_log(DEBUG.log_levels.WARN, module, message, data)
    end

    local function debug_error(module, message, data)
        debug_log(DEBUG.log_levels.ERROR, module, message, data)
    end

    -- Performance tracking
    local function debug_mark_start(name)
        if not DEBUG.enabled or not DEBUG.show_performance then return end
        DEBUG.perf_marks[name] = os.clock()
    end

    local function debug_mark_end(name)
        if not DEBUG.enabled or not DEBUG.show_performance then return end
        local start = DEBUG.perf_marks[name]
        if not start then return end

        local elapsed = (os.clock() - start) * 1000  -- ms
        DEBUG.perf_marks[name] = nil

        -- Store stats
        if not DEBUG.perf_stats[name] then
            DEBUG.perf_stats[name] = {count = 0, total = 0, min = elapsed, max = elapsed}
        end

        local stat = DEBUG.perf_stats[name]
        stat.count = stat.count + 1
        stat.total = stat.total + elapsed
        stat.min = math.min(stat.min, elapsed)
        stat.max = math.max(stat.max, elapsed)
        stat.avg = stat.total / stat.count

        debug_debug("PERF", string.format("%s: %.2fms", name, elapsed))
        return elapsed
    end

    -- Memory monitoring
    local function debug_log_memory(label)
        if not DEBUG.enabled then return end
        local mem_kb = collectgarbage("count")
        local mem_mb = mem_kb / 1024
        debug_info("MEMORY", string.format("%s: %.2f MB (%.0f KB)", label or "Current", mem_mb, mem_kb))

        -- Store in history
        table.insert(DEBUG.mem_history, {time = os.clock(), kb = mem_kb})
        if #DEBUG.mem_history > 60 then
            table.remove(DEBUG.mem_history, 1)
        end
    end

    -- Frame time tracking
    local function debug_update_frame_time()
        if not DEBUG.enabled then return end
        local now = os.clock()
        if DEBUG.last_frame_time > 0 then
            local frame_time = now - DEBUG.last_frame_time
            table.insert(DEBUG.frame_times, frame_time)
            if #DEBUG.frame_times > 60 then
                table.remove(DEBUG.frame_times, 1)
            end
        end
        DEBUG.last_frame_time = now
    end

    local function debug_get_fps()
        if #DEBUG.frame_times == 0 then return 0 end
        local sum = 0
        for _, t in ipairs(DEBUG.frame_times) do
            sum = sum + t
        end
        local avg = sum / #DEBUG.frame_times
        return avg > 0 and (1 / avg) or 0
    end

    -- Variable watching
    local function debug_watch(var_name, value)
        if not DEBUG.enabled then return end
        local old = DEBUG.watched[var_name]
        DEBUG.watched[var_name] = value
        if old ~= nil and old ~= value then
            debug_debug("WATCH", string.format("%s changed: %s -> %s", var_name, tostring(old), tostring(value)))
        end
    end

