    -- Flag to control when logging is active (only when ESP is enabled)
    -- esp_state.logging_active moved into esp_state

    local function esp_log(msg, level)
        -- ONLY log when ESP is actually enabled
        if not esp_state.logging_active then
            return
        end

        pcall(function()
            local timestamp = os.date("%Y-%m-%d %H:%M:%S")
            local lev = level or "INFO"
            local formatted = timestamp .. " [" .. lev .. "] " .. tostring(msg) .. "\n"
            local f = io.open(ESP_PATHS.log, "a")
            if f then
                f:write(formatted)
                f:flush()
                f:close()
            end
        end)
    end

    -- Initialize log function (will be called when ESP is first enabled)
    local function esp_log_init()
        esp_log("========================================", "INIT")
        esp_log("ESP DEBUG LOG STARTED", "INIT")
        esp_log("Log path: " .. ESP_PATHS.log, "INIT")
        esp_log("========================================", "INIT")
    end

    -- Manual 3D-to-2D projection (avoids out-parameter natives that crash)
    local function world_to_screen(world_x, world_y, world_z)
        local success, on_screen, screen_x, screen_y = pcall(function()
            -- Get camera data - call natives directly to avoid wrapper issues
            local cam_coord_result = invoker.call(0x14D6F5678D8F1B37)  -- GET_GAMEPLAY_CAM_COORD
            local cam_rot_result = invoker.call(0x837765A25378F0BB, 2)  -- GET_GAMEPLAY_CAM_ROT (2 = Euler)
            local cam_fov = invoker.call(0x65019750A0324133).float  -- GET_GAMEPLAY_CAM_FOV

            -- Try to get coordinates from result - try both accessors
            local cam_coords = cam_coord_result.scr_vec3 or cam_coord_result.vec3
            local cam_rot = cam_rot_result.scr_vec3 or cam_rot_result.vec3

            if not cam_coords or not cam_rot or not cam_fov then
                return false, 0.5, 0.5
            end

            -- Calculate direction vector from camera to world point
            local dx = world_x - cam_coords.x
            local dy = world_y - cam_coords.y
            local dz = world_z - cam_coords.z

            -- GTA uses ZXY Euler rotation order (yaw=Z, pitch=X, roll=Y)
            -- We invert to transform world→camera space: apply -rz then -rx
            local rx = math.rad(cam_rot.x)  -- pitch
            local rz = math.rad(cam_rot.z)  -- yaw

            -- Step 1: rotate around world Z (yaw)
            local cos_z = math.cos(-rz)
            local sin_z = math.sin(-rz)
            local rx1 =  dx * cos_z - dy * sin_z   -- camera right
            local ry1 =  dx * sin_z + dy * cos_z   -- camera forward (pre-pitch)
            local rz1 =  dz                         -- camera up (pre-pitch)

            -- Step 2: rotate around camera X (pitch)
            local cos_x = math.cos(-rx)
            local sin_x = math.sin(-rx)
            local cam_right   = rx1
            local cam_forward = ry1 * cos_x - rz1 * sin_x
            local cam_up      = ry1 * sin_x + rz1 * cos_x

            -- Depth in camera space: positive = in front of camera.
            -- We use cam_forward as depth. If it's too small the point is
            -- nearly perpendicular to the view (not behind), so we keep a
            -- smaller epsilon to avoid killing near-90° look-up/down cases.
            if cam_forward <= 0.01 then
                return false, 0.5, 0.5
            end

            -- Project to screen space
            local fov_rad = math.rad(cam_fov)
            local ok_ar, ar_r = pcall(invoker.call, 0xF1307EF624A80D87, true)
            local aspect = (ok_ar and ar_r and ar_r.float and ar_r.float > 0.5) and ar_r.float or (16.0/9.0)

            local f = 1.0 / math.tan(fov_rad * 0.5)  -- focal length

            -- sx: horizontal. cam_right positive = right of screen
            -- sz: vertical.   cam_up positive = up on screen
            local sx = 0.5 + (cam_right  / cam_forward) * (f / (2.0 * aspect))
            local sz = 0.5 - (cam_up     / cam_forward) * (f / 2.0)

            local is_on_screen = (sx >= 0.0 and sx <= 1.0 and sz >= 0.0 and sz <= 1.0)

            return is_on_screen, sx, sz
        end)

        if not success then
            esp_log("ERROR: Manual W2S failed: " .. tostring(on_screen), "ERROR")
            return false, 0.5, 0.5
        end

        return on_screen, screen_x, screen_y
    end

    -- ESP Thread - Professional with 2D screen-space rendering
    util.create_thread(function()
        local esp_was_enabled = false

        while true do
            if esp_state.enabled then
                -- First time enabled notification - ACTIVATE LOGGING HERE
                if not esp_was_enabled then
                    esp_state.logging_active = true  -- Enable logging when ESP is turned on
                    esp_log_init()  -- Write initialization message to log
                    esp_log(">>> ESP ENABLED FOR FIRST TIME <<<")
                    if util and util.toast then
                        util.toast("[ESP] Enabled - logging to: Kyron/Debug ESP/")
                    end
                    esp_was_enabled = true
                end

                esp_state.debug_frame_count = (esp_state.debug_frame_count or 0) + 1
                esp_state.name_data = {}  -- Clear player list data each frame

                -- Log ESP state every 60 frames
                if esp_state.debug_frame_count % 60 == 0 then
                    esp_log(string.format("ESP FRAME %d - Enabled=%s, Names=%s",
                        esp_state.debug_frame_count,
                        tostring(esp_state.enabled),
                        tostring(esp_state.draw_names)))
                end

                local me = players and players.me and players.me()
                if me and me.ped and me.coords then
                    if esp_state.debug_frame_count % 60 == 0 then
                        esp_log(string.format("  Me: ped=%s coords=(%.1f, %.1f, %.1f)",
                            tostring(me.ped), me.coords.x or 0, me.coords.y or 0, me.coords.z or 0))
                    end
                    -- Get camera position for billboarding
                    local cam_coords = invoker.call(0x14D6F5678D8F1B37) -- GET_GAMEPLAY_CAM_COORD
                    local cam_rot = invoker.call(0x837765A25378F0BB, 2) -- GET_GAMEPLAY_CAM_ROT

                    if esp_state.debug_frame_count % 60 == 0 then
                        local player_count = 0
                        if players and players.list then
                            for _, p in ipairs(players.list()) do
                                if p and p.ped and p.ped ~= me.ped then
                                    player_count = player_count + 1
                                end
                            end
                        end
                        debug_debug("ESP", string.format("Frame:%d Players:%d", esp_state.debug_frame_count, player_count))
                        debug_debug("ESP", string.format("Boxes:%s Health:%s Names:%s Snaplines:%s",
                            tostring(esp_state.draw_boxes),
                            tostring(esp_state.draw_health),
                            tostring(esp_state.draw_names),
                            tostring(esp_state.draw_snaplines)))
                    end

                    if players and players.list then
                        local player_list = players.list()
                        if esp_state.debug_frame_count % 60 == 0 then
                            esp_log("  Players.list() returned " .. #player_list .. " players")
                        end

                        for idx, p in ipairs(player_list) do
                            if p and p.ped and p.ped ~= me.ped and p.coords and p.name then
                                -- Calculate distance
                                local dx = p.coords.x - me.coords.x
                                local dy = p.coords.y - me.coords.y
                                local dz = p.coords.z - me.coords.z
                                local distance = math.sqrt(dx*dx + dy*dy + dz*dz)

                                if esp_state.debug_frame_count % 60 == 0 then
                                    esp_log(string.format("  Player #%d: %s | dist=%.1f | ped=%s | coords=(%.1f,%.1f,%.1f)",
                                        idx, p.name, distance, tostring(p.ped),
                                        p.coords.x, p.coords.y, p.coords.z))
                                end

                                debug_debug("ESP", string.format("Player %s at distance %.1f (max: %.1f)", p.name, distance, esp_state.max_distance))

                                -- Define coordinates HERE (outside distance check) so names work at any distance
                                local x = p.coords.x
                                local y = p.coords.y
                                local z = p.coords.z

                                if distance <= esp_state.max_distance then
                                    if esp_state.debug_frame_count % 60 == 0 then
                                        esp_log(string.format("  Player %s within range (%.1f <= %.1f)", p.name, distance, esp_state.max_distance))
                                    end
                                    debug_debug("ESP", string.format("Drawing ESP for %s", p.name))

                                    -- Get health
                                    local health = invoker.call(0xEEF059FAD016D209, p.ped) -- GET_ENTITY_HEALTH
                                    local max_health = invoker.call(0x4700A416E8324EF3, p.ped) -- GET_ENTITY_MAX_HEALTH
                                    local health_percent = 1.0
                                    if health and max_health and health.int and max_health.int and max_health.int > 0 then
                                        health_percent = health.int / max_health.int
                                    end

                                    -- Draw snaplines
                                    if esp_state.draw_snaplines then
                                        invoker.call(0x6B7256074AE34680,
                                            me.coords.x, me.coords.y, me.coords.z - 1.0,
                                            x, y, z,
                                            0, 255, 0, 200) -- DRAW_LINE (green)
                                    end

                                    -- Draw 3D box around player
                                    if esp_state.draw_boxes then
                                        local w = 0.5
                                        local h = 1.8
                                        local box_z = z - 1.0

                                        -- Bottom square
                                        invoker.call(0x6B7256074AE34680, x-w, y-w, box_z, x+w, y-w, box_z, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x+w, y-w, box_z, x+w, y+w, box_z, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x+w, y+w, box_z, x-w, y+w, box_z, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x-w, y+w, box_z, x-w, y-w, box_z, 255, 0, 0, 200)

                                        -- Top square
                                        invoker.call(0x6B7256074AE34680, x-w, y-w, box_z+h, x+w, y-w, box_z+h, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x+w, y-w, box_z+h, x+w, y+w, box_z+h, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x+w, y+w, box_z+h, x-w, y+w, box_z+h, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x-w, y+w, box_z+h, x-w, y-w, box_z+h, 255, 0, 0, 200)

                                        -- Vertical lines
                                        invoker.call(0x6B7256074AE34680, x-w, y-w, box_z, x-w, y-w, box_z+h, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x+w, y-w, box_z, x+w, y-w, box_z+h, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x+w, y+w, box_z, x+w, y+w, box_z+h, 255, 0, 0, 200)
                                        invoker.call(0x6B7256074AE34680, x-w, y+w, box_z, x-w, y+w, box_z+h, 255, 0, 0, 200)
                                    end

                                    -- DISTANCE-SCALED health bar (constant apparent size)
                                    if esp_state.draw_health and cam_coords and cam_coords.scr_vec3 and cam_rot and cam_rot.scr_vec3 then
                                        -- Calculate camera-to-player vector
                                        local to_player_x = x - cam_coords.scr_vec3.x
                                        local to_player_y = y - cam_coords.scr_vec3.y
                                        local to_player_len = math.sqrt(to_player_x*to_player_x + to_player_y*to_player_y)

                                        if to_player_len > 0.01 then
                                            -- Scale for constant APPARENT size on screen (clamped to avoid extremes)
                                            local scale = math.min(math.max(distance / 50.0, 0.8), 2.5)
                                            local bar_width = 1.2 * scale
                                            local bar_height = 0.15 * scale
                                            local bar_z = z + 1.0

                                            local r = math.floor(255 * (1 - health_percent))
                                            local g = math.floor(255 * health_percent)

                                            -- Normalize
                                            to_player_x = to_player_x / to_player_len
                                            to_player_y = to_player_y / to_player_len

                                            -- Calculate right vector (perpendicular to camera-to-player)
                                            local right_x = -to_player_y
                                            local right_y = to_player_x

                                            -- Draw dark gray background first (full width)
                                            for i = 0, 50 do
                                                local offset = (i / 50) * bar_height
                                                local half_width = bar_width / 2
                                                invoker.call(0x6B7256074AE34680,
                                                    x - right_x * half_width, y - right_y * half_width, bar_z + offset,
                                                    x + right_x * half_width, y + right_y * half_width, bar_z + offset,
                                                    40, 40, 40, 200)
                                            end

                                            -- Draw filled health bar facing camera
                                            for i = 0, 50 do
                                                local offset = (i / 50) * bar_height
                                                local line_width = bar_width * health_percent
                                                local half_width = line_width / 2

                                                invoker.call(0x6B7256074AE34680,
                                                    x - right_x * half_width, y - right_y * half_width, bar_z + offset,
                                                    x + right_x * half_width, y + right_y * half_width, bar_z + offset,
                                                    r, g, 0, 255)
                                            end
                                        end
                                    end
                                end

                                -- Draw player name above head using 3D line-based text (same as health bars!)
                                if esp_state.draw_names or esp_state.draw_distance then
                                    pcall(function()
                                        -- Build display text
                                        local display_text = ""
                                        if esp_state.draw_names and esp_state.draw_distance then
                                            display_text = string.format("%s [%.0fm]", p.name, distance)
                                        elseif esp_state.draw_names then
                                            display_text = p.name
                                        else
                                            display_text = string.format("%.0fm", distance)
                                        end

                                        -- Text height above player head
                                        local name_world_z = z + 1.3

                                        -- Distance-based color
                                        local r, g, b
                                        if distance > 300 then
                                            r, g, b = 255, 80, 80  -- Red
                                        elseif distance > 150 then
                                            r, g, b = 255, 255, 80  -- Yellow
                                        else
                                            r, g, b = 80, 255, 80  -- Green
                                        end

                                        -- Draw 3D text using line segments (just like health bars!)
                                        draw_3d_text(display_text, x, y, name_world_z, cam_coords, distance, r, g, b)
                                    end)
                                end

                                -- Collect player data for side panel list
                                if esp_state.draw_player_list and p.name then
                                    -- Filter out invalid player entries
                                    local is_valid = p.name and
                                                    type(p.name) == "string" and
                                                    #p.name > 0 and
                                                    not p.name:match("Invalid") and
                                                    not p.name:match("INVALID")

                                    if is_valid then
                                        table.insert(esp_state.name_data, {
                                            name = p.name,
                                            distance = distance,
                                            ped = p.ped  -- Store ped handle for 3D name rendering
                                        })
                                    end
                                end
                            end
                        end
                    end

                    -- No gamer tag cleanup needed (we use native 3D text now)

                    -- Render player list in side panel
                    if esp_state.draw_player_list and esp_state.name_data and #esp_state.name_data > 0 then
                        -- Sort by distance (closest first)
                        table.sort(esp_state.name_data, function(a, b) return a.distance < b.distance end)

                        local panel_x = 30
                        local panel_y = 200
                        local line_height = 24  -- Increased for bigger text

                        for i, ndata in ipairs(esp_state.name_data) do
                            if i > 10 then break end  -- Show max 10 players

                            local y_pos = panel_y + ((i - 1) * line_height)

                            if gui and gui.text then
                                local display_text = string.format("%s [%.0fm]", ndata.name, ndata.distance)

                                -- Determine color based on mode
                                local text_color
                                if esp_state.player_list_color_mode == 1 then
                                    -- Distance-based coloring
                                    if ndata.distance > 400 then
                                        text_color = color(255, 0, 0, 255)  -- Red for far
                                    elseif ndata.distance > 200 then
                                        text_color = color(255, 255, 0, 255)  -- Yellow for medium
                                    else
                                        text_color = color(0, 255, 0, 255)  -- Green for close
                                    end
                                elseif esp_state.player_list_color_mode == 2 then
                                    -- Rainbow - cycle through colors based on time and index
                                    local time = os.clock()
                                    local hue = ((time * 100) + (i * 30)) % 360
                                    local r, g, b = 0, 0, 0
                                    local h = hue / 60
                                    local x = (1 - math.abs(h % 2 - 1))
                                    if h < 1 then r, g, b = 1, x, 0
                                    elseif h < 2 then r, g, b = x, 1, 0
                                    elseif h < 3 then r, g, b = 0, 1, x
                                    elseif h < 4 then r, g, b = 0, x, 1
                                    elseif h < 5 then r, g, b = x, 0, 1
                                    else r, g, b = 1, 0, x
                                    end
                                    text_color = color(math.floor(r * 255), math.floor(g * 255), math.floor(b * 255), 255)
                                elseif esp_state.player_list_color_mode == 3 then
                                    -- White
                                    text_color = color(255, 255, 255, 255)
                                elseif esp_state.player_list_color_mode == 4 then
                                    -- Cyan
                                    text_color = color(0, 255, 255, 255)
                                elseif esp_state.player_list_color_mode == 5 then
                                    -- Pink/Magenta
                                    text_color = color(255, 0, 255, 255)
                                end

                                -- Draw background box for better readability
                                local bg_x = panel_x - 4
                                local bg_y = y_pos - 2
                                local bg_w = 280
                                local bg_h = 22
                                if gui and gui.rect then
                                    local bg = gui.rect(vec2(bg_x, bg_y), vec2(bg_w, bg_h))
                                    if bg then
                                        bg:color(color(0, 0, 0, 180))  -- Semi-transparent black
                                        bg:draw()
                                    end
                                end

                                -- Draw thick outline for bold effect
                                for ox = -2, 2 do
                                    for oy = -2, 2 do
                                        if ox ~= 0 or oy ~= 0 then
                                            local shadow = gui.text(display_text)
                                            if shadow then
                                                shadow:position(vec2(panel_x + ox, y_pos + oy))
                                                shadow:scale(18)
                                                shadow:color(color(0, 0, 0, 255))
                                                shadow:draw()
                                            end
                                        end
                                    end
                                end

                                -- Draw main text
                                local t = gui.text(display_text)
                                if t then
                                    t:position(vec2(panel_x, y_pos))
                                    t:scale(18)  -- Bigger text
                                    t:color(text_color)
                                    t:draw()
                                end
                            end
                        end
                    end

                    -- DISABLED: 3D names above head (causes crashes with invalid ped handles)
                    -- if esp_state.draw_names_above_head and esp_state.name_data and #esp_state.name_data > 0 then
                    --     [code removed - feature disabled due to crashes]
                    -- end

                    -- ============================================================
                    -- NPC ESP - Draw ESP for nearby NPCs (Non-Player Characters)
                    -- ============================================================
                    if esp_state.draw_npcs then
                        pcall(function()
                            -- GET_NEARBY_PEDS (0x23F8F5FC7E8C4A6B) crashes in Enhanced
                            -- when passed a raw Lua table (SEH write-violation, pcall can't catch).
                            -- Replaced with safe GET_CLOSEST_PED grid search.
                            local seen = {}
                            local npc_count = 0
                            local max_range = math.min(esp_state.npc_max_distance or 100, 200)
                            local px = me.coords.x
                            local py = me.coords.y
                            local pz = me.coords.z

                            local sample_pts = {
                                {0,0},{15,0},{-15,0},{0,15},{0,-15},
                                {10,10},{-10,10},{10,-10},{-10,-10},
                                {30,0},{-30,0},{0,30},{0,-30},
                                {40,40},{-40,40},{40,-40},{-40,-40},
                            }

                            for _, off in ipairs(sample_pts) do
                                if npc_count >= 30 then break end
                                local ok_p, pr = pcall(invoker.call, 0x57AB4A3080B91165,
                                    1.0*(px+off[1]), 1.0*(py+off[2]), 1.0*pz, 1.0*max_range, 1, 1)
                                if ok_p and pr then
                                    local ped_handle = pr.int or 0
                                    if ped_handle ~= 0 and ped_handle ~= me.ped and not seen[ped_handle] then
                                        seen[ped_handle] = true
                                        local ok_ex, ex = pcall(invoker.call, 0x7239B21A38F536BA, ped_handle)
                                        local ok_ip, ip = pcall(invoker.call, 0x12534C348C6CB68B, ped_handle)
                                        local is_player = ok_ip and ip and ip.bool

                                        if ok_ex and ex and ex.bool and not is_player then
                                            -- Get NPC coordinates (wrapped in pcall - stale handles crash Enhanced)
                                            local ok_nc, npc_coords = pcall(invoker.call, 0x3FEF770D40960D5A, ped_handle, false)

                                            if ok_nc and npc_coords and npc_coords.scr_vec3 then
                                                local nx = npc_coords.scr_vec3.x
                                                local ny = npc_coords.scr_vec3.y
                                                local nz = npc_coords.scr_vec3.z

                                                -- Calculate distance
                                                local dx = nx - me.coords.x
                                                local dy = ny - me.coords.y
                                                local dz = nz - me.coords.z
                                                local npc_distance = math.sqrt(dx*dx + dy*dy + dz*dz)

                                                -- Only draw if within NPC max distance
                                                if npc_distance <= esp_state.npc_max_distance then
                                                    npc_count = npc_count + 1

                                                    -- Limit to 50 NPCs to avoid performance issues
                                                    if npc_count <= 50 then
                                                        -- Draw 3D box around NPC (cyan color for NPCs)
                                                        if esp_state.draw_boxes then
                                                            local w = 0.4
                                                            local h = 1.8
                                                            local box_z = nz - 1.0

                                                            -- Cyan colored box for NPCs
                                                            -- Bottom square
                                                            invoker.call(0x6B7256074AE34680, nx-w, ny-w, box_z, nx+w, ny-w, box_z, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx+w, ny-w, box_z, nx+w, ny+w, box_z, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx+w, ny+w, box_z, nx-w, ny+w, box_z, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx-w, ny+w, box_z, nx-w, ny-w, box_z, 0, 255, 255, 180)

                                                            -- Top square
                                                            invoker.call(0x6B7256074AE34680, nx-w, ny-w, box_z+h, nx+w, ny-w, box_z+h, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx+w, ny-w, box_z+h, nx+w, ny+w, box_z+h, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx+w, ny+w, box_z+h, nx-w, ny+w, box_z+h, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx-w, ny+w, box_z+h, nx-w, ny-w, box_z+h, 0, 255, 255, 180)

                                                            -- Vertical lines
                                                            invoker.call(0x6B7256074AE34680, nx-w, ny-w, box_z, nx-w, ny-w, box_z+h, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx+w, ny-w, box_z, nx+w, ny-w, box_z+h, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx+w, ny+w, box_z, nx+w, ny+w, box_z+h, 0, 255, 255, 180)
                                                            invoker.call(0x6B7256074AE34680, nx-w, ny+w, box_z, nx-w, ny+w, box_z+h, 0, 255, 255, 180)
                                                        end

                                                        -- Draw health bar for NPCs
                                                        if esp_state.draw_health and cam_coords and cam_coords.scr_vec3 then
                                                            local health = invoker.call(0xEEF059FAD016D209, ped_handle) -- GET_ENTITY_HEALTH
                                                            local max_health = invoker.call(0x4700A416E8324EF3, ped_handle) -- GET_ENTITY_MAX_HEALTH
                                                            local health_percent = 1.0
                                                            if health and max_health and health.int and max_health.int and max_health.int > 0 then
                                                                health_percent = health.int / max_health.int
                                                            end

                                                            local to_npc_x = nx - cam_coords.scr_vec3.x
                                                            local to_npc_y = ny - cam_coords.scr_vec3.y
                                                            local to_npc_len = math.sqrt(to_npc_x*to_npc_x + to_npc_y*to_npc_y)

                                                            if to_npc_len > 0.01 then
                                                                local scale = math.min(math.max(npc_distance / 50.0, 0.8), 2.0)
                                                                local bar_width = 1.0 * scale
                                                                local bar_height = 0.12 * scale
                                                                local bar_z = nz + 0.9

                                                                local r = math.floor(255 * (1 - health_percent))
                                                                local g = math.floor(255 * health_percent)

                                                                to_npc_x = to_npc_x / to_npc_len
                                                                to_npc_y = to_npc_y / to_npc_len

                                                                local right_x = -to_npc_y
                                                                local right_y = to_npc_x

                                                                -- Draw background
                                                                for i = 0, 40 do
                                                                    local offset = (i / 40) * bar_height
                                                                    local half_width = bar_width / 2
                                                                    invoker.call(0x6B7256074AE34680,
                                                                        nx - right_x * half_width, ny - right_y * half_width, bar_z + offset,
                                                                        nx + right_x * half_width, ny + right_y * half_width, bar_z + offset,
                                                                        40, 40, 40, 180)
                                                                end

                                                                -- Draw filled health bar
                                                                for i = 0, 40 do
                                                                    local offset = (i / 40) * bar_height
                                                                    local line_width = bar_width * health_percent
                                                                    local half_width = line_width / 2

                                                                    invoker.call(0x6B7256074AE34680,
                                                                        nx - right_x * half_width, ny - right_y * half_width, bar_z + offset,
                                                                        nx + right_x * half_width, ny + right_y * half_width, bar_z + offset,
                                                                        r, g, 0, 240)
                                                                end
                                                            end
                                                        end

                                                        -- Draw NPC label and distance
                                                        if esp_state.draw_names or esp_state.draw_distance then
                                                            pcall(function()
                                                                local name_world_z = nz + 1.2
                                                                local on_screen, sx, sy = world_to_screen(nx, ny, name_world_z)
                                                                if on_screen and sx and sy then
                                                                    local res = game.resolution()
                                                                    local screen_px = sx * res.x
                                                                    local screen_py = sy * res.y

                                                                    local display_text = ""
                                                                    if esp_state.draw_names and esp_state.draw_distance then
                                                                        display_text = string.format("NPC [%.0fm]", npc_distance)
                                                                    elseif esp_state.draw_names then
                                                                        display_text = "NPC"
                                                                    else
                                                                        display_text = string.format("%.0fm", npc_distance)
                                                                    end

                                                                    -- Shadow
                                                                    for ox = -1, 1 do
                                                                        for oy = -1, 1 do
                                                                            if ox ~= 0 or oy ~= 0 then
                                                                                local shadow = gui.text(display_text)
                                                                                if shadow then
                                                                                    shadow:position(vec2(screen_px + ox, screen_py + oy))
                                                                                    shadow:scale(12)
                                                                                    shadow:color(color(0, 0, 0, 255))
                                                                                    shadow:draw()
                                                                                end
                                                                            end
                                                                        end
                                                                    end

                                                                    -- Main text (cyan for NPCs)
                                                                    local t = gui.text(display_text)
                                                                    if t then
                                                                        t:position(vec2(screen_px, screen_py))
                                                                        t:scale(12)
                                                                        t:color(color(0, 255, 255, 255))  -- Cyan
                                                                        t:draw()
                                                                    end
                                                                end
                                                            end)
                                                        end
                                                    end
                                                end
                                            end
                                        end
                                    end
                                end
                            end
                        end)
                    end
                end
            else
                -- ESP disabled - cleanup gamer tags and stop logging
                if esp_was_enabled then
                    esp_log(">>> ESP DISABLED <<<")
                    esp_log("========================================")
                    esp_state.logging_active = false  -- Stop logging when ESP is turned off
                    esp_was_enabled = false
                end

                if esp_state.gamer_tags and next(esp_state.gamer_tags) then
                    for ped, tag_id in pairs(esp_state.gamer_tags) do
                        -- REMOVE_MP_GAMER_TAG (0x31698AA80E0223F8)
                        invoker.call(0x31698AA80E0223F8, tag_id)
                    end
                    esp_state.gamer_tags = {}
                end
            end

            -- Render custom screen message at top of screen (works independently of ESP)
            if esp_state.custom_message_enabled and esp_state.custom_message_text and esp_state.custom_message_text ~= "" then
                if gui and gui.text then
                    -- Get screen position for message (positioned where F4 hint was)
                    local screen_width = 1920  -- Adjust if needed
                    local message_x = (screen_width / 2) + 250  -- Moved to the right
                    local message_y = 30  -- Top of screen

                    -- Determine color based on mode
                    local text_color
                    if esp_state.custom_message_color_mode == 1 then
                        -- White
                        text_color = color(255, 255, 255, 255)
                    elseif esp_state.custom_message_color_mode == 2 then
                        -- Rainbow
                        local time = os.clock()
                        local speed = esp_state.custom_message_rainbow_speed or 1.0
                        local hue = (time * 100 * speed) % 360
                        local r, g, b = 0, 0, 0
                        local h = hue / 60
                        local x = (1 - math.abs(h % 2 - 1))
                        if h < 1 then r, g, b = 1, x, 0
                        elseif h < 2 then r, g, b = x, 1, 0
                        elseif h < 3 then r, g, b = 0, 1, x
                        elseif h < 4 then r, g, b = 0, x, 1
                        elseif h < 5 then r, g, b = x, 0, 1
                        else r, g, b = 1, 0, x
                        end
                        text_color = color(math.floor(r * 255), math.floor(g * 255), math.floor(b * 255), 255)
                    elseif esp_state.custom_message_color_mode == 3 then
                        -- Red
                        text_color = color(255, 0, 0, 255)
                    elseif esp_state.custom_message_color_mode == 4 then
                        -- Green
                        text_color = color(0, 255, 0, 255)
                    elseif esp_state.custom_message_color_mode == 5 then
                        -- Blue
                        text_color = color(0, 0, 255, 255)
                    elseif esp_state.custom_message_color_mode == 6 then
                        -- Yellow
                        text_color = color(255, 255, 0, 255)
                    elseif esp_state.custom_message_color_mode == 7 then
                        -- Cyan
                        text_color = color(0, 255, 255, 255)
                    elseif esp_state.custom_message_color_mode == 8 then
                        -- Pink/Magenta
                        text_color = color(255, 0, 255, 255)
                    else
                        text_color = color(255, 255, 255, 255)  -- Default to white
                    end

                    -- Draw thick outline for bold effect (same as player list)
                    for ox = -2, 2 do
                        for oy = -2, 2 do
                            if ox ~= 0 or oy ~= 0 then
                                local shadow = gui.text(esp_state.custom_message_text)
                                if shadow then
                                    shadow:position(vec2(message_x + ox, message_y + oy))
                                    shadow:scale(24)  -- Slightly bigger than player list
                                    shadow:color(color(0, 0, 0, 255))
                                    if gui.justify then
                                        shadow:justify(gui.justify.center)
                                    end
                                    shadow:draw()
                                end
                            end
                        end
                    end

                    -- Draw main text
                    local t = gui.text(esp_state.custom_message_text)
                    if t then
                        t:position(vec2(message_x, message_y))
                        t:scale(24)  -- Slightly bigger than player list
                        t:color(text_color)
                        if gui.justify then
                            t:justify(gui.justify.center)
                        end
                        t:draw()
                    end
                end
            end

            util.yield(0) -- ESP runs every frame
        end
    end)

