    -- Helper to get player object with methods (like Zodiac's players.get())
    local function get_player_object(player_id)
        if not players or not players.list then return nil end
        for _, p in ipairs(players.list()) do
            if p and p.id == player_id then
                return p -- Return the actual player object
            end
        end
        return nil
    end

    -- Helper to request control of an entity.
    -- When a player ped occupies the entity, that player owns it on the network.
    -- We must lock migration first (so it doesn't snap back), flag as mission entity
    -- (forces the engine to allow authority transfer), then request + yield with
    -- enough delay (50ms per attempt) for the network handshake across a real session.
    local function request_control(entity)
        if not entity or entity == 0 then return false end
        local exists = invoker.call(0x7239B21A38F536BA, entity) -- DOES_ENTITY_EXIST
        if not exists or not exists.bool then return false end

        -- Ensure entity is networked before trying to take control
        local is_net = invoker.call(0xC7827959479DCC78, entity) -- NETWORK_GET_ENTITY_IS_NETWORKED
        if not is_net or not is_net.bool then
            invoker.call(0x06FAACD625D80CAA, entity) -- NETWORK_REGISTER_ENTITY_AS_NETWORKED
            util.yield(100)
        end

        -- Lock migration so control does not snap back to the occupying player
        local nid_r = invoker.call(0xA11700682F3AD45C, entity) -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
        if nid_r and nid_r.int and nid_r.int ~= 0 then
            invoker.call(0xE05E81A888FA63C8, nid_r.int, true)  -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
            invoker.call(0x299EEB23175895FC, nid_r.int, false) -- SET_NETWORK_ID_CAN_MIGRATE false
        end

        -- Flag as mission entity to force engine authority transfer
        invoker.call(0xAD738C3085FE7E11, entity, true, true) -- SET_ENTITY_AS_MISSION_ENTITY

        -- Request control with 50ms per attempt so the network handshake has time to complete
        for _ = 1, 15 do
            local has_control = invoker.call(0x01BF60A500E28887, entity) -- NETWORK_HAS_CONTROL_OF_ENTITY
            if has_control and has_control.bool then return true end
            invoker.call(0xB69317BF5E782347, entity) -- NETWORK_REQUEST_CONTROL_OF_ENTITY
            util.yield(50)
        end

        local final = invoker.call(0x01BF60A500E28887, entity)
        return final and final.bool or false
    end

    -- Helper to networkise an entity (make it visible to all players in session)
    local function networkise_entity(entity)
        if not entity or entity == 0 then return end
        -- DOES_ENTITY_EXIST (0x7239B21A38F536BA)
        local exists = invoker.call(0x7239B21A38F536BA, entity)
        if not exists or not exists.bool then return end

        -- NETWORK_IS_SESSION_STARTED (0x9DE624D2FC4B603F)
        local session_started = invoker.call(0x9DE624D2FC4B603F)
        if session_started and session_started.bool then
            -- NETWORK_GET_ENTITY_IS_NETWORKED (0xC7827959479DCC78)
            local is_networked = invoker.call(0xC7827959479DCC78, entity)
            if not is_networked or not is_networked.bool then
                -- NETWORK_REGISTER_ENTITY_AS_NETWORKED (0x06FAACD625D80CAA)
                invoker.call(0x06FAACD625D80CAA, entity)
                local start_time = os.clock()
                while os.clock() - start_time < 1.0 do
                    local check = invoker.call(0xC7827959479DCC78, entity)
                    if check and check.bool then break end
                    util.yield(0)
                end
            end

            -- ── v10 FIX: force ownership via game.update_net_obj_owner (no host required) ──
            local my_id = players.me and players.me().id or invoker.call(0x4F8644AF03D0E0D6).int
            if game and game.update_net_obj_owner then
                pcall(game.update_net_obj_owner, entity, my_id)
            end

            -- NETWORK_GET_NETWORK_ID_FROM_ENTITY (0xA11700682F3AD45C)
            local netId = invoker.call(0xA11700682F3AD45C, entity)
            if netId and netId.int and netId.int ~= 0 then
                -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES (0xE05E81A888FA63C8)
                invoker.call(0xE05E81A888FA63C8, netId.int, true)
                -- SET_NETWORK_ID_ALWAYS_EXISTS_FOR_PLAYER (0xA8A024587329F36A)
                invoker.call(0xA8A024587329F36A, netId.int, my_id, true)
                -- SET_NETWORK_ID_CAN_MIGRATE (0x299EEB23175895FC) – keep false so WE own it
                invoker.call(0x299EEB23175895FC, netId.int, false)
            end
        end
    end

