        ptfx_asset_loaded = nil,    -- currently loaded asset name
        ptfx_scroll = 0,            -- scroll offset for PTFX list
        ptfx_opacity = 1.0,         -- opacity/scale multiplier (0.1 – 3.0)

        -- Movement
        fov = 50.0,
        -- Vehicle Thrower
        veh_thrower_enabled   = false,
        veh_thrower_carrying  = false,
        veh_thrower_vehicle   = 0,
        veh_thrower_power     = 35.0,
        veh_thrower_search_radius = 15.0,
        -- Context Menu
        context_menu_enabled  = false,
        context_menu_active   = false,
        context_menu_entity   = 0,
        context_menu_type     = nil,
        context_menu_sel      = 1,
        context_menu_options  = {},
        -- Far POV Camera
        far_pov_enabled       = false,
        far_pov_distance      = 10.0,
        far_pov_cam           = nil,
        far_pov_yaw           = 0.0,
        far_pov_pitch         = -10.0,
        far_pov_initialized   = false,
    }

    -- Cleanup function for preview clone ped
    local function cleanup_preview_clone()
        if self_state.preview_active and self_state.preview_ped then
            pcall(function()
                -- Check if ped still exists
                if invoker.call(0x7239B21A38F536BA, self_state.preview_ped).bool then
                    -- Make invisible first
                    invoker.call(0xE3B6097CC25AA69E, self_state.preview_ped, false, false) -- SET_ENTITY_VISIBLE
                    -- Teleport clone far underground (safer than DELETE_ENTITY, prevents crashes)
                    invoker.call(0x06843DA7060A026B, self_state.preview_ped, 0.0, 0.0, -1000.0, false, false, false, false) -- SET_ENTITY_COORDS
                end
            end)
            self_state.preview_ped = nil
            self_state.preview_active = false
            self_state.preview_rotation = 0.0
        end
    end

    -- =========================================================================
    -- CONTEXT MENU THREAD
    -- Activated by [X] when context_menu_enabled is true.
    -- Raycasts from screen center, detects entity type, shows scrollable
    -- action menu with green 3D bounding box. Works on vehicles, peds, objects.
    -- =========================================================================
    util.create_thread(function()
        local ctx = self_state  -- alias

        -- Helper: build action list (vehicles only)
        local function build_options(etype)
            return {
                "KILL ENGINE", "FIX VEHICLE", "BURST TIRES", "HALT",
                "COPY VEHICLE", "BOOST", "LAUNCH", "EJECT", "TP INTO",
                "COPY HASH", "EXPLODE", "TP TO", "TP ON TOP", "BRING",
                "ENFLAME", "DELETE"
            }
        end

        -- Helper: 3D bounding box using 12 DRAW_LINE edges
        -- Uses GET_ENTITY_COORDS + safe type-based dimensions only.
        -- NEVER calls GET_MODEL_DIMENSIONS or GET_ENTITY_MODEL — GTA Enhanced throws
        -- a native SEH exception (0xC0000005) if the model streamer hasn't loaded
        -- the asset yet, and pcall CANNOT catch SEH exceptions, so it hard-crashes.
        local function draw_3d_box(entity, r, g, b, a)
            pcall(function()
                -- Hard handle range guard only — no DOES_ENTITY_EXIST call here.
                -- The outer loop throttles that check. Calling it again every frame
                -- from inside draw_3d_box doubles the stale-handle crash exposure.
                if type(entity) ~= "number" or entity <= 0 or entity > 0x7FFFFFFF then return end

                -- Get entity world position
                local ok_c, ec = pcall(invoker.call, 0x3FEF770D40960D5A, entity, false)
                if not ok_c or not ec then return end
                local pos = ec.scr_vec3 or ec.vec3
                if not pos then return end

                -- Get entity heading for rotation
                local ok_h, eh = pcall(invoker.call, 0xE83D4F9BA2A38914, entity)
                local hdg = (ok_h and eh and (eh.float or eh.flo)) or 0.0
                local rad = math.rad(hdg)
                local cs, sn = math.cos(rad), math.sin(rad)

                -- GET_ENTITY_TYPE: 1=ped, 2=vehicle, 3=object
                local hx, hy, hz_lo, hz_hi = 0.5, 0.5, -0.5, 0.5
                local ok_et, et_r = pcall(invoker.call, 0x8ACD366038D14505, entity)
                local etype_int = (ok_et and et_r and et_r.int) or 0
                if etype_int == 2 then
                    hx, hy, hz_lo, hz_hi = 1.05, 2.5, -0.75, 1.2
                elseif etype_int == 1 then
                    hx, hy, hz_lo, hz_hi = 0.22, 0.22, -0.9, 0.85
                end

                -- Build local-space corners → rotate into world space.
                -- GTA heading: 0=North(+Y), 90=West(-X).
                -- forward = (-sin(r), cos(r)), right = (cos(r), sin(r))
                -- local X = right axis (width), local Y = forward axis (length)
                -- world_x = pos.x + right.x*lx + forward.x*ly = pos.x + cos(r)*lx - sin(r)*ly
                -- world_y = pos.y + right.y*lx + forward.y*ly = pos.y + sin(r)*lx + cos(r)*ly
                local function to_world(lx, ly, lz)
                    return
                        pos.x + cs*lx - sn*ly,
                        pos.y + sn*lx + cs*ly,
                        pos.z + lz
                end

                -- 8 corners of the box
                local xs = {-hx, hx}
                local ys = {-hy, hy}
                local zs = {hz_lo, hz_hi}
                local corners = {}
                for _, xi in ipairs(xs) do
                    for _, yi in ipairs(ys) do
                        for _, zi in ipairs(zs) do
                            local wx, wy, wz = to_world(xi, yi, zi)
                            corners[#corners+1] = {wx, wy, wz}
                        end
                    end
                end

                -- 12 edges of a box
                local edges = {
                    {1,2},{3,4},{5,6},{7,8},
                    {1,3},{2,4},{5,7},{6,8},
                    {1,5},{2,6},{3,7},{4,8},
                }
                local DL = 0x6B7256074AE34680  -- DRAW_LINE
                for _, e in ipairs(edges) do
                    local c1, c2 = corners[e[1]], corners[e[2]]
                    if c1 and c2 then
                        pcall(invoker.call, DL,
                            1.0*c1[1], 1.0*c1[2], 1.0*c1[3],
                            1.0*c2[1], 1.0*c2[2], 1.0*c2[3],
                            r, g, b, a)
                    end
                end
            end)
        end

        -- Helper: execute chosen action on entity
        local function execute_action(action, entity, etype)
            pcall(function()
                local me = players.me()
                if not me then return end
                local my_ped = me.ped

                -- Acquire network control before any action that modifies the entity.
                -- Without this, all modifications silently fail when a player ped is
                -- seated in the vehicle, because that player holds network authority.
                -- DELETE doesn't need control (entities.delete handles that itself).
                -- TP INTO / TP TO / TP ON TOP / COPY HASH / COPY VEHICLE don't move the entity.
                if action ~= "DELETE" and action ~= "TP INTO" and action ~= "TP TO"
                   and action ~= "TP ON TOP" and action ~= "COPY HASH"
                   and action ~= "COPY VEHICLE" then
                    request.control(entity, true)
                end

                if action == "DELETE" then
                    pcall(entities.delete, entity)
                    ctx.context_menu_active = false

                elseif action == "TP TO" then
                    local ok_c, ec = pcall(invoker.call, 0x3FEF770D40960D5A, entity, false)
                    if ok_c and ec then
                        local p = ec.scr_vec3 or ec.vec3
                        if p then pcall(invoker.call, 0x06843DA7060A026B, my_ped, 1.0*p.x, 1.0*p.y, 1.0*p.z+2.0, false,false,false,false) end
                    end

                elseif action == "TP ON TOP" then
                    local ok_c, ec = pcall(invoker.call, 0x3FEF770D40960D5A, entity, false)
                    if ok_c and ec then
                        local p = ec.scr_vec3 or ec.vec3
                        if p then pcall(invoker.call, 0x06843DA7060A026B, my_ped, 1.0*p.x, 1.0*p.y, 1.0*p.z+3.5, false,false,false,false) end
                    end

                elseif action == "BRING" then
                    local ok_c, mc = pcall(invoker.call, 0x3FEF770D40960D5A, my_ped, false)
                    if ok_c and mc then
                        local p = mc.scr_vec3 or mc.vec3
                        if p then pcall(invoker.call, 0x06843DA7060A026B, entity, 1.0*p.x+2.0, 1.0*p.y, 1.0*p.z, false,false,false,false) end
                    end

                elseif action == "EXPLODE" then
                    local ok_c, ec = pcall(invoker.call, 0x3FEF770D40960D5A, entity, false)
                    if ok_c and ec then
                        local p = ec.scr_vec3 or ec.vec3
                        if p then pcall(invoker.call, 0xE3AD2BDBAEE269AC, 1.0*p.x, 1.0*p.y, 1.0*p.z, 5, 100.0, true, false, 1.0) end
                    end

                elseif action == "ENFLAME" then
                    -- Request network control so the fire sticks in online sessions
                    pcall(invoker.call, 0x2CE80BB3AA942EB9, entity)        -- NETWORK_REQUEST_CONTROL_OF_ENTITY
                    pcall(invoker.call, 0xF6A9D9708F6F23DF, entity)        -- START_ENTITY_FIRE
                    -- Also zero the petrol tank health so fire is guaranteed even without control
                    if etype == "vehicle" then
                        pcall(invoker.call, 0x70DB57649FA8D0D8, entity, -1.0) -- SET_VEHICLE_PETROL_TANK_HEALTH to -1 forces fire
                    end

                elseif action == "COPY HASH" then
                    local ok_m, mdl = pcall(invoker.call, 0x9F47B058362C84B5, entity)
                    if ok_m and mdl then
                        local hash = (mdl.int or 0) & 0xFFFFFFFF
                        safe_toast("Hash: 0x"..string.format("%X", hash))
                    end

                elseif action == "COPY VEHICLE" and etype == "vehicle" then
                    -- ── COPY VEHICLE ──────────────────────────────────────────────────────────
                    -- Uses spawn.vehicle() (new Lexis API) with register_as_network_object=true
                    -- and script_host_object=false so the clone is visible to ALL players in
                    -- public lobbies without requiring host or script-host.
                    -- All mods, colours, neon, livery, extras, plate are copied from source.
                    -- ──────────────────────────────────────────────────────────────────────────

                    -- Guard against re-entry (reset automatically on completion/error)
                    if ctx._copy_in_progress then return end
                    ctx._copy_in_progress = true

                    -- ── Step 1: Read model hash from source vehicle (synchronous, before job) ──
                    local ok_m, mdl = pcall(invoker.call, 0x9F47B058362C84B5, entity)  -- GET_ENTITY_MODEL
                    if not (ok_m and mdl and mdl.int and mdl.int ~= 0) then
                        safe_toast("Copy Vehicle: could not read model hash")
                        ctx._copy_in_progress = false
                        return
                    end
                    local src_hash = mdl.int  -- keep raw signed int — Lexis APIs accept it

                    -- ── Step 2: Read spawn position as PLAIN NUMBERS before the async job ──
                    -- IMPORTANT: never pass vc.scr_vec3 (FFI userdata) into a util.create_job
                    -- closure — the parent frame gets GC'd and .x/.y/.z become nil, causing the
                    -- vehicle to spawn at world origin (0,0,0) underwater.
                    local src_x, src_y, src_z, src_hdg = 0.0, 0.0, 0.0, 0.0
                    local got_pos = false

                    pcall(function()
                        local ok_vc, vc = pcall(invoker.call, 0x3FEF770D40960D5A, entity, false)
                        if ok_vc and vc then
                            local p = vc.scr_vec3 or vc.vec3
                            if p and p.x then
                                src_x = p.x + 0.0  -- force plain number copy
                                src_y = p.y + 0.0
                                src_z = p.z + 0.0
                                got_pos = true
                            end
                        end
                    end)

                    pcall(function()
                        local ok_vh, vh = pcall(invoker.call, 0xE83D4F9BA2A38914, entity)
                        if ok_vh and vh and vh.float then
                            src_hdg = vh.float + 0.0  -- force plain number copy
                        end
                    end)

                    -- Fallback to player position if vehicle coords unavailable
                    if not got_pos then
                        local me = players.me()
                        if me and me.coords then
                            src_x = (me.coords.x or 0.0) + 0.0
                            src_y = (me.coords.y or 0.0) + 0.0
                            src_z = (me.coords.z or 0.0) + 0.0
                            src_hdg = (me.heading or 0.0) + 0.0
                            got_pos = true
                        end
                    end

                    if not got_pos then
                        safe_toast("Copy Vehicle: could not get spawn position")
                        ctx._copy_in_progress = false
                        return
                    end

                    -- ── Step 3: Read ALL customizations synchronously before the async job ──
                    -- (entity handle may become stale inside the job if owner disconnects)
                    local c = {}

                    -- SET_VEHICLE_MOD_KIT must be called on source before reading any mods
                    pcall(invoker.call, 0x1F2AA07F00B3217A, entity, 0)  -- SET_VEHICLE_MOD_KIT

                    -- Standard colour indices (GET_VEHICLE_COLOURS)
                    local pri_p = pointer_int()
                    local sec_p = pointer_int()
                    pcall(invoker.call, 0xA19435F193E081AC, entity, pri_p, sec_p)
                    c.colors = { pri_p.value or 0, sec_p.value or 0 }
                    pri_p:free(); sec_p:free()

                    -- Whether custom RGB colours are set on primary / secondary
                    local r_pc = invoker.call(0xF095C0405307B21B, entity)  -- GET_IS_VEHICLE_PRIMARY_COLOUR_CUSTOM
                    local r_sc = invoker.call(0x910A32E7AAD2656C, entity)  -- GET_IS_VEHICLE_SECONDARY_COLOUR_CUSTOM
                    c.primary_custom   = r_pc and r_pc.bool or false
                    c.secondary_custom = r_sc and r_sc.bool or false

                    -- Custom RGB primary (GET_VEHICLE_CUSTOM_PRIMARY_COLOUR)
                    local r1 = pointer_int(); local g1 = pointer_int(); local b1 = pointer_int()
                    pcall(invoker.call, 0xB64CF2CCA9D95F52, entity, r1, g1, b1)
                    c.custom_primary = { r1.value or 0, g1.value or 0, b1.value or 0 }
                    r1:free(); g1:free(); b1:free()

                    -- Custom RGB secondary (GET_VEHICLE_CUSTOM_SECONDARY_COLOUR)
                    local r2 = pointer_int(); local g2 = pointer_int(); local b2 = pointer_int()
                    pcall(invoker.call, 0x8389CD56CA8072DC, entity, r2, g2, b2)
                    c.custom_secondary = { r2.value or 0, g2.value or 0, b2.value or 0 }
                    r2:free(); g2:free(); b2:free()

                    -- Pearlescent + wheel colour (GET_VEHICLE_EXTRA_COLOURS)
                    local pearl_p = pointer_int(); local wheel_p = pointer_int()
                    pcall(invoker.call, 0x3BC4245933A166F7, entity, pearl_p, wheel_p)
                    c.extra_colors = { pearl_p.value or 0, wheel_p.value or 0 }
                    pearl_p:free(); wheel_p:free()

                    -- Neon colour (GET_VEHICLE_NEON_COLOUR)
                    local nr = pointer_int(); local ng = pointer_int(); local nb = pointer_int()
                    pcall(invoker.call, 0x7619EEE8C886757F, entity, nr, ng, nb)
                    c.neon_color = { nr.value or 0, ng.value or 0, nb.value or 0 }
                    nr:free(); ng:free(); nb:free()

                    -- Tyre smoke colour (GET_VEHICLE_TYRE_SMOKE_COLOR)
                    local sr = pointer_int(); local sg = pointer_int(); local sb_p = pointer_int()
                    pcall(invoker.call, 0xB635392A4938B3C3, entity, sr, sg, sb_p)
                    c.smoke_color = { sr.value or 255, sg.value or 255, sb_p.value or 255 }
                    sr:free(); sg:free(); sb_p:free()

                    -- Neon enabled per-side (GET_VEHICLE_NEON_ENABLED, slots 0-3)
                    c.neon_enabled = {}
                    for i = 0, 3 do
                        local v = invoker.call(0x8C4B92553E4766A5, entity, i)
                        c.neon_enabled[i + 1] = v and v.bool or false
                    end

                    -- All visual mod slots 0-48 (GET_VEHICLE_MOD)
                    c.mods = {}
                    for slot = 0, 48 do
                        local v = invoker.call(0x772960298DA26FDB, entity, slot)
                        c.mods[slot + 1] = (v and v.int) or -1
                    end

                    -- Toggle mods: turbo(18), tyre smoke(20), xenon(22) (IS_TOGGLE_MOD_ON)
                    c.toggle_mods = {}
                    for _, slot in ipairs({ 18, 20, 22 }) do
                        local v = invoker.call(0x84B233A8C8FC8AE7, entity, slot)
                        c.toggle_mods[slot] = v and v.bool or false
                    end

                    -- Wheel type (GET_VEHICLE_WHEEL_TYPE)
                    c.wheel_type  = (invoker.call(0xB3ED1BFB4BE636DC, entity) or { int = 0 }).int
                    -- Window tint (GET_VEHICLE_WINDOW_TINT)
                    c.window_tint = (invoker.call(0x0EE21293DAD47C95, entity) or { int = 0 }).int
                    -- Plate style index (GET_VEHICLE_NUMBER_PLATE_TEXT_INDEX)
                    c.plate_type  = (invoker.call(0xF11BC2DD9A3E7195, entity) or { int = 0 }).int
                    -- Plate text string (GET_VEHICLE_NUMBER_PLATE_TEXT)
                    local pt_r = invoker.call(0x7CE1CCB9B293020E, entity)
                    c.plate_text  = (pt_r and pt_r.str) or ""
                    -- Livery index (GET_VEHICLE_LIVERY)
                    c.livery      = (invoker.call(0x2BB9230590DA5E8A, entity) or { int = -1 }).int
                    -- Xenon colour preset index (GET_VEHICLE_XENON_LIGHTS_COLOUR)
                    c.xenon_color = (invoker.call(0x3DFF319A831E0CDB, entity) or { int = 0 }).int

                    -- Vehicle extras 0-14 on/off (IS_VEHICLE_EXTRA_TURNED_ON)
                    c.extras = {}
                    for i = 0, 14 do
                        local v = invoker.call(0xD2E6822DBFD6C8BD, entity, i)
                        c.extras[i + 1] = v and v.bool or false
                    end

                    -- ── Step 4: Spawn + customise in a background job ──────────────────────
                    util.create_job(function()

                        -- Compute spawn offset: 6 m to the right-side of the source vehicle.
                        -- heading=0 → North (+Y), heading=90 → West (-X)
                        -- right-vector = (cos(hdg), sin(hdg)) in GTA world space
                        local tr  = math.rad(src_hdg)
                        local spawn_pos = {
                            x = src_x + math.cos(tr) * 6.0,
                            y = src_y + math.sin(tr) * 6.0,
                            z = src_z + 1.0,
                        }

                        -- ── Spawn the clone ─────────────────────────────────────────────────
                        -- Primary path: spawn.vehicle() (Lexis v10 API, docs.lexis.re/spawn)
                        --   register_as_network_object=true, script_host_object=false
                        --   → calls SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES + CAN_MIGRATE
                        --   → visible to ALL players in public lobbies without host/script-host
                        -- Fallback (spawn global not injected): raw CREATE_VEHICLE invoker call
                        --   + manual network registration via NETWORK_REGISTER_ENTITY_AS_NETWORKED
                        --   + SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES + SET_NETWORK_ID_CAN_MIGRATE
                        -- Mirrors the identical guard already used in the XML spawner.
                        if not request.model(src_hash) then
                            safe_toast("Copy Vehicle: model failed to load — try again")
                            ctx._copy_in_progress = false
                            return
                        end
                        local veh
                        if spawn and type(spawn.vehicle) == "function" then
                            local ok, r = pcall(spawn.vehicle, src_hash,
                                scr_vec3(spawn_pos.x, spawn_pos.y, spawn_pos.z), src_hdg, true, false)
                            veh = ok and r or nil
                        else
                            -- Fallback: raw CREATE_VEHICLE + manual net registration
                            local raw = invoker.call(0xAF35D0D2583051B0, src_hash,
                                1.0*spawn_pos.x, 1.0*spawn_pos.y, 1.0*spawn_pos.z,
                                1.0*src_hdg, true, false, false)
                            veh = raw and raw.int or nil
                            if veh and veh ~= 0 then
                                if not invoker.call(0xC7827959479DCC78, veh).bool then
                                    invoker.call(0x06FAACD625D80CAA, veh)           -- NETWORK_REGISTER_ENTITY_AS_NETWORKED
                                end
                                local netId = invoker.call(0xA11700682F3AD45C, veh).int  -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
                                if netId and netId ~= 0 then
                                    invoker.call(0xE05E81A888FA63C8, netId, true)   -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
                                    invoker.call(0x299EEB23175895FC, netId, true)   -- SET_NETWORK_ID_CAN_MIGRATE
                                end
                            end
                        end

                        if not veh or veh == 0 then
                            safe_toast("Copy Vehicle: spawn failed — try again")
                            ctx._copy_in_progress = false
                            return
                        end

                        -- Acquire local network authority so all writes below stick
                        request.control(veh, true)

                        -- Must initialise mod kit before reading/writing any mods
                        invoker.call(0x1F2AA07F00B3217A, veh, 0)  -- SET_VEHICLE_MOD_KIT

                        -- Wheel type must be set BEFORE individual wheel mods
                        invoker.call(0x487EB21CC7295BA1, veh, c.wheel_type)  -- SET_VEHICLE_WHEEL_TYPE

                        -- Apply all visual mod slots
                        for i, mod_index in ipairs(c.mods) do
                            if mod_index and mod_index >= 0 then
                                invoker.call(0x6AF0636DDEDCB6DD, veh, i - 1, mod_index, false)  -- SET_VEHICLE_MOD
                            end
                        end

                        -- Toggle mods (turbo / tyre-smoke / xenon) use a separate native
                        for slot, enabled in pairs(c.toggle_mods) do
                            invoker.call(0x2A1F4F37F95BAD08, veh, slot, enabled)  -- TOGGLE_VEHICLE_MOD
                        end

                        -- Standard paint colours (applies even when custom RGB is also set)
                        invoker.call(0x4F1D4BE3A7F24601, veh, c.colors[1], c.colors[2])  -- SET_VEHICLE_COLOURS

                        -- Custom RGB primary (only if source had a custom RGB primary)
                        if c.primary_custom then
                            invoker.call(0x7141766F91D15BEA, veh,
                                c.custom_primary[1], c.custom_primary[2], c.custom_primary[3])
                        end

                        -- Custom RGB secondary (only if source had a custom RGB secondary)
                        if c.secondary_custom then
                            invoker.call(0x36CED73BFED89754, veh,
                                c.custom_secondary[1], c.custom_secondary[2], c.custom_secondary[3])
                        end

                        -- Pearlescent + wheel colour (SET_VEHICLE_EXTRA_COLOURS)
                        invoker.call(0x2036F561ADD12E33, veh, c.extra_colors[1], c.extra_colors[2])

                        -- Window tint
                        invoker.call(0x57C51E6BAD752696, veh, c.window_tint)  -- SET_VEHICLE_WINDOW_TINT

                        -- Tyre smoke colour (slot 20 toggle already applied above)
                        invoker.call(0xB5BA80F839791C0F, veh,
                            c.smoke_color[1], c.smoke_color[2], c.smoke_color[3])

                        -- Neon: enabled states per-side, then colour
                        for i = 0, 3 do
                            invoker.call(0x2AA720E4287BF269, veh, i, c.neon_enabled[i + 1])
                        end
                        invoker.call(0x8E0A582209A62695, veh,
                            c.neon_color[1], c.neon_color[2], c.neon_color[3])

                        -- Plate text + style
                        if c.plate_text and c.plate_text ~= "" then
                            invoker.call(0x95A88F0B409CDA47, veh, c.plate_text)  -- SET_VEHICLE_NUMBER_PLATE_TEXT
                        end
                        invoker.call(0x9088EB5A43FFB0A1, veh, c.plate_type)  -- SET_VEHICLE_NUMBER_PLATE_TEXT_INDEX

                        -- Livery (skip if -1 / none)
                        if c.livery and c.livery >= 0 then
                            invoker.call(0x60BF608F1B8CD1B6, veh, c.livery)  -- SET_VEHICLE_LIVERY
                        end

                        -- Vehicle extras (SET_VEHICLE_EXTRA: 3rd param is DISABLE flag → invert)
                        for i = 0, 14 do
                            invoker.call(0x7EE3A3C5E4A40CC9, veh, i, not c.extras[i + 1])
                        end

                        -- Keep vehicle in world (mission entity flag) and set on ground
                        invoker.call(0xAD738C3085FE7E11, veh, true, true)   -- SET_ENTITY_AS_MISSION_ENTITY
                        invoker.call(0x49733E92263139D1, veh, 0)            -- SET_VEHICLE_ON_GROUND_PROPERLY
                        invoker.call(0x115722B1B9C14C1C, veh)               -- SET_VEHICLE_FIXED

                        safe_toast("Vehicle copied! (visible to all players)")
                        ctx._copy_in_progress = false
                    end)

                elseif action == "FIX VEHICLE" and etype == "vehicle" then
                    pcall(invoker.call, 0x115722B1B9C14C1C, entity)                    -- SET_VEHICLE_FIXED
                    pcall(invoker.call, 0x45F6D8EEF34ABEF1, entity, 1000.0)            -- SET_VEHICLE_ENGINE_HEALTH
                    pcall(invoker.call, 0xB77D05AC8C78AADB, entity, 1000.0)            -- SET_VEHICLE_BODY_HEALTH
                    pcall(invoker.call, 0x953DA1E1B12C0491, entity)                    -- SET_VEHICLE_DEFORMATION_FIXED
                    pcall(invoker.call, 0x70DB57649FA8D0D8, entity, 1000.0)            -- SET_VEHICLE_PETROL_TANK_HEALTH
                    pcall(invoker.call, 0x2497C4717C8B881E, entity, true, true, false) -- SET_VEHICLE_ENGINE_ON
                    pcall(invoker.call, 0x67B2C79AA7FF5738, entity, false)             -- SET_VEHICLE_IS_STOLEN (false = not stolen)
                    pcall(invoker.call, 0xFBA550EA44404EE6, entity, false)             -- SET_VEHICLE_NEEDS_TO_BE_HOTWIRED
                    pcall(invoker.call, 0xF7EC25A3EBEEC726, entity, false)             -- SET_VEHICLE_IS_WANTED
                    -- Fix all tyres
                    for i = 0, 7 do pcall(invoker.call, 0x6E13FC662B882D1D, entity, i) end  -- SET_VEHICLE_TYRE_FIXED
                    safe_toast("Vehicle Fixed")

                elseif action == "KILL ENGINE" and etype == "vehicle" then
                    pcall(invoker.call, 0x2497C4717C8B881E, entity, false, true, false)   -- SET_VEHICLE_ENGINE_ON false
                    pcall(invoker.call, 0x45F6D8EEF34ABEF1, entity, -4000.0)              -- SET_VEHICLE_ENGINE_HEALTH kill
                    safe_toast("Engine Killed")

                elseif action == "BURST TIRES" and etype == "vehicle" then
                    for i = 0, 7 do pcall(invoker.call, 0xEC6A202EE4960385, entity, i, true, 1000.0) end  -- SET_VEHICLE_TYRE_BURST (correct hash)
                    safe_toast("Tires Burst")

                elseif action == "HALT" and etype == "vehicle" then
                    pcall(invoker.call, 0x1C99BB7B6E96D16F, entity, 0.0, 0.0, 0.0)  -- SET_ENTITY_VELOCITY (correct hash, no extra bool)

                elseif action == "BOOST" and etype == "vehicle" then
                    -- Get vehicle heading and apply a strong forward velocity impulse (no Z)
                    local ok_h, eh = pcall(invoker.call, 0xE83D4F9BA2A38914, entity)
                    local hdg = (ok_h and eh and (eh.float or 0.0)) or 0.0
                    local rad = math.rad(hdg)
                    -- Forward in GTA: heading 0 = North (+Y), 90 = West (-X)
                    local fx = -math.sin(rad) * 40.0
                    local fy =  math.cos(rad) * 40.0
                    -- Get current Z velocity to preserve it (avoid suddenly dropping)
                    local ok_vel, vel_r = pcall(invoker.call, 0x4805D2B1D8CF940F, entity)  -- GET_ENTITY_VELOCITY
                    local cur_vz = (ok_vel and vel_r and (vel_r.z or (vel_r.vec3 and vel_r.vec3.z) or 0.0)) or 0.0
                    pcall(invoker.call, 0x1C99BB7B6E96D16F, entity, fx, fy, cur_vz)  -- SET_ENTITY_VELOCITY

                elseif action == "LAUNCH" and etype == "vehicle" then
                    pcall(invoker.call, 0x1C99BB7B6E96D16F, entity, 0.0, 0.0, 150.0)  -- SET_ENTITY_VELOCITY (correct hash)

                elseif action == "EJECT" and etype == "vehicle" then
                    -- EJECT: Uses the same ownership-taking method as Vehicle Thrower
                    -- (game.update_net_obj_owner) to reliably kick all occupants out.
                    -- Running async via util.create_job so the ownership yield doesn't
                    -- block the main UI thread.
                    local eject_entity = entity  -- capture before async
                    util.create_job(function()
                        -- ── Step 1: Take network ownership of the vehicle ──
                        -- Exactly the same approach used by Vehicle Thrower's E-key grab.
                        pcall(invoker.call, 0xAD738C3085FE7E11, eject_entity, true, true) -- SET_ENTITY_AS_MISSION_ENTITY
                        local _me = players and players.me and players.me()
                        local _my_id = _me and _me.id or -1
                        if _my_id >= 0 and game and game.update_net_obj_owner then
                            game.update_net_obj_owner(eject_entity, _my_id)
                            util.yield(100)  -- let the engine process the ownership transfer
                        else
                            -- Fallback for older Lexis builds (same as Vehicle Thrower fallback)
                            for _ = 1, 25 do
                                local has = invoker.call(0x01BF60A500E28887, eject_entity)
                                if has and has.bool then break end
                                invoker.call(0xB69317BF5E782347, eject_entity) -- NETWORK_REQUEST_CONTROL_OF_ENTITY
                                util.yield(50)
                            end
                        end

                        -- ── Step 2: Get net ID once for the Force Eject script event ──
                        local net_id = 0
                        local ok_nid, nid_r = pcall(invoker.call, 0xA11700682F3AD45C, eject_entity) -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
                        if ok_nid and nid_r and nid_r.int then net_id = nid_r.int end

                        -- ── Step 3: Iterate every seat and eject occupants ──
                        -- -1 = driver, 0..7 covers even the widest vehicles (buses etc.)
                        local ejected = 0
                        for seat = -1, 7 do
                            local ok_p, ped_r = pcall(invoker.call, 0xBB40DD2270B65366, eject_entity, seat, false) -- GET_PED_IN_VEHICLE_SEAT
                            if ok_p and ped_r and ped_r.int and ped_r.int ~= 0 then
                                local occ = ped_r.int

                                -- IS_PED_A_PLAYER: more reliable than comparing ped handles
                                local ok_ipa, ipa = pcall(invoker.call, 0x12534C348C6CB68B, occ)
                                local occ_is_player = ok_ipa and ipa and ipa.bool

                                if occ_is_player then
                                    -- ── Player ped ──
                                    -- Take ownership of the ped too (same method as the vehicle)
                                    -- so that REMOVE_PED_FROM_VEHICLE can actually execute.
                                    if _my_id >= 0 and game and game.update_net_obj_owner then
                                        game.update_net_obj_owner(occ, _my_id)
                                        util.yield(50)
                                    end

                                    -- Send the Force Eject script event (client-side trigger)
                                    local ok_pi, pi = pcall(invoker.call, 0x6C0E2E0125610278, occ) -- NETWORK_GET_PLAYER_INDEX_FROM_PED
                                    if ok_pi and pi and pi.int and pi.int >= 0 then
                                        local pl_obj = nil
                                        if players and players.get then
                                            pcall(function() pl_obj = players.get(pi.int) end)
                                        end
                                        if not pl_obj and players and players.list then
                                            for _, p in ipairs(players.list()) do
                                                if p and p.id == pi.int then pl_obj = p; break end
                                            end
                                        end
                                        if pl_obj and net_id ~= 0 then
                                            pcall(function() pl_obj:script_event(1898157052, {net_id}) end)
                                        end
                                    end

                                    -- Also apply direct removal now that we own the ped —
                                    -- works as a reliable second layer if the script event is
                                    -- blocked or the target has protections.
                                    pcall(invoker.call, 0xD3DBCE61A490BE02, occ, eject_entity, 4160) -- TASK_LEAVE_VEHICLE instant
                                    pcall(invoker.call, 0xC1AF4A66E9D3D3FE, occ)                     -- REMOVE_PED_FROM_VEHICLE
                                else
                                    -- ── NPC ped ──
                                    -- Take ownership of the NPC ped before commanding it.
                                    if _my_id >= 0 and game and game.update_net_obj_owner then
                                        game.update_net_obj_owner(occ, _my_id)
                                        util.yield(50)
                                    else
                                        for _ = 1, 15 do
                                            local has = invoker.call(0x01BF60A500E28887, occ)
                                            if has and has.bool then break end
                                            invoker.call(0xB69317BF5E782347, occ)
                                            util.yield(50)
                                        end
                                    end
                                    pcall(invoker.call, 0xD3DBCE61A490BE02, occ, eject_entity, 4160) -- TASK_LEAVE_VEHICLE instant
                                    pcall(invoker.call, 0xC1AF4A66E9D3D3FE, occ)                     -- REMOVE_PED_FROM_VEHICLE
                                end
                                ejected = ejected + 1
                            end
                        end

                        if ejected > 0 then
                            safe_toast("Ejected " .. ejected .. " occupant(s)")
                        else
                            safe_toast("Eject: no occupants found")
                        end
                    end)

                elseif action == "TP INTO" and etype == "vehicle" then
                    -- Check if driver seat (-1) is occupied
                    local driver_seat_free = true
                    pcall(function()
                        local ok_d, d = pcall(invoker.call, 0xBB40DD2270B65366, entity, -1)  -- GET_PED_IN_VEHICLE_SEAT (driver = -1)
                        if ok_d and d and d.int and d.int ~= 0 then
                            driver_seat_free = false
                        end
                    end)
                    if driver_seat_free then
                        -- Driver seat is free: teleport into driver seat
                        pcall(invoker.call, 0xF75B0D629E1C063D, my_ped, entity, -1)  -- SET_PED_INTO_VEHICLE
                    else
                        -- Driver seat is occupied: find first free passenger seat
                        local target_seat = nil
                        local ok_ms, ms = pcall(invoker.call, 0xA0BC8FAED8CFEB3C, entity)  -- GET_VEHICLE_MAX_NUMBER_OF_PASSENGERS
                        local max_seats = (ok_ms and ms and ms.int) or 7
                        for seat = 0, max_seats - 1 do
                            local ok_s, s = pcall(invoker.call, 0xBB40DD2270B65366, entity, seat)
                            if ok_s and s and (not s.int or s.int == 0) then
                                target_seat = seat
                                break
                            end
                        end
                        if target_seat then
                            pcall(invoker.call, 0xF75B0D629E1C063D, my_ped, entity, target_seat)  -- SET_PED_INTO_VEHICLE
                        else
                            -- All seats full: just get in passenger seat 0 anyway
                            pcall(invoker.call, 0xF75B0D629E1C063D, my_ped, entity, 0)
                        end
                    end

                end
            end)
        end

        -- Main loop
        while true do
            if not ctx.context_menu_enabled then
                ctx.context_menu_active = false
                util.yield(200)
                goto ctx_next
            end

            -- Detect X key press (0x58 = VK_X) to toggle context menu
            if input and input.key then
                local key_x = input.key(0x58)
                if key_x and key_x.just_pressed then
                    if ctx.context_menu_active then
                        -- Close
                        ctx.context_menu_active = false
                        ctx.context_menu_entity = 0
                        ctx.context_menu_type   = nil
                        ctx.context_menu_options = {}
                        ctx._ctx_exist_frame = 0
                        ctx._copy_in_progress = false
                    else
                        -- Safe entity detection for GTA Enhanced / Lexis
                        -- EVERY entity handle is validated with DOES_ENTITY_EXIST before
                        -- any other native is called on it. GET_ENTITY_COORDS on a stale
                        -- handle causes 0xC0000005 in Enhanced (crash #3 root cause).
                        pcall(function()
                            local me = players.me()
                            if not me then return end
                            local my_ped = me.ped or 0

                            local ok_pid, pid_r = pcall(invoker.call, 0x4F8644AF03D0E0D6)  -- PLAYER_ID
                            local my_player = (ok_pid and pid_r and pid_r.int) or 0

                            -- Shorthand: returns true only if handle is non-zero AND exists in world
                            local function entity_valid(ent)
                                if not ent or ent == 0 then return false end
                                local ok_ex, ex = pcall(invoker.call, 0x7239B21A38F536BA, ent)  -- DOES_ENTITY_EXIST
                                return ok_ex and ex and ex.bool == true
                            end

                            -- Safe GET_ENTITY_COORDS — only call after entity_valid()
                            local function get_coords(ent)
                                local ok_c, cr = pcall(invoker.call, 0x3FEF770D40960D5A, ent, false)
                                if not ok_c or not cr then return nil end
                                return cr.scr_vec3 or cr.vec3
                            end

                            local best_entity = 0
                            local best_etype  = "vehicle"

                            -- METHOD 1: free-aim entity (instant pick when weapon is drawn & aimed)
                            if my_player ~= 0 then
                                local ok_fa, fa = pcall(invoker.call, 0x3C49C870E66F0A28, my_player)
                                if ok_fa and fa then
                                    local ent = fa.ent or fa.int or 0
                                    if ent ~= 0 and ent ~= my_ped and entity_valid(ent) then
                                        local ok_et, et_r = pcall(invoker.call, 0x8ACD366038D14505, ent)
                                        if ok_et and et_r and et_r.int == 2 then
                                            best_entity = ent
                                        end
                                    end
                                end
                            end

                            -- METHOD 2: screen-space picker — ALL vehicle types
                            if best_entity == 0 then
                                local ok_pc, pc_r = pcall(invoker.call, 0x3FEF770D40960D5A, my_ped, false)
                                if ok_pc and pc_r then
                                    local ppc = pc_r.scr_vec3 or pc_r.vec3
                                    if ppc then
                                        local best_screen_dist = math.huge
                                        local seen = {}

                                        -- W2S using GTA's own native GET_SCREEN_COORD_FROM_WORLD_COORD
                                        -- Handles both Lexis v10 (ptr_float) and older (pointer_float)
                                        local float_ctor = (type(ptr_float) == "function" and ptr_float)
                                                        or (type(pointer_float) == "function" and pointer_float)

                                        local function w2s(wx, wy, wz)
                                            if float_ctor then
                                                local px = float_ctor()
                                                local py = float_ctor()
                                                local ok_w, res = pcall(invoker.call, 0x34E82F05DF2974F5,
                                                    1.0*wx, 1.0*wy, 1.0*wz, px, py)
                                                local on_s = ok_w and res and (res.bool == true)
                                                local sx   = px.value or 0.5
                                                local sy   = py.value or 0.5
                                                px:free(); py:free()
                                                return on_s, sx, sy
                                            else
                                                return kyron_w2s(wx, wy, wz)
                                            end
                                        end

                                        local function test_candidate(ent)
                                            if not ent or ent == 0 or ent == my_ped then return end
                                            if seen[ent] then return end
                                            seen[ent] = true
                                            if not entity_valid(ent) then return end
                                            local ok_et2, et_r2 = pcall(invoker.call, 0x8ACD366038D14505, ent)
                                            local et = (ok_et2 and et_r2 and et_r2.int) or 0
                                            if et ~= 2 then return end
                                            local ep = get_coords(ent)
                                            if not ep then return end
                                            -- Sample several heights: ground cars to helicopters
                                            local offsets = { 0.0, 0.5, 1.0, 1.5, 2.5, 3.5, 5.0 }
                                            for _, oz in ipairs(offsets) do
                                                local on_scr, sx, sy = w2s(ep.x, ep.y, ep.z + oz)
                                                if on_scr then
                                                    local sdx = sx - 0.5
                                                    local sdy = sy - 0.5
                                                    local sd  = sdx*sdx + sdy*sdy
                                                    -- No hard threshold — pick whichever on-screen vehicle
                                                    -- is closest to crosshair center (0.5, 0.5)
                                                    if sd < best_screen_dist then
                                                        best_screen_dist = sd
                                                        best_entity = ent
                                                        best_etype  = "vehicle"
                                                    end
                                                end
                                            end
                                        end

                                        -- Priority 1: every player's vehicle via players.list()
                                        -- Lexis v10 player struct has .vehicle (integer handle) directly.
                                        -- Also query GET_VEHICLE_PED_IS_IN (current + last) as fallback.
                                        if players and players.list then
                                            for _, p in ipairs(players.list()) do
                                                if p then
                                                    -- Direct .vehicle field (v10 player struct, most reliable)
                                                    if p.vehicle and p.vehicle ~= 0 then
                                                        test_candidate(p.vehicle)
                                                    end
                                                    -- Ped-based lookup (current vehicle, false = not last)
                                                    if p.ped and p.ped ~= 0 then
                                                        local ok_vi, vi = pcall(invoker.call, 0x9A9112A0FE9A4713, p.ped, false)
                                                        if ok_vi and vi and vi.int and vi.int ~= 0 then test_candidate(vi.int) end
                                                        -- Also check last vehicle (true) for entering/exiting peds
                                                        local ok_lv, lv = pcall(invoker.call, 0x9A9112A0FE9A4713, p.ped, true)
                                                        if ok_lv and lv and lv.int and lv.int ~= 0 then test_candidate(lv.int) end
                                                    end
                                                end
                                            end
                                        end

                                        -- Priority 2: pools.vehicle() — Lexis v10 returns memory_address[]
                                        -- MUST use game.guid_from_entity(addr) to convert to a handle.
                                        -- Passing require_valid_guid=true skips invalid/unstreamed entries.
                                        if pools and pools.vehicle and game and game.guid_from_entity then
                                            local ok_pool, pool_list = pcall(pools.vehicle, true)
                                            if ok_pool and pool_list then
                                                for _, addr in ipairs(pool_list) do
                                                    local ok_h, handle = pcall(game.guid_from_entity, addr)
                                                    if ok_h and handle and handle ~= 0 then
                                                        test_candidate(handle)
                                                    end
                                                end
                                            end
                                        end

                                        -- Priority 3: pools.ped() vehicle-in-seats
                                        -- Lexis v10: memory_address[], use game.guid_from_entity(addr).
                                        if pools and pools.ped and game and game.guid_from_entity then
                                            local ok_pp, ped_list = pcall(pools.ped, true)
                                            if ok_pp and ped_list then
                                                for _, addr in ipairs(ped_list) do
                                                    local ok_h, phandle = pcall(game.guid_from_entity, addr)
                                                    if ok_h and phandle and phandle ~= 0 and phandle ~= my_ped then
                                                        local ok_vi, vi = pcall(invoker.call, 0x9A9112A0FE9A4713, phandle, false)
                                                        if ok_vi and vi and vi.int and vi.int ~= 0 then
                                                            test_candidate(vi.int)
                                                        end
                                                    end
                                                end
                                            end
                                        end

                                        -- Priority 4: grid scan flags=1023, no class filter
                                        local qrad = 40.0
                                        for ox = -80, 80, 20 do
                                            for oy = -80, 80, 20 do
                                                local gx = ppc.x + ox
                                                local gy = ppc.y + oy
                                                for oz = -10, 200, 20 do
                                                    local gz = ppc.z + oz
                                                    local ok_v, vr = pcall(invoker.call, 0xF73EB622C4F1689B,
                                                        1.0*gx, 1.0*gy, 1.0*gz, qrad, 0, 1023)
                                                    if ok_v and vr then test_candidate(vr.int or 0) end
                                                end
                                            end
                                        end
                                    end
                                end
                            end

                            -- Final type check
                            if best_entity ~= 0 then
                                local ok_et, et_r = pcall(invoker.call, 0x8ACD366038D14505, best_entity)
                                local et = (ok_et and et_r and et_r.int) or 0
                                if et ~= 2 then best_entity = 0 end
                            end

                            if best_entity == 0 then
                                safe_toast("Context Menu: No vehicle found nearby")
                                return
                            end

                            ctx.context_menu_entity  = best_entity
                            ctx.context_menu_type    = best_etype
                            ctx.context_menu_options = build_options(best_etype)
                            -- Restore last used option for this entity type, default to 1
                            local last_name = ctx._last_sel and ctx._last_sel[best_etype]
                            local restored = 1
                            if last_name then
                                local opts = ctx.context_menu_options
                                for i, v in ipairs(opts) do
                                    if v == last_name then restored = i; break end
                                end
                            end
                            ctx.context_menu_sel     = restored
                            ctx.context_menu_active  = true
                        end)
                    end
                end
            end

            -- While context menu is active: handle scroll + click + draw
            if ctx.context_menu_active and ctx.context_menu_entity ~= 0 then
                pcall(function()
                    local entity = ctx.context_menu_entity
                    local etype  = ctx.context_menu_type
                    local opts   = ctx.context_menu_options
                    local sel    = ctx.context_menu_sel

                    -- Hard guard: entity handle must be a positive integer in a
                    -- sane range. Stale handles in GTA Enhanced can be any value;
                    -- passing them to DOES_ENTITY_EXIST throws an SEH exception
                    -- that pcall cannot catch (0xC0000005). We throttle the native
                    -- check to every 30 frames so the per-frame crash risk is gone.
                    if type(entity) ~= "number" or entity <= 0 or entity > 0x7FFFFFFF then
                        ctx.context_menu_active = false; return
                    end

                    -- Throttled DOES_ENTITY_EXIST: only check every 30 frames
                    ctx._ctx_exist_frame = (ctx._ctx_exist_frame or 0) + 1
                    if ctx._ctx_exist_frame >= 30 then
                        ctx._ctx_exist_frame = 0
                        local ok_ex, ex = pcall(invoker.call, 0x7239B21A38F536BA, entity)
                        if not ok_ex or not ex or not ex.bool then
                            ctx.context_menu_active = false; return
                        end
                    end

                    -- Draw bounding box (green, same as images)
                    draw_3d_box(entity, 0, 255, 0, 220)

                    -- Anchor menu to fixed screen position (right-center).
                    -- GET_SCREEN_COORD_FROM_WORLD_COORD (0x34E82F05DF2974F5) requires
                    -- out-pointer args in Enhanced and causes write-violation crash.
                    local res = game.resolution()
                    local sw, sh = res.x or 1920, res.y or 1080
                    local menu_x = math.floor(sw * 0.62)
                    local menu_y = math.floor(sh * 0.35)
                    local line_h = math.floor(18 * UI.scale)
                    local n      = #opts

                    -- Clamp to screen
                    menu_x = math.max(10, math.min(menu_x, sw - 160))
                    menu_y = math.max(10, math.min(menu_y, sh - n * line_h - 10))

                    -- ── Context Menu (Kyron theme, uses draw_rect/draw_text) ──
                    local ctx_w      = 190
                    local ctx_font   = math.floor(UI.font_small * 1.45)
                    local ctx_line_h = ctx_font + 8
                    local hdr_h      = ctx_font + 10
                    local total_h    = hdr_h + n * ctx_line_h + 2

                    -- Full dark panel background (matches C.header / C.sidebar)
                    draw_rect(menu_x, menu_y - hdr_h, ctx_w, total_h, color(18, 18, 22, 245), 0)

                    -- Header: accent-coloured bar with "KYRON" label
                    draw_rect(menu_x, menu_y - hdr_h, ctx_w, hdr_h, color(114, 137, 218, 230), 0)
                    draw_text("KYRON", menu_x + 8, menu_y - hdr_h + 3, ctx_font, color(255, 255, 255, 255))

                    -- Option rows
                    for i, opt in ipairs(opts) do
                        local is_sel = (i == sel)
                        local oy = menu_y + (i - 1) * ctx_line_h

                        -- Thin separator between rows
                        if i > 1 then
                            draw_rect(menu_x, oy, ctx_w, 1, color(255, 255, 255, 18), 0)
                        end

                        -- Selected row highlight (full-width blue bar like Image 2)
                        if is_sel then
                            draw_rect(menu_x, oy, ctx_w, ctx_line_h, color(114, 137, 218, 210), 0)
                        end

                        -- Text: bright white when selected, soft grey otherwise
                        local txt_col = is_sel and color(255, 255, 255, 255) or color(200, 200, 210, 225)
                        draw_text(opt, menu_x + 10, oy + 3, ctx_font, txt_col)
                    end

                    -- Bottom accent line
                    draw_rect(menu_x, menu_y + n * ctx_line_h, ctx_w, 2, color(114, 137, 218, 255), 0)

                    -- Sync line_h for scroll clamp
                    line_h = ctx_line_h

                    -- Scroll with mouse wheel to change selection
                    if MOUSE.scroll_up then
                        ctx.context_menu_sel = math.max(1, sel - 1)
                    elseif MOUSE.scroll_down then
                        ctx.context_menu_sel = math.min(n, sel + 1)
                    end

                    -- Left click to execute selected action
                    if MOUSE.just_pressed then
                        local chosen = opts[ctx.context_menu_sel]
                        -- Remember this choice per entity type so next open starts here
                        ctx._last_sel = ctx._last_sel or {}
                        ctx._last_sel[etype] = chosen
                        execute_action(chosen, entity, etype)
                        if ctx.context_menu_active then
                            ctx.context_menu_active = false
                        end
                    end
                end)
            end

            ::ctx_next::
            util.yield(0)
        end
    end)

    -- Money Loop - MULTIPLE METHODS FOR TESTING
    util.create_thread(function()
        casino_debug_log("Money loop thread started")

        while true do
            if self_state.money_loop_active then
                -- Track start time when loop is first activated
                if self_state.money_loop_start_time == 0 then
                    self_state.money_loop_start_time = os.time()
                    casino_debug_log("Money loop activated - METHOD: game.basket_transaction")
                end

                -- Calculate elapsed time in seconds
                local elapsed = os.time() - self_state.money_loop_start_time
                local interval = 5000  -- Default: 5 seconds

                -- After 15 minutes (900 seconds), switch to 10 second intervals
                if elapsed >= 900 then
                    interval = 10000  -- 10 seconds
                end

                -- Check current balance
                local wallet_before = 0
                local bank_before = 0
                pcall(function()
                    if account and account.stats then
                        wallet_before = account.stats("MPPLY_WALLET_BALANCE").int64 or 0
                        bank_before = account.stats("BANK_BALANCE").int64 or 0
                        casino_debug_log(string.format("Before: Wallet=$%d, Bank=$%d", wallet_before, bank_before))
                    end
                end)

                -- Choose method based on selection
                if self_state.money_loop_method == 1 then
                    -- $500K METHOD - Multiple fallbacks for both enhanced and legacy
                    -- TRY METHOD 1: Script Globals (Enhanced GTA only)
                    local success, err = pcall(function()
                        casino_debug_log("$500K METHOD 1: Trying script.globals (Enhanced only)")

                        if script and script.globals then
                            local enhanced_global = script.globals(1970025)
                            if enhanced_global then
                                enhanced_global.int32 = 1
                                casino_debug_log("Set enhanced_global(1970025) to 1 - triggers $500K")
                                util.yield(500)
                            else
                                error("Could not access script globals")
                            end
                        else
                            error("script.globals not available (Legacy GTA)")
                        end
                    end)

                    if not success then
                        casino_debug_log("$500K METHOD 1 FAILED: " .. tostring(err))

                        -- METHOD 2: Direct stat modification (Works on both enhanced and legacy)
                        local success2, err2 = pcall(function()
                            casino_debug_log("$500K METHOD 2: Trying direct stat modification")

                            local bank_stat = account.stats("BANK_BALANCE")
                            local current_bank = bank_stat.int64
                            casino_debug_log("Current bank: " .. tostring(current_bank))

                            bank_stat.int64 = current_bank + 500000
                            casino_debug_log("Set bank to: " .. tostring(current_bank + 500000))
                        end)

                        if not success2 then
                            casino_debug_log("$500K METHOD 2 FAILED: " .. tostring(err2))

                            -- METHOD 3: Multiple small transactions (last resort)
                            local success3, err3 = pcall(function()
                                casino_debug_log("$500K METHOD 3: Trying 3x $180K transactions")

                                for i = 1, 3 do
                                    if game and game.basket_transaction then
                                        local category = 1474183246
                                        local action = 1445302971
                                        local destination = 1
                                        local items = {
                                            { -1027218631, -1, 180000, 0, 1 }
                                        }
                                        game.basket_transaction(category, action, destination, items)
                                        casino_debug_log("Transaction " .. i .. "/3 executed")
                                        util.yield(200)
                                    end
                                end
                            end)

                            if not success3 then
                                casino_debug_log("$500K METHOD 3 FAILED: " .. tostring(err3))
                            else
                                casino_debug_log("$500K METHOD 3 SUCCESS (3x $180K = $540K)")
                            end
                        else
                            casino_debug_log("$500K METHOD 2 SUCCESS")
                        end
                    else
                        casino_debug_log("$500K METHOD 1 SUCCESS")
                    end
                else
                    -- METHOD: Basket Transaction (Default)
                    local success, err = pcall(function()
                    casino_debug_log("METHOD 1: Trying game.basket_transaction with CORRECT format")

                    -- Check if transaction busy
                    if game and game.is_transaction_busy and game.is_transaction_busy() then
                        casino_debug_log("Transaction is busy, skipping")
                        return
                    end

                    local category = 1474183246
                    local action = 1445302971
                    local destination = 1  -- transactions.json says target=1 (wallet)

                    -- CRITICAL: Items must be POSITIONAL ARRAY not named fields!
                    -- Format: { id, extra_inventory_id, price, stat, quantity }
                    -- From transactions.json: id=-1027218631, inventory=-1, price=180000, stat=0, count=1
                    local items = {
                        { -1027218631, -1, 180000, 0, 1 }
                    }

                    if game and game.basket_transaction then
                        casino_debug_log(string.format("Calling basket_transaction: cat=%d, act=%d, dest=%d, item=[%d, %d, %d, %d, %d]",
                            category, action, destination, items[1][1], items[1][2], items[1][3], items[1][4], items[1][5]))
                        game.basket_transaction(category, action, destination, items)
                        casino_debug_log("basket_transaction executed")

                        -- Wait a bit for transaction to process
                        util.yield(500)

                        -- Check balance after
                        local wallet_after = 0
                        local bank_after = 0
                        pcall(function()
                            if account and account.stats then
                                wallet_after = account.stats("MPPLY_WALLET_BALANCE").int64 or 0
                                bank_after = account.stats("BANK_BALANCE").int64 or 0
                                casino_debug_log(string.format("After: Wallet=$%d (+%d), Bank=$%d (+%d)",
                                    wallet_after, wallet_after - wallet_before,
                                    bank_after, bank_after - bank_before))
                            end
                        end)
                    else
                        casino_debug_log("ERROR: game.basket_transaction not available")
                    end
                end)

                if not success then
                    casino_debug_log("METHOD 1 FAILED: " .. tostring(err))

                    -- METHOD 2: Native transaction calls (fallback)
                    local success2, err2 = pcall(function()
                        casino_debug_log("METHOD 2: Trying native transaction calls")

                        local transaction_id = -1027218631
                        local category = 1474183246
                        local action = 1445302971
                        local amount = 180000

                        invoker.call(0x279F08B1A4B29B7E, transaction_id, category, action, 1)
                        casino_debug_log("Called NET_GAMESERVER_BASKET_START")

                        invoker.call(0x3C5FD37B5499582E, transaction_id, category, transaction_id, action, amount, 1)
                        casino_debug_log("Called NET_GAMESERVER_BEGIN_SERVICE")

                        invoker.call(0xE2A99A9B524BEFFF, transaction_id)
                        casino_debug_log("Called NET_GAMESERVER_END_SERVICE")

                        invoker.call(0x39BE7CEA8D9CC8E6, transaction_id)
                        casino_debug_log("Called NET_GAMESERVER_CHECKOUT_START")
                    end)

                    if not success2 then
                        casino_debug_log("METHOD 2 FAILED: " .. tostring(err2))

                        -- METHOD 3: Direct stat modification (last resort)
                        local success3, err3 = pcall(function()
                            casino_debug_log("METHOD 3: Trying direct stat modification")

                            local bank_stat = account.stats("BANK_BALANCE")
                            local current_bank = bank_stat.int64
                            casino_debug_log("Current bank: " .. tostring(current_bank))

                            bank_stat.int64 = current_bank + 180000
                            casino_debug_log("Set bank to: " .. tostring(current_bank + 180000))
                        end)

                        if not success3 then
                            casino_debug_log("METHOD 3 FAILED: " .. tostring(err3))
                        else
                            casino_debug_log("METHOD 3 SUCCESS")
                        end
                    else
                        casino_debug_log("METHOD 2 SUCCESS")
                    end
                    else
                        casino_debug_log("METHOD 1 SUCCESS")
                    end
                end

                util.yield(interval)
            else
                -- Reset start time when loop is stopped
                if self_state.money_loop_start_time ~= 0 then
                    casino_debug_log("Money loop deactivated")
                    self_state.money_loop_start_time = 0
                end
                util.yield(1000)
            end
        end
    end)

