            -- Fallback functions for natives used by the homing missile feature.
            -- Some Lexis builds' `natives` string-keyed table doesn't expose
            -- every entry (e.g. give_delayed_weapon_to_ped), even though the
            -- native itself exists and invoker.call(hash, ...) works fine.
            -- Each wrapper unwraps its return value exactly as natives.lua's own
            -- reference definition does (.int / .bool / void), so callers that
            -- expect a plain int/bool/nothing keep getting exactly that.
            local HASH_FALLBACKS <const> = {
                clear_sequence_task = function(taskSequence) invoker_call(0x3841422E9C488D8C, taskSequence) end,
                close_sequence_task = function(taskSequence) invoker_call(0x39E72BC99E6360CB, taskSequence) end,
                create_tracked_point = function() return invoker_call(0xE2C9439ED45DEA60).int end,
                delete_entity = function(entity) invoker_call(0xAE3CBE5BF394C9C9, entity) end,
                destroy_tracked_point = function(point) invoker_call(0xB25DC90BAD56CA42, point) end,
                disable_control_action = function(inputGroup, control, disable) invoker_call(0xFE99B66D079CF6BC, inputGroup, control, disable) end,
                draw_rect = function(x, y, width, height, r, g, b, a, p8) invoker_call(0x3A618A217E5154F0, x, y, width, height, r, g, b, a, p8) end,
                draw_sprite = function(textureDict, textureName, screenX, screenY, width, height, heading, red, green, blue, alpha, p11) invoker_call(0xE7FFAE5EBF23D890, textureDict, textureName, screenX, screenY, width, height, heading, red, green, blue, alpha, p11) end,
                get_blip_from_entity = function(entity) return invoker_call(0xBC8DBDCA2436F7E8, entity).int end,
                get_blip_hud_colour = function(blip) return invoker_call(0x729B5F1EFBC0AAEE, blip).int end,
                get_control_unbound_normal = function(inputGroup, control) return invoker_call(0x5B84D09CEC5209C5, inputGroup, control).float end,
                get_disabled_control_normal = function(inputGroup, control) return invoker_call(0x11E65974A982637C, inputGroup, control).float end,
                get_entity_can_be_damaged = function(p0) return invoker_call(0xD95CC5D2AB15A09F, p0).int end,
                get_entity_health = function(entity) return invoker_call(0xEEF059FAD016D209, entity).int end,
                get_entity_max_health = function(entity) return invoker_call(0x15D757606D170C3C, entity).int end,
                get_final_rendered_cam_fov = function() return invoker_call(0x80EC114669DAEFF4).float end,
                -- get_frame_count is used throughout this feature purely as a
                -- "did anything change since last tick" cache-invalidation
                -- signal (camera projection cache, entity pool cache). The
                -- real GET_FRAME_COUNT native increments once per rendered
                -- game frame; util.create_thread's tick cadence relative to
                -- that isn't guaranteed here, so if it doesn't advance
                -- between ticks the caches never refresh (no markers, no
                -- targeting). Falling back to the tick clock guarantees a
                -- changing value every tick, which is all any caller needs.
                get_frame_count = function() return util.get_tick_count() end,
                get_ground_z_for_3d_coord = function(x, y, z, groundZ, unk) return invoker_call(0xC906A7DAB05C8D2B, x, y, z, groundZ, unk).bool end,
                get_model_dimensions = function(modelHash, minimum, maximum) invoker_call(0x03E8D3D5F549087A, modelHash, minimum, maximum) end,
                get_ped_armour = function(ped) return invoker_call(0x9483AF821605B1D8, ped).int end,
                get_ped_in_vehicle_seat = function(vehicle, index, p2) return invoker_call(0xBB40DD2270B65366, vehicle, index, p2).int end,
                get_ped_type = function(ped) return invoker_call(0xFF059E1E4C01E63C, ped).int end,
                get_player_team = function(player) return invoker_call(0x37039302F4E0A008, player).int end,
                get_player_wanted_level = function(player) return invoker_call(0xE28E54788CE8F12D, player).int end,
                get_relationship_between_peds = function(ped1, ped2) return invoker_call(0xEBA5AD3A0EAF7121, ped1, ped2).int end,
                get_shape_test_result = function(rayHandle, hit, endCoords, surfaceNormal, entityHit) return invoker_call(0x3D87450E15D98694, rayHandle, hit, endCoords, surfaceNormal, entityHit).int end,
                get_sound_id = function() return invoker_call(0x430386FE9BF80B45).int end,
                get_vehicle_ped_is_in = function(ped, lastVehicle) return invoker_call(0x9A9112A0FE9A4713, ped, lastVehicle).int end,
                get_water_height = function(x, y, z, height) return invoker_call(0xF6829842C06AE524, x, y, z, height).bool end,
                give_delayed_weapon_to_ped = function(ped, weaponHash, time, equipNow) invoker_call(0xB282DC6EBD803C75, ped, weaponHash, time, equipNow) end,
                has_entity_clear_los_to_entity = function(entity1, entity2, traceType) return invoker_call(0xFCDFF7B72D23A1AC, entity1, entity2, traceType).bool end,
                has_ped_got_weapon = function(ped, weaponHash, p2) return invoker_call(0x8DECB02F88F428BC, ped, weaponHash, p2).bool end,
                has_sound_finished = function(soundId) return invoker_call(0xFCBDCE714A7C88E5, soundId).bool end,
                has_streamed_texture_dict_loaded = function(textureDict) return invoker_call(0x0145F696AAAAD2E4, textureDict).bool end,
                is_disabled_control_just_pressed = function(inputGroup, control) return invoker_call(0x91AEF906BCA88877, inputGroup, control).bool end,
                is_disabled_control_pressed = function(inputGroup, control) return invoker_call(0xE2587F8CBBD87B1D, inputGroup, control).bool end,
                is_entity_a_ghost = function(p0) return invoker_call(0x21D04D7BC538C146, p0).bool end,
                is_entity_dead = function(entity, p1) return invoker_call(0x5F9532F3B5CC2551, entity, p1).bool end,
                is_ped_a_player = function(ped) return invoker_call(0x12534C348C6CB68B, ped).bool end,
                is_ped_in_any_vehicle = function(ped, atGetIn) return invoker_call(0x997ABD671D25CA0B, ped, atGetIn).bool end,
                is_tracked_point_visible = function(point) return invoker_call(0xC45CCDAAC9221CA8, point).bool end,
                is_using_keyboard_and_mouse = function() return invoker_call(0xA571D46727E2B718).bool end,
                open_sequence_task = function(taskSequence) invoker_call(0xE8854A4326B9E12B, taskSequence) end,
                play_sound_from_coord = function(soundId, audioName, x, y, z, audioRef, p6, range, p8) invoker_call(0x8D8686B622B88120, soundId, audioName, x, y, z, audioRef, p6, range, p8) end,
                play_sound_frontend = function(soundId, audioName, audioRef, p3) invoker_call(0x67C540AA08E4A6F5, soundId, audioName, audioRef, p3) end,
                release_sound_id = function(soundId) invoker_call(0x353FC880830B88FA, soundId) end,
                set_tracked_point_info = function(point, x, y, z, radius) invoker_call(0x164ECBB3CF750CB0, point, x, y, z, radius) end,
                start_expensive_synchronous_shape_test_los_probe = function(x1, y1, z1, x2, y2, z2, flags, entity, p8) return invoker_call(0x377906D8A31E5586, x1, y1, z1, x2, y2, z2, flags, entity, p8).int end,
                stop_sound = function(soundId) invoker_call(0xA3B0C41BA5CC0BB5, soundId) end,
                task_perform_sequence = function(ped, taskSequence) invoker_call(0x5ABA3986D90D8A3B, ped, taskSequence) end,
