        local Players = (function()
            local Players = {}
            local contract = Contract
            local Runtime = Runtime
            local Util = HMUtil

            local players_api <const> = contract.table(players, "players")
            local players_me <const> = contract.func(players_api.me, "players.me")
            local players_list <const> = contract.func(players_api.list, "players.list")

            local function local_player()
                return contract.value(players_me(), "players.me()")
            end

            local function field(player, name)
                local value = player[name]
                if value ~= nil then return value end
                return contract.value(nil, "players.me()." .. name)
            end

            local function active_ped_context()
                local me = local_player()
                local exists = field(me, "exists")
                local ped = field(me, "ped")
                if not exists or ped == 0 then return nil, nil end
                return me, ped
            end

            function Players.local_id()
                return field(local_player(), "id")
            end

            function Players.local_ped()
                return field(local_player(), "ped")
            end

            function Players.local_coords()
                local me = active_ped_context()
                if not me then return nil end
                local coords = Util.required_vector3(field(me, "coords"))
                return contract.value(coords, "players.me().coords vector")
            end

            function Players.local_alive()
                local me = local_player()
                if not field(me, "exists") then return false end
                return me.alive and true or false
            end

            function Players.local_heading()
                local me = active_ped_context()
                if not me then return nil end
                return field(me, "heading")
            end

            function Players.local_vehicle()
                local me = local_player()
                if not field(me, "in_vehicle") then return 0 end
                return field(me, "vehicle")
            end

            function Players.local_driver_vehicle()
                local me = local_player()
                if not field(me, "in_vehicle") then return 0 end
                if not me.driver then return 0 end
                return field(me, "vehicle")
            end

            local function player_to_snapshot(p)
                return {
                    id = p.id,
                    name = p.name or "",
                    ped = p.ped,
                    exists = p.exists and true or false,
                    alive = p.alive and true or false,
                    in_vehicle = p.in_vehicle and true or false,
                    in_interior = p.in_interior and true or false,
                    vehicle = p.vehicle or 0,
                    model = p.model or 0,
                    vehicle_model = p.vehicle_model or 0,
                    coords = Util.vector3(p.coords),
                    friend = p.friend and true or false,
                    in_ceo = p.in_ceo and true or false,
                    gang_id = p.gang_id or 0,
                }
            end

            local slot_proxies = nil
            local proxy_by_id = nil

            local function ensure_slot_proxies()
                if slot_proxies and #slot_proxies > 0 then return slot_proxies end
                local list = contract.value(players_list(), "players.list()")
                slot_proxies = {}
                proxy_by_id = {}
                for i = 1, #list do
                    local p = list[i]
                    slot_proxies[i] = p
                    proxy_by_id[p.id] = p
                end
                return slot_proxies
            end

            function Players.seed()
                ensure_slot_proxies()
            end

            local SNAPSHOT_IDENTITY_MS <const> = 400
            local IDENTITY_BUDGET <const> = 3

            local snapshot_entries = {}
            local snapshot_list = {}

            local function fill_snapshot(entry, p, now, may_refresh_identity, detail_coords, detail_dist_sq)
                entry.id = p.id
                if not p.exists then
                    entry.exists = false
                    entry.ped = 0
                    entry.identity_ms = nil
                    return false
                end
                entry.exists = true
                entry.ped = p.ped

                local source = p.coords
                local coords = entry.coords
                if source then
                    coords.x = source.x or 0.0
                    coords.y = source.y or 0.0
                    coords.z = source.z or 0.0
                end

                if detail_dist_sq then
                    local dx = coords.x - detail_coords.x
                    local dy = coords.y - detail_coords.y
                    local dz = coords.z - detail_coords.z
                    if dx * dx + dy * dy + dz * dz > detail_dist_sq then
                        entry.detailed = false
                        return false
                    end
                    entry.in_interior = p.in_interior and true or false
                    if entry.in_interior then
                        entry.detailed = false
                        return false
                    end
                    entry.alive = p.alive and true or false
                    if not entry.alive then
                        entry.detailed = false
                        return false
                    end
                else
                    entry.in_interior = p.in_interior and true or false
                    entry.alive = p.alive and true or false
                end
                entry.detailed = true

                entry.in_vehicle = p.in_vehicle and true or false
                entry.driver = p.driver and true or false
                entry.vehicle = p.vehicle or 0
                entry.vehicle_model = p.vehicle_model or 0

                local age = entry.identity_ms and (now - entry.identity_ms) or nil
                local due = not age or age >= SNAPSHOT_IDENTITY_MS or age < 0
                if due and (may_refresh_identity or not entry.identity_ms) then
                    entry.name = p.name or ""
                    entry.model = p.model or 0
                    entry.friend = p.friend and true or false
                    entry.in_ceo = p.in_ceo and true or false
                    entry.gang_id = p.gang_id or 0
                    entry.identity_ms = now
                    return true
                end
                return false
            end

            function Players.session_snapshot(detail_coords, detail_dist)
                local proxies = ensure_slot_proxies()
                local now = Runtime.get_tick_count()
                local detail_dist_sq = detail_coords and detail_dist and (detail_dist * detail_dist) or nil

                local count = #proxies
                local identity_budget = IDENTITY_BUDGET
                for i = 1, count do
                    local p = proxies[i]
                    local entry = snapshot_entries[p.id]
                    if not entry then
                        entry = { coords = { x = 0.0, y = 0.0, z = 0.0 } }
                        snapshot_entries[p.id] = entry
                    end
                    if fill_snapshot(entry, p, now, identity_budget > 0, detail_coords, detail_dist_sq) then
                        identity_budget = identity_budget - 1
                    end
                    snapshot_list[i] = entry
                end
                for i = count + 1, #snapshot_list do snapshot_list[i] = nil end
                return snapshot_list
            end

            function Players.player_snapshot(player_id)
                if type(player_id) ~= "number" or player_id < 0 then return nil end
                ensure_slot_proxies()
                local p = proxy_by_id[player_id]
                if not p or not p.exists then return nil end
                return player_to_snapshot(p)
            end

            function Players.local_org_info()
                local me = local_player()
                return {
                    id = field(me, "id"),
                    in_ceo = me.in_ceo and true or false,
                    gang_id = me.gang_id or 0,
                }
            end

            function Players.local_teleport_target()
                local me = local_player()
                if field(me, "in_vehicle") then
                    local vehicle = field(me, "vehicle")
                    if vehicle ~= 0 then return vehicle end
                end
                return field(me, "ped")
            end

            function Players.local_teleport_target_is_vehicle()
                local me = local_player()
                if not field(me, "in_vehicle") then return false end
                return field(me, "vehicle") ~= 0
            end

            return Players

        end)()

        local ModelDims = (function()
            local ModelDims = {}

            local Native = Native
            local Pointer = Pointer

            local math_abs <const> = math.abs

            local cache = {}

            local function vec_copy(value)
                if not value then return { x = 0.0, y = 0.0, z = 0.0 } end
                return { x = value.x or 0.0, y = value.y or 0.0, z = value.z or 0.0 }
            end

            function ModelDims.read(model)
                if not model then return nil end
                local minimum = Pointer.scr_vec3()
                local maximum = Pointer.scr_vec3()
                local ok, result = xpcall(function()
                    Native.call("get_model_dimensions", model, minimum, maximum)
                    return {
                        min = vec_copy(Pointer.scr_vec3_value(minimum, nil)),
                        max = vec_copy(Pointer.scr_vec3_value(maximum, nil)),
                    }
                end, debug.traceback)
                Pointer.free(minimum)
                Pointer.free(maximum)
                if not ok then error(result, 0) end
                return result
            end

            function ModelDims.get(model_hash)
                if not model_hash or model_hash == 0 then return nil end
                local hit = cache[model_hash]
                if hit ~= nil then return hit or nil end

                local dims = ModelDims.read(model_hash)
                if math_abs(dims.min.x) <= 0.1 and math_abs(dims.max.x) <= 0.1 then
                    cache[model_hash] = false
                    return nil
                end
                cache[model_hash] = dims
                return dims
            end

            return ModelDims

        end)()

        local Projection = (function()
            local Projection = {}
            local Native = Native
            local Runtime = Runtime

            local math_sin <const> = math.sin
            local math_cos <const> = math.cos
            local math_tan <const> = math.tan
            local D2R <const> = math.pi / 180.0
            local NEAR_DEPTH <const> = 0.05

            local cache_frame = nil
            local cache = {}

            local active = { valid = false }
            local pending = { valid = false }

            local function promote(src)
                local rx, ry, rz = src.rx, src.ry, src.rz
                local sx, cx = math_sin(rx), math_cos(rx)
                local sy, cy = math_sin(ry), math_cos(ry)
                local sz, cz = math_sin(rz), math_cos(rz)
                active.right_x = cz * cy - sz * sx * sy
                active.right_y = sz * cy + cz * sx * sy
                active.right_z = -cx * sy
                active.fwd_x = -sz * cx
                active.fwd_y = cz * cx
                active.fwd_z = sx
                active.up_x = cz * sy + sz * sx * cy
                active.up_y = sz * sy - cz * sx * cy
                active.up_z = cx * cy
                active.cx, active.cy, active.cz = src.cx, src.cy, src.cz
                local tan_half = math_tan(src.fov * 0.5 * D2R)
                active.tan_half = tan_half
                active.aspect_tan = tan_half * (src.res_x / src.res_y)
                active.res_x, active.res_y = src.res_x, src.res_y
                active.valid = true
            end

            local function finite(v)
                return type(v) == "number" and v - v == 0
            end

            local function read_pending()
                local pos = Native.get_final_rendered_cam_coord()
                local rot = Native.get_final_rendered_cam_rot(2)
                local fov = Native.call("get_final_rendered_cam_fov")
                if not pos or not rot then
                    pending.valid = false
                    return
                end
                local px, py, pz = pos.x, pos.y, pos.z
                local rx, ry, rz = rot.x, rot.y, rot.z
                if not finite(fov) or fov <= 0.0 or fov >= 180.0
                    or not finite(px) or not finite(py) or not finite(pz)
                    or not finite(rx) or not finite(ry) or not finite(rz)
                then
                    pending.valid = false
                    return
                end
                local resolution = Runtime.resolution()
                pending.cx, pending.cy, pending.cz = px, py, pz
                pending.rx, pending.ry, pending.rz = rx * D2R, ry * D2R, rz * D2R
                pending.fov = fov
                pending.res_x, pending.res_y = resolution.x, resolution.y
                pending.valid = true
            end

            function Projection.refresh_camera()
                local frame = Native.call("get_frame_count")
                if frame == cache_frame then return end
                cache_frame = frame
                cache = {}
                if pending.valid then promote(pending) end
                read_pending()
                if not active.valid and pending.valid then promote(pending) end
            end

            local function project_xy(x, y, z)
                if not active.valid then
                    Projection.refresh_camera()
                    if not active.valid then return nil end
                end
                local dx = x - active.cx
                local dy = y - active.cy
                local dz = z - active.cz
                local depth = dx * active.fwd_x + dy * active.fwd_y + dz * active.fwd_z
                if depth < NEAR_DEPTH then return nil end
                local nx = 0.5 + 0.5 * ((dx * active.right_x + dy * active.right_y + dz * active.right_z)
                    / (active.aspect_tan * depth))
                if nx < 0.0 or nx > 1.0 then return nil end
                local ny = 0.5 - 0.5 * ((dx * active.up_x + dy * active.up_y + dz * active.up_z)
                    / (active.tan_half * depth))
                if ny < 0.0 or ny > 1.0 then return nil end
                return nx * active.res_x, ny * active.res_y, nx, ny
            end

            function Projection.world_to_screen(position)
                if not position then return nil end
                local x, y, z = position.x, position.y, position.z
                if type(x) ~= "number" or type(y) ~= "number" or type(z) ~= "number" then return nil end
                if x - x ~= 0 or y - y ~= 0 or z - z ~= 0 then return nil end

                local level_x = cache[x]
                local level_y = level_x and level_x[y]
                local cached = level_y and level_y[z]
                if cached ~= nil then return cached or nil end

                local sx, sy, normalized_x, normalized_y = project_xy(x, y, z)
                local result = false
                if sx then
                    result = {
                        x = sx,
                        y = sy,
                        normalized_x = normalized_x,
                        normalized_y = normalized_y,
                    }
                end
                if not level_x then
                    level_x = {}
                    cache[x] = level_x
                end
                if not level_y then
                    level_y = {}
                    level_x[y] = level_y
                end
                level_y[z] = result
                return result or nil
            end

            function Projection.world_to_screen_xy(position)
                if not position then return nil end
                local x, y, z = position.x, position.y, position.z
                if type(x) ~= "number" or type(y) ~= "number" or type(z) ~= "number" then return nil end
                if x - x ~= 0 or y - y ~= 0 or z - z ~= 0 then return nil end
                return project_xy(x, y, z)
            end

            function Projection.is_behind(position)
                if not active.valid then return false end
                local dx = position.x - active.cx
                local dy = position.y - active.cy
                local dz = position.z - active.cz
                return dx * active.fwd_x + dy * active.fwd_y + dz * active.fwd_z <= 0
            end

            function Projection.maybe_on_screen(position, radius)
                if not active.valid then return true end
                local dx = position.x - active.cx
                local dy = position.y - active.cy
                local dz = position.z - active.cz
                local depth = dx * active.fwd_x + dy * active.fwd_y + dz * active.fwd_z
                if depth - radius <= NEAR_DEPTH then return true end
                local limit = depth + radius
                local rv = dx * active.right_x + dy * active.right_y + dz * active.right_z
                local half_w = active.aspect_tan * limit
                if rv - radius > half_w or rv + radius < -half_w then return false end
                local uv = dx * active.up_x + dy * active.up_y + dz * active.up_z
                local half_h = active.tan_half * limit
                return uv - radius <= half_h and uv + radius >= -half_h
            end

            function Projection.clear_cache()
                cache_frame = nil
                cache = {}
                active.valid = false
                pending.valid = false
            end

            function Projection.free()
                Projection.clear_cache()
            end

            return Projection

        end)()

        local HMLogger = (function()
            local HMLogger = {}
            function HMLogger.info(module_name, message, payload)
                -- diagnostic only, matches Core.Logger's call signature; no-op to avoid
                -- porting the unrelated Fs/IoQueue/Trace file-logging stack
            end
            function HMLogger.warn(module_name, message, payload)
            end
            return HMLogger
        end)()

        local PedMemory = (function()
            local PedMemory = {}

            local Game = Game
            local Memory = Memory
            local Native = Native
            local Players = Players
            local Runtime = Runtime
            local logger = HMLogger

            local OFF_HEALTH <const> = 0x280
            local OFF_MAX <const> = 0x284
            local OFF_ARMOUR <const> = 0x150C
            local CHECK_TOLERANCE <const> = 1.5
            local CHECK_RETRY_MS <const> = 500

            local state = {
                checked = false,
                available = false,
                attempt_ms = nil,
            }

            local function ped_address(ped)
                if not ped or ped == 0 then return nil end
                local addr = Game.entity_from_guid(ped)
                if not addr or Memory.value(addr) == 0 then return nil end
                return addr
            end

            local function mem_field(addr, offset)
                return Memory.float(Memory.add(addr, offset))
            end

            local function ensure_checked()
                if state.checked then return end
                local now = Runtime.get_tick_count()
                if state.attempt_ms and now - state.attempt_ms < CHECK_RETRY_MS and now >= state.attempt_ms then
                    return
                end
                state.attempt_ms = now
                local ped = Players.local_ped()
                local addr = ped_address(ped)
                if not addr then return end

                local mh = mem_field(addr, OFF_HEALTH)
                local mm = mem_field(addr, OFF_MAX)
                local ma = mem_field(addr, OFF_ARMOUR)
                if mh == nil or mm == nil or ma == nil then return end

                local nh = Native.call("get_entity_health", ped) or 0
                local nm = Native.call("get_entity_max_health", ped) or 0
                local na = Native.call("get_ped_armour", ped) or 0

                if nh <= 0 or nm <= 0 then return end

                local ok = math.abs(mh - nh) <= CHECK_TOLERANCE
                    and math.abs(mm - nm) <= CHECK_TOLERANCE
                    and math.abs(ma - na) <= CHECK_TOLERANCE

                state.available = ok
                state.checked = true
                if ok then
                    logger.info("Core.PedMemory", "memory vitals offsets verified; using direct struct reads",
                        { health = mh, max = mm, armour = ma })
                else
                    logger.warn("Core.PedMemory", "memory offsets mismatch native -> native fallback",
                        { mem = { mh, mm, ma }, native = { nh, nm, na } })
                end
            end

            function PedMemory.health(ped)
                ensure_checked()
                if state.available then
                    local addr = ped_address(ped)
                    if addr then return mem_field(addr, OFF_HEALTH) end
                    return 0
                end
                return Native.call("get_entity_health", ped) or 0
            end

            function PedMemory.max_health(ped)
                ensure_checked()
                if state.available then
                    local addr = ped_address(ped)
                    if addr then return mem_field(addr, OFF_MAX) end
                    return 100
                end
                return Native.call("get_entity_max_health", ped) or 100
            end

            function PedMemory.armour(ped)
                ensure_checked()
                if state.available then
                    local addr = ped_address(ped)
                    if addr then return mem_field(addr, OFF_ARMOUR) end
                    return 0
                end
                return Native.call("get_ped_armour", ped) or 0
            end

            function PedMemory.vitals(ped, needs_health, needs_armour)
                ensure_checked()
                if state.available then
                    local addr = ped_address(ped)
                    if not addr then
                        if needs_health then
                            return 0, 100, needs_armour and 0 or nil
                        end
                        return nil, nil, needs_armour and 0 or nil
                    end
                    local health, max_health, armour
                    if needs_health then
                        health = mem_field(addr, OFF_HEALTH)
                        max_health = mem_field(addr, OFF_MAX)
                    end
                    if needs_armour then armour = mem_field(addr, OFF_ARMOUR) end
                    return health, max_health, armour
                end
                local health, max_health, armour
                if needs_health then
                    health = Native.call("get_entity_health", ped) or 0
                    max_health = Native.call("get_entity_max_health", ped) or 0
                end
                if needs_armour then armour = Native.call("get_ped_armour", ped) or 0 end
                return health, max_health, armour
            end

            function PedMemory.is_dead(ped)
                if not ped or ped == 0 then return true end
                ensure_checked()
                if state.available then
                    local addr = ped_address(ped)
                    if not addr then return true end
                    local h = mem_field(addr, OFF_HEALTH)
                    if h ~= nil then return h <= 0 end
                end
                if not Game.entity_exists(ped) then return true end
                return Native.call("is_entity_dead", ped, false) and true or false
            end

            return PedMemory

        end)()

        local PedData = (function()
            local Ped = {}

            local function joaat(text)
                text = text:lower()
                local hash = 0
                for i = 1, #text do
                    hash = (hash + text:byte(i)) & 0xFFFFFFFF
                    hash = (hash + (hash << 10)) & 0xFFFFFFFF
                    hash = (hash ~ (hash >> 6)) & 0xFFFFFFFF
                end
                hash = (hash + (hash << 3)) & 0xFFFFFFFF
                hash = (hash ~ (hash >> 11)) & 0xFFFFFFFF
                hash = (hash + (hash << 15)) & 0xFFFFFFFF
                return hash
            end

