                    local cfg = state.cfg
                    state.my_org = cfg.ignore_org_members and Players.local_org_info() or nil
                    state.my_team = cfg.ignore_team_members and Native.call("get_player_team", Players.local_id()) or nil
                    state.whitelist_refresh_ms = now
