                        local c = info.coords
                        local dx, dy, dz = c.x - my.x, c.y - my.y, c.z - my.z
                        local d_sq = dx * dx + dy * dy + dz * dz
                        local entry = nil
                        if info.in_vehicle and info.vehicle ~= 0 then
