                if info then
                    if not cfg.lock_players then return false end
                    if not info.detailed or should_ignore_player(state, info) then return false end
                elseif not cfg.lock_peds then
                    return false
                end
                return true
            end

            local function add_slot(state, entry, now)
                state.slots[#state.slots + 1] = {
                    entity = entry.entity,
                    is_vehicle = entry.is_vehicle and true or false,
                    is_player = state.players_by_ped[entry.entity] ~= nil,
                    driver = entry.driver or 0,
                    driver_is_player = state.players_by_ped[entry.driver or 0] ~= nil,
                    is_enemy = entry.is_enemy and true or false,
                    category = entry.category,
                    model_hash = entry.model_hash,
                    dist_sq = entry.dist_sq,
                    pos = entry.pos,
                    lock_ms = now,
                    confirmed = false,
                    los_clear = true,
                    los_lost_ms = nil,
                    screen_lost_ms = nil,
                    shot = false,
                }
            end

            local function still_targetable(state, slot)
                if slot.is_vehicle then
                    slot.driver = Native.call("get_ped_in_vehicle_seat", slot.entity, -1, false) or 0
                    slot.driver_is_player = state.players_by_ped[slot.driver] ~= nil
                    return passes_target_filters(state, slot)
                end
                if EntityPool.is_ped_in_vehicle(slot.entity) then return false end
                return passes_target_filters(state, slot)
            end

            local function slot_tier(cfg, entry)
                if cfg.enemy_mode ~= 1 then return 0 end
                if entry.is_player or entry.driver_is_player then return 2 end
                if entry.is_enemy then return 1 end
                return 0
            end

            local function lowest_priority_slot(state)
                local cfg = state.cfg
                local idx, worst_tier, worst_dist = nil, math.huge, -1
                for i = 1, #state.slots do
                    local slot = state.slots[i]
                    local tier = slot_tier(cfg, slot)
                    if tier < worst_tier or (tier == worst_tier and slot.dist_sq > worst_dist) then
                        idx, worst_tier, worst_dist = i, tier, slot.dist_sq
                    end
                end
                return idx, worst_tier, worst_dist
            end

            local LOS_CHECK_STRIDE <const> = 3

            local function validate_slots(state, now)
                local cfg = state.cfg
                local max_sq = cfg.lock_distance_max * cfg.lock_distance_max
                local min_sq = cfg.lock_distance_min * cfg.lock_distance_min
                state.los_rotor = ((state.los_rotor or 0) + 1) % LOS_CHECK_STRIDE
                for i = #state.slots, 1, -1 do
                    local slot = state.slots[i]
                    local entity = slot.entity
                    local drop = false
                    local pos = nil
                    if now < slot.lock_ms then slot.lock_ms = now end
                    if slot.los_lost_ms and now < slot.los_lost_ms then slot.los_lost_ms = now end
                    if slot.screen_lost_ms and now < slot.screen_lost_ms then slot.screen_lost_ms = now end
                    if not Game.entity_exists(entity) or EntityPool.is_entity_dead(entity)
                        or not still_targetable(state, slot)
                    then
                        drop = true
                    else
                        pos = Native.get_entity_coords(entity, false)
                        slot.pos = pos
                        if not pos or not state.my_coords then
                            drop = true
                        else
                            local dx, dy, dz = pos.x - state.my_coords.x, pos.y - state.my_coords.y, pos.z - state.my_coords.z
                            slot.dist_sq = dx * dx + dy * dy + dz * dz
                            if slot.dist_sq > max_sq or slot.dist_sq < min_sq then
                                drop = true
                            elseif cfg.use_screen_check and not on_screen(pos) then
                                slot.screen_lost_ms = slot.screen_lost_ms or now
                                if now - slot.screen_lost_ms > SCREEN_GRACE_MS then drop = true end
                            else
                                slot.screen_lost_ms = nil
                            end
                        end
                    end
                    if not drop then
                        if (i + state.los_rotor) % LOS_CHECK_STRIDE == 0 then
                            slot.los_clear = has_los(state, entity)
                        end
                        if slot.los_clear then visual_check(state, slot, pos) end
                        if not slot.los_clear then
                            slot.los_lost_ms = slot.los_lost_ms or now
                            if now - slot.los_lost_ms > LOS_GRACE_MS then drop = true end
                        else
                            slot.los_lost_ms = nil
                        end
                    end
                    if drop then
                        release_vis_point(slot)
                        table.remove(state.slots, i)
                    end
                end
                while #state.slots > cfg.max_targets do
                    local idx = lowest_priority_slot(state)
                    if not idx then break end
                    release_vis_point(state.slots[idx])
                    table.remove(state.slots, idx)
                end
            end

            local function acquire(state, candidates, now)
                local cfg = state.cfg
                local min_sq = cfg.lock_distance_min * cfg.lock_distance_min
                local max_sq = cfg.lock_distance_max * cfg.lock_distance_max
                for _, entry in ipairs(candidates) do
                    local entity = entry.entity
                    if entity ~= 0 and entity ~= state.my_vehicle and entity ~= state.my_ped
                        and entry.dist_sq >= min_sq and entry.dist_sq <= max_sq
                        and passes_target_filters(state, entry)
                        and not find_slot(state, entity)
                    then
                        local replace_idx = nil
                        local have_room = #state.slots < cfg.max_targets
                        if not have_room then
                            local idx, worst_tier, worst_dist = lowest_priority_slot(state)
                            if idx then
                                local tier = slot_tier(cfg, entry)
                                if tier > worst_tier or (tier == worst_tier and entry.dist_sq < worst_dist) then
                                    replace_idx = idx
                                end
                            end
                        end
                        if (have_room or replace_idx)
                            and (not cfg.use_screen_check or on_screen(entry.pos))
                            and has_los(state, entity)
                        then
                            local allowed, primed = probe_allows(state, entry)
                            if allowed then
                                if replace_idx then
                                    release_vis_point(state.slots[replace_idx])
                                    table.remove(state.slots, replace_idx)
                                end
                                add_slot(state, entry, now)
                                if primed then
                                    local slot = state.slots[#state.slots]
                                    slot.vis_point = primed.point
                                    slot.vis_ticks = primed.ticks
                                end
                            end
                        end
                    end
                end
            end

            local function confirm(state, now)
                local cfg = state.cfg
                for i = 1, #state.slots do
                    local slot = state.slots[i]
                    if not slot.confirmed and slot.los_clear
                        and (cfg.los_mode == 0 or not cfg.use_visual_check or (slot.vis_ticks or 0) > VIS_PRIME_TICKS)
                        and (cfg.instant_lock or now - slot.lock_ms >= LOCK_CONFIRM_MS)
                    then
                        slot.confirmed = true
                        if cfg.lockon_notify and slot.is_vehicle and slot.driver_is_player then
                            Native.set_vehicle_homing_lockedonto_state(slot.entity, 2)
                        end
                    end
                end
            end

            local pool_options = {
                include_vehicles = false,
                enabled_categories = ALL_CATEGORIES,
                needs_hostility = true,
                needs_model = true,
            }
            local lockable_options = {
                target_mode = 3,
                enemy_mode = 0,
                max_distance_sq = 0,
            }

            local DISCOVER_INTERVAL <const> = 3

            local WHITELIST_CACHE_WIPE_TICKS <const> = 2048

            function Targeting.tick(state)
                local cfg = state.cfg
                local now = Runtime.get_tick_count()
                state.tick_now = now

                Projection.refresh_camera()

                state.cache_wipe_rotor = ((state.cache_wipe_rotor or 0) + 1) % WHITELIST_CACHE_WIPE_TICKS
                if state.cache_wipe_rotor == 0 then
                    state.ghost_cache = nil
                    state.team_cache = nil
                end

                refresh_players(state)

                validate_slots(state, now)

                state.discover_rotor = ((state.discover_rotor or 0) + 1) % DISCOVER_INTERVAL
                if cfg.use_visual_check or state.discover_rotor == 0 then
                    local wanted = EntityPool.player_wanted_level(Players.local_id())
                    pool_options.enabled_categories = (cfg.enemy_mode == 2) and ENEMY_CATEGORIES or ALL_CATEGORIES
                    EntityPool.update(state.my_ped, state.my_coords, wanted, cfg.lock_distance_max, pool_options)

                    local candidates = player_candidates(state, {})
                    local seen = {}
                    for i = 1, #candidates do seen[candidates[i].entity] = true end
                    lockable_options.target_mode = cfg.target_mode
                    lockable_options.enemy_mode = cfg.enemy_mode
                    lockable_options.max_distance_sq = cfg.lock_distance_max * cfg.lock_distance_max
                    local pool = EntityPool.get_lockable_targets(lockable_options)
                    for i = 1, #pool do
                        local entry = pool[i]
                        if not seen[entry.entity] then candidates[#candidates + 1] = entry end
                    end

                    local probes = probe_state(state)
                    probes.serial = probes.serial + 1
                    acquire(state, candidates, now)
                    prune_probes(state)
                end

                confirm(state, now)
            end

            function Targeting.next_shot_target(state)
                for i = 1, #state.slots do
                    local slot = state.slots[i]
                    if slot.confirmed and not slot.shot then
                        slot.shot = true
                        return slot.entity
                    end
                end
                local first = nil
                for i = 1, #state.slots do
                    state.slots[i].shot = false
                    if not first and state.slots[i].confirmed then first = i end
                end
                if first then
                    state.slots[first].shot = true
                    return state.slots[first].entity
                end
                return 0
            end

            function Targeting.has_confirmed_unshot(state)
                for i = 1, #state.slots do
                    if state.slots[i].confirmed and not state.slots[i].shot then return true end
                end
                return false
            end

            function Targeting.clear_shot_flags(state)
                for i = 1, #state.slots do state.slots[i].shot = false end
            end

            function Targeting.unmark_shot(state, entity)
                if not entity or entity == 0 then return end
                for i = 1, #state.slots do
                    local slot = state.slots[i]
                    if slot.entity == entity then
                        slot.shot = false
                        return
                    end
                end
            end

            return Targeting

        end)()
        local CacheUtils = (function()
            local CacheUtils = {}

            local math_floor <const> = math.floor
            local table_move <const> = table.move
            local type <const> = type

            local DEFAULT_EVICT_RATIO <const> = 0.3

            local function get_evict_count(count, ratio)
                local evict_count = math_floor(count * (ratio or DEFAULT_EVICT_RATIO))
                if evict_count < 1 then evict_count = 1 end
                return evict_count
            end

            function CacheUtils.evict_ordered(cache, order, limit, ratio, remove_entry, current_count, evict_at_limit)
                local count = current_count or #order
                if evict_at_limit then
                    if count < limit then return count end
                elseif count <= limit then
                    return count
                end

                local evict_count = get_evict_count(limit, ratio)
                local order_len = #order
                if evict_count > order_len then evict_count = order_len end

                for i = 1, evict_count do
                    local entry = order[i]
                    if entry ~= nil then
                        if remove_entry then
                            remove_entry(cache, entry)
                        else
                            cache[entry] = nil
                        end
                    end
                end

                local remaining = order_len - evict_count
                if remaining > 0 then
                    table_move(order, evict_count + 1, order_len, 1)
                end
                for i = remaining + 1, order_len do
                    order[i] = nil
                end

                count = count - evict_count
                if count < 0 then return 0 end
                return count
            end

            function CacheUtils.evict_nested_pairs(buckets, remaining, ratio)
                local evicted = 0
                for _, bucket in pairs(buckets) do
                    if type(bucket) == "table" then
                        local bucket_count = 0
                        for _ in pairs(bucket) do bucket_count = bucket_count + 1 end

                        local to_evict = math_floor(bucket_count * (ratio or DEFAULT_EVICT_RATIO))
                        if to_evict < 1 and bucket_count > 0 then to_evict = 1 end
                        if to_evict > 0 then
                            local removed = 0
                            for key in pairs(bucket) do
                                if removed >= to_evict or evicted >= remaining then break end
                                bucket[key] = nil
                                removed = removed + 1
                                evicted = evicted + 1
                            end
                        end
                    end
                    if evicted >= remaining then break end
                end
                return evicted
            end

            function CacheUtils.prune_live_keys(cache, live_set)
                local count = 0
                for key in pairs(cache) do
                    if live_set[key] then
                        count = count + 1
                    else
                        cache[key] = nil
                    end
                end
                return count
            end

            function CacheUtils.evict_pairs(cache, count, limit, ratio, remove_entry)
                if count < limit then return count end

                local evict_target = get_evict_count(count, ratio)
                local evicted = 0

                for key, value in pairs(cache) do
                    if evicted >= evict_target then break end

                    local removed
                    if remove_entry then
                        removed = remove_entry(cache, key, value, evict_target - evicted, ratio or DEFAULT_EVICT_RATIO)
                    else
                        cache[key] = nil
                        removed = 1
                    end

                    if removed and removed > 0 then
                        evicted = evicted + removed
                    end
                end

                count = count - evicted
                if count < 0 then return 0 end
                return count
            end

            return CacheUtils

        end)()

        local Gui = (function()
            local Gui = {}
            local contract = Contract
            local CacheUtils = CacheUtils

            local gui_api <const> = contract.table(gui, "gui")
            local vec2_ctor <const> = contract.func(vec2, "vec2")
            local color_ctor <const> = contract.func(color, "color")

            Gui.justify = contract.table(gui_api.justify, "gui.justify")
            Gui.rounding = contract.table(gui_api.rounding, "gui.rounding")

            local gui_push_clip <const> = contract.func(gui_api.push_clip, "gui.push_clip")
            local gui_pop_clip <const> = contract.func(gui_api.pop_clip, "gui.pop_clip")
            local gui_line <const> = contract.func(gui_api.line, "gui.line")
            local gui_circle <const> = contract.func(gui_api.circle, "gui.circle")
            local gui_image <const> = contract.func(gui_api.image, "gui.image")
            local gui_image_rounded <const> = contract.func(gui_api.image_rounded, "gui.image_rounded")
            local gui_rebuild <const> = contract.func(gui_api.rebuild, "gui.rebuild")
            local gui_load_image <const> = contract.func(gui_api.load_image, "gui.load_image")
            local gui_load_font <const> = contract.func(gui_api.load_font, "gui.load_font")
            local gui_text_size <const> = contract.func(gui_api.text_size, "gui.text_size")
            local gui_text <const> = contract.func(gui_api.text, "gui.text")
            local gui_rect <const> = contract.func(gui_api.rect, "gui.rect")

            local vec2_cache = {}
            local color_cache = {}
            local vec2_order = {}
            local color_order = {}
            local VEC2_LIMIT <const> = 4096
            local COLOR_LIMIT <const> = 2048

            local math_floor <const> = math.floor

            local function clamp_byte(v)
                v = math_floor(v or 0)
                if v < 0 then return 0 end
                if v > 255 then return 255 end
                return v
            end

            local function color_hash(r, g, b, a)
                return r + (g * 256) + (b * 65536) + (a * 16777216)
            end

            local function remove_vec2_entry(cache, entry)
                local bucket = cache[entry[1]]
                if bucket then bucket[entry[2]] = nil end
            end

            function Gui.vec2(x, y)
                x = math_floor((x or 0) + 0.5)
                y = math_floor((y or 0) + 0.5)
                local bucket = vec2_cache[x]
                if bucket then
                    local cached = bucket[y]
                    if cached then return cached end
                else
                    bucket = {}
                    vec2_cache[x] = bucket
                end

                local value = vec2_ctor(x, y)
                bucket[y] = value
                vec2_order[#vec2_order + 1] = { x, y }
                CacheUtils.evict_ordered(vec2_cache, vec2_order, VEC2_LIMIT, 0.25, remove_vec2_entry)
                return value
            end

            function Gui.vec2_raw(x, y)
                return vec2_ctor(math.floor((x or 0) + 0.5), math.floor((y or 0) + 0.5))
            end

            function Gui.color(r, g, b, a)
                r = clamp_byte(r == nil and 255 or r)
                g = clamp_byte(g == nil and 255 or g)
                b = clamp_byte(b == nil and 255 or b)
                a = clamp_byte(a == nil and 255 or a)
                local key = color_hash(r, g, b, a)
                local cached = color_cache[key]
                if cached then return cached end

                local value = color_ctor(r, g, b, a)
                color_cache[key] = value
                color_order[#color_order + 1] = key
                CacheUtils.evict_ordered(color_cache, color_order, COLOR_LIMIT, 0.25)
                return value
            end

            function Gui.push_clip(pos, scale) return gui_push_clip(pos, scale) end
            function Gui.pop_clip() return gui_pop_clip() end
            function Gui.line(from, to, thickness, col) return gui_line(from, to, thickness, col) end
            function Gui.circle(pos, radius, col) return gui_circle(pos, radius, col) end
            function Gui.image(texture, pos, scale, col) return gui_image(texture, pos, scale, col) end
            function Gui.image_rounded(texture, pos, scale, col, rounding, flags) return gui_image_rounded(texture, pos, scale, col, rounding, flags) end
            function Gui.rebuild() return gui_rebuild() end
            function Gui.load_image(path) return gui_load_image(path) end
            function Gui.load_font(path, scale) return gui_load_font(path, scale) end
            function Gui.text_size(text, scale, options) return gui_text_size(text, scale, options) end
            function Gui.text(str) return gui_text(str) end
            function Gui.rect(pos, scale) return gui_rect(pos, scale) end

            function Gui.clear_caches()
                vec2_cache = {}
                color_cache = {}
                vec2_order = {}
                color_order = {}
            end

            return Gui

        end)()

        local HudDraw = (function()
            local HudDraw = {}
            local Gui = Gui
            local Native = Native
            local Runtime = Runtime
            local Util = HMUtil

            local WHITE <const> = { r = 255, g = 255, b = 255, a = 255 }

            local math_floor <const> = math.floor

            local function channel(color_value, key, default)
                if type(color_value) ~= "table" then return default end
                local value = color_value[key]
                if value == nil then return default end
                return math_floor(value)
            end

            local function rgba(color_value, default)
                default = default or WHITE
                return
                    channel(color_value, "r", default.r),
                    channel(color_value, "g", default.g),
                    channel(color_value, "b", default.b),
                    channel(color_value, "a", default.a)
            end

            function HudDraw.draw_rect(x, y, width, height, color_value)
                return HudDraw.draw_native_rect_screen(x, y, width, height, color_value)
            end


            function HudDraw.draw_sprite_screen(texture_dict, texture_name, x, y, width, height, heading, color_value)
                local resolution = Runtime.resolution()
                local r, g, b, a = rgba(color_value)
                return Native.call(
                    "draw_sprite",
                    texture_dict,
                    texture_name,
                    x / resolution.x,
                    y / resolution.y,
                    width / resolution.x,
                    height / resolution.y,
                    heading or 0.0,
                    r,
                    g,
                    b,
                    a,
                    0
                )
            end

            function HudDraw.draw_native_rect_screen(x, y, width, height, color_value)
                local resolution = Runtime.resolution()
                local r, g, b, a = rgba(color_value)
                return Native.call(
                    "draw_rect",
                    (x + width * 0.5) / resolution.x,
                    (y + height * 0.5) / resolution.y,
                    width / resolution.x,
                    height / resolution.y,
                    r,
                    g,
                    b,
                    a,
                    0
                )
            end

            function HudDraw.draw_marker_sphere(position, radius, color_value)
                position = Util.required_vector3(position)
                if not position then return nil end
                local r, g, b, a = rgba(color_value, { r = 255, g = 220, b = 40, a = 180 })
                return Native.draw_marker_sphere(position, radius or 1.0, r, g, b, a / 255.0)
            end

            function HudDraw.draw_scaleform_fullscreen(handle, color_value)
                if not handle or handle == 0 then return end
                local r, g, b, a = rgba(color_value)
                return Native.call("draw_scaleform_movie_fullscreen", handle, r, g, b, a, 0)
            end


            local function overlay_color(color_value, default)
                local r, g, b, a = rgba(color_value, default)
                return Gui.color(r, g, b, a)
            end


            function HudDraw.overlay_rect(x, y, width, height, color_value)
                Gui.rect(Gui.vec2_raw(x, y), Gui.vec2_raw(width, height)):color(overlay_color(color_value)):filled():draw()
            end

            function HudDraw.overlay_dot(center_x, center_y, size, color_value)
                size = size or 4
                HudDraw.overlay_rect(center_x - size * 0.5, center_y - size * 0.5, size, size, color_value)
            end

            function HudDraw.overlay_line(x1, y1, x2, y2, thickness, color_value)
                Gui.line(Gui.vec2_raw(x1, y1), Gui.vec2_raw(x2, y2), thickness or 1, overlay_color(color_value))
            end

            local WEIGHT_OFFSETS <const> = { { 1, 0 }, { 0, 1 } }

            local function draw_text_pass(text, x, y, scale, color, align)
                local obj = Gui.text(text)
                obj:position(Gui.vec2_raw(x, y))
                obj:scale(scale)
                obj:color(color)
                if align == true or align == "center" then
                    obj:justify(Gui.justify.center)
                elseif align == "right" then
                    obj:justify(Gui.justify.right)
                end
                obj:draw()
            end

            function HudDraw.overlay_text(text, x, y, scale, color_value, align, weight)
                text = tostring(text or "")
                scale = scale or 16
                local color = overlay_color(color_value)
                draw_text_pass(text, x, y, scale, color, align)
                local extra = math.min((tonumber(weight) or 1) - 1, #WEIGHT_OFFSETS)
                for i = 1, extra do
                    local off = WEIGHT_OFFSETS[i]
                    draw_text_pass(text, x + off[1], y + off[2], scale, color, align)
                end
            end

            return HudDraw

        end)()

