                    math_abs(dims.max.x - dims.min.x),
                    math_abs(dims.max.y - dims.min.y),
                    math_abs(dims.max.z - dims.min.z))
                if extent < 0.5 or extent > 30 then return DEFAULT_EXTENT_M end
                return extent
            end

            local function marker_size_px(state, slot, pos, screen, px_scale)
                if not state.cfg.use_auto_marker_size then return MARKER_FIXED_PX * px_scale end
                local fallback = MARKER_BASE_PX * px_scale
                local up = Projection.world_to_screen({ x = pos.x, y = pos.y, z = pos.z + 1.0 })
                if not up then return fallback end
                local dx, dy = up.x - screen.x, up.y - screen.y
                local px_per_m = math_sqrt(dx * dx + dy * dy)
                if px_per_m < 0.5 then return fallback end
                local size = target_extent(slot) * MARKER_PADDING * px_per_m
                return math_max(MARKER_MIN_PX * px_scale, math_min(MARKER_MAX_PX * px_scale, size))
            end

            local MARKER_LINE_THICKNESS <const> = 2
            local MARKER_CORNER_FRAC <const> = 0.28  -- corner-bracket length as a fraction of box size

            local function draw_lock_box(cx, cy, size, color_value, thickness)
                local half = size * 0.5
                local x1, y1 = cx - half, cy - half
                local x2, y2 = cx + half, cy + half
                local corner = size * MARKER_CORNER_FRAC

                -- Top-left corner
                HudDraw.overlay_line(x1, y1, x1 + corner, y1, thickness, color_value)
                HudDraw.overlay_line(x1, y1, x1, y1 + corner, thickness, color_value)
                -- Top-right corner
                HudDraw.overlay_line(x2, y1, x2 - corner, y1, thickness, color_value)
                HudDraw.overlay_line(x2, y1, x2, y1 + corner, thickness, color_value)
                -- Bottom-left corner
                HudDraw.overlay_line(x1, y2, x1 + corner, y2, thickness, color_value)
                HudDraw.overlay_line(x1, y2, x1, y2 - corner, thickness, color_value)
                -- Bottom-right corner
                HudDraw.overlay_line(x2, y2, x2 - corner, y2, thickness, color_value)
                HudDraw.overlay_line(x2, y2, x2, y2 - corner, thickness, color_value)
            end

            local function draw_lock_markers(state)
                if #state.slots == 0 then return end
                local px_scale = Runtime.resolution().y / 1080
                local thickness = math_max(1, MARKER_LINE_THICKNESS * px_scale)
                for i = 1, #state.slots do
                    local slot = state.slots[i]
                    local pos = slot.pos
                    local screen = pos and Projection.world_to_screen(pos)
                    if screen then
                        local size = marker_size_px(state, slot, pos, screen, px_scale)
                        if not slot.confirmed then size = size * 0.85 end
                        draw_lock_box(screen.x, screen.y, size, slot.confirmed and RED or AMBER, thickness)
                    end
                end
            end

            local targets_text = { slots = -1, max = -1, language = nil, text = "" }

            local function targets_text_for(state)
                local slots, max = #state.slots, state.cfg.max_targets
                local language = lang and lang.get_language() or nil
                if targets_text.slots ~= slots or targets_text.max ~= max or targets_text.language ~= language then
                    targets_text.slots = slots
                    targets_text.max = max
                    targets_text.language = language
                    targets_text.text = string_format("%s: %d/%d", _T("Targets"), slots, max)
                end
                return targets_text.text
            end

            local function draw_charge_bar(state)
                local resolution = Runtime.resolution()
                local width = BAR_WIDTH * resolution.x
                local height = BAR_HEIGHT * resolution.y
                local x = BAR_CENTER_X * resolution.x - width * 0.5
                local y = BAR_CENTER_Y * resolution.y - height * 0.5

                HudDraw.draw_rect(x, y, width, height, BAR_BG)

                local fill_color = state.is_recharging and BAR_CHARGING or BAR_READY
                local progress = math_max(0.0, math_min(1.0, (state.charge_level or 100) / 100.0))
                if progress > 0 then
                    HudDraw.draw_rect(x, y, width * progress, height, fill_color)
                end

                HudDraw.draw_rect(x, y, width, 1, BAR_BORDER)
                HudDraw.draw_rect(x, y + height - 1, width, 1, BAR_BORDER)
                HudDraw.draw_rect(x, y, 1, height, BAR_BORDER)
                HudDraw.draw_rect(x + width - 1, y, 1, height, BAR_BORDER)

                local font = math_max(12, math_min(24, (15 * resolution.y) // 1080))
                local text_y = y - font - 4
                HudDraw.overlay_text(state.is_recharging and _T("Charging") or _T("Ready"), x, text_y, font, fill_color)
                HudDraw.overlay_text(targets_text_for(state), x + width, text_y, font, TEXT_WHITE, "right")
            end

            function Hud.init(ctx)
                lang = ctx and ctx.lang or lang
            end

            function Hud.tick(state)
                local cfg = state.cfg
                if cfg.enable_lock_markers then draw_lock_markers(state) end
                if cfg.enable_charge_bar then draw_charge_bar(state) end
            end

            return Hud

        end)()

        local LockSound = (function()
            local LockSound = {}

            local Native = Native
            local Runtime = Runtime

            local SOUND_AMBER <const> = "VULKAN_LOCK_ON_AMBER"
            local SOUND_RED <const> = "VULKAN_LOCK_ON_RED"
            local SOUND_REF <const> = 0
            local RED_MS <const> = 700
            local AMBER_MAX_MS <const> = 1500
            local MIN_AGE_TICKS <const> = 2

            local TONE_NONE <const> = 0
            local TONE_AMBER <const> = 1
            local TONE_RED <const> = 2

            local tick_count = 0
            local now_ms = 0
            local entries = {}
            local dying = {}
            local pending_release = {}
            local desired = {}

            local function sound_finished(id)
                return Native.call("has_sound_finished", id) and true or false
            end

            local function any_tone_active()
                for _, entry in pairs(entries) do
                    if entry.tone ~= TONE_NONE and
                        (tick_count - entry.play_tick < MIN_AGE_TICKS or not sound_finished(entry.id)) then
                        return true
                    end
                end
                return false
            end

            local function play(entry, tone, name)
                local id = Native.call("get_sound_id")
                if id == nil or id == -1 then return end
                Native.call("play_sound_frontend", id, name, SOUND_REF, true)
                entry.id = id
                entry.tone = tone
                entry.play_tick = tick_count
                entry.play_ms = now_ms
            end

            local function stop_tone(entry)
                if entry.tone == TONE_NONE then return end
                if tick_count - entry.play_tick < MIN_AGE_TICKS then
                    dying[#dying + 1] = { id = entry.id, play_tick = entry.play_tick }
                else
                    Native.call("stop_sound", entry.id)
                    pending_release[#pending_release + 1] = { id = entry.id, stop_tick = tick_count }
                end
                entry.id = -1
                entry.tone = TONE_NONE
            end

            local function drain_deferred()
                for i = #dying, 1, -1 do
                    local d = dying[i]
                    if tick_count - d.play_tick >= MIN_AGE_TICKS then
                        Native.call("stop_sound", d.id)
                        pending_release[#pending_release + 1] = { id = d.id, stop_tick = tick_count }
                        table.remove(dying, i)
                    end
                end
                for i = #pending_release, 1, -1 do
                    local p = pending_release[i]
                    if tick_count - p.stop_tick >= MIN_AGE_TICKS then
                        Native.call("release_sound_id", p.id)
                        table.remove(pending_release, i)
                    end
                end
            end

            local function drop_entry(entity)
                local entry = entries[entity]
                if not entry then return end
                stop_tone(entry)
                entries[entity] = nil
            end

            function LockSound.stop_all()
                for entity in pairs(entries) do drop_entry(entity) end
            end

            function LockSound.shutdown()
                LockSound.stop_all()
                for i = #dying, 1, -1 do
                    Native.call("stop_sound", dying[i].id)
                    Native.call("release_sound_id", dying[i].id)
                    dying[i] = nil
                end
                for i = #pending_release, 1, -1 do
                    Native.call("release_sound_id", pending_release[i].id)
                    pending_release[i] = nil
                end
            end

            function LockSound.pump()
                tick_count = tick_count + 1
                now_ms = Runtime.get_tick_count()
                drain_deferred()
            end

            function LockSound.tick(state)
                if not state.cfg.enable_sounds or state.is_recharging then
                    LockSound.stop_all()
                    return
                end

                for entity in pairs(desired) do desired[entity] = nil end
                for i = 1, #state.slots do
                    local slot = state.slots[i]
                    desired[slot.entity] = slot.confirmed and TONE_RED or TONE_AMBER
                end

                for entity in pairs(entries) do
                    if not desired[entity] then drop_entry(entity) end
                end

                for entity, want in pairs(desired) do
                    local entry = entries[entity]
                    if not entry then
                        entry = { id = -1, tone = TONE_NONE, play_tick = 0, play_ms = 0,
                                  amber_done = false, red_done = false }
                        entries[entity] = entry
                    end
                    if entry.tone ~= TONE_NONE and now_ms < entry.play_ms then entry.play_ms = now_ms end
                    if entry.tone == TONE_AMBER then
                        if want == TONE_RED or now_ms - entry.play_ms >= AMBER_MAX_MS then
                            stop_tone(entry)
                            entry.amber_done = true
                        end
                    elseif entry.tone == TONE_RED then
                        if now_ms - entry.play_ms >= RED_MS then
                            stop_tone(entry)
                            entry.red_done = true
                        end
                    elseif want == TONE_AMBER then
                        if not entry.amber_done and not any_tone_active() then
                            play(entry, TONE_AMBER, SOUND_AMBER)
                        end
                    else
                        if not entry.red_done then
                            entry.amber_done = true
                            if not any_tone_active() then
                                play(entry, TONE_RED, SOUND_RED)
                            end
                        end
                    end
                end
            end

            return LockSound

        end)()

        local Launcher = (function()
            local Launcher = {}

            local Input = Input
            local Native = Native
            local Runtime = Runtime
            -- Hotkeys system not ported (rebind-UI framework, unrelated to missile mechanics)
            local ModelDims = ModelDims
            local Targeting = Targeting

            local CONTROL_GROUP <const> = 0
            local SHOT_DELAY_MS <const> = 300
            local RECHARGE_MS <const> = 2000
            local DISABLE_CONTROLS <const> = { 25, 68, 69, 70, 92, 99, 100, 114, 115, 262, 331 }
            local MOUSE_VKS <const> = { [0x01] = true, [0x02] = true, [0x04] = true, [0x05] = true, [0x06] = true }
            local AUTO_MARGIN_X <const> = 0.3
            local AUTO_MARGIN_Y <const> = 0.15

            local math_sin <const> = math.sin
            local math_cos <const> = math.cos
            local math_rad <const> = math.rad

            function Launcher.reset(state)
                state.shot_count = 0
                state.last_shot_ms = 0
                state.weapon_side = 0
                state.is_recharging = false
                state.recharge_start_ms = 0
                state.charge_level = 100
            end

            function Launcher.disable_controls()
                for i = 1, #DISABLE_CONTROLS do
                    Input.disable_control(CONTROL_GROUP, DISABLE_CONTROLS[i], true)
                end
            end

            local MOUSE_VK_CONTROLS <const> = { [0x01] = 24, [0x02] = 25 }

            local function vk_held(vk)
                local key_state = MOUSE_VKS[vk] and Input.mouse(vk) or Input.key(vk)
                if key_state and key_state.pressed then return true end
                local control = MOUSE_VK_CONTROLS[vk]
                if control and Input.disabled_pressed(CONTROL_GROUP, control) then return true end
                return false
            end

            local function binding_held(binding)
                if not binding then return false end
                if not vk_held(binding.vk) then return false end
                if binding.ctrl and not (vk_held(0xA2) or vk_held(0xA3)) then return false end
                if binding.shift and not (vk_held(0xA0) or vk_held(0xA1)) then return false end
                if binding.alt and not (vk_held(0xA4) or vk_held(0xA5)) then return false end
                return true
            end

            local function fire_held(state)
                if state.menu_open then return false end
                -- Hotkeys.is_enabled()/get_bindings() removed: no rebind-UI ported.
                -- Preserves the original default binding for "homing.fire" (vk = 0x02, RMB, no modifiers).
                return binding_held({ vk = 0x02 })
            end

            local function charge_ok(state, now)
                if not state.is_recharging then return true end
                if now < state.recharge_start_ms then state.recharge_start_ms = now end
                local actual = RECHARGE_MS / state.cfg.recharge_speed
                state.charge_level = 100 * (now - state.recharge_start_ms) / actual
                if state.charge_level >= 100 then
                    state.is_recharging = false
                    state.charge_level = 100
                    state.shot_count = 0
                    Targeting.clear_shot_flags(state)
                end
                return not state.is_recharging
            end

            local function launch_offset(state, side)
                local cfg = state.cfg
                if cfg.use_auto_dimensions then
                    local dims = ModelDims.get(state.my_vehicle_model)
                    if dims then
                        local ox = (side == 0) and (dims.max.x - AUTO_MARGIN_X) or (dims.min.x + AUTO_MARGIN_X)
                        return ox + 0.0, (dims.max.y - AUTO_MARGIN_Y) + 0.0
                    end
                end
                local ox = (side == 0) and cfg.missile_offset_x or -cfg.missile_offset_x
                return ox + 0.0, cfg.missile_offset_y + 0.0
            end

            local function shoot_missile(state, target_entity, side)
                local cfg = state.cfg
                local veh = state.my_vehicle
                local ox, oy = launch_offset(state, side)
                local launch = Native.get_offset_from_entity_in_world_coords(veh, ox, oy, cfg.missile_offset_z + 0.0)
                if not (launch and launch.x) then return false end

                local rot = Native.get_entity_rotation(veh, 2)
                local z_rad = math_rad(rot and rot.z or 0.0)
                local dir_x, dir_y = -math_sin(z_rad), math_cos(z_rad)
                local right_x, right_y = math_cos(z_rad), math_sin(z_rad)
                local arc_x = (side == 0) and cfg.missile_arc_offset or -cfg.missile_arc_offset
                local dist = cfg.missile_initial_distance

                local target = {
                    x = launch.x + dir_x * dist + right_x * arc_x + 0.0,
                    y = launch.y + dir_y * dist + right_y * arc_x + 0.0,
                    z = launch.z + cfg.missile_launch_z_offset + 0.0,
                }

                Native.shoot_single_bullet_between_coords_ignore_entity_new(
                    launch, target,
                    0, true, state.weapon_hash, state.my_ped,
                    true, false, cfg.missile_speed + 0.0, veh,
                    false, false, target_entity, false, false, false)

                if cfg.enable_sounds then
                    Native.call("play_sound_from_coord", -1, "Fire", launch.x + 0.0, launch.y + 0.0, launch.z + 0.0,
                        "DLC_BTL_Terrobyte_Turret_Sounds", true, 200, true)
                end
                return true
            end

            function Launcher.tick(state)
                local cfg = state.cfg
                local now = Runtime.get_tick_count()

                if not charge_ok(state, now) then return end

                local want = fire_held(state)
                if not want and cfg.auto_attack and Targeting.has_confirmed_unshot(state) then
                    want = true
                end
                if not want then return end
                if now < state.last_shot_ms then state.last_shot_ms = now end
                if now - state.last_shot_ms < SHOT_DELAY_MS then return end

                if not Native.call("has_ped_got_weapon", state.my_ped, state.weapon_hash, false) then
                    Native.call("give_delayed_weapon_to_ped", state.my_ped, state.weapon_hash, -1, false)
                    if state.logger then
                        state.logger.verbose("Features.HomingMissiles", "weapon stripped at fire; re-given")
                    end
                    return
                end

                local target = Targeting.next_shot_target(state)
                if cfg.require_lock_confirm and (not target or target == 0) then return end

                state.weapon_side = (state.weapon_side == 0) and 1 or 0
                if shoot_missile(state, target, state.weapon_side) then
                    state.shot_count = state.shot_count + 1
                    state.last_shot_ms = now
                    if state.shot_count >= cfg.max_targets then
                        state.is_recharging = true
                        state.recharge_start_ms = now
                        state.charge_level = 0
                    end
                else
                    Targeting.unmark_shot(state, target)
                end
            end

            return Launcher

        end)()
        local FeatureThread = (function()
            local FeatureThread = {}

            local Runtime = Runtime

            function FeatureThread.new(tick)
                local thread = {}
                local id = nil

                function thread.start()
                    if id then return false end
                    id = Runtime.create_thread(tick)
                    return true
                end

                function thread.stop()
                    if not id then return false end
                    local current = id
                    id = nil
                    Runtime.remove_thread(current)
                    return true
                end

                function thread.running()
                    return id ~= nil
                end

                return thread
            end

            return FeatureThread

        end)()

        local MissileRuntime = (function()
            local MissileRuntime = {}

            local FeatureThread = FeatureThread
            local Util = HMUtil
            local Players = Players
            local Native = Native
            local Game = Game
            local Script = Script
            local Targeting = Targeting
            local Launcher = Launcher
            local LockSound = LockSound
            local Hud = Hud

            local WEAPON_HASH <const> = 0xB4F96934
            local RC_HASHES <const> = { [0x5D0AAC8F] = true, [0x65B4004C] = true }

            local valid_coord = Util.valid_coord

            local function defaults()
                return {
                    max_targets = 6,
                    target_mode = 3,
                    lock_players = true,
                    lock_peds = true,
                    enemy_mode = 2,
                    los_mode = 1,
                    use_visual_check = false,
                    use_screen_check = true,
                    require_lock_confirm = true,
                    instant_lock = false,
                    auto_attack = false,
                    recharge_speed = 1.0,
                    exclude_animals = true,
                    missile_speed = 800.0,
                    lock_distance_min = 5.0,
                    lock_distance_max = 500.0,
                    missile_offset_x = 1.0,
                    missile_offset_y = 3.0,
                    missile_offset_z = 0.0,
                    missile_launch_z_offset = 1.0,
                    missile_initial_distance = 5.0,
                    missile_arc_offset = 1.5,
                    enable_sounds = true,
                    enable_lock_markers = true,
                    enable_charge_bar = true,
                    lockon_notify = true,
                    use_auto_dimensions = true,
                    use_auto_marker_size = false,
                    ignore_friends = true,
                    ignore_org_members = true,
                    ignore_team_members = false,
                    ignore_mission_players = true,
                    ignore_ghosted = true,
                }
            end

            local state = {
                enabled = false,
                logger = nil,
                menu_open = false,
                weapon_hash = WEAPON_HASH,
                cfg = defaults(),
                my_ped = 0,
                my_vehicle = 0,
                my_coords = nil,
                my_vehicle_model = 0,
                model_vehicle = 0,
                weapon_vehicle = 0,
                weapon_ped = 0,
                in_mission = false,
                slots = {},
                players_by_ped = {},
                shot_count = 0,
                last_shot_ms = 0,
                weapon_side = 0,
                is_recharging = false,
                recharge_start_ms = 0,
                charge_level = 100,
            }

            local function log_verbose(message)
                if state.logger then state.logger.verbose("Features.HomingMissiles", message) end
            end

            local function is_camera_app_open()
                return Script.running("appcamera")
            end

            local function vehicle_model(vehicle)
                if state.model_vehicle ~= vehicle then
                    state.model_vehicle = vehicle
                    state.my_vehicle_model = Native.get_entity_model(vehicle)
                end
                return state.my_vehicle_model
            end

            local function should_pause_lockon(vehicle)
                return is_camera_app_open() or RC_HASHES[vehicle_model(vehicle)] or false
            end

            function MissileRuntime.reset()
                Targeting.clear(state)
                Launcher.reset(state)
                LockSound.stop_all()
                state.my_vehicle = 0
                state.my_coords = nil
                state.my_vehicle_model = 0
                state.model_vehicle = 0
                state.weapon_vehicle = 0
                state.weapon_ped = 0
            end

            local function tick()
                LockSound.pump()

                if not state.enabled then
                    MissileRuntime.stop()
                    return
                end

                local my_ped = Players.local_ped()
                if not my_ped or my_ped == 0 then MissileRuntime.reset(); return end

                local vehicle = Players.local_driver_vehicle()
                if vehicle == 0 or not Game.entity_exists(vehicle) then
                    MissileRuntime.reset()
                    return
                end

                local coords = Players.local_coords()
                if not valid_coord(coords) then return end

                if should_pause_lockon(vehicle) then
                    MissileRuntime.reset()
                    return
                end

                state.my_ped = my_ped
                state.my_vehicle = vehicle
                state.my_coords = coords

                if state.weapon_vehicle ~= vehicle or state.weapon_ped ~= my_ped then
                    Native.call("give_delayed_weapon_to_ped", my_ped, state.weapon_hash, -1, false)
                    state.weapon_vehicle = vehicle
                    state.weapon_ped = my_ped
                    Launcher.reset(state)
                end

                state.in_mission = Game.in_mission()

                Launcher.disable_controls()
                Targeting.tick(state)
                LockSound.tick(state)
                Launcher.tick(state)
                Hud.tick(state)
            end

            local thread = FeatureThread.new(tick)

            function MissileRuntime.init(ctx)
                state.logger = ctx and ctx.logger or state.logger
                Hud.init({ lang = ctx and ctx.lang })
                return true
            end

            function MissileRuntime.start()
                if not thread.start() then return end
                log_verbose("HomingMissiles thread started")
            end

            function MissileRuntime.stop()
                if not thread.stop() then return end
                MissileRuntime.reset()
                LockSound.shutdown()
                log_verbose("HomingMissiles thread stopped")
            end

            function MissileRuntime.evaluate()
                if state.enabled then MissileRuntime.start() else MissileRuntime.stop() end
            end

            function MissileRuntime.on_menu_open() state.menu_open = true end
            function MissileRuntime.on_menu_close() state.menu_open = false end

            function MissileRuntime.on_shutdown()
                MissileRuntime.stop()
                LockSound.shutdown()
            end

            function MissileRuntime.set_enabled(value)
                state.enabled = value and true or false
                MissileRuntime.evaluate()
            end

            MissileRuntime.defaults = defaults

            local function clamp(value, lo, hi, fallback)
                local n = tonumber(value)
                if not n then return fallback end
                if n < lo then return lo end
                if n > hi then return hi end
                return n
            end

            function MissileRuntime.apply_config(config)
                if type(config) ~= "table" then return end
                local cfg = state.cfg
                local d = defaults()
                cfg.max_targets = math.floor(clamp(config.max_targets, 1, 8, d.max_targets))
                cfg.target_mode = math.floor(clamp(config.target_mode, 1, 3, d.target_mode))
                cfg.enemy_mode = math.floor(clamp(config.enemy_mode, 0, 2, d.enemy_mode))
                cfg.los_mode = math.floor(clamp(config.los_mode, 0, 2, d.los_mode))
                cfg.recharge_speed = clamp(config.recharge_speed, 0.1, 10.0, d.recharge_speed)
                cfg.missile_speed = clamp(config.missile_speed, 100, 10000, d.missile_speed)
                cfg.lock_distance_min = clamp(config.lock_distance_min, 1, 50, d.lock_distance_min)
                cfg.lock_distance_max = clamp(config.lock_distance_max, 100, 1000, d.lock_distance_max)
                cfg.missile_offset_x = clamp(config.missile_offset_x, 0.5, 3.0, d.missile_offset_x)
                cfg.missile_offset_y = clamp(config.missile_offset_y, 1.0, 8.0, d.missile_offset_y)
                cfg.missile_offset_z = clamp(config.missile_offset_z, 0.0, 2.0, d.missile_offset_z)
                cfg.missile_launch_z_offset = clamp(config.missile_launch_z_offset, 0.0, 20.0, d.missile_launch_z_offset)
                cfg.missile_initial_distance = clamp(config.missile_initial_distance, 1.0, 10.0, d.missile_initial_distance)
                cfg.missile_arc_offset = clamp(config.missile_arc_offset, 0.0, 20.0, d.missile_arc_offset)
                if config.lock_players ~= nil then cfg.lock_players = config.lock_players and true or false end
                if config.lock_peds ~= nil then cfg.lock_peds = config.lock_peds and true or false end
                if config.use_visual_check ~= nil then cfg.use_visual_check = config.use_visual_check and true or false end
                if config.use_screen_check ~= nil then cfg.use_screen_check = config.use_screen_check and true or false end
                if config.require_lock_confirm ~= nil then cfg.require_lock_confirm = config.require_lock_confirm and true or false end
                if config.instant_lock ~= nil then cfg.instant_lock = config.instant_lock and true or false end
                if config.auto_attack ~= nil then cfg.auto_attack = config.auto_attack and true or false end
                if config.exclude_animals ~= nil then cfg.exclude_animals = config.exclude_animals and true or false end
                if config.enable_sounds ~= nil then cfg.enable_sounds = config.enable_sounds and true or false end
                if config.enable_lock_markers ~= nil then cfg.enable_lock_markers = config.enable_lock_markers and true or false end
                if config.enable_charge_bar ~= nil then cfg.enable_charge_bar = config.enable_charge_bar and true or false end
                if config.lockon_notify ~= nil then cfg.lockon_notify = config.lockon_notify and true or false end
                if config.use_auto_dimensions ~= nil then cfg.use_auto_dimensions = config.use_auto_dimensions and true or false end
                if config.use_auto_marker_size ~= nil then cfg.use_auto_marker_size = config.use_auto_marker_size and true or false end
                if config.ignore_friends ~= nil then cfg.ignore_friends = config.ignore_friends and true or false end
                if config.ignore_org_members ~= nil then cfg.ignore_org_members = config.ignore_org_members and true or false end
                if config.ignore_team_members ~= nil then cfg.ignore_team_members = config.ignore_team_members and true or false end
                if config.ignore_mission_players ~= nil then cfg.ignore_mission_players = config.ignore_mission_players and true or false end
                if config.ignore_ghosted ~= nil then cfg.ignore_ghosted = config.ignore_ghosted and true or false end
            end

            return MissileRuntime

        end)()


        -- ---- Glue: wire MissileRuntime into Kyron -----------------------------
        MissileRuntime.init({})

        local homing_state = {
            enabled = false,
            max_targets = 6,
            target_mode = 3,
            lock_players = true,
            lock_peds = true,
            enemy_mode = 2,
            los_mode = 1,
            use_visual_check = false,
            use_screen_check = true,
            require_lock_confirm = true,
            instant_lock = false,
            auto_attack = false,
            recharge_speed = 1.0,
            exclude_animals = true,
            missile_speed = 800.0,
            lock_distance_min = 5.0,
            lock_distance_max = 500.0,
            missile_offset_x = 1.0,
            missile_offset_y = 3.0,
            missile_offset_z = 0.0,
            missile_launch_z_offset = 1.0,
            missile_initial_distance = 5.0,
            missile_arc_offset = 1.5,
            enable_sounds = true,
            enable_lock_markers = true,
            enable_charge_bar = true,
            use_auto_marker_size = false,
            lockon_notify = true,
            use_auto_dimensions = true,
            ignore_friends = true,
            ignore_org_members = true,
            ignore_team_members = false,
            ignore_mission_players = true,
            ignore_ghosted = true,
        }

        local function homing_push_config()
            MissileRuntime.apply_config(homing_state)
        end
        homing_push_config()

        local function homing_set_option(key, value)
            homing_state[key] = value
            if key == "enabled" then
                MissileRuntime.set_enabled(value)
            else
                homing_push_config()
            end
        end

        return MissileRuntime, homing_state, homing_set_option
    end)()

    -- =========================================================================
    -- HOMING MISSILES TAB (faithful port from the original ClickUl_Refactor
    -- HomingMissiles feature — Targeting/EntityPool/Launcher/LockSound/Hud/
    -- MissileRuntime — see the block above for the adapter+core port)
    -- =========================================================================

    function draw_vehicle_missiles_panel(px, py, pw, ph, scroll_offset)
        -- The widgets below (group_header/checkbox/slider/button/text_label)
        -- are auto-layout and read/advance the shared ui_layout cursor, which
        -- the Vehicle tab's manual px/sy layout doesn't use. Scope the cursor
        -- to this panel's rect for the duration of the call, then restore it
        -- so the rest of draw_vehicle_panel_content is unaffected. The content
        -- list is taller than the panel, so it's shifted up by scroll_offset
        -- the same way the Upgrades/Paint/etc. branches scroll.
        local saved_x, saved_y, saved_w = ui_layout.content_x, ui_layout.widget_y, ui_layout.content_w
        local content_top = py + 8
        local clipped = gui and gui.push_clip and vec2
        if clipped then gui.push_clip(vec2(px, py), vec2(pw, ph)) end
        begin_content(px, content_top - (scroll_offset or 0), pw)

        group_header("Homing Missiles")
        local v_enabled = checkbox("Enable Homing Missiles", homing_state.enabled)
        if v_enabled ~= homing_state.enabled then homing_set_option("enabled", v_enabled) end
        text_label("Hold RMB while driving to fire")

        local v = slider("Missile Speed", homing_state.missile_speed, 100, 10000)
        if v ~= homing_state.missile_speed then homing_set_option("missile_speed", v) end

        v = math.floor(slider("Max Targets", homing_state.max_targets, 1, 8) + 0.5)
        if v ~= homing_state.max_targets then homing_set_option("max_targets", v) end

        v = slider("Recharge Speed", homing_state.recharge_speed, 0.1, 10.0)
        if v ~= homing_state.recharge_speed then homing_set_option("recharge_speed", v) end

        do
            local modes = {"Vehicles", "Peds", "All"}
            if button("Target Type: " .. modes[homing_state.target_mode]) then
                homing_set_option("target_mode", (homing_state.target_mode % 3) + 1)
            end
        end
        do
            local modes = {"Off", "Priority", "Only"}
            if button("Enemy Priority: " .. modes[homing_state.enemy_mode + 1]) then
                homing_set_option("enemy_mode", (homing_state.enemy_mode + 1) % 3)
            end
        end
        do
            local modes = {"Off", "Loose", "Strict"}
            if button("Line of Sight: " .. modes[homing_state.los_mode + 1]) then
                homing_set_option("los_mode", (homing_state.los_mode + 1) % 3)
            end
        end

        group_header("Range")
        v = slider("Lock Distance Min", homing_state.lock_distance_min, 1, 50)
        if v ~= homing_state.lock_distance_min then homing_set_option("lock_distance_min", v) end
        v = slider("Lock Distance Max", homing_state.lock_distance_max, 100, 1000)
        if v ~= homing_state.lock_distance_max then homing_set_option("lock_distance_max", v) end
        v = slider("Launch Arc", homing_state.missile_arc_offset, 0.0, 20.0)
        if v ~= homing_state.missile_arc_offset then homing_set_option("missile_arc_offset", v) end
        v = slider("Launch Climb", homing_state.missile_launch_z_offset, 0.0, 20.0)
        if v ~= homing_state.missile_launch_z_offset then homing_set_option("missile_launch_z_offset", v) end

        group_header("Targeting")
        local toggles = {
            { key = "lock_players", label = "Lock Players" },
            { key = "lock_peds", label = "Lock NPCs" },
            { key = "exclude_animals", label = "Ignore Animals" },
            { key = "use_screen_check", label = "On-Screen Only" },
            { key = "use_visual_check", label = "Visual Occlusion Check" },
            { key = "require_lock_confirm", label = "Require Lock Confirm" },
            { key = "instant_lock", label = "Instant Lock" },
            { key = "auto_attack", label = "Auto Attack" },
            { key = "lockon_notify", label = "Lock-on Warning" },
            { key = "use_auto_dimensions", label = "Auto Muzzle Offset" },
        }
        for _, t in ipairs(toggles) do
            local tv = checkbox(t.label, homing_state[t.key])
            if tv ~= homing_state[t.key] then homing_set_option(t.key, tv) end
        end

        group_header("Exclusions")
        local exclusions = {
            { key = "ignore_friends", label = "Ignore Friends" },
            { key = "ignore_org_members", label = "Ignore Organization" },
            { key = "ignore_team_members", label = "Ignore Team" },
            { key = "ignore_mission_players", label = "Ignore Mission Players" },
            { key = "ignore_ghosted", label = "Ignore Ghosted" },
        }
        for _, t in ipairs(exclusions) do
            local tv = checkbox(t.label, homing_state[t.key])
            if tv ~= homing_state[t.key] then homing_set_option(t.key, tv) end
        end

        group_header("HUD")
        local hud_toggles = {
            { key = "enable_lock_markers", label = "Lock Markers" },
            { key = "enable_charge_bar", label = "Charge Bar" },
            { key = "use_auto_marker_size", label = "Auto Marker Size" },
            { key = "enable_sounds", label = "Lock-on Sounds" },
        }
        for _, t in ipairs(hud_toggles) do
            local tv = checkbox(t.label, homing_state[t.key])
            if tv ~= homing_state[t.key] then homing_set_option(t.key, tv) end
        end

        -- ui_layout.widget_y has advanced past every widget drawn above; add
        -- back the scroll shift to recover the true (unscrolled) content
        -- height for the caller's max_scroll calculation.
        local total_content_height = (ui_layout.widget_y + (scroll_offset or 0)) - content_top

        if clipped then gui.pop_clip() end
        begin_content(saved_x, saved_y, saved_w)

        return total_content_height
    end


