            {name = "Fleeca Bank", x = 147.0, y = -1044.0, z = 29.4},
            {name = "Paleto Bank", x = -104.0, y = 6468.0, z = 31.6},
            {name = "Vangelico Jewelry", x = -631.0, y = -236.0, z = 38.1},
            {name = "UD Vault", x = 2.5, y = -663.0, z = 16.1},
        },
    }

    local world_state = {
        selected_category = 1,
        list_scroll = 0,
    }

    local function teleport_to(x, y, z, name)
        local me = players and players.me and players.me()
        if not me then
            safe_toast("Cannot get player")
            return
        end

        local entity = (me.vehicle and me.vehicle ~= 0) and me.vehicle or me.ped
        if entity and N.SET_ENTITY_COORDS_NO_OFFSET then
            pcall(N.SET_ENTITY_COORDS_NO_OFFSET, entity, x, y, z, false, false, false)
            safe_toast("Teleported to " .. name)
        else
            safe_toast("Teleport not available")
        end
    end

    -- =========================================================================
    -- FUNNY OUTFIT SPAWNER (Model > Funny)
    -- Fresh port of ClickUi's outfit spawner (Constructor/CraftLab JSON +
    -- Menyoo OutfitPedData XML), rebuilt against Kyron's own native/file API
    -- (request.*, entities.*, invoker.call — verified against docs.lexis.re
    -- and the alloc8or GTAV native database). The folder-scan convention
    -- (Kyron\outfits\Json\ and Kyron\outfits\Menyoo\, folders.txt, dirs.scan
    -- fallback) is kept from Kyron's previous scanner; everything else —
    -- parsing, ped-attribute application, spawning/attach behavior — is a
    -- fresh implementation matching ClickUi's OutfitSpawner / PedAppearance /
    -- EntityTreeSpawner / PedParser modules, not the old "Modded" tab, which
    -- has been removed entirely.
    -- Wrapped in its own do..end: this enclosing function is already near
    -- Lua's 200-local-variable ceiling, so only the entry point below is
    -- allowed to escape as an upvalue instead of every helper becoming a
    -- counted local.
    -- =========================================================================

    local draw_outfit_spawner_tab
    do

    local outfit_spawner_state = {
        sub_tab = 1,               -- 1 = Json, 2 = Menyoo
        json_outfits = {},
        menyoo_outfits = {},
        json_loaded = false,
        menyoo_loaded = false,
        json_scroll = 0,
        menyoo_scroll = 0,
        is_spawning = false,
        active_handles = {},       -- entity handles spawned by the current outfit
        active_ptfx = {},          -- looped particle-fx handles started on the ped/entities
        active_name = nil,
        spawned_ped = nil,         -- standalone ped, only set when spawn_mode is Spawn Ped or Change Player Model
        original_player_ped_hash = nil,  -- remembered so "Change Player Model" outfits can be reasoned about later
    }

    -- Spawn Mode: 1 = Spawn Ped (separate ped, not you), 2 = Apply to Player
    -- (default — outfit goes directly on you), 3 = Change Player Model
    -- (spawns the outfit as a standalone ped, then swaps your player onto
    -- it). Matches ClickUi's Settings.OUTFIT_SPAWN_MODE exactly.
    local SPAWN_MODE_SPAWN_PED, SPAWN_MODE_APPLY_TO_PLAYER, SPAWN_MODE_CHANGE_PLAYER_MODEL = 1, 2, 3
    local SPAWN_MODE_LABELS = {"Spawn Ped", "Apply to Player", "Change Player Model"}

    -- Per-format settings, matching ClickUi's Settings.lua defaults
    -- (json_outfit / menyoo_outfit sections). Kept in-memory for this
    -- session — not written to Kyron's on-disk config, to avoid touching
    -- an unrelated save format.
    local outfit_spawner_settings = {
        json = {
            spawn_mode = SPAWN_MODE_APPLY_TO_PLAYER,
            delete_old_outfit = true,
            disable_collision = false,
            apply_head_features = false,
        },
        menyoo = {
            spawn_mode = SPAWN_MODE_APPLY_TO_PLAYER,
            delete_old_outfit = true,
            disable_collision = false,
            apply_head_features = false,
            apply_components = true,
            apply_props = true,
            apply_decals = true,
            apply_damage_packs = true,
            apply_attachments = true,
        },
    }

    -- paths.script's exact meaning is ambiguous between docs.lexis.re
    -- (script's own folder) and this file's other already-working scanners'
    -- comments (scripts ROOT, requiring an explicit "Kyron\" segment) — so,
    -- matching the pattern those other working scanners already use, try
    -- both candidates and use whichever dirs.exists() confirms.
    local function outfit_spawner_base_dir()
        local candidates = {}
        if paths and paths.script then
            local s = paths.script
            if not s:match("[/\\]$") then s = s .. "\\" end
            table.insert(candidates, s .. "Kyron\\outfits\\")  -- paths.script = scripts ROOT
            table.insert(candidates, s .. "outfits\\")         -- paths.script = this script's own folder
        end
        if paths and paths.game then
            local g = paths.game
            if not g:match("[/\\]$") then g = g .. "\\" end
            table.insert(candidates, g .. "scripts\\Kyron\\outfits\\")
        end

        for _, c in ipairs(candidates) do
            local ok, exists = pcall(dirs.exists, c)
            if ok and exists then return c end
        end

        -- Nothing exists yet — create the first candidate (matches the
        -- comment convention used elsewhere in this file) so a fresh
        -- install has somewhere to drop outfit files into.
        local primary = candidates[1] or "outfits\\"
        if dirs and dirs.create then pcall(dirs.create, primary) end
        return primary
    end

    -- ═══════════════════════════ shared numeric/table helpers ═══════════════════════════

    local function to_num(v, default)
        if v == nil then return default end
        if type(v) == "number" then return v end
        local n = tonumber(v)
        if n ~= nil then return n end
        return default
    end

    local function to_int(v, default)
        local n = to_num(v, default)
        if n == nil then return default end
        return math.floor(n + 0.5)
    end

    local function to_bool(v)
        if v == nil then return false end
        if type(v) == "boolean" then return v end
        if type(v) == "number" then return v ~= 0 end
        if v == "true" or v == "1" or v == "yes" or v == "on" then return true end
        return false
    end

    -- Accepts {x=,y=,z=} or a 3-item array; returns a plain {x,y,z} table.
    local function vec3(v)
        if type(v) ~= "table" then return {x = 0.0, y = 0.0, z = 0.0} end
        return {
            x = to_num(v.x or v[1], 0.0) + 0.0,
            y = to_num(v.y or v[2], 0.0) + 0.0,
            z = to_num(v.z or v[3], 0.0) + 0.0,
        }
    end

    -- Numeric key like "_5" or 5 -> 5 ; anything else -> nil.
    local function slot_id(key)
        if type(key) == "number" then return math.floor(key) end
        local digits = tostring(key):match("^_?(%d+)$")
        if digits then return tonumber(digits) end
        return nil
    end

    -- ═══════════════════════════ minimal JSON decoder ═══════════════════════════
    -- Recursive-descent parser: standard JSON, no comments/trailing commas
    -- (matches every mod-menu export ClickUi supports).

    local function json_decode(str)
        local pos = 1
        local len = #str

        local function skip_ws()
            local _, e = str:find("^[ \t\r\n]*", pos)
            if e then pos = e + 1 end
        end

        local parse_value

        local function parse_string()
            pos = pos + 1
            local start = pos
            local out = {}
            while pos <= len do
                local c = str:sub(pos, pos)
                if c == '"' then
                    out[#out + 1] = str:sub(start, pos - 1)
                    pos = pos + 1
                    return table.concat(out)
                elseif c == '\\' then
                    out[#out + 1] = str:sub(start, pos - 1)
                    local nc = str:sub(pos + 1, pos + 1)
                    if nc == 'n' then out[#out + 1] = "\n"
                    elseif nc == 't' then out[#out + 1] = "\t"
                    elseif nc == 'r' then out[#out + 1] = "\r"
                    elseif nc == 'u' then
                        out[#out + 1] = "?"
                        pos = pos + 4
                    else out[#out + 1] = nc
                    end
                    pos = pos + 2
                    start = pos
                else
                    pos = pos + 1
                end
            end
            out[#out + 1] = str:sub(start, pos - 1)
            return table.concat(out)
        end

        local function parse_number()
            local s, e = str:find("^-?%d+%.?%d*[eE]?[%+%-]?%d*", pos)
            local numstr = str:sub(s, e)
            pos = e + 1
            return tonumber(numstr)
        end

        local function parse_object()
            pos = pos + 1
            local obj = {}
            skip_ws()
            if str:sub(pos, pos) == '}' then pos = pos + 1; return obj end
            while true do
                skip_ws()
                local key = parse_string()
                skip_ws()
                pos = pos + 1  -- ':'
                skip_ws()
                obj[key] = parse_value()
                skip_ws()
                local c = str:sub(pos, pos)
                if c == ',' then pos = pos + 1
                elseif c == '}' then pos = pos + 1; break
                else break end
            end
            return obj
        end

        local function parse_array()
            pos = pos + 1
            local arr = {}
            skip_ws()
            if str:sub(pos, pos) == ']' then pos = pos + 1; return arr end
            while true do
                skip_ws()
                arr[#arr + 1] = parse_value()
                skip_ws()
                local c = str:sub(pos, pos)
                if c == ',' then pos = pos + 1
                elseif c == ']' then pos = pos + 1; break
                else break end
            end
            return arr
        end

        parse_value = function()
            skip_ws()
            local c = str:sub(pos, pos)
            if c == '{' then return parse_object()
            elseif c == '[' then return parse_array()
            elseif c == '"' then return parse_string()
            elseif c == 't' then pos = pos + 4; return true
            elseif c == 'f' then pos = pos + 5; return false
            elseif c == 'n' then pos = pos + 4; return nil
            else return parse_number()
            end
        end

        local ok, result = pcall(parse_value)
        if not ok then return nil end
        return result
    end

    -- ═══════════════════════════ native wrappers ═══════════════════════════
    -- Every hash below is confirmed against the alloc8or GTAV native database
    -- (https://github.com/alloc8or/gta5-nativedb-data) and cross-checked
    -- against natives already used elsewhere in this script.

    local NATIVE = {
        PLAYER_PED_ID                       = 0xD80958FC74E988A6,
        PLAYER_ID                           = 0x4F8644AF03D0E0D6,
        CHANGE_PLAYER_PED                   = 0x048189FAC643DEEE,
        SET_PED_COMPONENT_VARIATION         = 0x262B14F48D29DE80,
        SET_PED_DEFAULT_COMPONENT_VARIATION = 0x45EEE61580806D63,
        SET_PED_PROP_INDEX                  = 0x93376B65A266EB5F,
        CLEAR_PED_PROP                      = 0x0943E5B8E078E76E,
        SET_PED_HEAD_BLEND_DATA             = 0x9414E18B9434C2FE,
        SET_PED_HEAD_OVERLAY                = 0x48F44967FA05CC1E,
        SET_PED_HEAD_OVERLAY_TINT           = 0x497BF74A7B9CB952,
        SET_PED_MICRO_MORPH                 = 0x71A5C1DBA060049E,
        SET_PED_HAIR_TINT                   = 0x4CFFC65454C93A49,
        SET_HEAD_BLEND_EYE_COLOR            = 0x50B56988B170AFDF,
        ADD_PED_DECORATION_FROM_HASHES      = 0x5F5D1665E352A839,
        CLEAR_PED_DECORATIONS               = 0x0E5173C163976E38,
        APPLY_PED_DAMAGE_PACK               = 0x46DF918788CB093F,
        SET_PED_CONFIG_FLAG                 = 0x1913FE4CBF41C463,
        SET_PED_MAX_HEALTH                  = 0xF5F6378C4F3419D3,
        SET_ENTITY_HEALTH                   = 0x6B76DC1F3AE6E6A3,
        SET_PED_ARMOUR                      = 0xCEA04D83135264CC,
        SET_PED_KEEP_TASK                   = 0x971D38760FBC02EF,
        SET_BLOCKING_OF_NON_TEMPORARY_EVENTS= 0x9F8AA94D6D97DBF4,
        SET_PED_CAN_RAGDOLL                 = 0xB128377056A54E2A,
        SET_PED_RAGDOLL_ON_COLLISION        = 0xF0A4F1BBF4FA7497,
        SET_PED_RELATIONSHIP_GROUP_HASH     = 0xC80A74AC829DDD92,
        SET_PED_COMBAT_ATTRIBUTES           = 0x9F7794730795E019,
        SET_PED_COMBAT_RANGE                = 0x3C606747B23E497B,
        SET_PED_COMBAT_MOVEMENT             = 0x4D9CA1009AFBD057,
        SET_PED_MOVEMENT_CLIPSET            = 0xAF8A94EDE7712BEF,
        SET_PED_WEAPON_MOVEMENT_CLIPSET     = 0x2622E35B77D3ACA2,
        SET_FACIAL_IDLE_ANIM_OVERRIDE       = 0xFFC24B988B938B38,
        TASK_PLAY_ANIM                      = 0xEA47FE3719165B94,
        TASK_START_SCENARIO_IN_PLACE        = 0x142A02425FF02BD9,
        GIVE_WEAPON_TO_PED                  = 0xBF0FD6E56C964FCB,
        SET_CURRENT_PED_WEAPON              = 0xADF692B254977C0C,
        GET_HASH_KEY                        = 0xD24D37CC275948CC,
        CREATE_PED                          = 0xD49F9B0955C367DE,
        DELETE_ENTITY                       = 0xAE3CBE5BF394C9C9,
        DOES_ENTITY_EXIST                   = 0x7239B21A38F536BA,
        ATTACH_ENTITY_TO_ENTITY             = 0x6B9BBD38AB0796DF,
        DETACH_ENTITY                       = 0x961AC54BF0613F5D,
        IS_ENTITY_ATTACHED                  = 0xB346476EF1A64897,
        PROCESS_ENTITY_ATTACHMENTS          = 0xF4080490ADC51C6F,
        GET_PED_BONE_INDEX                  = 0x3F428D08BE5AAE31,
        IS_ENTITY_A_PED                     = 0x524AC5ECEA15343E,
        SET_ENTITY_COLLISION                = 0x1A9205C1B9EE827F,
        FREEZE_ENTITY_POSITION              = 0x428CA6DBD1094446,
        NETWORK_GET_ENTITY_IS_NETWORKED     = 0xC7827959479DCC78,
        NETWORK_REGISTER_ENTITY_AS_NETWORKED= 0x06FAACD625D80CAA,
        NETWORK_GET_NETWORK_ID_FROM_ENTITY  = 0xA11700682F3AD45C,
        SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES = 0xE05E81A888FA63C8,
        SET_NETWORK_ID_CAN_MIGRATE          = 0x299EEB23175895FC,
        GET_ENTITY_COORDS                   = 0x3FEF770D40960D5A,
        SET_ENTITY_COORDS_NO_OFFSET         = 0x239A3351AC1DA385,
        GET_ENTITY_HEADING                  = 0xE83D4F9BA2A38914,
        USE_PARTICLE_FX_ASSET               = 0x6C38AF3693A69A91,
        START_PARTICLE_FX_LOOPED_ON_ENTITY  = 0x1AE42C1660FD6517,
        START_PARTICLE_FX_LOOPED_ON_ENTITY_BONE = 0xC6EB449E33977F0B,
        STOP_PARTICLE_FX_LOOPED             = 0x8F75998877616996,
