    local network_tab_state = {
        sub_tabs = {"Teleport"},
        sub_tab   = 1,  -- 1 = Teleport
    }

    local function draw_network_tab()
        local s       = UI.scale
        local base_x  = ui_layout.content_x
        local base_y  = ui_layout.widget_y
        local total_w = ui_layout.content_w

        -- ── Sub-tab bar (uses existing draw_subtabs helper + is_mouse_in) ────
        local new_tab, stab_consumed = sub_tab_bar(
            network_tab_state.sub_tabs,
            network_tab_state.sub_tab,
            base_x, base_y, total_w
        )
        network_tab_state.sub_tab = new_tab

        local cy      = base_y + stab_consumed + math.floor(4 * s)
        local btn_h   = math.floor((UI.button_h or 32) * s)
        local btn_gap = math.floor(6 * s)
        local pad     = math.floor(8 * s)
        local btn_w   = total_w - pad * 2

        -- ── Teleport sub-tab ─────────────────────────────────────────────────
        if network_tab_state.sub_tab == 1 then

            -- Section header
            local section_h = math.floor(22 * s)
            draw_rect(base_x + pad, cy, btn_w, section_h, C.header,
                      math.floor((UI.widget_rounding or 5) * s))
            draw_text("Force Teleport", base_x + pad + math.floor(8 * s),
                      cy + math.floor(4 * s), UI.font_small, C.text)
            cy = cy + section_h + math.floor(8 * s)

            -- ── Teleport Everyone to Me ───────────────────────────────────────
            if small_button("Teleport Everyone to Me", base_x + pad, cy, btn_w, btn_h) then
                pcall(function()
                    local me = players.me()
                    if not me then
                        safe_toast("[KYRON] Network: Could not get local player.")
                        return
                    end
                    local my_coords = me.coords
                    if not my_coords then
                        safe_toast("[KYRON] Network: Could not get your coordinates.")
                        return
                    end

                    local pulled = 0
                    for _, p in ipairs(players.list()) do
                        if p and p.id ~= me.id and p.connected then
                            pcall(function()
                                p:teleport(my_coords)
                                pulled = pulled + 1
                            end)
                        end
                    end

                    safe_toast(string.format("[KYRON] Teleported %d player(s) to your location.", pulled))
                end)
            end
            cy = cy + btn_h + btn_gap

            -- ── Start Pizza This for Everyone (West Vinewood) ────────────────
            if small_button("Start Pizza This (West Vinewood)", base_x + pad, cy, btn_w, btn_h) then
                pcall(function()
                    local me = players.me()
                    if not me then
                        safe_toast("[KYRON] Network: Could not get local player.")
                        return
                    end

                    -- "Force Job Join" SE — hash already verified in BLOCKED_SCRIPT_EVENTS.
                    -- Sending this to a player forces their client to launch am_pi_menu
                    -- (Pizza This) regardless of who holds host or script host.
                    -- params: { activity_script_hash, flags }
                    local SE_FORCE_JOB  = -2069144087     -- "Force Job Join"
                    local AM_PI_MENU    = joaat("am_pi_menu")

                    local sent = 0
                    for _, p in ipairs(players.list()) do
                        if p and p.connected and p.id ~= me.id then
                            pcall(function()
                                p:script_event(SE_FORCE_JOB, {AM_PI_MENU, 0, 0})
                                sent = sent + 1
                            end)
                        end
                    end

                    safe_toast(string.format(
                        "[KYRON] Pizza This SE sent to %d player(s).",
                        sent
                    ))
                end)
            end
            cy = cy + btn_h + btn_gap

        end  -- sub_tab == 1
    end

