    -- Freeze Weather Thread (using ZODIAC's native)
    util.create_job(function()
        while true do
            if online_state and online_state.freeze_weather then
                local weather_types = {
                    "EXTRASUNNY", "CLEAR", "CLOUDS", "SMOG", "FOGGY", "OVERCAST",
                    "RAIN", "THUNDER", "CLEARING", "NEUTRAL", "SNOW", "BLIZZARD"
                }
                local selected = online_state.selected_weather or 1
                local weather = weather_types[selected] or "CLEAR"
                pcall(natives.SET_WEATHER_TYPE_ZODIAC, weather)
            end
            util.yield(1000) -- Check every second
        end
    end)

