    local HEIST_CATEGORIES = {
        {name = "Cayo Perico", icon = ""},
        {name = "Casino", icon = ""},
        {name = "Doomsday", icon = ""},
        {name = "Classic", icon = ""},
        {name = "Auto Shop", icon = ""},
        {name = "Agency", icon = ""},
        {name = "Salvage", icon = ""},
        {name = "Cluckin Bell", icon = ""},
        {name = "Cuts", icon = ""},
        {name = "Force Ready", icon = ""},
    }

    local heist_state = {
        selected_category = 1,
        scroll_offset = 0,
        cayo_cuts = {host = 100, p2 = 100, p3 = 100, p4 = 100},
        casino_cuts = {host = 100, p2 = 100, p3 = 100, p4 = 100},
        doomsday_cuts = {p1 = 100, p2 = 100, p3 = 100, p4 = 100},
        apartment_cuts = {p1 = 100, p2 = 0, p3 = 0, p4 = 0},
    }

    -- Helper to draw a slider in heist panel
    local function heist_slider(label, value, min, max, px, py, pw, s)
        local slider_w = pw
        local slider_h = math.floor(36 * s)
        local track_h = math.floor(6 * s)
        local hover = is_mouse_in(px, py, slider_w, slider_h)

        draw_rect(px, py, slider_w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
        draw_text(string.format("%s: %d%%", label, math.floor(value)), px + math.floor(8 * s), py + math.floor(4 * s), UI.font_small, C.text)

        local track_y = py + math.floor(22 * s)
        local track_x = px + math.floor(8 * s)
        local track_w = slider_w - math.floor(16 * s)

        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))
        local pct = (value - min) / (max - min)
        draw_rect(track_x, track_y, track_w * pct, track_h, C.accent, math.floor(3 * s))

        if hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
            value = min + (max - min) * mouse_pct
        end

        return value, slider_h
    end

    -- Helper to draw a casino slider (no % sign, with description)
    local function casino_slider(label, value, min, max, px, py, pw, s, descriptions)
        local slider_w = pw
        local slider_h = math.floor(36 * s)
        local track_h = math.floor(6 * s)
        local hover = is_mouse_in(px, py, slider_w, slider_h)

        draw_rect(px, py, slider_w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))

        -- Build label with description
        local desc = ""
        if descriptions and descriptions[math.floor(value)] then
            desc = " - " .. descriptions[math.floor(value)]
        end
        draw_text(string.format("%s: %d%s", label, math.floor(value), desc), px + math.floor(8 * s), py + math.floor(4 * s), UI.font_small, C.text)

        local track_y = py + math.floor(22 * s)
        local track_x = px + math.floor(8 * s)
        local track_w = slider_w - math.floor(16 * s)

        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))
        local pct = (value - min) / (max - min)
        draw_rect(track_x, track_y, track_w * pct, track_h, C.accent, math.floor(3 * s))

        if hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
            value = min + (max - min) * mouse_pct
        end

        return value, slider_h
    end

    -- Helper to draw heist panel content with scrolling
    local function draw_heist_panel_content(panel_x, panel_y, panel_w, panel_h)
        local s = UI.scale
        local btn_h = math.floor(28 * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)
        local section_gap = math.floor(12 * s)
        local usable_w = panel_w - side_pad * 2

        local cat = HEIST_CATEGORIES[heist_state.selected_category]

        -- Build content list for current category
        local items = {}

        local function add_section(title)
            table.insert(items, {type = "section", text = title})
        end

        local function add_button(label, callback)
            table.insert(items, {type = "button", text = label, action = callback})
        end

        local function add_slider(label, state_table, key, min, max)
            table.insert(items, {type = "slider", text = label, state = state_table, key = key, min = min, max = max})
        end

        -- ===================== CAYO PERICO =====================
        if cat.name == "Cayo Perico" then
            add_section("Setup")
            add_button("Unlock All POI", function()
                for i = 0, 1 do
                    local p = "MP" .. i .. "_"
                    account.stats(p .. "H4CNF_BS_GEN").int32 = -1
                    account.stats(p .. "H4CNF_BS_ENTR").int32 = 63
                    account.stats(p .. "H4CNF_BS_ABIL").int32 = 63
                    account.stats(p .. "H4CNF_APPROACH").int32 = -1
                    account.stats(p .. "H4_PLAYTHROUGH_STATUS").int32 = 10
                end
                if script and script.locals then pcall(function() script.locals("heist_island_planning", 1570).int32 = 2 end) end
                safe_toast("All POI Unlocked!")
            end)
            add_button("Remove Cooldown", function()
                local p = "MP" .. (script and script.globals and script.globals(1574927).int32 or 0) .. "_"
                account.stats(p .. "H4_TARGET_POSIX").int32 = 1659643454
                account.stats(p .. "H4_COOLDOWN").int32 = 0
                safe_toast("Cooldown Removed!")
            end)
            add_button("Reload Planning", function()
                if script and script.locals then pcall(function() script.locals("heist_island_planning", 1570).int32 = 2 end) end
                safe_toast("Planning Reloaded!")
            end)

            add_section("Target")
            add_button("Panther Statue", function()
                local p = "MP" .. (script and script.globals and script.globals(1574927).int32 or 0) .. "_"
                account.stats(p .. "H4CNF_TARGET").int32 = 5
                safe_toast("Panther Set!")
            end)
            add_button("Pink Diamond", function()
                local p = "MP" .. (script and script.globals and script.globals(1574927).int32 or 0) .. "_"
                account.stats(p .. "H4CNF_TARGET").int32 = 3
                safe_toast("Diamond Set!")
