    -- ===== CONSTRUCTOR STATE =====

    local constructor = {
        -- Mode flags
        placement_mode = false,
        edit_mode = false,

        -- Current selection
        selected_object = nil,
        selected_index = 1,

        -- Object registry
        objects = {},
        object_counter = 0,

        -- UI state
        category_collapsed = {},

        -- Camera
        placement_camera = nil,
        camera_distance = 3.0,
        camera_sensitivity = 0.3,
        camera_fov = 70.0,

        -- Player state
        original_ped_coords = nil,
        original_ped_heading = nil,
        player_frozen = false,
        player_hidden = false,

        -- Movement/rotation
        movement_speed = 0.05,  -- max speed (0-1 scale shown as 0-100)
        rotation_speed = 3.0,   -- max rotation speed (degrees, shown as 0-100)
        fine_mode = false,  -- Hold Shift for fine adjustments
        -- Acceleration velocities (per-key, reset to 0 when key released)
        _vel = {w=0, s=0, a=0, d=0, up=0, dn=0,
                q=0, e=0, aup=0, adn=0, alt=0, art=0},
        axis_lock = {x=false, y=false, z=false},
        snap_enabled = false,
        snap_grid = 1.0,

        -- Undo/redo
        undo_stack = {},
        redo_stack = {},
        max_undo = 50,

        -- JSON
        save_name = "",
        save_input_focused = false,  -- Track if text input is focused
        constructs_dir = "",  -- Will be set dynamically at runtime
        load_at_player = false,  -- If true, load constructs in front of player instead of original position

        -- Edit attached mode (O key toggle)
        edit_attached_mode = false,  -- When true, moving an attached prop updates its offset
        saved_constructs = {},

        -- UI state
        ui_tab = 1,  -- 1=Objects, 2=Properties, 3=Save/Load, 4=Settings
        objects_scroll = 0,
        props_scroll = 0,
        files_scroll = 0,
        search_query = "",

        -- Spawn props list
        spawn_search = "",
        spawn_scroll = 0,
        selected_prop_hash = "",
    }

    -- Initialize constructs directory dynamically (same as vehicle save)
    do
        local base = (paths and paths.script) or ".\\"
        if not base:match("[\\/]$") then base = base .. "\\" end
        constructor.constructs_dir = base .. "Kyron\\constructs\\"

        -- Ensure directory exists
        if dirs and dirs.create then
            pcall(dirs.create, base .. "Kyron\\")
            pcall(dirs.create, constructor.constructs_dir)
        end
    end

    -- Common prop models for quick spawning
    -- CONSTRUCTOR_PROPS - will be populated after PROPS_DATA is defined
    local CONSTRUCTOR_PROPS = {}

    -- ===== UTILITY FUNCTIONS =====

    local function vec3_add(a, b)
        return {x = a.x + b.x, y = a.y + b.y, z = a.z + b.z}
    end

    local function vec3_sub(a, b)
        return {x = a.x - b.x, y = a.y - b.y, z = a.z - b.z}
    end

    local function vec3_mul(v, scalar)
        return {x = v.x * scalar, y = v.y * scalar, z = v.z * scalar}
    end

    local function vec3_length(v)
        return math.sqrt(v.x * v.x + v.y * v.y + v.z * v.z)
    end

    local function vec3_normalize(v)
        local len = vec3_length(v)
        if len > 0 then
            return {x = v.x / len, y = v.y / len, z = v.z / len}
        end
        return {x = 0, y = 0, z = 0}
    end

    -- ===== CAMERA FUNCTIONS =====

    local function get_camera_vectors()
        if not constructor.placement_camera then
            return {x=0,y=1,z=0}, {x=1,y=0,z=0}, {x=0,y=0,z=1}
        end

        local cam_rot = invoker.call(0x7D304C1C955E3E12, constructor.placement_camera, 2).scr_vec3 -- GET_CAM_ROT
        local pitch = cam_rot.x * (math.pi / 180.0)
        local yaw = cam_rot.z * (math.pi / 180.0)

        local forward = {
            x = -math.sin(yaw) * math.cos(pitch),
            y = math.cos(yaw) * math.cos(pitch),
            z = math.sin(pitch)
        }

        local right = {
            x = math.cos(yaw),
            y = math.sin(yaw),
            z = 0
        }

        local up = {x = 0, y = 0, z = 1}

        return forward, right, up
    end

    local function create_placement_camera()
        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int  -- GET_PLAYER_PED
        local ped_coords = invoker.call(0x3FEF770D40960D5A, player_ped, false).scr_vec3  -- GET_ENTITY_COORDS

        constructor.placement_camera = invoker.call(0x40C23491CE83059B,
            "DEFAULT_SCRIPTED_CAMERA",
            ped_coords.x, ped_coords.y + 5.0, ped_coords.z + 3.0,
            -15.0, 0.0, 0.0,
            constructor.camera_fov, false, 0
        ).int  -- CREATE_CAM_WITH_PARAMS

        invoker.call(0x026FB97D0A425F84, constructor.placement_camera, true)  -- SET_CAM_ACTIVE
        invoker.call(0x07E5B515DB0636FC, true, false, 1000, true, false, 0)  -- RENDER_SCRIPT_CAMS
    end

    local function destroy_placement_camera()
        if constructor.placement_camera then
            invoker.call(0x07E5B515DB0636FC, false, false, 1000, true, false, 0)  -- RENDER_SCRIPT_CAMS
            invoker.call(0x865908C81A2C22E9, constructor.placement_camera, true)  -- DESTROY_CAM
            constructor.placement_camera = nil
        end
    end

    local function update_camera_with_input()
        if not constructor.placement_camera then return end

        local forward, right, up = get_camera_vectors()
        local cam_coords = invoker.call(0xBAC038F7459AE5AE, constructor.placement_camera).scr_vec3  -- GET_CAM_COORD
        local cam_rot = invoker.call(0x7D304C1C955E3E12, constructor.placement_camera, 2).scr_vec3  -- GET_CAM_ROT

        local sensitivity = constructor.camera_sensitivity
        local new_coords = {x = cam_coords.x, y = cam_coords.y, z = cam_coords.z}

        -- WASD movement
        if invoker.call(0xE2587F8BA56E4143, 2, 32).bool then  -- W
            new_coords.x = new_coords.x + forward.x * sensitivity
            new_coords.y = new_coords.y + forward.y * sensitivity
            new_coords.z = new_coords.z + forward.z * sensitivity
        end
        if invoker.call(0xE2587F8BA56E4143, 2, 33).bool then  -- S
            new_coords.x = new_coords.x - forward.x * sensitivity
            new_coords.y = new_coords.y - forward.y * sensitivity
            new_coords.z = new_coords.z - forward.z * sensitivity
        end
        if invoker.call(0xE2587F8BA56E4143, 2, 34).bool then  -- A
            new_coords.x = new_coords.x - right.x * sensitivity
            new_coords.y = new_coords.y - right.y * sensitivity
        end
        if invoker.call(0xE2587F8BA56E4143, 2, 35).bool then  -- D
            new_coords.x = new_coords.x + right.x * sensitivity
            new_coords.y = new_coords.y + right.y * sensitivity
        end

        -- Space/Ctrl for up/down
        if invoker.call(0xE2587F8BA56E4143, 2, 22).bool then  -- Space
            new_coords.z = new_coords.z + (up.z * sensitivity)
        end
        if invoker.call(0xE2587F8BA56E4143, 2, 36).bool then  -- Ctrl
            new_coords.z = new_coords.z - (up.z * sensitivity)
        end

        invoker.call(0x4D41783FB745E42E, constructor.placement_camera, new_coords.x, new_coords.y, new_coords.z)  -- SET_CAM_COORD

        -- Mouse rotation
        local move_lr = invoker.call(0xEC3C9B8D5327B563, 2, 1).float  -- GET_CONTROL_NORMAL (mouse X)
        local move_ud = invoker.call(0xEC3C9B8D5327B563, 2, 2).float  -- GET_CONTROL_NORMAL (mouse Y)

        local new_rot = {x = cam_rot.x, y = cam_rot.y, z = cam_rot.z}
        if move_ud ~= 0 then
            new_rot.x = new_rot.x - (move_ud * 5)
        end
        if move_lr ~= 0 then
            new_rot.z = new_rot.z - (move_lr * 5)
        end

        invoker.call(0x85973643155D0B07, constructor.placement_camera, new_rot.x, new_rot.y, new_rot.z, 2)  -- SET_CAM_ROT

        -- Scroll wheel FOV
        if invoker.call(0x580417101DDB492F, 2, 241).bool then  -- Scroll up
            constructor.camera_fov = math.max(10, constructor.camera_fov - 5)
            invoker.call(0xB13C14F66A00D047, constructor.placement_camera, constructor.camera_fov)  -- SET_CAM_FOV
        elseif invoker.call(0x580417101DDB492F, 2, 242).bool then  -- Scroll down
            constructor.camera_fov = math.min(120, constructor.camera_fov + 5)
            invoker.call(0xB13C14F66A00D047, constructor.placement_camera, constructor.camera_fov)  -- SET_CAM_FOV
        end
    end

    -- ===== OBJECT MANAGEMENT =====

    local function create_constructor_object(hash_code, position, skip_ground_placement)
        local hash = hash_code  -- Use hash directly (no need for GET_HASH_KEY)

        -- Request model using Lexis v10 blocking API (works without host/script host)
        if not request.model(hash) then
            return nil  -- Model didn't load
        end

        -- ── Create object via Lexis v10 spawn.object() (no host/script host required) ──
        -- spawn.object(model, coords, register_as_network_object=true, script_host_object=false)
        -- Setting script_host_object=false is the key fix: the old CREATE_OBJECT call used
        -- bScriptHostObj=true which blocked spawning for non-hosts in public lobbies.
        local obj_handle = nil
        if spawn and type(spawn.object) == "function" then
            local ok, r = pcall(spawn.object, hash, scr_vec3(position.x, position.y, position.z), true, false)
            obj_handle = (ok and r and r ~= 0) and r or nil
        end

        -- Fallback: raw native with bScriptHostObj=false + manual net registration
        if not obj_handle then
            local raw = invoker.call(0x509D5878EB39E842, hash, position.x, position.y, position.z, true, false, false)  -- CREATE_OBJECT (bNetworkObject=true, bScriptHostObj=false)
            obj_handle = (raw and raw.int and raw.int ~= 0) and raw.int or nil
            if obj_handle then
                -- Manual network registration for fallback path
                local is_net = invoker.call(0xC7827959479DCC78, obj_handle)  -- NETWORK_GET_ENTITY_IS_NETWORKED
                if not is_net or not is_net.bool then
                    invoker.call(0x06FAACD625D80CAA, obj_handle)  -- NETWORK_REGISTER_ENTITY_AS_NETWORKED
                    local t0 = os.clock()
                    while os.clock() - t0 < 1.0 do
                        local chk = invoker.call(0xC7827959479DCC78, obj_handle)
                        if chk and chk.bool then break end
                        util.yield(0)
                    end
                end
                local my_id = players.me and players.me().id or invoker.call(0x4F8644AF03D0E0D6).int
                if game and game.update_net_obj_owner then
                    pcall(game.update_net_obj_owner, obj_handle, my_id)
                end
                local netId_res = invoker.call(0xA11700682F3AD45C, obj_handle)  -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
                if netId_res and netId_res.int and netId_res.int ~= 0 then
                    invoker.call(0xE05E81A888FA63C8, netId_res.int, true)   -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
                    invoker.call(0x299EEB23175895FC, netId_res.int, false)  -- SET_NETWORK_ID_CAN_MIGRATE (keep ownership)
                end
                invoker.call(0xF1CA12B18AEF5298, obj_handle, false)  -- NETWORK_SET_ENTITY_ONLY_EXISTS_FOR_PARTICIPANTS
            end
        end
        -- ── END SPAWN ──

        if not obj_handle or obj_handle == 0 then
            invoker.call(0xE532F5D78798DAAB, hash)  -- SET_MODEL_AS_NO_LONGER_NEEDED
            return nil
        end

        -- Place on ground properly (like working prop spawner) - UNLESS loading from file
        if not skip_ground_placement then
            invoker.call(0xAD738C3085FE7E11, obj_handle, true, true)  -- PLACE_OBJECT_ON_GROUND_PROPERLY
        end

        constructor.object_counter = constructor.object_counter + 1

        local obj = {
            id = constructor.object_counter,
            handle = obj_handle,
            model = tostring(hash),  -- Store hash as string for display
            model_hash = hash,
            position = {x = position.x, y = position.y, z = position.z},
            rotation = {x = 0, y = 0, z = 0},
            offset = {x = 0, y = 0, z = 0},
            parent = nil,
            children = {},
            is_attached = false,
            is_frozen = false,
            options = {
                has_collision = true,
                has_gravity = true,
                is_visible = true,
            }
        }

        table.insert(constructor.objects, obj)
        invoker.call(0xE532F5D78798DAAB, hash)  -- SET_MODEL_AS_NO_LONGER_NEEDED

        return obj
    end

    local function delete_constructor_object(obj)
        if not obj then return end

        -- Delete children first
        for _, child in ipairs(obj.children) do
            delete_constructor_object(child)
        end

        -- Delete entity safely using Lexis v10 API (no host required)
        pcall(function()
            if obj.handle and obj.handle ~= 0 and invoker.call(0x7239B21A38F536BA, obj.handle).bool then  -- DOES_ENTITY_EXIST
                -- Lexis v10: force control before any entity manipulation
                request.control(obj.handle, true)
                -- Detach first
                invoker.call(0xA7A41F2AD7F12C5C, obj.handle, true, true)  -- DETACH_ENTITY
                -- Freeze position
                invoker.call(0x428CA6DBD1094446, obj.handle, true)  -- FREEZE_ENTITY_POSITION
                -- Set collision off
                invoker.call(0x1A9205C1B9EE827F, obj.handle, false, false)  -- SET_ENTITY_COLLISION
                -- Make invisible
                invoker.call(0xEA1C610A04DB6BBB, obj.handle, false, false)  -- SET_ENTITY_VISIBLE
                util.yield(10)  -- Wait before deleting
                -- Lexis v10: use game.network_unregister_entity for clean network removal (no host required)
                if game and game.network_unregister_entity then
                    pcall(game.network_unregister_entity, obj.handle, false)
                else
                    -- Fallback: mark as no longer needed
                    invoker.call(0xE532F5D78798DAAB, obj.handle)  -- SET_ENTITY_AS_NO_LONGER_NEEDED
                end
            end
        end)

        -- Remove from parent's children
        if obj.parent then
            for i, child in ipairs(obj.parent.children) do
                if child.id == obj.id then
                    table.remove(obj.parent.children, i)
                    break
                end
            end
        end

        -- Remove from objects list
        for i, o in ipairs(constructor.objects) do
            if o.id == obj.id then
                table.remove(constructor.objects, i)
                break
            end
        end
    end

    local function update_object_position(obj, new_pos)
        obj.position = {x = new_pos.x, y = new_pos.y, z = new_pos.z}
        if obj.handle and invoker.call(0x7239B21A38F536BA, obj.handle).bool then
            -- Lexis v10: request control so we can move without being host
            request.control(obj.handle, true)
            invoker.call(0x06843DA7060A026B, obj.handle, new_pos.x, new_pos.y, new_pos.z, false, false, false, false)  -- SET_ENTITY_COORDS
        end
    end

    local function update_object_rotation(obj, new_rot)
        obj.rotation = {x = new_rot.x, y = new_rot.y, z = new_rot.z}
        if obj.handle and invoker.call(0x7239B21A38F536BA, obj.handle).bool then
            -- Lexis v10: request control so we can rotate without being host
            request.control(obj.handle, true)
            invoker.call(0x8524A8B0171D5E07, obj.handle, new_rot.x, new_rot.y, new_rot.z, 2, true)  -- SET_ENTITY_ROTATION
        end
    end

    local function attach_object(child, parent)
        if not child or not parent or child.id == parent.id then return end

        child.parent = parent
        child.is_attached = true
        table.insert(parent.children, child)

        if child.handle and parent.handle then
            -- Lexis v10: force control of both entities before attaching (no host/script host required)
            request.control(child.handle, true)
            request.control(parent.handle, true)

            -- Get world positions
            local parent_pos = invoker.call(0x3FEF770D40960D5A, parent.handle, false).scr_vec3
            local child_pos = invoker.call(0x3FEF770D40960D5A, child.handle, false).scr_vec3
            local parent_rot = invoker.call(0xAFBD61CC738D9EB9, parent.handle, 2).scr_vec3  -- GET_ENTITY_ROTATION
            local child_rot = invoker.call(0xAFBD61CC738D9EB9, child.handle, 2).scr_vec3  -- GET_ENTITY_ROTATION

            -- Calculate world offset
            local world_dx = child_pos.x - parent_pos.x
            local world_dy = child_pos.y - parent_pos.y
            local world_dz = child_pos.z - parent_pos.z

            -- Convert to parent's local space using rotation matrix
            local heading_rad = math.rad(-parent_rot.z)  -- Negative for inverse rotation
            local cos_h = math.cos(heading_rad)
            local sin_h = math.sin(heading_rad)

            -- Rotate world offset to local space (2D rotation around Z axis)
            local local_x = world_dx * cos_h - world_dy * sin_h
            local local_y = world_dx * sin_h + world_dy * cos_h
            local local_z = world_dz

            -- Calculate relative rotation (child rotation relative to parent)
            local rel_pitch = child_rot.x - parent_rot.x
            local rel_roll = child_rot.y - parent_rot.y
            local rel_yaw = child_rot.z - parent_rot.z

            -- Store local offsets and rotation for saving
            child.offset = {x = local_x, y = local_y, z = local_z}
            child.rot_offset = {x = rel_pitch, y = rel_roll, z = rel_yaw}

            -- ATTACH_ENTITY_TO_ENTITY - EXACT same parameters as vehicle attachment
            invoker.call(0x6B9BBD38AB0796DF, child.handle, parent.handle, 0,
                local_x, local_y, local_z,
                rel_pitch, rel_roll, rel_yaw,
                false, true, false, false, 2, true)  -- fixedRot=TRUE like vehicle attachment
        end
    end

    -- Re-attach with updated offset (for editing attached props)
    local function reattach_object(child)
        if not child or not child.is_attached or not child.parent then return end
        if not child.handle or not child.parent.handle then return end

        -- Lexis v10: force control of both entities before re-attaching (no host/script host required)
        request.control(child.handle, true)
        request.control(child.parent.handle, true)

        -- Use stored offset and rot_offset
        local off = child.offset or {x=0, y=0, z=0}
        local rot_off = child.rot_offset or {x=0, y=0, z=0}

        invoker.call(0x6B9BBD38AB0796DF, child.handle, child.parent.handle, 0,
            off.x, off.y, off.z,
            rot_off.x, rot_off.y, rot_off.z,
            false, false, false, false, 2, true)
    end

    local function detach_object(obj)
        if not obj or not obj.is_attached then return end

        if obj.handle and invoker.call(0x7239B21A38F536BA, obj.handle).bool then
            -- Lexis v10: force control before detaching (no host/script host required)
            request.control(obj.handle, true)
            invoker.call(0x961AC54BF0613F5D, obj.handle, true, true)  -- DETACH_ENTITY
        end

        if obj.parent then
            for i, child in ipairs(obj.parent.children) do
                if child.id == obj.id then
                    table.remove(obj.parent.children, i)
                    break
                end
            end
        end

        obj.parent = nil
        obj.is_attached = false
    end

    -- ===== PLACEMENT MODE =====

    local function enter_placement_mode()
        if constructor.placement_mode then return end
        if not constructor.selected_object then
            safe_toast("Select an object first!")
            return
        end

        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int

        -- Clear tasks to stop running animation (like noclip does)
        invoker.call(0xE1EF3C1216AFF2CD, player_ped)  -- CLEAR_PED_TASKS_IMMEDIATELY

        -- Disable collision (like noclip)
        invoker.call(0x1A9205C1B9EE827F, player_ped, false, false)  -- SET_ENTITY_COLLISION

        -- Set invincible (like noclip)
        invoker.call(0x3882114BDE571AD4, player_ped, true)  -- SET_ENTITY_INVINCIBLE

        -- Disable ragdoll (like noclip)
        invoker.call(0xB128377056A54E2A, player_ped, false)  -- SET_PED_CAN_RAGDOLL

        -- Freeze player
        invoker.call(0x428CA6DBD1094446, player_ped, true)  -- FREEZE_ENTITY_POSITION

        -- Keep player visible (don't hide)
        invoker.call(0xEA1C610A04DB6BBB, player_ped, true, false)  -- SET_ENTITY_VISIBLE

        -- Store initial object position
        if constructor.selected_object.handle then
            local obj_pos = invoker.call(0x3FEF770D40960D5A, constructor.selected_object.handle, true).scr_vec3
            constructor.placement_obj_x = obj_pos.x
            constructor.placement_obj_y = obj_pos.y
            constructor.placement_obj_z = obj_pos.z
        end

        -- Create orbit camera around the prop (use correct native hash!)
        local cam_distance = 8.0
        local cam_x = constructor.placement_obj_x + cam_distance
        local cam_y = constructor.placement_obj_y
        local cam_z = constructor.placement_obj_z + 3.0

        -- CREATE_CAM_WITH_PARAMS - correct hash is 0xB51194800B257161
        constructor.placement_camera = invoker.call(0xB51194800B257161,
            "DEFAULT_SCRIPTED_CAMERA",
            cam_x, cam_y, cam_z,
            0.0, 0.0, 0.0,
            50.0, false, 0
        ).int

        if constructor.placement_camera and constructor.placement_camera ~= 0 then
            -- Point camera at prop
            invoker.call(0xF75497BB865F0803, constructor.placement_camera, constructor.placement_obj_x, constructor.placement_obj_y, constructor.placement_obj_z)  -- POINT_CAM_AT_COORD
            invoker.call(0x026FB97D0A425F84, constructor.placement_camera, true)  -- SET_CAM_ACTIVE
            invoker.call(0x07E5B515DB0636FC, true, false, 0, true, false, 0)  -- RENDER_SCRIPT_CAMS
        end

        -- Initialize camera orbit angle
        constructor.cam_angle = 0.0
        constructor.cam_pitch = 10.0
        constructor.cam_distance = 20.0  -- Default zoom distance (was 8.0)

        -- Initialize free look (reset when entering placement mode)
        -- Start rotated to the right so camera is in correct position
        constructor.cam_free_yaw = 270
        constructor.cam_free_pitch = 0
        constructor.free_looking = false

        constructor.placement_mode = true
        safe_toast("Placement Mode: ON (WASD=Move, Mouse=Orbit)")
    end

    local function exit_placement_mode()
        if not constructor.placement_mode then return end

        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int

        -- Destroy camera
        if constructor.placement_camera then
            invoker.call(0x07E5B515DB0636FC, false, false, 0, true, false, 0)  -- RENDER_SCRIPT_CAMS off
            invoker.call(0x865908C81A2C22E9, constructor.placement_camera, true)  -- DESTROY_CAM
            constructor.placement_camera = nil
        end

        -- Restore collision (like noclip exit)
        invoker.call(0x1A9205C1B9EE827F, player_ped, true, true)  -- SET_ENTITY_COLLISION

        -- Restore ragdoll (like noclip exit)
        invoker.call(0xB128377056A54E2A, player_ped, true)  -- SET_PED_CAN_RAGDOLL

        -- Remove invincibility (like noclip exit)
        invoker.call(0x3882114BDE571AD4, player_ped, false)  -- SET_ENTITY_INVINCIBLE

        -- Unfreeze player
        invoker.call(0x428CA6DBD1094446, player_ped, false)  -- FREEZE_ENTITY_POSITION

        -- Make visible
        invoker.call(0xEA1C610A04DB6BBB, player_ped, true, false)  -- SET_ENTITY_VISIBLE

        constructor.placement_mode = false
        safe_toast("Placement Mode: OFF")
        -- Phone input (control 27) auto-resumes next frame since DISABLE_CONTROL_ACTION
        -- only suppresses for the frame it is called — no script restart needed.
    end

    local function position_selected_object_at_camera()
        if not constructor.selected_object or not constructor.placement_camera then return end

        local forward, right, up = get_camera_vectors()
        local cam_pos = invoker.call(0xBAC038F7459AE5AE, constructor.placement_camera).scr_vec3

        local distance = constructor.camera_distance
        local new_pos = {
            x = cam_pos.x + (forward.x * distance),
            y = cam_pos.y + (forward.y * distance),
            z = cam_pos.z + (forward.z * distance)
        }

        update_object_position(constructor.selected_object, new_pos)
    end

    -- ===== PLACEMENT MODE TICK LOOP =====

    local function placement_mode_tick()
        if not constructor.placement_mode then return end
        if not constructor.selected_object then
            exit_placement_mode()
            return
        end

        -- Zero player velocity every frame to prevent physics (like noclip)
        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int
        invoker.call(0x1C99BB7B6E96D16F, player_ped, 0.0, 0.0, 0.0)  -- SET_ENTITY_VELOCITY

        -- If in vehicle, disable vehicle controls (including radio wheel and horn)
        local in_veh = invoker.call(0x9A9112A0FE9A4713, player_ped, false) -- GET_VEHICLE_PED_IS_IN
        if in_veh and (in_veh.int or in_veh.ent or 0) ~= 0 then
            local veh_handle = in_veh.int or in_veh.ent
            invoker.call(0x1C99BB7B6E96D16F, veh_handle, 0.0, 0.0, 0.0) -- SET_ENTITY_VELOCITY (stop vehicle)
            invoker.call(0xFE99B66D079CF6BC, 0, 71, true) -- DISABLE_CONTROL_ACTION: VehicleAccelerate
            invoker.call(0xFE99B66D079CF6BC, 0, 72, true) -- DISABLE_CONTROL_ACTION: VehicleBrake
            invoker.call(0xFE99B66D079CF6BC, 0, 59, true) -- DISABLE_CONTROL_ACTION: VehicleMoveLeftRight
            invoker.call(0xFE99B66D079CF6BC, 0, 60, true) -- DISABLE_CONTROL_ACTION: VehicleMoveUpDown
            invoker.call(0xFE99B66D079CF6BC, 0, 86, true) -- DISABLE_CONTROL_ACTION: VehicleHorn
            invoker.call(0xFE99B66D079CF6BC, 0, 85, true) -- DISABLE_CONTROL_ACTION: VehicleRadioWheel (NextRadio)
            invoker.call(0xFE99B66D079CF6BC, 0, 84, true) -- DISABLE_CONTROL_ACTION: PrevRadio
            invoker.call(0xFE99B66D079CF6BC, 0, 81, true) -- DISABLE_CONTROL_ACTION: VehicleRadioWheelUD
            invoker.call(0xFE99B66D079CF6BC, 0, 82, true) -- DISABLE_CONTROL_ACTION: VehicleRadioWheelLR
        end

        -- Disable phone input this frame (control 27 = INPUT_PHONE).
        -- Per-frame disables auto-expire when placement mode ends — no script kill needed.
        invoker.call(0xFE99B66D079CF6BC, 0, 27, true)  -- DISABLE_CONTROL_ACTION: INPUT_PHONE

        -- Suppress weapon wheel (like when menu is open)
        invoker.call(0x0AFC4AF510774B47)  -- HUD_SUPPRESS_WEAPON_WHEEL_RESULTS_THIS_FRAME

        -- Camera controls:
        -- Mouse movement = orbit camera around object (always active)
        -- Scroll wheel   = zoom in/out
        -- Middle mouse   = drag object in screen space
        if constructor.placement_camera then
            local move_lr = invoker.call(0xEC3C9B8D5327B563, 2, 1).float  -- GET_CONTROL_NORMAL (mouse X)
            local move_ud = invoker.call(0xEC3C9B8D5327B563, 2, 2).float  -- GET_CONTROL_NORMAL (mouse Y)

            -- Mouse always orbits around the object (no button held needed)
            local mid_mouse = invoker.call(0xF3A21BCD95725A4A, 0, 26).bool  -- middle mouse
            if not mid_mouse then
                -- Only orbit when NOT dragging the object with middle mouse
                if move_lr ~= 0 then
                    constructor.cam_angle = constructor.cam_angle - (move_lr * 5.0)
                end
                if move_ud ~= 0 then
                    constructor.cam_pitch = math.max(-80, math.min(80, constructor.cam_pitch + (move_ud * 5.0)))
                end
            end

            -- Calculate camera position orbiting the object
            local angle_rad = math.rad(constructor.cam_angle)
            local pitch_rad = math.rad(constructor.cam_pitch)

            local cam_x = constructor.placement_obj_x + math.cos(angle_rad) * constructor.cam_distance * math.cos(pitch_rad)
            local cam_y = constructor.placement_obj_y + math.sin(angle_rad) * constructor.cam_distance * math.cos(pitch_rad)
            local cam_z = constructor.placement_obj_z + math.sin(pitch_rad) * constructor.cam_distance + 2.0

            invoker.call(0x4D41783FB745E42E, constructor.placement_camera, cam_x, cam_y, cam_z)  -- SET_CAM_COORD
            invoker.call(0xF75497BB865F0803, constructor.placement_camera, constructor.placement_obj_x, constructor.placement_obj_y, constructor.placement_obj_z)  -- POINT_CAM_AT_COORD

            -- Scroll wheel: zoom in/out
            if invoker.call(0xE2587F8CBBD87B1D, 2, 241).bool then  -- Scroll Up = zoom in
                constructor.cam_distance = math.max(2.0, constructor.cam_distance - 0.5)
            end
            if invoker.call(0xE2587F8CBBD87B1D, 2, 242).bool then  -- Scroll Down = zoom out
                constructor.cam_distance = math.min(100.0, constructor.cam_distance + 0.5)
            end

            -- MIDDLE MOUSE DRAG: move object in screen-relative space
            if mid_mouse and (move_lr ~= 0 or move_ud ~= 0) then
                local cam_r = invoker.call(0x7D304C1C955E3E12, constructor.placement_camera, 2).scr_vec3
                if cam_r then
                    local sensitivity = constructor.cam_distance * 0.015
                    local yaw = math.rad(cam_r.z)
                    local dx = -math.cos(yaw) * move_lr * sensitivity
                    local dy = -math.sin(yaw) * move_lr * sensitivity
                    local dz = -move_ud * sensitivity
                    constructor.placement_obj_x = constructor.placement_obj_x + dx
                    constructor.placement_obj_y = constructor.placement_obj_y + dy
                    constructor.placement_obj_z = constructor.placement_obj_z + dz
                    update_object_position(constructor.selected_object, {
                        x = constructor.placement_obj_x,
                        y = constructor.placement_obj_y,
                        z = constructor.placement_obj_z
                    })
                end
            end
        end

        -- Get camera rotation (for movement direction)
        local cam_rot
        if constructor.placement_camera then
            cam_rot = invoker.call(0x7D304C1C955E3E12, constructor.placement_camera, 2).scr_vec3  -- GET_CAM_ROT
        else
            cam_rot = invoker.call(0x837765A25378F0BB, 0).scr_vec3  -- GET_GAMEPLAY_CAM_ROT
        end

        if cam_rot then
            local pitch = math.rad(cam_rot.x)
            local heading = math.rad(cam_rot.z)

            -- Check input (like noclip)
            local w_down = invoker.call(0xF3A21BCD95725A4A, 0, 32).bool  -- W
            local s_down = invoker.call(0xF3A21BCD95725A4A, 0, 33).bool  -- S
            local a_down = invoker.call(0xF3A21BCD95725A4A, 0, 34).bool  -- A
            local d_down = invoker.call(0xF3A21BCD95725A4A, 0, 35).bool  -- D
            local space_down = invoker.call(0xF3A21BCD95725A4A, 0, 22).bool  -- Space
            local ctrl_down = invoker.call(0xF3A21BCD95725A4A, 0, 36).bool  -- Ctrl

            -- Acceleration ramp: each key builds velocity 0→max while held, resets when released
            local max_spd = constructor.movement_speed  -- 0.01–1.0
            local accel   = max_spd * 0.06             -- reaches max in ~17 frames (~0.5s at 30fps)
            local v = constructor.accel_vel or {w=0,s=0,a=0,d=0,up=0,dn=0}
            constructor.accel_vel = v

            -- Check if editing attached prop (O key toggle)
            if input and input.key and input.key(0x4F).just_pressed then  -- O key
                constructor.edit_attached_mode = not constructor.edit_attached_mode
                if constructor.edit_attached_mode then
                    safe_toast("Edit Attached: ON - Move offset relative to parent")
                else
                    safe_toast("Edit Attached: OFF - Normal movement")
                end
            end

            -- Check if this prop is attached and we're in edit mode
            local is_editing_attached = constructor.edit_attached_mode and constructor.selected_object.is_attached

            if is_editing_attached then
                -- Move the OFFSET instead of world position
                local obj = constructor.selected_object
                obj.offset = obj.offset or {x=0, y=0, z=0}

                v.w  = w_down  and math.min(v.w  + accel, max_spd) or 0
                v.s  = s_down  and math.min(v.s  + accel, max_spd) or 0
                v.a  = a_down  and math.min(v.a  + accel, max_spd) or 0
                v.d  = d_down  and math.min(v.d  + accel, max_spd) or 0
                v.up = space_down and math.min(v.up + accel, max_spd) or 0
                v.dn = ctrl_down  and math.min(v.dn + accel, max_spd) or 0

                if w_down  then obj.offset.y = obj.offset.y + v.w  end
                if s_down  then obj.offset.y = obj.offset.y - v.s  end
                if a_down  then obj.offset.x = obj.offset.x - v.a  end
                if d_down  then obj.offset.x = obj.offset.x + v.d  end
                if space_down then obj.offset.z = obj.offset.z + v.up end
                if ctrl_down  then obj.offset.z = obj.offset.z - v.dn end

                -- Re-attach with new offset
                reattach_object(obj)
            else
                -- Normal movement - move object in world space
                v.w  = w_down  and math.min(v.w  + accel, max_spd) or 0
                v.s  = s_down  and math.min(v.s  + accel, max_spd) or 0
                v.a  = a_down  and math.min(v.a  + accel, max_spd) or 0
                v.d  = d_down  and math.min(v.d  + accel, max_spd) or 0
                v.up = space_down and math.min(v.up + accel, max_spd) or 0
                v.dn = ctrl_down  and math.min(v.dn + accel, max_spd) or 0

                if w_down then
                    constructor.placement_obj_x = constructor.placement_obj_x - math.sin(heading) * math.cos(pitch) * v.w
                    constructor.placement_obj_y = constructor.placement_obj_y + math.cos(heading) * math.cos(pitch) * v.w
                    constructor.placement_obj_z = constructor.placement_obj_z + math.sin(pitch) * v.w
                end
                if s_down then
                    constructor.placement_obj_x = constructor.placement_obj_x + math.sin(heading) * math.cos(pitch) * v.s
                    constructor.placement_obj_y = constructor.placement_obj_y - math.cos(heading) * math.cos(pitch) * v.s
                    constructor.placement_obj_z = constructor.placement_obj_z - math.sin(pitch) * v.s
                end
                if a_down then
                    constructor.placement_obj_x = constructor.placement_obj_x - math.cos(heading) * v.a
                    constructor.placement_obj_y = constructor.placement_obj_y - math.sin(heading) * v.a
                end
                if d_down then
                    constructor.placement_obj_x = constructor.placement_obj_x + math.cos(heading) * v.d
                    constructor.placement_obj_y = constructor.placement_obj_y + math.sin(heading) * v.d
                end
                if space_down then
                    constructor.placement_obj_z = constructor.placement_obj_z + v.up
                end
                if ctrl_down then
                    constructor.placement_obj_z = constructor.placement_obj_z - v.dn
                end

                -- Update object position
                local new_pos = {
                    x = constructor.placement_obj_x,
                    y = constructor.placement_obj_y,
                    z = constructor.placement_obj_z
                }
                update_object_position(constructor.selected_object, new_pos)
            end

            -- Rotation controls with acceleration (Q/E for Z axis)
            local max_rot  = constructor.rotation_speed   -- degrees, 1–45
            local rot_accel = max_rot * 0.06
            local rv = constructor.accel_rot or {q=0,e=0,aup=0,adn=0,alt=0,art=0}
            constructor.accel_rot = rv

            local q_dn  = invoker.call(0xE2587F8CBBD87B1D, 0, 44).bool   -- Q
            local e_dn  = invoker.call(0xE2587F8CBBD87B1D, 0, 38).bool   -- E
            rv.q  = q_dn  and math.min(rv.q  + rot_accel, max_rot) or 0
            rv.e  = e_dn  and math.min(rv.e  + rot_accel, max_rot) or 0

            if q_dn then
                if is_editing_attached then
                    local obj = constructor.selected_object
                    obj.rot_offset = obj.rot_offset or {x=0, y=0, z=0}
                    obj.rot_offset.z = obj.rot_offset.z + rv.q
                    reattach_object(obj)
                else
                    local new_rot = {x = constructor.selected_object.rotation.x, y = constructor.selected_object.rotation.y, z = constructor.selected_object.rotation.z + rv.q}
                    update_object_rotation(constructor.selected_object, new_rot)
                end
            end
            if e_dn then
                if is_editing_attached then
                    local obj = constructor.selected_object
                    obj.rot_offset = obj.rot_offset or {x=0, y=0, z=0}
                    obj.rot_offset.z = obj.rot_offset.z - rv.e
                    reattach_object(obj)
                else
                    local new_rot = {x = constructor.selected_object.rotation.x, y = constructor.selected_object.rotation.y, z = constructor.selected_object.rotation.z - rv.e}
                    update_object_rotation(constructor.selected_object, new_rot)
                end
            end

            -- Arrow key rotation (Roll Y, Pitch X) with acceleration
            local arrow_max   = max_rot * 0.5
            local arrow_accel = arrow_max * 0.06

            local aup_dn = invoker.call(0xE2587F8CBBD87B1D, 0, 172).bool  -- Up Arrow
            local adn_dn = invoker.call(0xE2587F8CBBD87B1D, 0, 173).bool  -- Down Arrow
            local alt_dn = invoker.call(0xE2587F8CBBD87B1D, 0, 174).bool  -- Left Arrow
            local art_dn = invoker.call(0xE2587F8CBBD87B1D, 0, 175).bool  -- Right Arrow
            rv.aup = aup_dn and math.min(rv.aup + arrow_accel, arrow_max) or 0
            rv.adn = adn_dn and math.min(rv.adn + arrow_accel, arrow_max) or 0
            rv.alt = alt_dn and math.min(rv.alt + arrow_accel, arrow_max) or 0
            rv.art = art_dn and math.min(rv.art + arrow_accel, arrow_max) or 0

            -- Left Arrow = Roll left
            if alt_dn then
                if is_editing_attached then
                    local obj = constructor.selected_object
                    obj.rot_offset = obj.rot_offset or {x=0, y=0, z=0}
                    obj.rot_offset.y = obj.rot_offset.y + rv.alt
                    reattach_object(obj)
                else
                    local new_rot = {x = constructor.selected_object.rotation.x, y = constructor.selected_object.rotation.y + rv.alt, z = constructor.selected_object.rotation.z}
                    update_object_rotation(constructor.selected_object, new_rot)
                end
            end
            -- Right Arrow = Roll right
            if art_dn then
                if is_editing_attached then
                    local obj = constructor.selected_object
                    obj.rot_offset = obj.rot_offset or {x=0, y=0, z=0}
                    obj.rot_offset.y = obj.rot_offset.y - rv.art
                    reattach_object(obj)
                else
                    local new_rot = {x = constructor.selected_object.rotation.x, y = constructor.selected_object.rotation.y - rv.art, z = constructor.selected_object.rotation.z}
                    update_object_rotation(constructor.selected_object, new_rot)
                end
            end
            -- Up Arrow = Pitch up
            if aup_dn then
                if is_editing_attached then
                    local obj = constructor.selected_object
                    obj.rot_offset = obj.rot_offset or {x=0, y=0, z=0}
                    obj.rot_offset.x = obj.rot_offset.x + rv.aup
                    reattach_object(obj)
                else
                    local new_rot = {x = constructor.selected_object.rotation.x + rv.aup, y = constructor.selected_object.rotation.y, z = constructor.selected_object.rotation.z}
                    update_object_rotation(constructor.selected_object, new_rot)
                end
            end
            -- Down Arrow = Pitch down
            if adn_dn then
                if is_editing_attached then
                    local obj = constructor.selected_object
                    obj.rot_offset = obj.rot_offset or {x=0, y=0, z=0}
                    obj.rot_offset.x = obj.rot_offset.x - rv.adn
                    reattach_object(obj)
                else
                    local new_rot = {x = constructor.selected_object.rotation.x - rv.adn, y = constructor.selected_object.rotation.y, z = constructor.selected_object.rotation.z}
                    update_object_rotation(constructor.selected_object, new_rot)
                end
            end

            -- Delete object (X key = control 73) - 60% keyboard friendly
            if invoker.call(0x580417101DDB492F, 0, 73).bool then  -- X key (Duck)
                delete_constructor_object(constructor.selected_object)
                constructor.selected_object = nil
                exit_placement_mode()
                return
            end

            -- Duplicate/Place keybind (V key)
            if input and input.key and input.key(0x56).just_pressed then  -- V key
                local obj = constructor.selected_object
                local new_obj = create_constructor_object(obj.model_hash, {x = obj.position.x, y = obj.position.y, z = obj.position.z})
                if new_obj then
                    update_object_rotation(new_obj, {x = obj.rotation.x, y = obj.rotation.y, z = obj.rotation.z})
                    new_obj.collision_enabled = obj.collision_enabled
                    new_obj.frozen = obj.frozen
                    if new_obj.handle and new_obj.handle ~= 0 then
                        invoker.call(0x1A9205C1B9EE827F, new_obj.handle, obj.collision_enabled ~= false, true)
                        invoker.call(0x428CA6DBD1094446, new_obj.handle, obj.frozen == true)
                    end
                    constructor.selected_object = new_obj
                    constructor.selected_index = #constructor.objects
                    -- Update placement object position tracking
                    constructor.placement_obj_x = new_obj.position.x
                    constructor.placement_obj_y = new_obj.position.y
                    constructor.placement_obj_z = new_obj.position.z
                    safe_toast("Duplicated! Move the new prop")
                end
            end
        end

        -- Exit placement mode (Tab key = control 37, or Escape = 200)
        if invoker.call(0x580417101DDB492F, 0, 200).bool then  -- Escape
            exit_placement_mode()
        end

        -- Draw on-screen controls (positioned lower so not off screen)
        if gui and gui.text then
            local help_lines = {
                "PLACEMENT MODE" .. (constructor.edit_attached_mode and " [EDIT ATTACHED]" or ""),
                "WASD: Move | Space/Ctrl: Up/Down",
                "Mouse: Orbit Cam | Scroll: Zoom | MMouse: Drag Obj",
                "Q/E: Rotate Z | Arrows: Roll/Pitch | V: Duplicate",
                "O: Edit Attached | X: Delete | Esc: Exit"
            }

            -- Position at top left of screen
            local start_y = 50  -- Top of screen
            for i, line in ipairs(help_lines) do
                -- Draw shadow/outline
                for ox = -1, 1 do
                    for oy = -1, 1 do
                        if ox ~= 0 or oy ~= 0 then
                            local shadow = gui.text(line)
                            if shadow then
                                shadow:position(vec2(20 + ox, start_y + (i - 1) * 20 + oy))
                                shadow:scale(i == 1 and 18 or 14)
                                shadow:color(color(0, 0, 0, 255))
                                shadow:draw()
                            end
                        end
                    end
                end

                -- Draw main text
                local t = gui.text(line)
                if t then
                    t:position(vec2(20, start_y + (i - 1) * 20))
                    t:scale(i == 1 and 18 or 14)
                    t:color(i == 1 and color(0, 255, 255, 255) or color(255, 255, 255, 255))
                    t:draw()
                end
            end
        end
    end

    -- Start placement mode tick loop
    util.create_thread(function()
        while true do
            placement_mode_tick()
            util.yield(0)
        end
    end)

    -- ===== JSON SAVE/LOAD =====

    -- Helper function to convert table to JSON string
    local function table_to_json(t, indent)
        indent = indent or ""
        -- Check if this is a pure array (sequential integer keys from 1)
        local is_array = true
        local max_n = 0
        for k, _ in pairs(t) do
            if type(k) ~= "number" or k ~= math.floor(k) or k < 1 then
                is_array = false
                break
            end
            if k > max_n then max_n = k end
        end
        if is_array and max_n ~= #t then is_array = false end

        local inner = indent .. "  "
        if is_array then
            if max_n == 0 then return "[]" end
            local parts = {}
            for i = 1, max_n do
                local v = t[i]
                local s
                if type(v) == "table" then s = table_to_json(v, inner)
                elseif type(v) == "boolean" then s = v and "true" or "false"
                elseif type(v) == "number" then s = tostring(v)
                elseif type(v) == "string" then s = '"' .. tostring(v):gsub('"', '\\"') .. '"'
                else s = '"' .. tostring(v) .. '"' end
                parts[i] = inner .. s
            end
            return "[\n" .. table.concat(parts, ",\n") .. "\n" .. indent .. "]"
        else
            local parts = {}
            for k, v in pairs(t) do
                local s
                if type(v) == "table" then s = table_to_json(v, inner)
                elseif type(v) == "boolean" then s = v and "true" or "false"
                elseif type(v) == "number" then s = tostring(v)
                elseif type(v) == "string" then s = '"' .. tostring(v):gsub('"', '\\"') .. '"'
                elseif v == nil then s = "null"
                else s = '"' .. tostring(v) .. '"' end
                table.insert(parts, inner .. '"' .. tostring(k) .. '": ' .. s)
            end
            if #parts == 0 then return "{}" end
            return "{\n" .. table.concat(parts, ",\n") .. "\n" .. indent .. "}"
        end
    end

    -- Update index file when saving (defined before save function)
    local function update_constructs_index(filename)
        -- Read existing index
        local existing = {}
        local index_path = constructor.constructs_dir .. "_index.txt"
        local index_file = io.open(index_path, "r")
        if index_file then
            for line in index_file:lines() do
                if line and line ~= "" then
                    existing[line] = true
                end
            end
            index_file:close()
        end

        -- Add new filename if not already in index
        local full_name = filename .. ".json"
        if not existing[full_name] then
            local index_write = io.open(index_path, "a")
            if index_write then
                index_write:write(full_name .. "\n")
                index_write:close()
            end
        end
    end

    local function save_construct_to_json(filename)
        local data = {
            version = "1.1",  -- Updated version for vehicle support
            name = filename,
            created = os.date("%Y-%m-%d %H:%M:%S"),
            objects = {},
            vehicle = nil  -- Will store vehicle info if props are attached to one
        }

        -- Check if any props are attached to a vehicle and get vehicle info
        local vehicle_handle = nil
        for _, obj in ipairs(constructor.objects) do
            if obj.attached_to_vehicle then
                vehicle_handle = obj.attached_to_vehicle
                break
            end
        end

        -- Save vehicle information if found
        if vehicle_handle and invoker.call(0x7239B21A38F536BA, vehicle_handle).bool then
            local veh_model_hash = invoker.call(0x9F47B058362C84B5, vehicle_handle).int  -- GET_ENTITY_MODEL
            local veh_pos = invoker.call(0x3FEF770D40960D5A, vehicle_handle, false).scr_vec3
            local veh_rot = invoker.call(0xAFBD61CC738D9EB9, vehicle_handle, 2).scr_vec3
            local veh_colors = {}
            -- Get primary and secondary colors
            local color1 = invoker.call(0xEEBFC7A8771E6116, vehicle_handle, 0, 0)  -- GET_VEHICLE_CUSTOM_PRIMARY_COLOUR
            if color1 then
                veh_colors.primary_r = color1.int or 0
                veh_colors.primary_g = 0
                veh_colors.primary_b = 0
            end

            data.vehicle = {
                model_hash = veh_model_hash,
                position = {x = veh_pos.x, y = veh_pos.y, z = veh_pos.z},
                rotation = {x = veh_rot.x, y = veh_rot.y, z = veh_rot.z}
            }
        end

        for _, obj in ipairs(constructor.objects) do
            -- Get ACTUAL world position and rotation from entity, not stored values
            local actual_pos = obj.position
            local actual_rot = obj.rotation
            if obj.handle and invoker.call(0x7239B21A38F536BA, obj.handle).bool then
                local pos = invoker.call(0x3FEF770D40960D5A, obj.handle, true).scr_vec3   -- GET_ENTITY_COORDS (alive=true = rendered pos)
                local rot = invoker.call(0xAFBD61CC738D9EB9, obj.handle, 2).scr_vec3      -- GET_ENTITY_ROTATION
                actual_pos = {x = pos.x, y = pos.y, z = pos.z}
                actual_rot = {x = rot.x, y = rot.y, z = rot.z}
            end

            table.insert(data.objects, {
                id = obj.id,
                model = obj.model,
                model_hash = obj.model_hash,
                position = actual_pos,
                rotation = actual_rot,
                offset = obj.offset,
                rot_offset = obj.rot_offset,
                is_attached = obj.is_attached,
                parent_id = obj.parent and obj.parent.id or nil,
                attached_to_vehicle = obj.attached_to_vehicle ~= nil,  -- Boolean flag
                attach_offset = obj.attach_offset,  -- Local space offset for vehicle attachment
                attach_rotation = obj.attach_rotation,  -- Rotation for vehicle attachment
                collision_enabled = obj.collision_enabled,
                frozen = obj.frozen,
                invincible = obj.invincible,
                visible = obj.visible,
                options = obj.options
            })
        end

        local json_str = table_to_json(data, "")
        local filepath = constructor.constructs_dir .. filename .. ".json"

        local file = io.open(filepath, "w")
        if file then
            file:write(json_str)
            file:close()
            -- Update the index file so refresh works
            update_constructs_index(filename)
            safe_toast("Saved: " .. filename)
            return true
        else
            safe_toast("Failed to save!")
            return false
        end
    end

    local function load_construct_from_json(filename)
        local filepath = constructor.constructs_dir .. filename

        local file = io.open(filepath, "r")
        if not file then
            safe_toast("Failed to load!")
            return false
        end

        local json_str = file:read("*all")
        file:close()

        local objects_loaded = 0
        local loaded_objects = {}  -- Track loaded objects by their saved ID for attachments
        local attachment_queue = {}  -- Queue attachments for after all objects are created
        local spawned_vehicle = nil  -- Track spawned vehicle for prop attachments

        -- Calculate offset if loading at player position
        local offset_x, offset_y, offset_z = 0, 0, 0

        if constructor.load_at_player then
            local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int
            local player_pos = invoker.call(0x3FEF770D40960D5A, player_ped, true).scr_vec3
            local heading = invoker.call(0xE83D4F9BA2A38914, player_ped).float

            local rad = math.rad(heading)
            local spawn_x = player_pos.x - math.sin(rad) * 5
            local spawn_y = player_pos.y + math.cos(rad) * 5
            local spawn_z = player_pos.z + 1.0

            -- Find first object/vehicle position to calculate offset
            local first_model_start = json_str:find('"model":%s*"([^"]+)"', 1)
            local vehicle_start = json_str:find('"vehicle":%s*{', 1)

            -- If vehicle exists, use its position for offset calculation
            if vehicle_start and vehicle_start < (first_model_start or math.huge) then
                local veh_search_area = json_str:sub(vehicle_start, vehicle_start + 500)
                local veh_pos_match = veh_search_area:match('"position":%s*{([^}]+)}')
                if veh_pos_match then
                    local vx = tonumber(veh_pos_match:match('"x":%s*([%-%.%deE]+)'))
                    local vy = tonumber(veh_pos_match:match('"y":%s*([%-%.%deE]+)'))
                    local vz = tonumber(veh_pos_match:match('"z":%s*([%-%.%deE]+)'))
                    if vx and vy and vz then
                        offset_x, offset_y, offset_z = spawn_x - vx, spawn_y - vy, spawn_z - vz
                    end
                end
            elseif first_model_start then
                local first_search_area = json_str:sub(first_model_start, first_model_start + 500)
                local first_pos_match = first_search_area:match('"position":%s*{([^}]+)}')
                if first_pos_match then
                    local fx = tonumber(first_pos_match:match('"x":%s*([%-%.%deE]+)'))
                    local fy = tonumber(first_pos_match:match('"y":%s*([%-%.%deE]+)'))
                    local fz = tonumber(first_pos_match:match('"z":%s*([%-%.%deE]+)'))
                    if fx and fy and fz then
                        offset_x, offset_y, offset_z = spawn_x - fx, spawn_y - fy, spawn_z - fz
                    end
                end
            end
        end

        -- Spawn vehicle first if it exists in the save file
        local vehicle_start = json_str:find('"vehicle":%s*{')
        if vehicle_start then
            -- Extract a large section containing the vehicle data
            local vehicle_section = json_str:sub(vehicle_start, vehicle_start + 1000)
            local veh_model_hash = tonumber(vehicle_section:match('"model_hash":%s*([%-]?%d+)'))

            -- Extract position
            local veh_pos_match = vehicle_section:match('"position":%s*{([^}]+)}')
            local vx, vy, vz
            if veh_pos_match then
                vx = tonumber(veh_pos_match:match('"x":%s*([%-%.%deE]+)'))
                vy = tonumber(veh_pos_match:match('"y":%s*([%-%.%deE]+)'))
                vz = tonumber(veh_pos_match:match('"z":%s*([%-%.%deE]+)'))
            end

            -- Extract rotation
            local veh_rot_match = vehicle_section:match('"rotation":%s*{([^}]+)}')
            local veh_pos_str = veh_pos_match  -- For compatibility
            local veh_rot_str = veh_rot_match  -- For compatibility

            if veh_model_hash and vx and vy and vz then
                    -- Request vehicle model
                    invoker.call(0x963D27A58DF860AC, veh_model_hash)  -- REQUEST_MODEL
                    local wait_count = 0
                    while not invoker.call(0x98A4EB5D89A0C952, veh_model_hash).bool and wait_count < 50 do
                        util.yield(100)
                        wait_count = wait_count + 1
                    end

                    -- Spawn vehicle at calculated position
                -- Calculate spawn position with offset
                local veh_spawn_x = vx + offset_x
                local veh_spawn_y = vy + offset_y
                local veh_spawn_z = vz + offset_z

                -- Get heading from rotation Z
                local veh_heading = 0.0
                local vrx, vry, vrz = 0, 0, 0
                if veh_rot_match then
                    vrx = tonumber(veh_rot_match:match('"x":%s*([%-%.%deE]+)')) or 0
                    vry = tonumber(veh_rot_match:match('"y":%s*([%-%.%deE]+)')) or 0
                    vrz = tonumber(veh_rot_match:match('"z":%s*([%-%.%deE]+)')) or 0
                    veh_heading = vrz
                end

                -- Spawn vehicle
                spawned_vehicle = invoker.call(0xAF35D0D2583051B0, veh_model_hash, veh_spawn_x, veh_spawn_y, veh_spawn_z, veh_heading, true, false, false).int
                if spawned_vehicle and spawned_vehicle ~= 0 then
                    -- Set full rotation
                    invoker.call(0x8524A8B0171D5E07, spawned_vehicle, vrx, vry, vrz, 2, true)
                    safe_toast("Spawned vehicle!")
                end
            end
        end

        -- Parse all objects - supports both JSON array [...] and legacy object {"1":{...}} format
        local search_pos = 1
        while true do
            local model_start, model_end, model = json_str:find('"model":%s*"([^"]+)"', search_pos)
            if not model_start then break end

            -- Find the start of THIS object's block by scanning back for the nearest unmatched '{'
            local obj_block_start = model_start
            local back_depth = 0
            for i = model_start, math.max(1, model_start - 500), -1 do
                local ch = json_str:sub(i, i)
                if ch == '}' then back_depth = back_depth + 1
                elseif ch == '{' then
                    if back_depth == 0 then obj_block_start = i; break
                    else back_depth = back_depth - 1 end
                end
            end

            -- Find the matching closing '}' for this object block
            local depth = 0
            local obj_block_end = model_start + 1200
            for i = obj_block_start, math.min(#json_str, obj_block_start + 2000) do
                local ch = json_str:sub(i, i)
                if ch == '{' then depth = depth + 1
                elseif ch == '}' then
                    depth = depth - 1
                    if depth == 0 then obj_block_end = i; break end
                end
            end
            local search_area = json_str:sub(obj_block_start, obj_block_end)

            -- Extract model_hash (preferred) or convert model string to number
            local model_hash = tonumber(search_area:match('"model_hash":%s*([%-]?%d+)'))
            if not model_hash then
                model_hash = tonumber(model)  -- Fallback: convert model string to number
            end

            -- Extract ID
            local saved_id = tonumber(search_area:match('"id":%s*(%d+)'))

            -- Extract position
            local pos_x, pos_y, pos_z
            local pos_match = search_area:match('"position":%s*{([^}]+)}')
            if pos_match then
                pos_x = tonumber(pos_match:match('"x":%s*([%-%.%deE]+)'))
                pos_y = tonumber(pos_match:match('"y":%s*([%-%.%deE]+)'))
                pos_z = tonumber(pos_match:match('"z":%s*([%-%.%deE]+)'))
            end

            -- Extract rotation
            local rot_x, rot_y, rot_z
            local rot_match = search_area:match('"rotation":%s*{([^}]+)}')
            if rot_match then
                rot_x = tonumber(rot_match:match('"x":%s*([%-%.%deE]+)'))
                rot_y = tonumber(rot_match:match('"y":%s*([%-%.%deE]+)'))
                rot_z = tonumber(rot_match:match('"z":%s*([%-%.%deE]+)'))
            end

            -- Extract frozen state
            local frozen = search_area:match('"frozen":%s*(%a+)') == "true"

            -- Extract collision
            local collision = search_area:match('"has_collision":%s*(%a+)') ~= "false"

            -- Extract attachment data
            local is_attached = search_area:match('"is_attached":%s*(%a+)') == "true"
            local parent_id = tonumber(search_area:match('"parent_id":%s*(%d+)'))
            local attached_to_vehicle = search_area:match('"attached_to_vehicle":%s*(%a+)') == "true"

            -- Extract additional properties
            local invincible = search_area:match('"invincible":%s*(%a+)') == "true"
            local visible_str = search_area:match('"visible":%s*(%a+)')
            local visible = visible_str ~= "false"  -- Default to true

            -- Extract attach_offset if present
            local attach_off_x, attach_off_y, attach_off_z
            local attach_offset_match = search_area:match('"attach_offset":%s*{([^}]+)}')
            if attach_offset_match then
                attach_off_x = tonumber(attach_offset_match:match('"x":%s*([%-%.%deE]+)'))
                attach_off_y = tonumber(attach_offset_match:match('"y":%s*([%-%.%deE]+)'))
                attach_off_z = tonumber(attach_offset_match:match('"z":%s*([%-%.%deE]+)'))
            end

            -- Extract attach_rotation if present
            local attach_rot_x, attach_rot_y, attach_rot_z
            local attach_rotation_match = search_area:match('"attach_rotation":%s*{([^}]+)}')
            if attach_rotation_match then
                attach_rot_x = tonumber(attach_rotation_match:match('"x":%s*([%-%.%deE]+)'))
                attach_rot_y = tonumber(attach_rotation_match:match('"y":%s*([%-%.%deE]+)'))
                attach_rot_z = tonumber(attach_rotation_match:match('"z":%s*([%-%.%deE]+)'))
            end

            -- Spawn the object
            if model_hash and pos_x and pos_y and pos_z then
                -- If attached to vehicle, don't apply player offset (will be positioned by attachment)
                -- Otherwise apply offset for loading at player position
                local position = {
                    x = attached_to_vehicle and pos_x or (pos_x + offset_x),
                    y = attached_to_vehicle and pos_y or (pos_y + offset_y),
                    z = attached_to_vehicle and pos_z or (pos_z + offset_z)
                }

                local obj = create_constructor_object(model_hash, position, true)  -- Skip ground placement when loading
                if obj then
                    -- Freeze and force exact saved position immediately
                    if obj.handle and obj.handle ~= 0 then
                        invoker.call(0x428CA6DBD1094446, obj.handle, true)  -- FREEZE_ENTITY_POSITION
                        invoker.call(0x1C99BB7B6E96D16F, obj.handle, 0.0, 0.0, 0.0)  -- SET_ENTITY_VELOCITY zero
                        -- Force exact saved coords (prevents any physics/ground-snap drift)
                        invoker.call(0x06843DA7060A026B, obj.handle, position.x, position.y, position.z, false, false, false, false)  -- SET_ENTITY_COORDS
                    end

                    -- Set rotation (ONLY if NOT attached to anything - attached props use rot_offset/attach_rotation instead)
                    if rot_x and rot_y and rot_z and not attached_to_vehicle and not is_attached then
                        update_object_rotation(obj, {x = rot_x, y = rot_y, z = rot_z})
                    end

                    -- Store frozen state
                    obj.frozen = frozen

                    -- Set collision
                    obj.collision_enabled = collision
                    if obj.handle and obj.handle ~= 0 then
                        invoker.call(0x1A9205C1B9EE827F, obj.handle, collision, false)
                    end

                    -- Set invincible
                    obj.invincible = invincible
                    if obj.handle and obj.handle ~= 0 and invincible then
                        invoker.call(0x3882114831B6BC3, obj.handle, true)  -- SET_ENTITY_INVINCIBLE
                    end

                    -- Set visible
                    obj.visible = visible
                    if obj.handle and obj.handle ~= 0 and not visible then
                        invoker.call(0xEA1C610A04DB6BBB, obj.handle, false, false)  -- SET_ENTITY_VISIBLE
                    end

                    -- Attach to spawned vehicle if needed
                    if attached_to_vehicle and spawned_vehicle and spawned_vehicle ~= 0 then
                        if obj.handle and obj.handle ~= 0 then
                            -- Use saved attach_offset if available, otherwise calculate from position
                            local use_x, use_y, use_z
                            if attach_off_x and attach_off_y and attach_off_z then
                                -- Use saved local space offsets (preferred - accurate)
                                use_x = attach_off_x
                                use_y = attach_off_y
                                use_z = attach_off_z
                            else
                                -- Fallback: calculate from world position (less accurate)
                                local veh_pos = invoker.call(0x3FEF770D40960D5A, spawned_vehicle, false).scr_vec3
                                use_x = position.x - veh_pos.x
                                use_y = position.y - veh_pos.y
                                use_z = position.z - veh_pos.z
                            end

                            -- Use saved rotation if available, otherwise default to 0
                            local use_rot_x = attach_rot_x or 0.0
                            local use_rot_y = attach_rot_y or 0.0
                            local use_rot_z = attach_rot_z or 0.0

                            -- Attach to vehicle with saved offsets and rotation
                            invoker.call(0x6B9BBD38AB0796DF, obj.handle, spawned_vehicle, 0, use_x, use_y, use_z, use_rot_x, use_rot_y, use_rot_z, false, true, false, false, 2, true)
                            obj.attached_to_vehicle = spawned_vehicle
                            obj.is_attached = true
                            obj.attach_offset = {x = use_x, y = use_y, z = use_z}
                            obj.attach_rotation = {x = use_rot_x, y = use_rot_y, z = use_rot_z}
                        end
                    end

                    -- Track this object by its saved ID
                    if saved_id then
                        loaded_objects[saved_id] = obj
                    end

                    -- Queue attachment if needed (for prop-to-prop attachments)
                    if is_attached and parent_id and not attached_to_vehicle then
                        table.insert(attachment_queue, {
                            child = obj,
                            parent_id = parent_id,
                            search_area = search_area
                        })
                    end

                    objects_loaded = objects_loaded + 1
                end
            end

            search_pos = obj_block_end + 1
        end

        -- Process attachments after all objects are created
        for _, attachment_data in ipairs(attachment_queue) do
            local child = attachment_data.child
            local parent = loaded_objects[attachment_data.parent_id]

            if parent and child then
                -- Extract offset
                local off_x, off_y, off_z = 0, 0, 0
                local off_match = attachment_data.search_area:match('"offset":%s*{([^}]+)}')
                if off_match then
                    off_x = tonumber(off_match:match('"x":%s*([%-%.%deE]+)')) or 0
                    off_y = tonumber(off_match:match('"y":%s*([%-%.%deE]+)')) or 0
                    off_z = tonumber(off_match:match('"z":%s*([%-%.%deE]+)')) or 0
                end

                -- Extract rotation offset
                local roff_x, roff_y, roff_z = 0, 0, 0
                local roff_match = attachment_data.search_area:match('"rot_offset":%s*{([^}]+)}')
                if roff_match then
                    roff_x = tonumber(roff_match:match('"x":%s*([%-%.%deE]+)')) or 0
                    roff_y = tonumber(roff_match:match('"y":%s*([%-%.%deE]+)')) or 0
                    roff_z = tonumber(roff_match:match('"z":%s*([%-%.%deE]+)')) or 0
                end

                -- Attach the objects
                child.parent = parent
                child.is_attached = true
                child.offset = {x = off_x, y = off_y, z = off_z}
                child.rot_offset = {x = roff_x, y = roff_y, z = roff_z}

                if child.handle and parent.handle then
                    invoker.call(0x6B9BBD38AB0796DF, child.handle, parent.handle, -1, off_x, off_y, off_z, roff_x, roff_y, roff_z, false, false, false, false, 2, true)
                end
            end
        end

        if objects_loaded > 0 then
            constructor.selected_object = constructor.objects[#constructor.objects - objects_loaded + 1]
            constructor.selected_index = #constructor.objects - objects_loaded + 1
            safe_toast("Loaded " .. objects_loaded .. " objects from " .. filename)
        else
            safe_toast("No objects found in " .. filename)
        end

        return objects_loaded > 0
    end

    local function refresh_saved_constructs_list()
        constructor.saved_constructs = {}

        -- Read from index file (since io.popen doesn't work in Lexis)
        local index_path = constructor.constructs_dir .. "_index.txt"
        local index_file = io.open(index_path, "r")
        if index_file then
            for line in index_file:lines() do
                if line and line ~= "" then
                    -- Verify the file still exists
                    local check_file = io.open(constructor.constructs_dir .. line, "r")
                    if check_file then
                        check_file:close()
                        table.insert(constructor.saved_constructs, line)
                    end
                end
            end
            index_file:close()
        end

        -- Also check if any common names exist (fallback)
        if #constructor.saved_constructs == 0 then
            local common_names = {"build", "construct", "map", "test", "save1", "save2", "save3"}
            for _, name in ipairs(common_names) do
                local check_file = io.open(constructor.constructs_dir .. name .. ".json", "r")
                if check_file then
                    check_file:close()
                    table.insert(constructor.saved_constructs, name .. ".json")
                end
            end
        end
    end

