        json_search = "",
        json_search_focused = false,
        json_scroll = 0,
        json_collapsed = {},
        json_delete_old = true,
        json_teleport = true,
        json_engine_on = true,
        json_godmode = false,
        json_radio_off = false,
        json_spawn_in_air = false,
        json_max_upgrade = false,
        json_invisible = false,
        json_last_spawned = nil,
        json_last_attachments = {},
        json_is_spawning = false,
        json_map_spawned = {},       -- Handles from last JSON map spawn
        json_map_name = nil,         -- Name of last loaded JSON map
    }

