            elseif category == "Van" then
                vehicles = {
                    {model="boxville5", name="Armored Boxville"},
                    {model="Bison3", name="Bison"},
                    {model="bison", name="Bison"},
                    {model="Bison2", name="Bison"},
                    {model="bobcatXL", name="Bobcat XL"},
                    {model="boxville4", name="Boxville"},
                    {model="boxville3", name="Boxville"},
                    {model="boxville", name="Boxville"},
                    {model="boxville2", name="Boxville"},
                    {model="boxville6", name="Boxville (LSDS)"},
                    {model="burrito2", name="Bugstars Burrito"},
                    {model="Burrito4", name="Burrito"},
                    {model="burrito5", name="Burrito"},
                    {model="Burrito", name="Burrito"},
                    {model="burrito3", name="Burrito"},
                    {model="CAMPER", name="Camper"},
                    {model="speedo2", name="Clown Van"},
                    {model="gburrito", name="Gang Burrito"},
                    {model="gburrito2", name="Gang Burrito"},
                    {model="journey", name="Journey"},
                    {model="journey2", name="Journey II"},
                    {model="minivan", name="Minivan"},
                    {model="minivan2", name="Minivan Custom"},
                    {model="paradise", name="Paradise"},
                    {model="pony", name="Pony"},
                    {model="pony2", name="Pony"},
                    {model="rumpo2", name="Rumpo"},
                    {model="rumpo", name="Rumpo"},
                    {model="rumpo3", name="Rumpo Custom"},
                    {model="speedo", name="Speedo"},
                    {model="speedo5", name="Speedo Custom"},
                    {model="speedo4", name="Speedo Custom"},
                    {model="Surfer2", name="Surfer"},
                    {model="SURFER", name="Surfer"},
                    {model="surfer3", name="Surfer Custom"},
                    {model="Taco", name="Taco Van"},
                    {model="youga", name="Youga"},
                    {model="youga2", name="Youga Classic"},
                    {model="youga3", name="Youga Classic 4x4"},
                    {model="youga5", name="Youga Custom"},
                    {model="youga4", name="Youga Custom"},
                }
            else
                vehicles = {{model="adder", name="Adder"}}
            end

            -- Filter by search
            local filtered = {}
            for _, veh in ipairs(vehicles) do
                if search_query == "" or veh.name:lower():find(search_query, 1, true) or veh.model:lower():find(search_query, 1, true) then
                    table.insert(filtered, veh)
                end
            end

            if #filtered > 0 then
                -- Category header (always draw if in view)
                local header_h = math.floor(36 * s)
                -- Default to collapsed (true) - user must click to expand
                local collapsed = spawn_state.collapsed[category]
                if collapsed == nil then collapsed = true end  -- Default collapsed

                -- Draw header if any part is visible
                if item_y + header_h >= list_y and item_y <= list_y + list_h then
                    local header_hover = is_mouse_in(left_x + math.floor(8 * s), item_y, left_w - math.floor(16 * s), header_h)

                    draw_rect(left_x + math.floor(8 * s), item_y, left_w - math.floor(16 * s), header_h, header_hover and C.accent or C.header, math.floor(4 * s))
                    local arrow = collapsed and ">" or "v"
                    draw_text(arrow .. category .. " (" .. #filtered .. ")", left_x + math.floor(16 * s), item_y + math.floor(10 * s), UI.font_small, C.text)

                    if header_hover and MOUSE.just_pressed then
                        spawn_state.collapsed[category] = not collapsed
                        safe_toast((collapsed and "Expanded " or "Collapsed ") .. category)
                    end
                end
                item_y = item_y + header_h
                total_items = total_items + 1

                -- Vehicle items (if not collapsed)
                if not collapsed then
                    for _, veh in ipairs(filtered) do
                        local item_h = math.floor(30 * s)
                        if item_y + item_h >= list_y and item_y <= list_y + list_h then
                            -- Full width clickable area
                            local item_hover = is_mouse_in(left_x + math.floor(8 * s), item_y, left_w - math.floor(16 * s), item_h)

                            -- Background highlight
                            if item_hover then
                                draw_rect(left_x + math.floor(8 * s), item_y, left_w - math.floor(16 * s), item_h, C.accent, math.floor(3 * s))
                            end

                            -- Vehicle name text
                            draw_text(veh.name, left_x + math.floor(20 * s), item_y + math.floor(7 * s), UI.font_tiny, item_hover and C.bg or C.text)

                            -- Click handler (EXACTLY LIKE CLICKUI WIDGETS)
                            if item_hover then
                                if not veh._preview_hash then
                                    pcall(function()
                                        local r = invoker.call(0xD24D37CC275948CC, tostring(veh.model))
                                        if r and r.int and r.int ~= 0 then veh._preview_hash = r.int end
                                    end)
                                end
                                if veh._preview_hash then spawn_state.preview_hovered_model = veh._preview_hash end
                            end
                            if item_hover and MOUSE.just_pressed and not spawn_state.is_spawning then
                                debug_info("SPAWN", "Vehicle clicked: " .. veh.name)
                                spawn_vehicle(veh.model, veh.name)
                            end
                        end
                        item_y = item_y + item_h
                        total_items = total_items + 1
                    end
                end
            end
        end

        -- Scroll shadows for vehicle list
        do
            local list_max_scroll = math.max(0, (total_items * math.floor(32 * s)) - list_h)
            local shadow_h = math.floor(8 * s)
            if scroll_offset > 0 then
                draw_rect(left_x, list_y, left_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            if scroll_offset < list_max_scroll then
                draw_rect(left_x, list_y + list_h - shadow_h, left_w, shadow_h, color(0, 0, 0, 40), 0)
            end

            -- Scrollbar for vehicle list
            if list_max_scroll > 0 then
                local sb_w = math.floor(4 * s)
                local sb_x = left_x + left_w - sb_w - math.floor(1 * s)
                local sb_h = list_h - math.floor(6 * s)
                local thumb_h = math.max(math.floor(24 * s), sb_h * (list_h / (list_h + list_max_scroll)))
                local thumb_y = list_y + math.floor(3 * s) + (sb_h - thumb_h) * (scroll_offset / list_max_scroll)
                draw_rect(sb_x, list_y + math.floor(3 * s), sb_w, sb_h, C.checkbox_off, math.floor(2 * s))
                draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(2 * s))
            end
        end

        -- Scroll handling
        if is_mouse_in(left_x, list_y, left_w, list_h) then
            if MOUSE.scroll_up then
                spawn_state.vehicle_scroll[spawn_state.search_query] = math.max(0, scroll_offset - math.floor(100 * s))
            elseif MOUSE.scroll_down then
                local max_scroll = math.max(0, (total_items * math.floor(32 * s)) - list_h)
                spawn_state.vehicle_scroll[spawn_state.search_query] = math.min(max_scroll, scroll_offset + math.floor(100 * s))
            end
        end

        -- RIGHT COLUMN: Spawn options (with scrolling support)
        draw_rect(right_x, content_y, right_w, content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Initialize scroll state
        spawn_state.options_scroll = spawn_state.options_scroll or 0
        local opt_start_y = content_y + math.floor(12 * s)
        local opt_panel_h = content_h - math.floor(24 * s)

        -- Apply scroll offset
        local opt_y = opt_start_y - spawn_state.options_scroll
        local opt_x = right_x + math.floor(12 * s)
        local opt_w = right_w - math.floor(24 * s)

        -- Helper to check if element is visible (for culling)
        local function opt_visible(y, h)
            return y + h >= opt_start_y and y <= content_y + content_h
        end

        -- Header
        if opt_visible(opt_y, UI.font_small) then
            draw_text("Spawn Options", opt_x, opt_y, UI.font_small, C.accent)
        end
        opt_y = opt_y + math.floor(28 * s)

        -- All 11 spawn options in 2 columns
        local cb_w = (opt_w - math.floor(8 * s)) / 2
        local cb_h = math.floor(24 * s)
        local box_size = math.floor(16 * s)

        local function draw_checkbox_pair(label1, state1, label2, state2)
            -- Only draw if visible
            if opt_visible(opt_y, cb_h) then
                -- Left toggle
                spawn_state[state1] = inline_toggle(label1, spawn_state[state1], opt_x, opt_y, cb_w, cb_h)
                -- Right toggle
                spawn_state[state2] = inline_toggle(label2, spawn_state[state2], opt_x + cb_w + math.floor(8 * s), opt_y, cb_w, cb_h)
            end

            opt_y = opt_y + cb_h
        end

        draw_checkbox_pair("Teleport to Vehicle", "teleport_to_vehicle", "Delete Old Vehicle", "delete_old_vehicle")
        draw_checkbox_pair("Spawn in Air", "spawn_in_air", "Engine On", "engine_on")
        draw_checkbox_pair("Max Performance", "max_performance", "Max Upgrade", "max_upgrade")
        draw_checkbox_pair("Clean Vehicle", "clean_vehicle", "Bulletproof Tires", "bulletproof_tires")
        draw_checkbox_pair("Vehicle Godmode", "vehicle_godmode", "Radio Off", "radio_off")

        -- Keep Velocity (single)
        if opt_visible(opt_y, cb_h) then
            spawn_state.keep_velocity = inline_toggle("Keep Velocity", spawn_state.keep_velocity, opt_x, opt_y, cb_w, cb_h)
        end
        opt_y = opt_y + cb_h + math.floor(8 * s)

        -- Section divider
        if opt_visible(opt_y, math.floor(2 * s)) then
            draw_rect(opt_x, opt_y, opt_w, math.floor(1 * s), color(80, 80, 80, 100), 0)
        end
        opt_y = opt_y + math.floor(10 * s)

        -- Customization section
        if opt_visible(opt_y, UI.font_small) then
            draw_text("Vehicle Customization", opt_x, opt_y, UI.font_small, C.accent)
        end
        opt_y = opt_y + math.floor(24 * s)

        -- Enable Presets checkbox
        if opt_visible(opt_y, cb_h) then
            spawn_state.use_preset = inline_toggle("Enable Presets", spawn_state.use_preset, opt_x, opt_y, opt_w, cb_h)
        end
        opt_y = opt_y + cb_h + math.floor(8 * s)

        if spawn_state.use_preset then
            -- Color mode selector
            if opt_visible(opt_y, UI.font_tiny) then
                draw_text("Color Mode:", opt_x, opt_y, UI.font_tiny, C.text_dim)
            end
            opt_y = opt_y + math.floor(20 * s)

            local modes = {"Classic", "RGB", "Chameleon"}
            local mode_gap = math.floor(6 * s)
            local mode_w = (opt_w - mode_gap * 2) / 3
            local mode_h = math.floor(28 * s)

            if opt_visible(opt_y, mode_h) then
                for i, mode in ipairs(modes) do
                    local mx = opt_x + (i - 1) * (mode_w + mode_gap)
                    local mode_hover = is_mouse_in(mx, opt_y, mode_w, mode_h)
                    local is_active = (spawn_state.color_mode == i)

                    draw_rect(mx, opt_y, mode_w, mode_h, is_active and C.accent or (mode_hover and C.widget_hover or C.widget_bg), math.floor(4 * s))

                    -- Draw text with proper centering
                    local text_x = mx + mode_w / 2
                    local text_y = opt_y + (mode_h - UI.font_tiny) / 2
                    draw_text(mode, text_x - (UI.font_tiny * string.len(mode) / 4), text_y, UI.font_tiny, is_active and C.bg or C.text)

                    if mode_hover and MOUSE.just_pressed then
                        spawn_state.color_mode = i
                    end
                end
            end
            opt_y = opt_y + mode_h + math.floor(12 * s)

            -- Helper function for increment/decrement selector
            local function draw_selector(label, current_value, min_value, max_value, display_name)
                local row_h = math.floor(24 * s)
                local btn_w = math.floor(20 * s)
                local gap = math.floor(4 * s)
                local total_h = math.floor(18 * s) + row_h + math.floor(8 * s)
                local new_value = current_value
                local left_hover = false
                local right_hover = false

                -- Only draw and interact if visible
                if opt_visible(opt_y, total_h) then
                    -- Label
                    draw_text(label, opt_x, opt_y + math.floor(4 * s), UI.font_tiny, C.text_dim)
                    local btn_y = opt_y + math.floor(18 * s)

                    -- Left button (<)
                    left_hover = is_mouse_in(opt_x, btn_y, btn_w, row_h)
                    draw_rect(opt_x, btn_y, btn_w, row_h, left_hover and C.widget_hover or C.widget_bg, math.floor(3 * s))
                    draw_text("<", opt_x + math.floor(6 * s), btn_y + math.floor(4 * s), UI.font_tiny, C.text)

                    -- Display name in center
                    local center_x = opt_x + btn_w + gap
                    local center_w = opt_w - (btn_w * 2) - (gap * 2)
                    draw_rect(center_x, btn_y, center_w, row_h, C.widget_bg, math.floor(3 * s))
                    local text_w = string.len(display_name) * UI.font_tiny / 2
                    draw_text(display_name, center_x + (center_w - text_w) / 2, btn_y + math.floor(4 * s), UI.font_tiny, C.text)

                    -- Right button (>)
                    local right_x = opt_x + opt_w - btn_w
                    right_hover = is_mouse_in(right_x, btn_y, btn_w, row_h)
                    draw_rect(right_x, btn_y, btn_w, row_h, right_hover and C.widget_hover or C.widget_bg, math.floor(3 * s))
                    draw_text(">", right_x + math.floor(6 * s), btn_y + math.floor(4 * s), UI.font_tiny, C.text)

                    -- Handle clicks
                    if left_hover and MOUSE.just_pressed then
                        new_value = current_value - 1
                        if new_value < min_value then new_value = max_value end
                    elseif right_hover and MOUSE.just_pressed then
                        new_value = current_value + 1
                        if new_value > max_value then new_value = min_value end
                    end
                end

                opt_y = opt_y + total_h

                return new_value
            end

            -- Helper function for RGB sliders (MATCHES heist_slider pattern EXACTLY)
            local function draw_rgb_slider(label, value, color_r, color_g, color_b)
                value = tonumber(value) or 0
                value = math.max(0, math.min(255, value))

                local slider_w = opt_w
                local slider_h = math.floor(36 * s)
                local track_h = math.floor(6 * s)

                -- Only draw and interact if visible
                if opt_visible(opt_y, slider_h) then
                    local hover = is_mouse_in(opt_x, opt_y, slider_w, slider_h)

                    -- Background (same as heist_slider)
                    draw_rect(opt_x, opt_y, slider_w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                    draw_text(string.format("%s: %d", label, math.floor(value)), opt_x + math.floor(8 * s), opt_y + math.floor(4 * s), UI.font_small, C.text)

                    -- Track (same as heist_slider)
                    local track_y = opt_y + math.floor(22 * s)
                    local track_x = opt_x + math.floor(8 * s)
                    local track_w = slider_w - math.floor(16 * s)

                    -- Background track
                    draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))

                    -- Fill with color (using color() function like all other colors)
                    local pct = value / 255
                    draw_rect(track_x, track_y, track_w * pct, track_h, color(color_r, color_g, color_b, 255), math.floor(3 * s))

                    -- Mouse handling (EXACTLY like heist_slider)
                    if hover and MOUSE.pressed then
                        local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
                        value = math.floor(mouse_pct * 255)
                    end
                end

                opt_y = opt_y + slider_h + math.floor(4 * s)

                return value
            end

            if spawn_state.color_mode == 1 then
                -- Mode 1 - Classic Colors
                spawn_state.primary_color = draw_selector(
                    "Primary Color",
                    spawn_state.primary_color,
                    1,
                    70,
                    PAINT_NAMES[spawn_state.primary_color] or "Black"
                )

                spawn_state.secondary_color = draw_selector(
                    "Secondary Color",
                    spawn_state.secondary_color,
                    1,
                    70,
                    PAINT_NAMES[spawn_state.secondary_color] or "Black"
                )

            elseif spawn_state.color_mode == 2 then
                -- Mode 2 - RGB Mode
                if opt_visible(opt_y, UI.font_tiny) then
                    draw_text("Primary RGB", opt_x, opt_y, UI.font_tiny, C.text)
                end
                opt_y = opt_y + math.floor(18 * s)

                spawn_state.primary_color_rgb.r = draw_rgb_slider("R", spawn_state.primary_color_rgb.r, 255, 0, 0)
                spawn_state.primary_color_rgb.g = draw_rgb_slider("G", spawn_state.primary_color_rgb.g, 0, 255, 0)
                spawn_state.primary_color_rgb.b = draw_rgb_slider("B", spawn_state.primary_color_rgb.b, 0, 0, 255)

                opt_y = opt_y + math.floor(8 * s)
                if opt_visible(opt_y, UI.font_tiny) then
                    draw_text("Secondary RGB", opt_x, opt_y, UI.font_tiny, C.text)
                end
                opt_y = opt_y + math.floor(18 * s)

                spawn_state.secondary_color_rgb.r = draw_rgb_slider("R", spawn_state.secondary_color_rgb.r, 255, 0, 0)
                spawn_state.secondary_color_rgb.g = draw_rgb_slider("G", spawn_state.secondary_color_rgb.g, 0, 255, 0)
                spawn_state.secondary_color_rgb.b = draw_rgb_slider("B", spawn_state.secondary_color_rgb.b, 0, 0, 255)

            elseif spawn_state.color_mode == 3 then
                -- Mode 3 - Chameleon Mode
                spawn_state.chameleon_paint = draw_selector(
                    "Chameleon Paint",
                    spawn_state.chameleon_paint,
                    1,
                    63,
                    CHAMELEON_PRESETS[spawn_state.chameleon_paint].name or "None"
                )
            end

            -- Additional selectors for all modes
            opt_y = opt_y + math.floor(12 * s)
            if opt_visible(opt_y, UI.font_tiny) then
                draw_text("Additional Options", opt_x, opt_y, UI.font_tiny, C.accent)
            end
            opt_y = opt_y + math.floor(20 * s)

            spawn_state.xenon_color = draw_selector(
                "Xenon Color",
                spawn_state.xenon_color,
                1,
                13,
                XENON_PRESETS[spawn_state.xenon_color].name or "Default"
            )

            spawn_state.neon_color = draw_selector(
                "Neon Color",
                spawn_state.neon_color,
                1,
                13,
                NEON_PRESETS[spawn_state.neon_color].name or "None"
            )

            spawn_state.tire_smoke_color = draw_selector(
                "Tire Smoke",
                spawn_state.tire_smoke_color,
                1,
                10,
                SMOKE_PRESETS[spawn_state.tire_smoke_color].name or "None"
            )

            spawn_state.window_tint = draw_selector(
                "Window Tint",
                spawn_state.window_tint,
                1,
                7,
                WINDOW_TINTS[spawn_state.window_tint] or "None"
            )

            spawn_state.plate_type = draw_selector(
                "Plate Type",
                spawn_state.plate_type,
                1,
                13,
                PLATE_TYPES[spawn_state.plate_type] or "Blue on White"
            )
        end

        -- Calculate total content height and handle scrolling
        local total_opt_height = opt_y + spawn_state.options_scroll - opt_start_y + math.floor(20 * s)
        local max_opt_scroll = math.max(0, total_opt_height - opt_panel_h)

        -- Scroll shadows for options panel
        if max_opt_scroll > 0 then
            local shadow_h = math.floor(8 * s)
            if spawn_state.options_scroll > 0 then
                draw_rect(right_x, content_y, right_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            if spawn_state.options_scroll < max_opt_scroll then
                draw_rect(right_x, content_y + content_h - shadow_h, right_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            -- Scrollbar
            local sb_w = math.floor(4 * s)
            local sb_x = right_x + right_w - sb_w - math.floor(1 * s)
            local sb_h = content_h - math.floor(6 * s)
            local thumb_h = math.max(math.floor(24 * s), sb_h * (opt_panel_h / total_opt_height))
            local thumb_y = content_y + math.floor(3 * s) + (sb_h - thumb_h) * (spawn_state.options_scroll / max_opt_scroll)
            draw_rect(sb_x, content_y + math.floor(3 * s), sb_w, sb_h, C.checkbox_off, math.floor(2 * s))
            draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(2 * s))
        end

        -- Handle scroll wheel for options panel
        if is_mouse_in(right_x, content_y, right_w, content_h) then
            if MOUSE.scroll_up then
                spawn_state.options_scroll = math.max(0, spawn_state.options_scroll - math.floor(40 * s))
            elseif MOUSE.scroll_down then
                spawn_state.options_scroll = math.min(max_opt_scroll, spawn_state.options_scroll + math.floor(40 * s))
            end
        end

        -- Clamp scroll
        spawn_state.options_scroll = math.max(0, math.min(max_opt_scroll, spawn_state.options_scroll))

    -- TAB 2: SAVED VEHICLES
    elseif spawn_state.main_tab == 2 then
        -- Initialize state variables
        spawn_state.saved_vehicles = spawn_state.saved_vehicles or {}
        spawn_state.save_filename = spawn_state.save_filename or ""
        spawn_state.saved_scroll = spawn_state.saved_scroll or 0

        -- Load saved vehicles from disk on first access
        if not spawn_state.saved_vehicles_loaded then
            spawn_state.saved_vehicles_loaded = true
            load_saved_vehicles_from_disk()
        end

        -- Dual column layout
        local gap = math.floor(12 * s)
        local left_w = math.floor(300 * s)
        local right_w = total_w - left_w - gap
        local left_x = base_x
        local right_x = base_x + left_w + gap

        -- LEFT COLUMN: Saved vehicles list
        draw_rect(left_x, content_y, left_w, content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local list_y = content_y + math.floor(12 * s)
        local saved_count = #spawn_state.saved_vehicles
        draw_text("Saved Vehicles (" .. saved_count .. ")", left_x + math.floor(12 * s), list_y, UI.font_small, C.accent)
        list_y = list_y + math.floor(32 * s)

        -- Draw saved vehicles list
        if saved_count == 0 then
            draw_text("No saved vehicles", left_x + math.floor(20 * s), list_y + math.floor(20 * s), UI.font_tiny, C.text_dim)
        else
            -- Simple list without scrolling for now
            local item_h = math.floor(44 * s)
            for i = 1, math.min(#spawn_state.saved_vehicles, 10) do  -- Limit to 10 for testing
                local saved = spawn_state.saved_vehicles[i]
                if saved and saved.name and saved.model then
                    local item_y = list_y + (i - 1) * (item_h + math.floor(4 * s))

                    -- Check mouse hover
                    local item_hover = is_mouse_in(left_x + math.floor(8 * s), item_y, left_w - math.floor(16 * s), item_h)
                    local is_selected = (spawn_state.selected_saved_vehicle == i)

                    -- Draw item background (highlight on hover or if selected)
                    local bg_color = is_selected and C.accent or (item_hover and C.widget_hover or C.widget_bg)
                    draw_rect(left_x + math.floor(8 * s), item_y, left_w - math.floor(16 * s), item_h, bg_color, math.floor(3 * s))

                    -- Draw name
                    local text_color = is_selected and C.bg or (item_hover and C.text or C.text)
                    draw_text(saved.name, left_x + math.floor(16 * s), item_y + math.floor(6 * s), UI.font_tiny, text_color)

                    -- Draw model hash
                    local model_color = is_selected and C.bg or (item_hover and C.text_dim or C.text_dim)
                    draw_text("Hash: " .. tostring(saved.model), left_x + math.floor(16 * s), item_y + math.floor(24 * s), UI.font_tiny, model_color)

                    -- Click to select and spawn
                    if item_hover and MOUSE.just_pressed then
                        debug_info("SAVED_VEH", "CLICKED vehicle " .. i .. ": " .. saved.name .. " (hash: " .. saved.model .. ")")
                        spawn_state.selected_saved_vehicle = i
                        safe_toast("Spawning: " .. saved.name)
                        -- Spawn immediately on click
                        spawn_saved_vehicle(saved)
                    end
                end
            end
        end

        -- RIGHT COLUMN: Save panel
        draw_rect(right_x, content_y, right_w, content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local opt_y = content_y + math.floor(12 * s)
        local opt_x = right_x + math.floor(12 * s)
        local opt_w = right_w - math.floor(24 * s)

        draw_text("Save Current Vehicle", opt_x, opt_y, UI.font_small, C.accent)
        opt_y = opt_y + math.floor(32 * s)

        -- Name input label
        draw_text("Vehicle Name:", opt_x, opt_y, UI.font_tiny, C.text_dim)
        opt_y = opt_y + math.floor(20 * s)

        -- Name input box
        spawn_state.save_input_focused = spawn_state.save_input_focused or false
        local input_h = math.floor(28 * s)
        local input_hover = is_mouse_in(opt_x, opt_y, opt_w, input_h)

        -- Click to focus/unfocus
        if input_hover and MOUSE.just_pressed then
            spawn_state.save_input_focused = not spawn_state.save_input_focused
        end

        -- Keyboard input (like search box in vehicles tab)
        if spawn_state.save_input_focused and input and input.key then
            -- Backspace
            if input.key(0x08).just_pressed then
                if #spawn_state.save_filename > 0 then
                    spawn_state.save_filename = spawn_state.save_filename:sub(1, -2)
                end
            end

            -- Numbers (0-9)
            for code = 0x30, 0x39 do
                if input.key(code).just_pressed then
                    spawn_state.save_filename = spawn_state.save_filename .. string.char(code)
                end
            end

            -- Letters (A-Z)
            for code = 0x41, 0x5A do
                if input.key(code).just_pressed then
                    spawn_state.save_filename = spawn_state.save_filename .. string.char(code):lower()
                end
            end

            -- Space
            if input.key(0x20).just_pressed then
                spawn_state.save_filename = spawn_state.save_filename .. " "
            end
        end

        local input_bg = spawn_state.save_input_focused and C.widget_hover or (input_hover and C.widget_hover or C.widget_bg)
        draw_rect(opt_x, opt_y, opt_w, input_h, input_bg, math.floor((UI.widget_rounding or 5) * s))
        -- Accent border when focused
        if spawn_state.save_input_focused then
            draw_rect(opt_x, opt_y, opt_w, math.floor(2 * s), C.accent, math.floor(6 * s))
            draw_rect(opt_x, opt_y + input_h - math.floor(2 * s), opt_w, math.floor(2 * s), C.accent, math.floor(6 * s))
            draw_rect(opt_x, opt_y, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
            draw_rect(opt_x + opt_w - math.floor(2 * s), opt_y, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
        end

        local display_name = spawn_state.save_filename or ""
        if spawn_state.save_input_focused then
            display_name = display_name .. "_"
        end

        if display_name == "" or display_name == "_" then
            draw_text("Enter name...", opt_x + math.floor(10 * s), opt_y + math.floor(6 * s), UI.font_tiny, color(100,100,100,180))
        else
            draw_text(display_name, opt_x + math.floor(10 * s), opt_y + math.floor(6 * s), UI.font_tiny, C.text)
        end

        opt_y = opt_y + input_h + math.floor(16 * s)

        -- Save button
        local btn_h = math.floor((UI.button_h or 32) * s)
        local save_hover = is_mouse_in(opt_x, opt_y, opt_w, btn_h)
        local save_bg = save_hover and C.accent or C.widget_bg

        draw_rect(opt_x, opt_y, opt_w, btn_h, save_bg, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Save Vehicle", opt_x + math.floor(8 * s), opt_y + math.floor(8 * s), UI.font_tiny, save_hover and C.bg or C.text)

        -- Save button click
        if save_hover and MOUSE.just_pressed then
            save_current_vehicle(spawn_state.save_filename)
        end

    -- TAB 3: PROPS
    elseif spawn_state.main_tab == 3 then
        -- Dual column layout
        local gap = math.floor(12 * s)
        local left_w = math.floor(420 * s)
        local right_w = total_w - left_w - gap
        local left_x = base_x
        local right_x = base_x + left_w + gap

        -- LEFT COLUMN: Prop categories and list
        draw_rect(left_x, content_y, left_w, content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local list_y = content_y + math.floor(12 * s)
        local list_x = left_x + math.floor(12 * s)
        local list_w = left_w - math.floor(24 * s)

        draw_text("Prop Spawner", list_x, list_y, UI.font_small, C.accent)
        list_y = list_y + math.floor(28 * s)

        -- Search bar
        local search_h = math.floor(32 * s)
        local search_box_x = list_x
        local search_box_w = list_w
        local search_hover = is_mouse_in(search_box_x, list_y, search_box_w, search_h)

        -- Click to focus/unfocus (but not on clear button)
        local clear_btn_w_pre = math.floor(24 * s)
        local clear_x_pre = search_box_x + search_box_w - clear_btn_w_pre - math.floor(2 * s)
        local on_clear_btn = #spawn_state.prop_search_query > 0 and is_mouse_in(clear_x_pre, list_y, clear_btn_w_pre, search_h)
        if search_hover and MOUSE.just_pressed and not on_clear_btn then
            spawn_state.prop_search_focused = not spawn_state.prop_search_focused
        end

        -- Keyboard input using input.key (like ClickUI)
        if spawn_state.prop_search_focused and input and input.key then
            -- Backspace
            if input.key(0x08).just_pressed then
                if #spawn_state.prop_search_query > 0 then
                    spawn_state.prop_search_query = spawn_state.prop_search_query:sub(1, -2)
                end
            end
            -- 0-9
            for code = 0x30, 0x39 do
                if input.key(code).just_pressed then
                    spawn_state.prop_search_query = spawn_state.prop_search_query .. string.char(code)
                end
            end
            -- A-Z
            for code = 0x41, 0x5A do
                if input.key(code).just_pressed then
                    spawn_state.prop_search_query = spawn_state.prop_search_query .. string.char(code):lower()
                end
            end
            -- Space
            if input.key(0x20).just_pressed then
                spawn_state.prop_search_query = spawn_state.prop_search_query .. " "
            end
        end

        -- Search box background
        local search_bg = spawn_state.prop_search_focused and C.widget_hover or (search_hover and C.widget_hover or C.widget_bg)
        draw_rect(search_box_x, list_y, search_box_w, search_h, search_bg, math.floor(4 * s))

        -- Accent border when focused
        if spawn_state.prop_search_focused then
            draw_rect(search_box_x, list_y, search_box_w, math.floor(2 * s), C.accent, math.floor(6 * s))
            draw_rect(search_box_x, list_y + search_h - math.floor(2 * s), search_box_w, math.floor(2 * s), C.accent, math.floor(6 * s))
            draw_rect(search_box_x, list_y, math.floor(2 * s), search_h, C.accent, math.floor(6 * s))
            draw_rect(search_box_x + search_box_w - math.floor(2 * s), list_y, math.floor(2 * s), search_h, C.accent, math.floor(6 * s))
        end

        -- Clear button (X) when there is text
        local clear_btn_w = math.floor(24 * s)
        if #spawn_state.prop_search_query > 0 then
            local clear_x = search_box_x + search_box_w - clear_btn_w - math.floor(2 * s)
            local clear_hover = is_mouse_in(clear_x, list_y, clear_btn_w, search_h)
            draw_rect(clear_x, list_y + math.floor(2 * s), clear_btn_w, search_h - math.floor(4 * s), clear_hover and color(80,80,80,200) or color(60,60,60,180), math.floor(4 * s))
            draw_text_centered("X", clear_x, list_y, clear_btn_w, search_h, UI.font_small, clear_hover and color(255,100,100,255) or C.text_dim)
            if clear_hover and MOUSE.just_pressed then
                spawn_state.prop_search_query = ""
            end
        end

        -- Search text / placeholder
        local display_text = spawn_state.prop_search_query
        if spawn_state.prop_search_focused then
            display_text = display_text .. "_"
        end
        local text_x = search_box_x + math.floor(8 * s)
        if #spawn_state.prop_search_query == 0 then
            draw_text("Search props...", text_x, list_y + math.floor(8 * s), UI.font_tiny, color(100,100,100,180))
        else
            draw_text(display_text, text_x, list_y + math.floor(8 * s), UI.font_tiny, spawn_state.prop_search_focused and C.text or C.text)
        end

        list_y = list_y + search_h + math.floor(8 * s)

        draw_text("Click prop to spawn in front of you", list_x, list_y, UI.font_tiny, C.text_dim)
        list_y = list_y + math.floor(20 * s)

        -- Prop categories with collapsible lists
        local item_h = math.floor(32 * s)
        local list_h = content_h - (list_y - content_y) - math.floor(12 * s)
        local list_y_start = list_y

        spawn_state.prop_scroll = spawn_state.prop_scroll or 0
        local scroll_y = list_y_start - spawn_state.prop_scroll
        local total_content = 0

        -- Filter props by search query
        local search_lower = string.lower(spawn_state.prop_search_query)
        local filtered_props = {}
        if search_lower ~= "" then
            -- Build filtered list
            for _, category in ipairs(PROP_CATEGORIES) do
                local props = PROPS_DATA[category]
                if props then
                    for _, prop in ipairs(props) do
                        if string.find(string.lower(prop.name), search_lower, 1, true) then
                            if not filtered_props[category] then
                                filtered_props[category] = {}
                            end
                            table.insert(filtered_props[category], prop)
                        end
                    end
                end
            end
        end

        for _, category in ipairs(PROP_CATEGORIES) do
            local props = search_lower ~= "" and filtered_props[category] or PROPS_DATA[category]
            if props and #props > 0 then
                local header_h = math.floor(28 * s)
                local collapsed = spawn_state.prop_collapsed[category]
                if collapsed == nil then collapsed = true end

                if scroll_y + header_h >= list_y_start and scroll_y <= content_y + content_h then
                    local header_hover = is_mouse_in(list_x, scroll_y, list_w, header_h)
                    draw_rect(list_x, scroll_y, list_w, header_h, header_hover and C.accent or C.header, math.floor((UI.widget_rounding or 5) * s))
                    local arrow = collapsed and ">" or "v"
                    draw_text(arrow .. category .. " (" .. #props .. ")", list_x + math.floor(8 * s), scroll_y + math.floor(6 * s), UI.font_small, C.text)

                    if header_hover and MOUSE.just_pressed then
                        spawn_state.prop_collapsed[category] = not collapsed
                    end
                end
                scroll_y = scroll_y + header_h + math.floor(2 * s)
                total_content = total_content + header_h + math.floor(2 * s)

                if not collapsed then
                    for _, prop in ipairs(props) do
                        if scroll_y + item_h >= list_y_start and scroll_y <= content_y + content_h then
                            local item_hover = is_mouse_in(list_x + math.floor(12 * s), scroll_y, list_w - math.floor(24 * s), item_h)
                            draw_rect(list_x + math.floor(12 * s), scroll_y, list_w - math.floor(24 * s), item_h, item_hover and C.widget_hover or C.widget_bg, math.floor(4 * s))
                            draw_text(prop.name, list_x + math.floor(20 * s), scroll_y + math.floor(8 * s), UI.font_tiny, C.text)

                            if item_hover and MOUSE.just_pressed and not spawn_state.is_spawning then
                                spawn_state.is_spawning = true
                                safe_toast("Spawning: " .. prop.name)

                                util.create_job(function()
                                    pcall(function()
                                        local ped = invoker.call(0xD80958FC74E988A6).int
                                        local pos = invoker.call(0x3FEF770D40960D5A, ped, true).scr_vec3
                                        local heading = invoker.call(0xE83D4F9BA2A38914, ped).float

                                        local rad = math.rad(heading)
                                        local spawn_x = pos.x - math.sin(rad) * 3
                                        local spawn_y = pos.y + math.cos(rad) * 3
                                        local spawn_z = pos.z - 1.0

                                        local hash = prop.hash  -- use stored hash; GET_HASH_KEY(prop.name) fails for display names like "Prop Prlg Snowpile" (spaces/caps give wrong joaat)
                                        invoker.call(0x963D27A58DF860AC, hash)

                                        local timeout = 50
                                        while timeout > 0 and not invoker.call(0x98A4EB5D89A0C952, hash).bool do
                                            timeout = timeout - 1
                                            util.yield()
                                        end

                                        if invoker.call(0x98A4EB5D89A0C952, hash).bool then
                                            local obj = invoker.call(0x509D5878EB39E842, hash, spawn_x, spawn_y, spawn_z, true, true, false).int
                                            if obj and obj ~= 0 then
                                                invoker.call(0xAD738C3085FE7E11, obj, true, true)
                                                invoker.call(0x8E2530AA8ADA980E, obj, heading)
                                                table.insert(spawn_state.spawned_props, obj)
                                                safe_toast("Spawned: " .. prop.name)
                                            end
                                        end
                                        invoker.call(0xE532F5D78798DAAB, hash)
                                    end)
                                    spawn_state.is_spawning = false
                                end)
                            end
                        end
                        scroll_y = scroll_y + item_h + math.floor(2 * s)
                        total_content = total_content + item_h + math.floor(2 * s)
                    end
                end
            end
        end

        local max_scroll = math.max(0, total_content - list_h)
        if is_mouse_in(left_x, list_y_start, left_w, list_h) then
            if MOUSE.scroll_up then
                spawn_state.prop_scroll = math.max(0, spawn_state.prop_scroll - math.floor(40 * s))
            elseif MOUSE.scroll_down then
                spawn_state.prop_scroll = math.min(max_scroll, spawn_state.prop_scroll + math.floor(40 * s))
            end
        end

        -- RIGHT COLUMN: Prop manipulation controls
        draw_rect(right_x, content_y, right_w, content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Initialize right column scroll
        spawn_state.right_scroll = spawn_state.right_scroll or 0
        local right_content_y = content_y + math.floor(12 * s)
        local right_content_h = content_h - math.floor(24 * s)

        local opt_y = right_content_y - spawn_state.right_scroll
        local opt_x = right_x + math.floor(12 * s)
        local opt_w = right_w - math.floor(24 * s)
        local btn_h = math.floor(28 * s)
        local total_right_h = 0

        -- Helper to check if element is visible in scrollable area
        local function is_in_view(y, h)
            return y + h >= right_content_y and y <= right_content_y + right_content_h
        end

        if is_in_view(opt_y, math.floor(32 * s)) then
            draw_text("Prop Controls (" .. #spawn_state.spawned_props .. ")", opt_x, opt_y, UI.font_small, C.accent)
        end
        opt_y = opt_y + math.floor(32 * s)
        total_right_h = total_right_h + math.floor(32 * s)

        if #spawn_state.spawned_props > 0 then
            -- Delete all button
            local del_all_hover = is_in_view(opt_y, btn_h) and is_mouse_in(opt_x, opt_y, opt_w, btn_h)

            if is_in_view(opt_y, btn_h) then
                draw_rect(opt_x, opt_y, opt_w, btn_h, del_all_hover and color(200, 50, 50, 255) or C.widget_bg, math.floor(4 * s))
                draw_text("Delete All Props", opt_x + math.floor(8 * s), opt_y + math.floor(6 * s), UI.font_tiny, C.text)
            end

            if del_all_hover and MOUSE.just_pressed then
                for _, obj in ipairs(spawn_state.spawned_props) do
                    pcall(function()
                        if obj and obj ~= 0 and invoker.call(0x7239B21A38F536BA, obj).bool then
                            -- Detach first
                            invoker.call(0xA7A41F2AD7F12C5C, obj, true, true)
                            -- Freeze position
                            invoker.call(0x428CA6DBD1094446, obj, true)
                            -- Set collision off
                            invoker.call(0x1A9205C1B9EE827F, obj, false, false)
                            -- Make invisible
                            invoker.call(0xEA1C610A04DB6BBB, obj, false, false)
                            util.yield(10)
                            -- Mark as no longer needed
                            invoker.call(0xE532F5D78798DAAB, obj)
                        end
                    end)
                end
                spawn_state.spawned_props = {}
                spawn_state.selected_prop_index = nil
                spawn_state.slider_states = {}
                safe_toast("All props deleted")
            end
            opt_y = opt_y + btn_h + math.floor(12 * s)
            total_right_h = total_right_h + btn_h + math.floor(12 * s)

            -- Cycle through spawned props
            spawn_state.selected_prop_index = spawn_state.selected_prop_index or 1
            if spawn_state.selected_prop_index > #spawn_state.spawned_props then
                spawn_state.selected_prop_index = 1
            end

            if is_in_view(opt_y, math.floor(20 * s)) then
                draw_text("Selected Prop: " .. spawn_state.selected_prop_index .. "/" .. #spawn_state.spawned_props, opt_x, opt_y, UI.font_tiny, C.text_dim)
            end
            opt_y = opt_y + math.floor(20 * s)
            total_right_h = total_right_h + math.floor(20 * s)

            -- Cycle buttons
            local cycle_w = (opt_w - math.floor(8 * s)) / 2
            local prev_hover = is_in_view(opt_y, btn_h) and is_mouse_in(opt_x, opt_y, cycle_w, btn_h)
            local next_hover = is_in_view(opt_y, btn_h) and is_mouse_in(opt_x + cycle_w + math.floor(8 * s), opt_y, cycle_w, btn_h)

            if is_in_view(opt_y, btn_h) then
                draw_rect(opt_x, opt_y, cycle_w, btn_h, prev_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                draw_text("< Previous", opt_x + math.floor(6 * s), opt_y + math.floor(6 * s), UI.font_tiny, C.text)

                draw_rect(opt_x + cycle_w + math.floor(8 * s), opt_y, cycle_w, btn_h, next_hover and C.widget_hover or C.widget_bg, math.floor(4 * s))
                draw_text("Next >", opt_x + cycle_w + math.floor(14 * s), opt_y + math.floor(6 * s), UI.font_tiny, C.text)
            end

            if prev_hover and MOUSE.just_pressed then
                spawn_state.selected_prop_index = spawn_state.selected_prop_index - 1
                if spawn_state.selected_prop_index < 1 then spawn_state.selected_prop_index = #spawn_state.spawned_props end
            elseif next_hover and MOUSE.just_pressed then
                spawn_state.selected_prop_index = spawn_state.selected_prop_index + 1
                if spawn_state.selected_prop_index > #spawn_state.spawned_props then spawn_state.selected_prop_index = 1 end
            end
            opt_y = opt_y + btn_h + math.floor(16 * s)
            total_right_h = total_right_h + btn_h + math.floor(16 * s)

            -- Get selected prop
            local obj = spawn_state.spawned_props[spawn_state.selected_prop_index]
            if obj and invoker.call(0x7239B21A38F536BA, obj).bool then
                -- Initialize slider state for this prop
                spawn_state.slider_states = spawn_state.slider_states or {}
                if not spawn_state.slider_states[obj] then
                    local current_pos = invoker.call(0x3FEF770D40960D5A, obj, true).scr_vec3
                    spawn_state.slider_states[obj] = {
                        pos_x = 0, pos_y = 0, pos_z = 0,
                        rot_x = 0, rot_y = 0, rot_z = 0,
                        attach_x = 0, attach_y = 0, attach_z = 0,
                        attached_to = nil,
                        base_pos = {x = current_pos.x, y = current_pos.y, z = current_pos.z}
                    }
                end
                local slider_state = spawn_state.slider_states[obj]

                -- Prop slider function
                local function prop_slider(label, value, min, max, unit, format)
                    unit = unit or ""
                    format = format or "%s: %.2f%s"
                    local slider_h = math.floor(36 * s)
                    local track_h = math.floor(6 * s)

                    -- Define track dimensions (needed for mouse interaction)
                    local track_y = opt_y + math.floor(22 * s)
                    local track_x = opt_x + math.floor(8 * s)
                    local track_w = opt_w - math.floor(16 * s)

                    -- Check if slider is visible in scroll area
                    local is_visible = is_in_view(opt_y, slider_h)
                    local hover = is_mouse_in(opt_x, opt_y, opt_w, slider_h)

                    if is_visible then
                        draw_rect(opt_x, opt_y, opt_w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                        draw_text(string.format(format, label, value, unit), opt_x + math.floor(8 * s), opt_y + math.floor(4 * s), UI.font_small, C.text)

                        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))
                        local pct = (value - min) / (max - min)
                        local fill_w = track_w * pct
                        if fill_w > 0 then
                            draw_rect(track_x, track_y, fill_w, track_h, C.accent, math.floor(3 * s))
                        end
                    end

                    if hover and MOUSE.pressed then
                        local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
                        value = min + (max - min) * mouse_pct
                    end

                    opt_y = opt_y + slider_h + math.floor(4 * s)
                    total_right_h = total_right_h + slider_h + math.floor(4 * s)
                    return value
                end

                -- Position sliders
                if is_in_view(opt_y, math.floor(18 * s)) then
                    draw_text("Position Sliders", opt_x, opt_y, UI.font_tiny, C.text_dim)
                end
                opt_y = opt_y + math.floor(18 * s)
                total_right_h = total_right_h + math.floor(18 * s)

                slider_state.pos_x = prop_slider("X (Left/Right)", slider_state.pos_x, -25, 25, "m", "%s: %.2f%s")
                slider_state.pos_y = prop_slider("Y (Forward/Back)", slider_state.pos_y, -25, 25, "m", "%s: %.2f%s")
                slider_state.pos_z = prop_slider("Z (Up/Down)", slider_state.pos_z, -25, 25, "m", "%s: %.2f%s")

                -- Apply position relative to base position
                if slider_state.base_pos then
                    invoker.call(0x239A3351AC1DA385, obj, slider_state.base_pos.x + slider_state.pos_x, slider_state.base_pos.y + slider_state.pos_y, slider_state.base_pos.z + slider_state.pos_z, false, false, false)
                end

                -- Rotation sliders
                if is_in_view(opt_y, math.floor(18 * s)) then
                    draw_text("Rotation Sliders", opt_x, opt_y, UI.font_tiny, C.text_dim)
                end
                opt_y = opt_y + math.floor(18 * s)
                total_right_h = total_right_h + math.floor(18 * s)

                slider_state.rot_x = prop_slider("Pitch (Up/Down)", slider_state.rot_x, -180, 180, "°", "%s: %.1f%s")
                slider_state.rot_y = prop_slider("Roll (Lean)", slider_state.rot_y, -180, 180, "°", "%s: %.1f%s")
                slider_state.rot_z = prop_slider("Yaw (Left/Right)", slider_state.rot_z, -180, 180, "°", "%s: %.1f%s")

                -- Apply rotation
                invoker.call(0x8524A8B0171D5E07, obj, slider_state.rot_x, slider_state.rot_y, slider_state.rot_z, 2, true)

                -- Check if attached
                local is_attached = invoker.call(0xB346476EF1A64897, obj).bool
                if is_attached then
                    -- Attachment offset sliders
                    if is_in_view(opt_y, math.floor(18 * s)) then
                        draw_text("Attachment Offset", opt_x, opt_y, UI.font_tiny, C.text_dim)
                    end
                    opt_y = opt_y + math.floor(18 * s)
                    total_right_h = total_right_h + math.floor(18 * s)

                    slider_state.attach_x = prop_slider("Offset X (Left/Right)", slider_state.attach_x, -25, 25, "m", "%s: %.2f%s")
                    slider_state.attach_y = prop_slider("Offset Y (Forward/Back)", slider_state.attach_y, -25, 25, "m", "%s: %.2f%s")
                    slider_state.attach_z = prop_slider("Offset Z (Up/Down)", slider_state.attach_z, -25, 25, "m", "%s: %.2f%s")

                    -- Re-attach with new offset
                    if slider_state.attached_to then
                        invoker.call(0xA7A41F2AD7F12C5C, obj, false, true)
                        invoker.call(0x6B9BBD38AB0796DF, obj, slider_state.attached_to, 0, slider_state.attach_x, slider_state.attach_y, slider_state.attach_z, 0.0, 0.0, 0.0, false, false, false, false, 2, true)
                    end
                end

                -- Attach controls
                local ctrl_h = math.floor(26 * s)
                if is_in_view(opt_y, math.floor(18 * s)) then
                    draw_text("Attachment", opt_x, opt_y, UI.font_tiny, C.text_dim)
                end
                opt_y = opt_y + math.floor(18 * s)
                total_right_h = total_right_h + math.floor(18 * s)

                local attach_labels = {"Attach to Vehicle", "Detach"}
                for i, label in ipairs(attach_labels) do
                    local ax = opt_x + (i-1) * (opt_w / 2 + math.floor(4 * s))
                    local aw = opt_w / 2 - math.floor(2 * s)

                    local a_hover = is_in_view(opt_y, ctrl_h) and is_mouse_in(ax, opt_y, aw, ctrl_h)

                    if is_in_view(opt_y, ctrl_h) then
                        draw_rect(ax, opt_y, aw, ctrl_h, a_hover and C.widget_hover or C.widget_bg, math.floor(3 * s))
                        draw_text(label, ax + math.floor(6 * s), opt_y + math.floor(6 * s), UI.font_tiny, C.text)
                    end

                    if a_hover and MOUSE.just_pressed then
                        if i == 1 then
                            local ped = invoker.call(0xD80958FC74E988A6).int
                            local veh = invoker.call(0x9A9112A0FE9A4713, ped, false).int
                            if veh and veh ~= 0 then
                                slider_state.attached_to = veh
                                invoker.call(0x6B9BBD38AB0796DF, obj, veh, 0, slider_state.attach_x, slider_state.attach_y, slider_state.attach_z, 0.0, 0.0, 0.0, false, false, false, false, 2, true)
                                -- Update base position to current position after attaching
                                local current_pos = invoker.call(0x3FEF770D40960D5A, obj, true).scr_vec3
                                slider_state.base_pos = {x = current_pos.x, y = current_pos.y, z = current_pos.z}
                                slider_state.pos_x = 0
                                slider_state.pos_y = 0
                                slider_state.pos_z = 0
                                safe_toast("Attached to vehicle")
                            else
                                safe_toast("Not in a vehicle")
                            end
                        else
                            -- Detach the prop - turn off collision first, then detach, then turn collision back on
                            invoker.call(0x1A9205C1B9EE827F, obj, false, false)  -- SET_ENTITY_COLLISION off
                            util.yield(10)
                            invoker.call(0xA7A41F2AD7F12C5C, obj, true, true)  -- DETACH_ENTITY
                            util.yield(10)
                            invoker.call(0x1A9205C1B9EE827F, obj, true, true)  -- SET_ENTITY_COLLISION on
                            -- Get current position after detaching
                            local current_pos = invoker.call(0x3FEF770D40960D5A, obj, true).scr_vec3
                            -- Update base position to current position
                            slider_state.base_pos = {x = current_pos.x, y = current_pos.y, z = current_pos.z}
                            slider_state.attached_to = nil
                            slider_state.attach_x = 0
                            slider_state.attach_y = 0
                            slider_state.attach_z = 0
                            slider_state.pos_x = 0
                            slider_state.pos_y = 0
                            slider_state.pos_z = 0
                            -- Ensure prop state reflects collision is on
                            prop_state.collision = true
                            safe_toast("Detached")
                        end
                    end
                end
                opt_y = opt_y + ctrl_h + math.floor(12 * s)
                total_right_h = total_right_h + ctrl_h + math.floor(12 * s)

                -- Advanced controls
                if is_in_view(opt_y, math.floor(18 * s)) then
                    draw_text("Advanced", opt_x, opt_y, UI.font_tiny, C.text_dim)
                end
                opt_y = opt_y + math.floor(18 * s)
                total_right_h = total_right_h + math.floor(18 * s)

                -- Initialize prop states
                spawn_state.prop_states = spawn_state.prop_states or {}
                spawn_state.prop_states[obj] = spawn_state.prop_states[obj] or {frozen = false, collision = true, visible = true, invincible = false}
                local prop_state = spawn_state.prop_states[obj]

                -- Toggle controls in 2 columns
                local toggle_labels = {
                    {"Freeze Position", "frozen"},
                    {"Disable Collision", "collision"},
                    {"Make Invisible", "visible"},
                    {"Invincible", "invincible"}
                }

                for i, data in ipairs(toggle_labels) do
                    local label = data[1]
                    local state_key = data[2]
                    local row = math.floor((i-1) / 2)
                    local col = (i-1) % 2
                    local tx = opt_x + col * (opt_w / 2 + math.floor(4 * s))
                    local ty = opt_y + row * (ctrl_h + math.floor(4 * s))
                    local tw = opt_w / 2 - math.floor(2 * s)

                    -- Check if button should be highlighted
                    local is_active
                    if state_key == "collision" or state_key == "visible" then
                        is_active = not prop_state[state_key]  -- Inverted: blue when disabled/invisible
                    else
                        is_active = prop_state[state_key]  -- Normal: blue when enabled
                    end

                    local t_hover = is_in_view(ty, ctrl_h) and is_mouse_in(tx, ty, tw, ctrl_h)

                    if is_in_view(ty, ctrl_h) then
                        draw_rect(tx, ty, tw, ctrl_h, is_active and C.accent or (t_hover and C.widget_hover or C.widget_bg), math.floor(3 * s))
                        draw_text(label, tx + math.floor(6 * s), ty + math.floor(6 * s), UI.font_tiny, is_active and C.bg or C.text)
                    end

                    if t_hover and MOUSE.just_pressed then
                        if state_key == "frozen" then
                            prop_state.frozen = not prop_state.frozen
                            invoker.call(0x428CA6DBD1094446, obj, prop_state.frozen)  -- FREEZE_ENTITY_POSITION
                        elseif state_key == "collision" then
                            prop_state.collision = not prop_state.collision
                            invoker.call(0x1A9205C1B9EE827F, obj, prop_state.collision, prop_state.collision)  -- SET_ENTITY_COLLISION
                        elseif state_key == "visible" then
                            prop_state.visible = not prop_state.visible
                            invoker.call(0xEA1C610A04DB6BBB, obj, prop_state.visible, false)  -- SET_ENTITY_VISIBLE
                        elseif state_key == "invincible" then
                            prop_state.invincible = not prop_state.invincible
                            invoker.call(0x3882114BDE571AD4, obj, prop_state.invincible)  -- SET_ENTITY_INVINCIBLE
                        end
                        safe_toast((is_active and "Disabled: " or "Enabled: ") .. label)
                    end
                end
                opt_y = opt_y + ctrl_h * 2 + math.floor(16 * s)
                total_right_h = total_right_h + ctrl_h * 2 + math.floor(16 * s)

                -- Delete selected prop
                local del_hover = is_in_view(opt_y, ctrl_h) and is_mouse_in(opt_x, opt_y, opt_w, ctrl_h)

                if is_in_view(opt_y, ctrl_h) then
                    draw_rect(opt_x, opt_y, opt_w, ctrl_h, del_hover and color(200, 50, 50, 255) or C.widget_bg, math.floor(3 * s))
                    draw_text("Delete This Prop", opt_x + math.floor(8 * s), opt_y + math.floor(6 * s), UI.font_tiny, C.text)
                end

                if del_hover and MOUSE.just_pressed then
                    util.create_job(function()
                        pcall(function()
                            if obj and obj ~= 0 and invoker.call(0x7239B21A38F536BA, obj).bool then
                                -- Detach first
                                invoker.call(0xA7A41F2AD7F12C5C, obj, false, true)
                                -- Freeze position
                                invoker.call(0x428CA6DBD1094446, obj, true)
                                -- Set collision off
                                invoker.call(0x1A9205C1B9EE827F, obj, false, false)
                                -- Make invisible
                                invoker.call(0xEA1C610A04DB6BBB, obj, false, false)
                                util.yield(10)
                                -- Mark as no longer needed
                                invoker.call(0xE532F5D78798DAAB, obj)
                            end
                        end)
                    end)
                    spawn_state.prop_states[obj] = nil
                    table.remove(spawn_state.spawned_props, spawn_state.selected_prop_index)
                    if #spawn_state.spawned_props == 0 then
                        spawn_state.selected_prop_index = nil
                    elseif spawn_state.selected_prop_index > #spawn_state.spawned_props then
                        spawn_state.selected_prop_index = #spawn_state.spawned_props
                    end
                    safe_toast("Prop deleted")
                end
                total_right_h = total_right_h + ctrl_h
            else
                -- Prop no longer exists, remove from list
                table.remove(spawn_state.spawned_props, spawn_state.selected_prop_index)
                if #spawn_state.spawned_props == 0 then
                    spawn_state.selected_prop_index = nil
                end
            end
        else
            if is_in_view(opt_y, math.floor(20 * s)) then
                draw_text("No props spawned", opt_x, opt_y, UI.font_tiny, C.text_dim)
            end
            total_right_h = total_right_h + math.floor(20 * s)
        end

        -- Add bottom padding to ensure all content is scrollable
        total_right_h = total_right_h + math.floor(40 * s)

        -- Right column scroll handler
        local max_right_scroll = math.max(0, total_right_h - right_content_h)
        if is_mouse_in(right_x, content_y, right_w, content_h) then
            if MOUSE.scroll_up then
                spawn_state.right_scroll = math.max(0, spawn_state.right_scroll - math.floor(40 * s))
            elseif MOUSE.scroll_down then
                spawn_state.right_scroll = math.min(max_right_scroll, spawn_state.right_scroll + math.floor(40 * s))
            end
        end

    -- TAB 4: MAP BUILDER
    elseif spawn_state.main_tab == 4 then
        -- ADVANCED CONSTRUCTOR TAB
        draw_constructor_ui()

    -- TAB 5: MENYOO XML SPAWNER (ported from ClickUI)
    elseif spawn_state.main_tab == 5 then
        local s = UI.scale
        local gap = math.floor(12 * s)
        local left_w = math.floor(300 * s)
        local right_w = ui_layout.content_w - left_w - gap
        local left_x = base_x
        local right_x = base_x + left_w + gap

        -- ── Fuzzy search helper ──
        local function menyoo_fuzzy(text, query)
            if not query or query == "" then return true end
            if not text then return false end
            local tl, ql = text:lower(), query:lower()
            local ti = 1
            for i = 1, #ql do
                local c = ql:sub(i, i)
                local found = false
                while ti <= #tl do
                    if tl:sub(ti, ti) == c then ti = ti + 1; found = true; break end
                    ti = ti + 1
                end
                if not found then return false end
            end
            return true
        end

        -- ── XML parser: extract first matching tag value ──
        -- ── XML Helpers (ported from UnifiedSpawner) ──
        local function xml_get_element(xml, tag)
            -- Returns the full inner content of <tag>...</tag>
            if not xml or not tag then return nil end
            local pattern = "<" .. tag .. "[^>]*>(.-)</" .. tag .. ">"
            local s, e, inner = xml:find(pattern)
            if s then return inner end
            return nil
        end

        local function xml_get_content(xml, tag)
            local inner = xml_get_element(xml, tag)
            if not inner then return nil end
            return inner:match("^%s*(.-)%s*$")
        end

        local function xml_safe_num(str, default)
            if str == nil then return default end
            if type(str) == "number" then return str end
            str = tostring(str):gsub(",", "."):match("^%s*(.-)%s*$")
            if str == "" then return default end
            return tonumber(str) or default
        end

        -- ── XML Parser: parse Menyoo vehicle XML ──
        local function parse_menyoo_xml(path)
            -- Guard: use file.exists (new Lexis API) before attempting open.
            -- This surfaces path errors early instead of silently returning nil.
            if not (file and file.exists) then
                debug_warn("MENYOO", "file API unavailable")
                return nil
            end
            if not file.exists(path) then
                debug_warn("MENYOO", "File not found: " .. tostring(path))
                return nil
            end
            local raw = nil
            pcall(function()
                local fh = file.open(path, {})
                if fh and fh.valid then raw = fh.text end
            end)
            if not raw or raw == "" then
                debug_warn("MENYOO", "file.open returned empty text for: " .. tostring(path))
                return nil
            end

            -- Detect Spooner/Menyoo map file (SpoonerPlacements root = world-coordinate map)
            if raw:find("<SpoonerPlacements") then
                return { is_spooner_map = true, raw = raw }
            end

            local function get(xml, tag)
                if not xml or not tag then return nil end
                local s, e, inner = xml:find("<" .. tag .. "[^>]*>(.-)</" .. tag .. ">")
                if s then return inner:match("^%s*(.-)%s*$") end
                return nil
            end

            local function num(str, def)
                if str == nil then return def end
                return tonumber((tostring(str):gsub(",", "."))) or def
            end

            local function read_colours(block)
                local vp = get(block, "VehicleProperties")
                local col = vp and get(vp, "Colours")
                local c1 = num(col and get(col, "Primary"), 0)
                local c2 = num(col and get(col, "Secondary"), 0)
                return c1, c2
            end

            local function parse_attachments(spooner)
                local list = {}
                if not spooner then return list end
                local pos = 1
                while true do
                    local os = spooner:find("<Attachment[^>]*>", pos)
                    if not os then break end
                    local depth = 1; local p = os + 1; local ce = nil
                    while depth > 0 and p <= #spooner do
                        local no = spooner:find("<Attachment[^>]*>", p)
                        local nc = spooner:find("</Attachment>", p)
                        if not nc then break end
                        if no and no < nc then depth=depth+1; p=no+1
                        else
                            depth=depth-1
                            if depth==0 then ce=nc+#"</Attachment>"-1; break end
                            p=nc+1
                        end
                    end
                    if not ce then break end

                    local blk = spooner:sub(os, ce)
                    local hash_str = get(blk, "ModelHash")
                    local att_hash = hash_str and tonumber(hash_str)
                    if att_hash then
                        local att_type = num(get(blk, "Type"), 3)
                        local init_h   = num(get(blk, "InitialHandle"), nil)
                        local lod_dist = num(get(blk, "LodDistance"), 16960)

                        local inner_xml = nil
                        local last_inner = nil
                        local is = 1
                        while true do
                            local f = blk:find("<Attachment[^>]*>", is)
                            if not f then break end
                            last_inner = f; is = f + 1
                        end
                        if last_inner then
                            local after = blk:match("<Attachment[^>]*>(.*)", last_inner)
                            if after then
                                local ci = after:find("</Attachment>")
                                if ci then inner_xml = after:sub(1, ci-1) end
                            end
                        end

                        local entry = {
                            model         = att_hash,
                            att_type      = att_type,
                            init_handle   = init_h,
                            lod_distance  = lod_dist,
                            parent_handle = inner_xml and num(get(inner_xml, "AttachedTo"), nil),
                            bone          = inner_xml and num(get(inner_xml, "BoneIndex"), 0) or 0,
                            x             = inner_xml and num(get(inner_xml, "X"), 0.0) or 0.0,
                            y             = inner_xml and num(get(inner_xml, "Y"), 0.0) or 0.0,
                            z             = inner_xml and num(get(inner_xml, "Z"), 0.0) or 0.0,
                            pitch         = inner_xml and num(get(inner_xml, "Pitch"), 0.0) or 0.0,
                            roll          = inner_xml and num(get(inner_xml, "Roll"), 0.0) or 0.0,
                            yaw           = inner_xml and num(get(inner_xml, "Yaw"), 0.0) or 0.0,
                        }
                        if att_type == 2 then
                            entry.colour1, entry.colour2 = read_colours(blk)
                        end
                        table.insert(list, entry)
                    end
                    pos = ce + 1
                end
                return list
            end

            local model_str = get(raw, "ModelHash")
            if not model_str then return nil end
            local model_hash = tonumber(model_str)
            if not model_hash then return nil end

            local init_handle = num(get(raw, "InitialHandle"), nil)
            local c1, c2 = read_colours(raw)

            local spooner_block = nil
            do
                local s, e, inner = raw:find("<SpoonerAttachments[^>]*>(.*)</SpoonerAttachments>")
                spooner_block = inner
            end

            return {
                model       = model_hash,
                colour1     = c1,
                colour2     = c2,
                init_handle = init_handle,
                attachments = parse_attachments(spooner_block),
            }
        end

        -- ── Scan Menyoo folder on disk ──
        local function scan_menyoo_files()
            spawn_state.menyoo_vehicles = {}
            spawn_state.menyoo_loaded = false

            if not (dirs and dirs.exists) then
                safe_toast("[Kyron] Menyoo: dirs API not available")
                spawn_state.menyoo_loaded = true
                return
            end

            -- Check file_read permission — dirs.list silently returns {} without it
            if this and this.permissions and permission and permission.file_read then
                if this.permissions() & permission.file_read == 0 then
                    safe_toast("[Kyron] Menyoo: Missing 'file_read' permission!\nIn Lexis: right-click Kyron script > Permissions > enable file_read, then reload.")
                    spawn_state.menyoo_loaded = true
                    return
                end
            end

            -- paths.script = scripts ROOT folder (e.g. "...\Grand Theft Auto V\scripts\")
            -- NOT the script subfolder. So we must include "Kyron\" explicitly.
            -- Also try paths.game as a second source for the same path.
            local candidates = {}
            if paths and paths.script then
                local s = paths.script
                if not s:match("[/\\]$") then s = s .. "\\" end
                -- Primary: scripts root + Kyron subfolder + Vehicles\Menyoo
                table.insert(candidates, s .. "Kyron\\Vehicles\\Menyoo\\")
                -- Fallback: in case paths.script already includes the script name
                table.insert(candidates, s .. "Vehicles\\Menyoo\\")
            end
            if paths and paths.game then
                local g = paths.game
                if not g:match("[/\\]$") then g = g .. "\\" end
                table.insert(candidates, g .. "scripts\\Kyron\\Vehicles\\Menyoo\\")
            end

            local base_dir = nil
            for _, c in ipairs(candidates) do
                local ok, exists = pcall(dirs.exists, c)
                if ok and exists then
                    base_dir = c
                    break
                end
            end

            if not base_dir then
                local tried = {}
                for _, c in ipairs(candidates) do tried[#tried+1] = c end
                safe_toast("[Kyron] Menyoo folder not found.\nTried:\n" .. table.concat(tried, "\n"))
                spawn_state.menyoo_loaded = true
                return
            end

            -- Helper: scan XML files in a single folder using new Lexis API
            local function scan_xml_in_folder(folder, subfolder_label)
                folder = folder:gsub("[/\\]?$", "\\")
                if not dirs.exists(folder) then return end

                -- Diagnostic: try no filter first to see what dirs.list actually returns
                local ok_all, all_files = pcall(dirs.list, folder)
                local ok_xml, xml_files = pcall(dirs.list, folder, "xml")
                local ok_dotxml, dotxml_files = pcall(dirs.list, folder, ".xml")

                -- Use whichever returned results
                local files = nil
                if ok_xml and xml_files and #xml_files > 0 then
                    files = xml_files
                elseif ok_dotxml and dotxml_files and #dotxml_files > 0 then
                    files = dotxml_files
                elseif ok_all and all_files and #all_files > 0 then
                    -- filter manually for .xml
                    files = {}
                    for _, fp in ipairs(all_files) do
                        if fp:lower():match("%.xml$") then
                            table.insert(files, fp)
                        end
                    end
                end

                -- Toast diagnostics for the ROOT folder scan only so we see what happened
                if subfolder_label == "Root" then
                    local all_count = (ok_all and all_files) and #all_files or 0
                    local xml_count = (ok_xml and xml_files) and #xml_files or 0
                    local dotxml_count = (ok_dotxml and dotxml_files) and #dotxml_files or 0
                    local first = (ok_all and all_files and #all_files > 0) and tostring(all_files[1]) or "none"
                    safe_toast("[Kyron] Menyoo diag: all=" .. all_count
                        .. " xml=" .. xml_count
                        .. " .xml=" .. dotxml_count
                        .. "\nFirst file: " .. first)
                end

                if not files then return end
                for _, fp in ipairs(files) do
                    local fname = fp:match("[/\\]([^/\\]+)%.xml$") or fp:match("([^/\\]+)%.xml$") or fp:match("[^/\\]+$")
                    if fname then
                        fname = fname:gsub("%.xml$", "")
                        -- Always construct full absolute path from the known folder + filename.
                        -- dirs.list may return bare filenames after the v10 fix; using fp
                        -- directly with file.open would then fail the "within Lexis folder" check.
                        local full_path = folder .. fname .. ".xml"
                        local xml_model_hash = nil
                        pcall(function()
                            if file and file.exists and file.exists(full_path) then
                                local xf = file.open(full_path, {})
                                if xf and xf.valid and xf.text then
                                    local chunk = xf.text:sub(1, 4096)
                                    local hs = chunk:match("<ModelHash>%s*(0x%x+)%s*</ModelHash>")
                                              or chunk:match("<ModelHash>%s*(%d+)%s*</ModelHash>")
                                              or chunk:match("<ModelHash>%s*(-?%d+)%s*</ModelHash>")
                                    if hs then xml_model_hash = tonumber(hs) end
                                end
                            end
                        end)
                        table.insert(spawn_state.menyoo_vehicles, {
                            name            = fname,
                            path            = full_path,    -- guaranteed full absolute path
                            subfolder       = subfolder_label or "Root",
                            model_hash_hint = xml_model_hash,
                        })
                    end
                end
            end

            -- 1) Scan root XML files
            scan_xml_in_folder(base_dir, "Root")

            -- 2) Read folders.txt using file.open (new Lexis API — io.open is path-restricted)
            local folders_txt = base_dir .. "folders.txt"
            local loaded_from_txt = false
            if file and file.open then
                local fh = file.open(folders_txt, {})
                if fh and fh.valid and fh.text and fh.text ~= "" then
                    loaded_from_txt = true
                    for line in fh.text:gmatch("[^\r\n]+") do
                        line = line:match("^%s*(.-)%s*$")  -- trim whitespace
                        if line and line ~= "" and not line:match("^#") then
                            local sub_path = base_dir .. line .. "\\"
                            scan_xml_in_folder(sub_path, line)
                        end
                    end
                end
            end

            if not loaded_from_txt then
                -- No folders.txt: use dirs.scan to list subdirectories (added 5/25/2026)
                local ok_d, subdirs = pcall(dirs.scan, base_dir)
                if ok_d and subdirs then
                    for _, subdir in ipairs(subdirs) do
                        local dname = subdir:match("[/\\]([^/\\]+)[/\\]?$") or subdir
                        scan_xml_in_folder(subdir:gsub("[/\\]?$", "\\"), dname)
                    end
                end
            end

            table.sort(spawn_state.menyoo_vehicles, function(a, b)
                if a.subfolder ~= b.subfolder then return a.subfolder < b.subfolder end
                return a.name:lower() < b.name:lower()
            end)

            spawn_state.menyoo_loaded = true
            -- Collapse all folders by default after scan
            spawn_state.menyoo_collapsed = {}
            local _seen_grps_m = {}
            for _, v in ipairs(spawn_state.menyoo_vehicles) do
                local g = v.subfolder or "Root"
                if not _seen_grps_m[g] then _seen_grps_m[g] = true; spawn_state.menyoo_collapsed[g] = true end
            end
            local total = #spawn_state.menyoo_vehicles
            if total > 0 then
                safe_toast("Menyoo: Loaded " .. total .. " vehicles")
            else
                safe_toast("Menyoo: No XML files found.\nFound folder: " .. tostring(base_dir) .. "\ndirs.list returned 0 xml files")
            end
        end

        -- ── Spawn a Menyoo XML vehicle ──
        -- Uses the same approach as UnifiedSpawner: request.model + CREATE_VEHICLE,
        -- then ATTACH_ENTITY_TO_ENTITY with scr_vec3 objects (required by Lexis).
        local function spawn_menyoo_vehicle(entry)
            if spawn_state.menyoo_is_spawning then return end
            spawn_state.menyoo_is_spawning = true

            util.create_job(function()
                local xml_data = parse_menyoo_xml(entry.path)
                if not xml_data then
                    safe_toast("Menyoo: Could not parse XML: " .. entry.name)
                    spawn_state.menyoo_is_spawning = false
                    return
                end

                -- ── SPOONER MAP MODE: each <Placement> has absolute world coords ──
                if xml_data.is_spooner_map then
                    local raw = xml_data.raw

                    local function xget(xml, tag)
                        if not xml or not tag then return nil end
                        local _, _, inner = xml:find("<" .. tag .. "[^>]*>(.-)</" .. tag .. ">")
                        if inner then return inner:match("^%s*(.-)%s*$") end
                        return nil
                    end
                    local function xnum(v, d)
                        local n = tonumber(v); return n ~= nil and n or d
                    end
                    local function xbool(v)
                        if v == nil then return nil end
                        local s = tostring(v):lower():match("^%s*(.-)%s*$")
                        return s == "true" or s == "1" or s == "yes"
                    end
                    local function xget_block(xml, tag)
                        if not xml then return nil end
                        local os, oe = xml:find("<" .. tag .. "[^>]*>")
                        if not os then return nil end
                        local cs = xml:find("</" .. tag .. ">", oe + 1)
                        if not cs then return nil end
                        return xml:sub(oe + 1, cs - 1)
                    end
                    local model_cache = {}  -- hash -> true/false, avoids re-requesting same model
                    local function map_request_model(hash)
                        if not hash or hash == 0 then return false end
                        if model_cache[hash] ~= nil then return model_cache[hash] end
                        -- request.model is the new Lexis blocking API; handles timeout internally.
                        local ok = request.model(hash)
                        model_cache[hash] = ok
                        return ok
                    end

                    if spawn_state.menyoo_delete_old then
                        for _, h in ipairs(spawn_state.menyoo_last_attachments or {}) do
                            if h and h ~= 0 then pcall(entities.delete, h) end
                        end
                        spawn_state.menyoo_last_attachments = {}
                        if spawn_state.menyoo_last_spawned and spawn_state.menyoo_last_spawned ~= 0 then
                            pcall(entities.delete, spawn_state.menyoo_last_spawned)
                            spawn_state.menyoo_last_spawned = nil
                        end
                        -- Also delete previous map objects
                        for _, h in ipairs(spawn_state.menyoo_map_spawned or {}) do
                            if h and h ~= 0 then pcall(entities.delete, h) end
                        end
                        spawn_state.menyoo_map_spawned = {}
                        spawn_state.menyoo_map_name = nil
                        util.yield(100)
                    end

                    local spawned = spawn_state.menyoo_map_spawned
                    spawn_state.menyoo_map_name = entry.name

                    safe_toast("Menyoo Map: Spawning " .. entry.name .. "...")
                    local spawned_count = 0
                    local failed_count  = 0
                    local search_pos    = 1
                    local obj_index     = 0

                    while true do
                        local ts, te = raw:find("<Placement[^>]*>", search_pos)
                        if not ts then break end
                        local ce_s, ce_e = raw:find("</Placement>", te)
                        if not ce_s then break end
                        local block = raw:sub(ts, ce_s + #"</Placement>" - 1)
                        search_pos = ce_e + 1
                        obj_index  = obj_index + 1

                        pcall(function()
                            local hash_str = xget(block, "ModelHash")
                            if not hash_str then return end

                            local model_hash
                            if hash_str:match("^0[xX]") then
                                model_hash = tonumber(hash_str:sub(3), 16)
                            else
                                model_hash = tonumber(hash_str)
                            end
                            if not model_hash or model_hash == 0 then return end

                            local ent_type   = xget(block, "Type") or "3"
                            local frozen     = xbool(xget(block, "FrozenPos"))
                            local dyn_str    = xget(block, "Dynamic")
                            local dynamic    = (dyn_str == nil) and true or xbool(dyn_str)

                            local pr = xget_block(block, "PositionRotation")
                            if not pr then return end

                            local coords = {}
                            for tag, val in pr:gmatch("<([%w_]+)>([^<]*)</[%w_]+>") do
                                coords[tag] = xnum(val:match("^%s*(.-)%s*$"), 0)
                            end
                            local px    = coords.X     or 0
                            local py    = coords.Y     or 0
                            local pz    = coords.Z     or 0
                            local pitch = coords.Pitch or 0
                            local roll  = coords.Roll  or 0
                            local yaw   = coords.Yaw   or 0

                            if not map_request_model(model_hash) then
                                failed_count = failed_count + 1
                                return
                            end

                            local ent = 0
                            local typ = tostring(ent_type)
                            if typ == "2" or invoker.call(0x9F7BCA5B9751FA19, model_hash).bool then
                                ent = _menyoo_spawn_veh(model_hash, px, py, pz, yaw) or 0
                            elseif typ == "1" or invoker.call(0x71A6D1ED7E8A94F9, model_hash).bool then
                                ent = _menyoo_spawn_ped(model_hash, px, py, pz, yaw) or 0
                            else
                                ent = _menyoo_spawn_obj(model_hash, px, py, pz) or 0
                            end

                            if ent == 0 then failed_count = failed_count + 1; return end

                            -- spawn.* already registers + networks the entity; just request control
                            pcall(invoker.call, 0xB69317BF5E782347, ent)  -- NETWORK_REQUEST_CONTROL_OF_ENTITY
                            invoker.call(0xAD738C3085FE7E11, ent, true, true)
                            invoker.call(0x428CA6DBD1094446, ent, true)  -- freeze first
                            invoker.call(0x8524A8B0171D5E07, ent, 1.0*pitch, 1.0*roll, 1.0*yaw, 2, true)
                            invoker.call(0x239A3351AC1DA385, ent, 1.0*px, 1.0*py, 1.0*pz, true, true, false)
                            invoker.call(0x0DC7CABAB1E9B67E, model_hash)
                            table.insert(spawned, ent)
                            spawned_count = spawned_count + 1
                        end)

                        if obj_index % 10 == 0 then util.yield(0) end
                    end

                    safe_toast("Menyoo Map: Done! " .. spawned_count .. " spawned" ..
                        (failed_count > 0 and (" (" .. failed_count .. " failed)") or "") ..
                        " from " .. entry.name)

                    -- Teleport to first spawned object if option is on
                    if spawn_state.menyoo_teleport and #spawned > 0 then
                        util.yield(300)
                        local first = spawned[1]
                        if first and first ~= 0 then
                            local ok_p, pos = pcall(invoker.call, 0x3FEF770D40960D5A, first, true)
                            if ok_p and pos and pos.x then
                                local my_ped = invoker.call(0x43A66C31C68491C0, -1).int
                                if my_ped and my_ped ~= 0 then
                                    pcall(invoker.call, 0x06843DA7060A026B, my_ped, 1.0*pos.x, 1.0*pos.y, 1.0*(pos.z + 2.0), false, false, false, true)
                                end
                            end
                        end
                    end

                    spawn_state.menyoo_is_spawning = false
                    return
                end
                -- ── END SPOONER MAP MODE ──

                if spawn_state.menyoo_delete_old then
                    for _, h in ipairs(spawn_state.menyoo_last_attachments or {}) do
                        if h and h ~= 0 then pcall(entities.delete, h) end
                    end
                    spawn_state.menyoo_last_attachments = {}
                    if spawn_state.menyoo_last_spawned and spawn_state.menyoo_last_spawned ~= 0 then
                        pcall(entities.delete, spawn_state.menyoo_last_spawned)
                        spawn_state.menyoo_last_spawned = nil
                    end
                    util.yield(100)
                end

                local ped = invoker.call(0x43A66C31C68491C0, -1).int
                if not ped or ped == 0 then
                    safe_toast("Menyoo: No player ped")
                    spawn_state.menyoo_is_spawning = false
                    return
                end
                local coords = invoker.call(0x3FEF770D40960D5A, ped, false).scr_vec3
                if not coords or not coords.x then
                    safe_toast("Menyoo: Could not get coords")
                    spawn_state.menyoo_is_spawning = false
                    return
                end
                local heading = invoker.call(0xE83A169BE1F8E88F, ped, false).flo or 0.0
                local sx = coords.x - math.sin(math.rad(heading)) * 5.0
                local sy = coords.y + math.cos(math.rad(heading)) * 5.0
                local sz = coords.z + 1.0

                local function load_model(hash)
                    -- request.model is the new Lexis blocking API (docs.lexis.re/docs/api/request)
                    -- It handles REQUEST_MODEL + HAS_MODEL_LOADED polling internally.
                    return request.model(hash)
                end

                if not load_model(xml_data.model) then
                    safe_toast("Menyoo: Model failed to load")
                    spawn_state.menyoo_is_spawning = false
                    return
                end

                if spawn_state.menyoo_spawn_in_air then
                    local ip = invoker.call(0xA0948AB42D7BA0DE, xml_data.model).bool
                    local ih = invoker.call(0xDCE4334788AF94EA, xml_data.model).bool
                    if ip or ih then sz = sz + 30.0 end
                end

                local root_veh = _menyoo_spawn_veh(xml_data.model, sx, sy, sz, heading)
                invoker.call(0xE532F5D78798DAAB, xml_data.model)

                -- spawn.vehicle returns nil on failure (not 0), guard for both
                if not root_veh or root_veh == 0 then
                    safe_toast("Menyoo: Spawn failed")
                    spawn_state.menyoo_is_spawning = false
                    return
                end

                spawn_state.menyoo_last_spawned = root_veh
                spawn_state.menyoo_last_attachments = {}

                invoker.call(0xAD738C3085FE7E11, root_veh, true, true)
                invoker.call(0x8E2C98D9CAF3DB09, root_veh, heading)
                invoker.call(0x4F1D4BE3422D8E0, root_veh, xml_data.colour1, xml_data.colour2)
                -- Clear stolen flag and allow blend so others can actually drive
                pcall(invoker.call, 0x67B2C79AA7FF5738, root_veh, false)  -- SET_VEHICLE_IS_STOLEN false
                pcall(invoker.call, 0x9B8E5CC6B20562E9, root_veh, true)   -- NETWORK_SET_ENTITY_CAN_BLEND

                local mt = 0
                while mt < 50 do
                    local r = invoker.call(0x48B0AABB8E95D7F3, root_veh)
                    if r and r.bool then break end
                    mt = mt + 1; util.yield(100)
                end

                if spawn_state.menyoo_godmode   then invoker.call(0x3882114BDE571AD4, root_veh, true) end
                if spawn_state.menyoo_engine_on then invoker.call(0x2497C4717C8B881E, root_veh, true, true, false) end
                if spawn_state.menyoo_radio_off then
                    invoker.call(0x3B988190C0AA6C0B, root_veh, false)
                    invoker.call(0x1B9C0099CB942AC6, root_veh, "RADIO_OFF")
                end
                if spawn_state.menyoo_invisible then
                    invoker.call(0x44A0870B7E92D7C0, root_veh, 0, false)
                    invoker.call(0xEA1C610A04DB6BBB, root_veh, false, false)
                end
                if spawn_state.menyoo_max_upgrade then
                    invoker.call(0x1F2AA07F00B3217A, root_veh, 0)
                    for i = 0, 49 do
                        local n = invoker.call(0x33F2E3FE70EAAE1D, root_veh, i).int
                        if n and n > 0 then invoker.call(0x6AF0636DDEDCB6DD, root_veh, i, n-1, false) end
                    end
                end

                local parent_map = { [0] = root_veh }
                if xml_data.init_handle then
                    parent_map[xml_data.init_handle] = root_veh
                    parent_map[tostring(xml_data.init_handle)] = root_veh
                end

                for _, att in ipairs(xml_data.attachments) do
                    pcall(function()
                        if not load_model(att.model) then return end

                        local ent = 0
                        if att.att_type == 2 then
                            ent = _menyoo_spawn_veh(att.model, sx, sy, sz, heading) or 0
                        else
                            ent = _menyoo_spawn_obj(att.model, sx, sy, sz) or 0
                        end
                        invoker.call(0xE532F5D78798DAAB, att.model)

                        if not ent or ent == 0 then return end

                        invoker.call(0xAD738C3085FE7E11, ent, true, true)
                        invoker.call(0x1A9205C1B9EE827F, ent, true, true)

                        if att.att_type == 2 and att.colour1 then
                            local vmt = 0
                            while vmt < 30 do
                                local r = invoker.call(0x48B0AABB8E95D7F3, ent)
                                if r and r.bool then break end
                                vmt = vmt + 1; util.yield(100)
                            end
                            invoker.call(0x4F1D4BE3422D8E0, ent, att.colour1, att.colour2 or 0)
                        end

                        local parent_h = parent_map[att.parent_handle]
                                      or parent_map[tostring(att.parent_handle or "")]
                                      or root_veh

                        if att.init_handle then
                            parent_map[att.init_handle] = ent
                            parent_map[tostring(att.init_handle)] = ent
                        end

                        local bone = (att.bone and att.bone >= 0) and att.bone or 0
                        pcall(function()
                            invoker.call(0x6B9BBD38AB0796DF,
                                ent, parent_h, bone,
                                att.x or 0.0, att.y or 0.0, att.z or 0.0,
                                att.pitch or 0.0, att.roll or 0.0, att.yaw or 0.0,
                                false, false, true, false, 2, true, false)
                        end)
                        pcall(function() invoker.call(0x53E0DF1A2A3CF0CA, ent, true) end)
                        pcall(function() invoker.call(0x5927F96A78577363, ent, att.lod_distance or 16960) end)  -- SET_ENTITY_LOD_DIST

                        table.insert(spawn_state.menyoo_last_attachments, ent)
                    end)
                end

                if spawn_state.menyoo_teleport and root_veh ~= 0 then
                    util.yield(200)
                    invoker.call(0xF75B0D629E1C063D, ped, root_veh, -1)
                end

                safe_toast("Menyoo: Spawned " .. entry.name)
                spawn_state.menyoo_is_spawning = false
            end)
        end

        -- ─────────────────────────────────────────────────────────────────────
        -- LEFT COLUMN: File list with search
        -- ─────────────────────────────────────────────────────────────────────
        draw_rect(left_x, content_y, left_w, content_h, C.sidebar, math.floor(5 * s))

        -- Header
        local hdr_h = math.floor(28 * s)
        draw_rect(left_x, content_y, left_w, hdr_h, C.header, math.floor(5 * s))
        local xml_count = #spawn_state.menyoo_vehicles
        draw_text("Menyoo XML Vehicles (" .. xml_count .. ")", left_x + math.floor(8 * s), content_y + math.floor(6 * s), UI.font_small, C.text)

        -- Search bar
        local search_h = math.floor(30 * s)
        local search_y2 = content_y + hdr_h + math.floor(4 * s)
        local search_x2 = left_x + math.floor(6 * s)
        local search_w2 = left_w - math.floor(12 * s)
        local s_hover = is_mouse_in(search_x2, search_y2, search_w2, search_h)
        local on_clear = #spawn_state.menyoo_search > 0 and
                         is_mouse_in(search_x2 + search_w2 - math.floor(26 * s), search_y2, math.floor(24 * s), search_h)

        if s_hover and MOUSE.just_pressed and not on_clear then
            spawn_state.menyoo_search_focused = not spawn_state.menyoo_search_focused
        end
        if spawn_state.menyoo_search_focused and input and input.key then
            if input.key(0x08).just_pressed and #spawn_state.menyoo_search > 0 then
                spawn_state.menyoo_search = spawn_state.menyoo_search:sub(1, -2)
            end
            for code = 0x30, 0x39 do
                if input.key(code).just_pressed then
                    spawn_state.menyoo_search = spawn_state.menyoo_search .. string.char(code)
                end
            end
            for code = 0x41, 0x5A do
                if input.key(code).just_pressed then
                    spawn_state.menyoo_search = spawn_state.menyoo_search .. string.char(code):lower()
                end
            end
            if input.key(0x20).just_pressed then
                spawn_state.menyoo_search = spawn_state.menyoo_search .. " "
            end
        end

        local s_bg = (spawn_state.menyoo_search_focused or s_hover) and C.widget_hover or C.widget_bg
        draw_rect(search_x2, search_y2, search_w2, search_h, s_bg, math.floor(4 * s))
        if spawn_state.menyoo_search_focused then
            draw_rect(search_x2, search_y2 + search_h - math.floor(2 * s), search_w2, math.floor(2 * s), C.accent, 0)
        end
        if #spawn_state.menyoo_search > 0 then
            local cx = search_x2 + search_w2 - math.floor(26 * s)
            local c_hover = is_mouse_in(cx, search_y2, math.floor(24 * s), search_h)
            draw_rect(cx, search_y2 + math.floor(3 * s), math.floor(22 * s), search_h - math.floor(6 * s), c_hover and color(80,80,80,200) or color(60,60,60,180), math.floor(4 * s))
            draw_text_centered("X", cx, search_y2, math.floor(22 * s), search_h, UI.font_small, c_hover and color(255,100,100,255) or C.text_dim)
            if c_hover and MOUSE.just_pressed then spawn_state.menyoo_search = "" end
        end
        local disp_txt = spawn_state.menyoo_search .. (spawn_state.menyoo_search_focused and "_" or "")
        if #spawn_state.menyoo_search == 0 then
            draw_text("Search XML files...", search_x2 + math.floor(10 * s), search_y2 + math.floor(8 * s), UI.font_small, color(100,100,100,180))
        else
            draw_text(disp_txt, search_x2 + math.floor(10 * s), search_y2 + math.floor(8 * s), UI.font_small, C.text)
        end

        -- Vehicle list (scrollable, grouped by subfolder)
        local list_top = search_y2 + search_h + math.floor(6 * s)
        local list_h2  = content_h - hdr_h - search_h - math.floor(16 * s)
        local item_h   = math.floor(30 * s)
        local cat_h    = math.floor(26 * s)

        -- Filter
        local filtered_groups = {}
        local total_filtered = 0
        for _, v in ipairs(spawn_state.menyoo_vehicles) do
            if menyoo_fuzzy(v.name, spawn_state.menyoo_search) or (v.model_hash_hint and menyoo_fuzzy(spawn_state.hash_to_model[v.model_hash_hint] or "", spawn_state.menyoo_search)) then
                local grp = v.subfolder or "Root"
                if not filtered_groups[grp] then filtered_groups[grp] = {} end
                table.insert(filtered_groups[grp], v)
                total_filtered = total_filtered + 1
            end
        end

        -- Measure total scroll height
        local scroll_total = 0
        local sorted_groups = {}
        for grp in pairs(filtered_groups) do table.insert(sorted_groups, grp) end
        table.sort(sorted_groups)

        for _, grp in ipairs(sorted_groups) do
            scroll_total = scroll_total + cat_h + math.floor(4 * s)
            if not spawn_state.menyoo_collapsed[grp] then
                scroll_total = scroll_total + #filtered_groups[grp] * item_h
            end
        end

        -- Mouse scroll
        if is_mouse_in(left_x, list_top, left_w, list_h2) then
            if MOUSE.scroll_up then
                spawn_state.menyoo_scroll = spawn_state.menyoo_scroll - math.floor(30 * s)
            elseif MOUSE.scroll_down then
                spawn_state.menyoo_scroll = spawn_state.menyoo_scroll + math.floor(30 * s)
            end
        end
        local max_scroll = math.max(0, scroll_total - list_h2)
        spawn_state.menyoo_scroll = math.max(0, math.min(spawn_state.menyoo_scroll, max_scroll))

        -- Draw list background panel (acts as visual clip boundary)
        draw_rect(left_x, list_top, left_w, list_h2, C.sidebar, math.floor(4 * s))

        local list_bottom = list_top + list_h2
        local draw_y = list_top - spawn_state.menyoo_scroll

        if xml_count == 0 then
            if not spawn_state.menyoo_loaded then
                draw_text("Click 'Scan Folder' to load XML files", left_x + math.floor(8 * s), list_top + math.floor(12 * s), UI.font_small, C.text_dim)
            else
                draw_text("No XML vehicles found.", left_x + math.floor(8 * s), list_top + math.floor(12 * s), UI.font_small, C.text_dim)
                draw_text("Expected path:", left_x + math.floor(8 * s), list_top + math.floor(28 * s), UI.font_small, C.text_dim)
                draw_text("scripts\\Kyron\\vehicles\\Menyoo\\", left_x + math.floor(8 * s), list_top + math.floor(44 * s), UI.font_small, C.accent)
                draw_text("(Check debug log F1 for tried paths)", left_x + math.floor(8 * s), list_top + math.floor(62 * s), UI.font_small, color(150,150,150,200))
            end
        else
            for _, grp in ipairs(sorted_groups) do
                local vehicles_in_grp = filtered_groups[grp]

                -- Group header (collapsible) - only draw if inside visible area
                if draw_y + cat_h > list_top and draw_y < list_bottom then
                    local clipped_cat_h = math.min(cat_h, list_bottom - draw_y)
                    local grp_hover = is_mouse_in(left_x + math.floor(4 * s), draw_y, left_w - math.floor(8 * s), clipped_cat_h)
                    local grp_bg = grp_hover and C.widget_hover or C.header
                    draw_rect(left_x + math.floor(4 * s), draw_y, left_w - math.floor(8 * s), clipped_cat_h, grp_bg, math.floor(4 * s))
                    if draw_y + math.floor(5 * s) < list_bottom then
                        local arrow = spawn_state.menyoo_collapsed[grp] and ">" or "v"
                        draw_text(arrow .. "  " .. grp .. " (" .. #vehicles_in_grp .. ")",
                            left_x + math.floor(10 * s), draw_y + math.floor(5 * s), UI.font_small, C.text)
                    end
                    if grp_hover and MOUSE.just_pressed then
                        spawn_state.menyoo_collapsed[grp] = not spawn_state.menyoo_collapsed[grp]
                    end
                end
                draw_y = draw_y + cat_h + math.floor(4 * s)

                -- Items - only draw if inside visible area
                if not spawn_state.menyoo_collapsed[grp] then
                    for _, v in ipairs(vehicles_in_grp) do
                        if draw_y + item_h > list_top and draw_y < list_bottom then
                            local clipped_item_h = math.min(item_h - math.floor(4 * s), list_bottom - draw_y - math.floor(2 * s))
                            if clipped_item_h > 0 then
                                local btn_x = left_x + math.floor(12 * s)
                                local btn_w = left_w - math.floor(20 * s)
                                local btn_hover = is_mouse_in(btn_x, draw_y + math.floor(2 * s), btn_w, clipped_item_h)
                                local btn_bg = btn_hover and C.widget_hover or C.widget_bg
                                draw_rect(btn_x, draw_y + math.floor(2 * s), btn_w, clipped_item_h, btn_bg, math.floor(4 * s))
                                if draw_y + math.floor(8 * s) < list_bottom then
                                    draw_text(v.name, btn_x + math.floor(8 * s), draw_y + math.floor(8 * s), UI.font_small, C.text)
                                end
                                if btn_hover then
                                    -- Cache model hash from XML path (quick string search, no full parse)
                                    if not v._preview_hash and v.path then
                                        pcall(function()
                                            -- Use file.open (new Lexis API) — io.open is path-restricted
                                            if file and file.open then
                                                local xf = file.open(v.path, {})
                                                if xf and xf.valid and xf.text then
                                                    local chunk = xf.text:sub(1, 2048)
                                                    local hs = chunk:match("<ModelHash>%s*(0x%x+)%s*</ModelHash>")
                                                             or chunk:match("<ModelHash>%s*(%d+)%s*</ModelHash>")
                                                    if hs then v._preview_hash = tonumber(hs) end
                                                end
                                            end
                                        end)
                                    end
                                    if v._preview_hash then spawn_state.preview_hovered_model = v._preview_hash end
                                end
                                if btn_hover and MOUSE.just_pressed then
                                    spawn_menyoo_vehicle(v)
                                end
                            end
                        end
                        draw_y = draw_y + item_h
                        if draw_y >= list_bottom then break end
                    end
                end
                if draw_y >= list_bottom then break end
            end
        end

        -- ─────────────────────────────────────────────────────────────────────
        -- RIGHT COLUMN: Options panel
        -- ─────────────────────────────────────────────────────────────────────
        draw_rect(right_x, content_y, right_w, content_h, C.sidebar, math.floor(5 * s))

        local oh = math.floor(28 * s)
        draw_rect(right_x, content_y, right_w, oh, C.header, math.floor(5 * s))
        draw_text("Spawn Options", right_x + math.floor(8 * s), content_y + math.floor(6 * s), UI.font_small, C.text)

        local opt_x       = right_x + math.floor(10 * s)
        local opt_w       = right_w - math.floor(20 * s)
        local opt_panel_y = content_y + oh  -- content starts after header
        local opt_panel_h = content_h - oh  -- available height for scrollable content

        -- Scroll the options panel
        if is_mouse_in(right_x, opt_panel_y, right_w, opt_panel_h) then
            if MOUSE.scroll_up then
                spawn_state.menyoo_options_scroll = spawn_state.menyoo_options_scroll - math.floor(30 * s)
            elseif MOUSE.scroll_down then
                spawn_state.menyoo_options_scroll = spawn_state.menyoo_options_scroll + math.floor(30 * s)
            end
        end

        -- We'll compute total height after, clamp scroll
        local oy_start = opt_panel_y + math.floor(8 * s) - spawn_state.menyoo_options_scroll
        local oy_cur   = oy_start
        local opt_bot  = opt_panel_y + opt_panel_h  -- bottom boundary

        -- Scan button
        local scan_h = math.floor(32 * s)
        if oy_cur + scan_h > opt_panel_y and oy_cur < opt_bot then
            local scan_hover = is_mouse_in(opt_x, oy_cur, opt_w, scan_h)
            draw_rect(opt_x, oy_cur, opt_w, scan_h, scan_hover and C.accent or C.widget_bg, math.floor(4 * s))
            draw_text_centered(spawn_state.menyoo_loaded and "Rescan Folder" or "Scan Folder",
                opt_x, oy_cur, opt_w, scan_h, UI.font_small,
                scan_hover and color(255,255,255,255) or C.accent)
            if scan_hover and MOUSE.just_pressed then
                local ok_scan, err_scan = pcall(scan_menyoo_files)
                if not ok_scan then
                    safe_toast("[Kyron] Menyoo scan error: " .. tostring(err_scan))
                end
            end
        end
        oy_cur = oy_cur + scan_h + math.floor(10 * s)

        -- Separator
        if oy_cur > opt_panel_y and oy_cur < opt_bot then
            draw_rect(opt_x, oy_cur, opt_w, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
        end
        oy_cur = oy_cur + math.floor(1 * s) + math.floor(8 * s)

        -- Helper: draw a toggle checkbox row (skip if outside visible area)
        local cb_h = math.floor(26 * s)
        local function menyoo_checkbox(label, key)
            if oy_cur + cb_h > opt_panel_y and oy_cur < opt_bot then
                local val = spawn_state[key]
                local box_size = math.floor(16 * s)
                local box_y = oy_cur + math.floor((cb_h - box_size) / 2)
                local row_hover = is_mouse_in(opt_x, oy_cur, opt_w, cb_h)
                local box_bg = val and C.accent or C.widget_bg
                draw_rect(opt_x, box_y, box_size, box_size, box_bg, math.floor(3 * s))
                if val then
                    draw_text_centered("v", opt_x, box_y, box_size, box_size, UI.font_small, color(255,255,255,255))
                end
                draw_text(label, opt_x + box_size + math.floor(8 * s), oy_cur + math.floor(5 * s), UI.font_small, row_hover and C.text or C.text_dim)
                if row_hover and MOUSE.just_pressed then
                    spawn_state[key] = not spawn_state[key]
                end
            end
            oy_cur = oy_cur + cb_h
        end

        menyoo_checkbox("Delete Old Vehicle",    "menyoo_delete_old")
        menyoo_checkbox("Teleport to Vehicle",   "menyoo_teleport")
        menyoo_checkbox("Auto Start Engine",     "menyoo_engine_on")
        menyoo_checkbox("Vehicle God Mode",      "menyoo_godmode")
        menyoo_checkbox("Radio Off",             "menyoo_radio_off")
        menyoo_checkbox("Spawn Aircraft in Air", "menyoo_spawn_in_air")
        menyoo_checkbox("Max Visual Upgrade",    "menyoo_max_upgrade")
        menyoo_checkbox("Invisible Vehicle",     "menyoo_invisible")

        -- Clamp scroll now that we know total height
        local total_opt_h = (oy_cur - oy_start) + spawn_state.menyoo_options_scroll
        local max_opt_scroll = math.max(0, total_opt_h - opt_panel_h + math.floor(50 * s))
        spawn_state.menyoo_options_scroll = math.max(0, math.min(spawn_state.menyoo_options_scroll, max_opt_scroll))

        oy_cur = oy_cur + math.floor(8 * s)
        if oy_cur > opt_panel_y and oy_cur < opt_bot then
            draw_rect(opt_x, oy_cur, opt_w, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
        end
        oy_cur = oy_cur + math.floor(10 * s)

        -- Delete last spawned vehicle button
        local del_h = math.floor(32 * s)
        if oy_cur + del_h > opt_panel_y and oy_cur < opt_bot then
            local del_hover = is_mouse_in(opt_x, oy_cur, opt_w, del_h)
            draw_rect(opt_x, oy_cur, opt_w, del_h, del_hover and color(180,50,50,220) or C.widget_bg, math.floor(4 * s))
            draw_text_centered("Delete Last Vehicle", opt_x, oy_cur, opt_w, del_h, UI.font_small,
                del_hover and color(255,255,255,255) or color(200,80,80,255))
            if del_hover and MOUSE.just_pressed then
                if spawn_state.menyoo_last_spawned and spawn_state.menyoo_last_spawned ~= 0 then
                    for _, att in ipairs(spawn_state.menyoo_last_attachments or {}) do
                        if att and att ~= 0 then pcall(entities.delete, att) end
                    end
                    spawn_state.menyoo_last_attachments = {}
                    pcall(entities.delete, spawn_state.menyoo_last_spawned)
                    spawn_state.menyoo_last_spawned = nil
                    safe_toast("Menyoo: Deleted last vehicle")
                else
                    safe_toast("Menyoo: No vehicle to delete")
                end
            end
        end
        oy_cur = oy_cur + del_h + math.floor(12 * s)

        -- ── Map spawn controls (shown when a Spooner map is loaded) ──
        local map_obj_count = #(spawn_state.menyoo_map_spawned or {})
        if map_obj_count > 0 or spawn_state.menyoo_map_name then
            if oy_cur > opt_panel_y and oy_cur < opt_bot then
                draw_rect(opt_x, oy_cur, opt_w, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
            end
            oy_cur = oy_cur + math.floor(10 * s)

            -- Map name label
            if oy_cur > opt_panel_y and oy_cur < opt_bot then
                local lbl = spawn_state.menyoo_map_name or "Map"
                draw_text("Map: " .. lbl .. " (" .. map_obj_count .. " obj)", opt_x, oy_cur, UI.font_small - 1, color(160,210,255,255))
            end
            oy_cur = oy_cur + math.floor(20 * s)

            -- Teleport to map button
            local tp_h = math.floor(30 * s)
            if oy_cur + tp_h > opt_panel_y and oy_cur < opt_bot then
                local tp_hov = is_mouse_in(opt_x, oy_cur, opt_w, tp_h)
                draw_rect(opt_x, oy_cur, opt_w, tp_h, tp_hov and C.btn_hover or C.widget_bg, math.floor(4 * s))
                draw_text_centered("Teleport to Map", opt_x, oy_cur, opt_w, tp_h, UI.font_small,
                    tp_hov and C.text or C.text_dim)
                if tp_hov and MOUSE.just_pressed then
                    local map_list = spawn_state.menyoo_map_spawned or {}
                    local first = map_list[1]
                    if first and first ~= 0 then
                        local ok_pos, pos = pcall(invoker.call, 0x3FEF770D40960D5A, first, true)
                        if ok_pos and pos and pos.x then
                            local my_ped = invoker.call(0x43A66C31C68491C0, -1).int
                            if my_ped and my_ped ~= 0 then
                                pcall(invoker.call, 0x06843DA7060A026B, my_ped, 1.0*pos.x, 1.0*pos.y, 1.0*(pos.z + 2.0), false, false, false, true)
                                safe_toast("Teleported to map: " .. (spawn_state.menyoo_map_name or ""))
                            end
                        end
                    else
                        safe_toast("No map loaded")
                    end
                end
            end
            oy_cur = oy_cur + tp_h + math.floor(6 * s)

            -- Delete map button
            local dmap_h = math.floor(30 * s)
            if oy_cur + dmap_h > opt_panel_y and oy_cur < opt_bot then
                local dmap_hov = is_mouse_in(opt_x, oy_cur, opt_w, dmap_h)
                draw_rect(opt_x, oy_cur, opt_w, dmap_h, dmap_hov and color(180,50,50,220) or C.widget_bg, math.floor(4 * s))
                draw_text_centered("Delete Map", opt_x, oy_cur, opt_w, dmap_h, UI.font_small,
                    dmap_hov and color(255,255,255,255) or color(200,80,80,255))
                if dmap_hov and MOUSE.just_pressed then
                    local removed = 0
                    for _, h in ipairs(spawn_state.menyoo_map_spawned or {}) do
                        if h and h ~= 0 then pcall(entities.delete, h); removed = removed + 1 end
                    end
                    spawn_state.menyoo_map_spawned = {}
                    spawn_state.menyoo_map_name = nil
                    safe_toast("Map deleted (" .. removed .. " objects removed)")
                end
            end
            oy_cur = oy_cur + dmap_h + math.floor(12 * s)
        end

        -- Status indicator
        if spawn_state.menyoo_is_spawning then
            draw_text("⏳ Spawning...", opt_x, oy_cur, UI.font_small, C.accent)
        elseif spawn_state.menyoo_last_spawned then
            draw_text("✓ Vehicle spawned", opt_x, oy_cur, UI.font_small, color(100,220,100,255))
        end

    -- ─────────────────────────────────────────────────────────────────────
    -- ─────────────────────────────────────────────────────────────────────
    -- TAB 6: INI SPAWNER
    -- ─────────────────────────────────────────────────────────────────────
    elseif spawn_state.main_tab == 6 then
        local s = UI.scale
        -- NOTE: content_h and content_y come from the outer draw_spawn_tab scope
        -- (they already subtract maintab_h). Do NOT redefine content_h here.
        local hdr_h = math.floor(28 * s)
        local gap2 = math.floor(12 * s)
        local left_w2 = math.floor(300 * s)
        local right_w2 = ui_layout.content_w - left_w2 - gap2
        local left_x2  = ui_layout.content_x
        local right_x2 = ui_layout.content_x + left_w2 + gap2

        -- =====================================================================
        -- INI SPAWNER CORE  (ported from UnifiedSpawner)
        -- =====================================================================

        local ini_parse_cache = ini_parse_cache or {}

        local function trim_s(s2) return s2 and s2:match("^%s*(.-)%s*$") or "" end
        local function to_bool(v) local l=tostring(v):lower(); return l=="true" or l=="1" end
        local function safe_num(v, def) local num_str = tostring(v):gsub(",","."):gsub("tb$",""); return tonumber(num_str) or def end
        local function esc_pat(s2) return s2:gsub("([%(%)%.%%%+%-%*%?%[%^%$])", "%%%1") end

        -- ── INI parser (UnifiedSpawner logic) ──────────────────────────────
        local function parse_ini(content)
            if not content or content=="" then return {} end
            local cache_key = #content..":"..content:sub(1,64)..":"..content:sub(-64)
            if ini_parse_cache[cache_key] then return ini_parse_cache[cache_key] end
            if content:sub(1,3)=="\239\187\191" then content=content:sub(4) end

            local info = {}
            local current_table = nil
            local current_name = "\xFF"
            local is_parent_found = false

            for line in (content.."\n"):gmatch("([^\r\n]+)") do
                if line:match("[\128-\255]") and not line:match("[%[=]") then goto cont end
                local ci = line:find("[#;]")
                if ci == 1 then goto cont end
                if ci then line = line:sub(1, ci-1) end
                line = trim_s(line)
                if line=="" then goto cont end

                -- Nested subsection [ParentSection.Sub]
                if current_name ~= "\xFF" then
                    local nested = line:match("^%[" .. esc_pat(current_name:sub(3)) .. "%.(.+)%]$")
                    if nested then
                        if not info[#info][nested] then info[#info][nested]={} end
                        current_table = info[#info][nested]
                        goto cont
                    end
                end

                -- New section header
                if line:match("^%[.+%]$") then
                    current_table = {}
                    info[#info+1] = current_table
                    local sec = line:match("^%[(.+)%]$")
                    current_name = "%[" .. esc_pat(sec)
                    info[#info]._section_name = sec
                    local is_att = sec:match("^Attached") ~= nil
                    local is_veh = sec == "Vehicle"
                    local is_num = sec:match("^%d+$") ~= nil
                    if is_veh then
                        if not is_parent_found then info[#info].is_parent_vehicle=true; is_parent_found=true end
                    elseif is_att then
                        info[#info].IsAttached=true
                    elseif is_num then
                        if not is_parent_found then info[#info].is_parent_vehicle=true; is_parent_found=true
                        else info[#info].IsAttached=true end
                    end
                    goto cont
                end

                -- Key=Value
                if line:find("=",1,true) and current_table then
                    if line:sub(-1)=="=" then line=line:sub(1,-2) end
                    local k,v = line:match("^(.-)%s*=%s*(.*)$")
                    if k and k~="" then
                        k=trim_s(k); v=v or ""
                        local vl=v:lower()
                        local pv
                        if vl=="true" then pv=true
                        elseif vl=="false" then pv=false
                        else pv=safe_num(v,nil) or v end
                        current_table[k]=pv
                        if pv==false and (k=="IsAttached" or k=="isAttached") then
                            if not is_parent_found then info[#info].is_parent_vehicle=true; is_parent_found=true end
                        end
                    end
                else
                    -- Bare coordinate format: x123.4
                    local ck,cv = line:match("^([xyz])([%d.-]+)$")
                    if ck and cv and current_table and current_table[ck]==nil then
                        current_table[ck]=tonumber(cv)
                    end
                end
                ::cont::
            end

            ini_parse_cache[cache_key] = info
            return info
        end

        -- ── INI type detection ──────────────────────────────────────────────
        local function get_ini_type(content)
            if not content then return nil end
            if content:find("^%[VEHICLE%]") or
               (content:find("License Plate Text Index",1,true) and content:find("Tire Smoke Green",1,true)) then
                return "type_1"
            end
            if content:find("T%d+ ?=") and content:find("M%d+ ?=") then
                if content:find("[AllObjects]",1,true) and content:find("ScorchedRender = ",1,true) then
                    return "type_2a"
                end
                return "type_2b"
            end
            if content:find("[Vehicle]",1,true) and content:find("model=",1,true) and content:find("%d%d=[-%d]+") then
                return "type_3"
            end
            if (content:find("NeonEnabled",1,true) or content:find("Radio=",1,true)) and
               (content:find("TOGGLE_",1,true) or content:find("Froozen=",1,true)) and
               content:find("[Vehicle]",1,true) then
                return "type_4"
            end
            if content:find("[0]",1,true) and not content:find("%[%a+%d*%]") then
                return "type_5"
            end
            -- Fallback: try to detect by looking for any [section] with Model/model field
            if content:find("Model=") or content:find("model=") then
                return "type_3"
            end
            return nil
        end

        -- ── Get model hash from section ────────────────────────────────────
        local function get_model_hash(info)
            return info.Model or info.model or info.Hash or info.hash or info.ModelHash
        end

        -- ── Determine if section is the parent/root entity ─────────────────
        local function is_parent_section(info)
            if info.is_parent_vehicle then return true end
            if info.IsAttached==false or info.IsAttached==nil then
                if info.SelfNumeration~=nil and info.AttachNumeration==nil then return true end
                if info.SelfNumeration==nil and info.AttachNumeration==nil then return true end
            end
            return false
        end

        -- ── Apply ped scenario or animation ────────────────────────────────
        local function apply_ped_anim(ped, pp)
            if not ped or ped==0 then return end
            -- Scenario (e.g. dancing)
            if pp.ScenarioActive==true and pp.ScenarioName then
                pcall(invoker.call, 0x142A02425FF02BD9, ped, pp.ScenarioName, 0, true)  -- TASK_START_SCENARIO_IN_PLACE
                return
            end
            -- Animation dict+clip
            if pp.AnimActive==true and pp.AnimDict and pp.AnimName then
                -- Request anim dict first
                pcall(invoker.call, 0xD3BD40951412FEF6, pp.AnimDict)  -- REQUEST_ANIM_DICT
                local timeout=0
                while timeout<30 do
                    local ok,ld=pcall(invoker.call, 0xD031A9162D01088C, pp.AnimDict)
                    if ok and ld and ld.bool then break end
                    util.yield(50); timeout=timeout+1
                end
                -- TASK_PLAY_ANIM(ped, dict, name, blendIn, blendOut, duration, flag, playbackRate, lockX, lockY, lockZ)
                pcall(invoker.call, 0xEA47FE3719165B94, ped, pp.AnimDict, pp.AnimName, 8.0, 1.0, -1, 1, 1.0, false, false, false)
            end
        end

        -- ── Apply ped mods (components, props, scenario, weapon, etc.) ──────
        local function apply_ped_mods_ini(ped, info)
            if not ped or ped==0 then return end
            local pp = info.PedProperties or info.Ped or info

            if pp.IsStill==true then
                pcall(invoker.call, 0x1913FE4CBF41C463, ped, 292, true)  -- SET_PED_CONFIG_FLAG(DisablePedConstraints)
            end
            if pp.CanRagdoll~=nil then
                pcall(invoker.call, 0xB128377056A54E2A, ped, to_bool(pp.CanRagdoll))
            end
            if pp.MaxHealth~=nil then
                local hp=safe_num(pp.MaxHealth,200)
                pcall(invoker.call, 0xF5F6378C4F3419D3, ped, hp)   -- SET_PED_MAX_HEALTH
                pcall(invoker.call, 0xCEA6925C9EFD2B97, ped, hp-100)  -- SET_ENTITY_HEALTH
            end
            if pp.Armor~=nil then
                pcall(invoker.call, 0xCEA04D83135264CC, ped, safe_num(pp.Armor,0))
            end
            if pp.CurrentWeapon and pp.CurrentWeapon~=0 then
                pcall(invoker.call, 0xBF0FD6E56C964FCB, ped, safe_num(pp.CurrentWeapon,0), 9999, false, true)
            end

            -- Components (drawable, texture)
            local comps = pp.PedComps
            if comps then
                for i=0,11 do
                    local c=comps[i] or comps["_"..i] or comps[tostring(i)]
                    if c then
                        local did, tid = 0, 0
                        if type(c)=="table" then did=c[1] or c.comp_id or 0; tid=c[2] or c.texture_id or 0
                        else local pts={}; for p in tostring(c):gmatch("([^,]+)") do pts[#pts+1]=tonumber(p) or 0 end
                            did=pts[1] or 0; tid=pts[2] or 0 end
                        pcall(invoker.call, 0x262B14F48D29DE80, ped, i, did, tid, 0)
                    end
                end
            end

            -- Props (hat, glasses, etc.)
            local props = pp.PedProps
            if props then
                for i=0,9 do
                    local p=props[i] or props["_"..i] or props[tostring(i)]
                    if p then
                        local pid, tid = -1, 0
                        if type(p)=="table" then pid=p[1] or p.prop_id or -1; tid=p[2] or p.texture_id or 0
                        else local pts={}; for pt in tostring(p):gmatch("([^,]+)") do pts[#pts+1]=tonumber(pt) or 0 end
                            pid=pts[1] or -1; tid=pts[2] or 0 end
                        if pid>=0 then pcall(invoker.call, 0x93376B65A266EB5F, ped, i, pid, tid, true, false)
                        else pcall(invoker.call, 0x0943E5B8E078E76E, ped, i) end  -- CLEAR_PED_PROP
                    end
                end
            end

            -- Ignore events (so they hold position/animation)
            if pp.IgnoreEvents==true or pp.AnimActive==true or pp.ScenarioActive==true then
                pcall(invoker.call, 0x9F0903C2172D7F43, ped, true)   -- SET_BLOCKING_OF_NON_TEMPORARY_EVENTS
                pcall(invoker.call, 0x1913FE4CBF41C463, ped, 17, true)  -- SET_PED_CONFIG_FLAG AlwaysAllowSharedExplode
            end

            -- Movement clipset
            if pp.MovementGroupName then
                pcall(request.dict, pp.MovementGroupName)
                pcall(invoker.call, 0xAF8A140B06071ECF, ped, pp.MovementGroupName, 1.0, true)  -- SET_PED_MOVEMENT_CLIPSET
            end

            -- Apply scenario or animation
            apply_ped_anim(ped, pp)
        end

        -- ── Apply entity options (frozen, alpha, visibility) ────────────────
        local function apply_ini_entity_opts(entity, info)
            if not entity or entity==0 then return end
            local frozen = info.FrozenPos or info.frozen or info.Frozen or info.froozen or info.Froozen
            if frozen~=nil and to_bool(frozen) then
                pcall(invoker.call, 0x428CA6DBD1094446, entity, true)
            end
            if info.OpacityLevel~=nil then
                local alpha=safe_num(info.OpacityLevel,nil)
                if alpha then pcall(invoker.call, 0x44A0870B7E92D7C0, entity, math.floor(alpha)) end
            end
            if info.IsVisible~=nil and not to_bool(info.IsVisible) then
                pcall(invoker.call, 0xEA1C610A04DB6BBB, entity, false, false)
            end
        end

        -- ── Spawn one entity (vehicle / ped / object) ───────────────────────
        local function ini_spawn_entity(hash, sx, sy, sz, hdg)
            if not hash then return 0 end
            local h = type(hash)=="string" and (tonumber(hash) or (function()
                local ok,r=pcall(invoker.call,0xD24D37CC275948CC,hash); return ok and r and r.int or 0
            end)()) or math.tointeger and math.tointeger(hash) or math.floor(hash)
            if not h or h==0 then return 0 end
            if not request.model(h) then return 0 end
            -- [v10 FIX] Try vehicle, ped, object via public-lobby safe helpers
            local ent = _menyoo_spawn_veh(h, sx, sy, sz, hdg or 0) or 0
            if ent==0 then ent = _menyoo_spawn_ped(h, sx, sy, sz, hdg or 0) or 0 end
            if ent==0 then ent = _menyoo_spawn_obj(h, sx, sy, sz)            or 0 end
            pcall(invoker.call, 0xE532F5D78798DAAB, h)
            if ent~=0 then
                invoker.call(0xAD738C3085FE7E11, ent, true, true)     -- SET_ENTITY_AS_MISSION_ENTITY
                invoker.call(0x1A9205C1B9EE827F, ent, true, true)     -- SET_ENTITY_COLLISION(ent, true, true)
            end
            return ent
        end

        -- ── Attach entity to parent with raw floats (16 args, Menyoo style) ─
        local function ini_attach(child, parent, info, sx, sy, sz)
            if not child or child==0 or not parent or parent==0 then return end
            local att = info.Attachment or info.Placement or {}
            -- "x offset" / "y offset" / "z offset" are ClickUI/Stand INI style keys with spaces
            local ox = safe_num(info["x offset"] or info["x_offset"] or info.X or info.x or info.xt or info.OffsetX or att.X, 0)
            local oy = safe_num(info["y offset"] or info["y_offset"] or info.Y or info.y or info.yt or info.OffsetY or att.Y, 0)
            local oz = safe_num(info["z offset"] or info["z_offset"] or info.Z or info.z or info.zt or info.OffsetZ or att.Z, 0)
            local pitch = safe_num(info.Pitch or info.pitch or info.RotX or att.Pitch, 0)
            local roll  = safe_num(info.Roll  or info.roll  or info.RotY or att.Roll,  0)
            local yaw   = safe_num(info.Yaw   or info.yaw   or info.RotZ or att.Yaw,   0)
            local bone  = safe_num((att.BoneIndex or info.Bone or info.bone), 0)
            local col_proof = info.IsCollisionProof or info.collision or info.Collision
            local collision = col_proof==nil and true or not to_bool(col_proof)
            pcall(invoker.call, 0x6B9BBD38AB0796DF,
                child, parent, bone,
                1.0*ox, 1.0*oy, 1.0*oz,
                1.0*pitch, 1.0*roll, 1.0*yaw,
                false, false, collision, false, 2, true, false)
            pcall(invoker.call, 0xEA1C610A04DB6BBB, child, true, false)  -- SET_ENTITY_VISIBLE
            pcall(invoker.call, 0x5927F96A78577363, child, 16960)        -- SET_ENTITY_LOD_DIST
        end

        -- ── Apply vehicle mods from INI (stream-in wait first) ─────────────
        local function apply_ini_vehicle_mods(veh, info, ini_type)
            if not veh or veh==0 then return end
            -- Wait for stream-in (same as Menyoo/JSON spawners)
            for _=1,50 do
                local ok,r=pcall(invoker.call, 0x48B0AABB8E95D7F3, veh)
                if ok and r and r.bool then break end
                util.yield(100)
            end
            invoker.call(0x1F2AA07F00B3217A, veh, 0)  -- SET_VEHICLE_MOD_KIT

            -- Primary/secondary colour (also handles "primary paint" / "secondary paint" Stand/ClickUI style)
            local c1 = info.PrimaryColour   or info.Colour1      or info.colour1      or info.Color1
                     or info["primary paint"] or info["primary colour"] or info["primary color"]
            local c2 = info.SecondaryColour or info.Colour2      or info.colour2      or info.Color2
                     or info["secondary paint"] or info["secondary colour"] or info["secondary color"]
            if c1 then pcall(invoker.call, 0x4F1D4BE3A7F24601, veh, safe_num(c1,0), safe_num(c2 or 0, 0)) end

            -- Custom RGB
            local rp=info.CustomPrimaryColourR; local gp=info.CustomPrimaryColourG; local bp=info.CustomPrimaryColourB
            if rp and gp and bp then pcall(invoker.call, 0x7141766F91D15BEA, veh, safe_num(rp,255), safe_num(gp,255), safe_num(bp,255)) end
            local rs=info.CustomSecondaryColourR; local gs=info.CustomSecondaryColourG; local bs=info.CustomSecondaryColourB
            if rs and gs and bs then pcall(invoker.call, 0x36CED73BFED89754, veh, safe_num(rs,255), safe_num(gs,255), safe_num(bs,255)) end

            -- Pearlescent / wheel colour
            local pearl = info.PearlColour or info.PearlColor
                       or info["pearlescent colour"] or info["pearlescent color"] or info["pearl colour"]
            local wcol  = info.WheelColour or info.WheelColor
                       or info["wheel colour"] or info["wheel color"]
            if pearl or wcol then pcall(invoker.call, 0x2036F561ADD12E33, veh, safe_num(pearl or 0,0), safe_num(wcol or 0,0)) end

            -- Wheel type
            local wt = info.WheelType or info.wheeltype or info["wheel type"]
            if wt then pcall(invoker.call, 0x487EB21CC7295BA1, veh, safe_num(wt,0)) end

            -- Window tint
            local wti = info.WindowTint or info.windowtint or info["window tint"]
            if wti then pcall(invoker.call, 0x57C51E6BAD752696, veh, safe_num(wti,0)) end

            -- Plate text / index
            local pt = info["License Plate Text"] or info.LicensePlateText or info.NumberPlateText
            if pt then pcall(invoker.call, 0x95A88F0B409CDA47, veh, tostring(pt)) end
            local pi = info["License Plate Text Index"] or info.LicensePlateIndex or info.NumberPlateIndex
            if pi then pcall(invoker.call, 0x9088EB5A43FFB0A1, veh, safe_num(pi,0)) end

            -- Tyre smoke colour
            local tsr=info["Tyre Smoke Red"] or info["tyre smoke red"] or info.TyreSmokeRed or info.TireSmokeRed
            local tsg=info["Tyre Smoke Green"] or info["tyre smoke green"] or info.TyreSmokeGreen or info.TireSmokeGreen
            local tsb=info["Tyre Smoke Blue"] or info["tyre smoke blue"] or info.TyreSmokeBlue or info.TireSmokeBlue
            if tsr or tsg or tsb then pcall(invoker.call, 0xB5BA80F839791C0F, veh, safe_num(tsr,255), safe_num(tsg,255), safe_num(tsb,255)) end

            -- Bulletproof tyres
            local bpt = info.BulletProofTyres or info.BulletproofTires or info["bulletproof tyres"] or info["bulletproof tires"]
            if bpt~=nil then pcall(invoker.call, 0xC98B4B2D9C8DA1EB, veh, not to_bool(bpt)) end

            -- Neon: handles both NeonEnabled style AND "neon 0/1/2/3" + "neon red/green/blue" (Stand/ClickUI style)
            local ne = info.NeonEnabled or info.neonEnabled
            local neon0 = info["neon 0"]; local neon1 = info["neon 1"]
            local neon2 = info["neon 2"]; local neon3 = info["neon 3"]
            if ne then
                local nl=to_bool(info.NeonFront or false); local nr=to_bool(info.NeonBack or false)
                local nm=to_bool(info.NeonLeft or false);  local nk=to_bool(info.NeonRight or false)
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 0, nm)
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 1, nk)
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 2, nl)
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 3, nr)
                local nr2=info.NeonColourR or info["Neon Colour R"]; local ng=info.NeonColourG or info["Neon Colour G"]; local nb=info.NeonColourB or info["Neon Colour B"]
                if nr2 or ng or nb then pcall(invoker.call, 0x8E0A582209A62695, veh, safe_num(nr2,255), safe_num(ng,255), safe_num(nb,255)) end
            elseif neon0~=nil or neon1~=nil or neon2~=nil or neon3~=nil then
                -- "neon 0"=left "neon 1"=right "neon 2"=front "neon 3"=back
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 0, (safe_num(neon0,0)==1))
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 1, (safe_num(neon1,0)==1))
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 2, (safe_num(neon2,0)==1))
                pcall(invoker.call, 0x2AA720E4287BF269, veh, 3, (safe_num(neon3,0)==1))
                local nr2=info["neon red"]; local ng=info["neon green"]; local nb=info["neon blue"]
                if nr2 or ng or nb then pcall(invoker.call, 0x8E0A582209A62695, veh, safe_num(nr2,255), safe_num(ng,255), safe_num(nb,255)) end
            end

            -- Mods from a sibling [Vehicle Mods] section (Stand/ClickUI style): numeric keys 0=2, 1=5 etc.
            if info._vehicle_mods_section then
                for k,v in pairs(info._vehicle_mods_section) do
                    local slot = tonumber(k)
                    if slot~=nil and type(v)=="number" and v>=0 then
                        pcall(invoker.call, 0x6AF0636DDEDCB6DD, veh, slot, v, false)
                    end
                end
            end
            -- Mods from a sibling [Vehicle Toggles] section: numeric keys 17=0, 18=1 etc.
            if info._vehicle_toggles_section then
                for k,v in pairs(info._vehicle_toggles_section) do
                    local slot = tonumber(k)
                    if slot~=nil then
                        pcall(invoker.call, 0x772960328CE265C3, veh, slot, v==1 or v==true)
                    end
                end
            end
            -- Mods (type_1 / type_4: keys like "Mod0", "MOD_SPOILERS")
            -- Scan all keys for mod slots
            for k,v in pairs(info) do
                local slot = nil
                if type(k)=="string" then
                    slot = tonumber(k:match("^[Mm]od(%d+)$")) or
                           tonumber(k:match("^MOD_")) and nil  -- named mods handled separately
                end
                if slot~=nil and type(v)=="number" and v>=0 then
                    pcall(invoker.call, 0x6AF0636DDEDCB6DD, veh, slot, v, false)
                end
            end

            -- type_2 / type_3 style: numeric keys like T0=, T1= (tuning) M0= (model)
            for k,v in pairs(info) do
                if type(k)=="string" then
                    local tslot = tonumber(k:match("^T(%d+)$"))
                    if tslot~=nil and type(v)=="number" and v>=0 then
                        pcall(invoker.call, 0x6AF0636DDEDCB6DD, veh, tslot, v, false)
                    end
                end
            end

            -- TOGGLE_ mods (type_4)
            for k,v in pairs(info) do
                if type(k)=="string" and k:match("^TOGGLE_") then
                    local slot = safe_num(info[k:gsub("TOGGLE_","")], nil)
                    if slot then pcall(invoker.call, 0x772960328CE265C3, veh, slot, to_bool(v)) end
                end
            end

            -- Extras
            for i=0,12 do
                local ev=info["Extra"..i] or info["EXTRA_"..i]
                if ev~=nil then
                    pcall(invoker.call, 0x7EE3A3C5E4A40CC9, veh, i, not to_bool(ev))  -- SET_VEHICLE_EXTRA
                end
            end

            -- Livery
            local liv=info.Livery or info.livery
            if liv~=nil then pcall(invoker.call, 0x60BF608F1B8CD1B6, veh, safe_num(liv,0)) end

            -- Drift tyres
            local dt=info.DriftTyresEnabled or info.driftTyres
            if dt~=nil then pcall(invoker.call, 0x1837AF7D2D97BF45, veh, to_bool(dt)) end
        end

        -- ── Main INI spawn dispatcher ───────────────────────────────────────
        local function spawn_ini_vehicle(entry)
            if spawn_state.ini_is_spawning then return end
            spawn_state.ini_is_spawning = true

            util.create_job(function()
                local raw = nil
                pcall(function()
                    if file and file.open then
                        local fh = file.open(entry.path, {})
                        if fh and fh.valid and fh.text then raw = fh.text end
                    end
                end)
                if not raw or raw=="" then safe_toast("INI: Cannot read: "..entry.name); spawn_state.ini_is_spawning=false; return end

                local ini_type = get_ini_type(raw)
                if not ini_type then safe_toast("INI: Unknown format: "..entry.name); spawn_state.ini_is_spawning=false; return end

                local parsed = parse_ini(raw)
                if not parsed or #parsed==0 then safe_toast("INI: Parse failed: "..entry.name); spawn_state.ini_is_spawning=false; return end

                -- Delete old
                if spawn_state.ini_delete_old then
                    if spawn_state.ini_last_spawned and spawn_state.ini_last_spawned~=0 then
                        pcall(entities.delete, spawn_state.ini_last_spawned); spawn_state.ini_last_spawned=nil
                    end
                    for _,h in ipairs(spawn_state.ini_last_attachments or {}) do pcall(entities.delete,h) end
                    spawn_state.ini_last_attachments={}
                    util.yield(100)
                end

                -- Player position
                local ok_ped,ped=pcall(invoker.call,0x43A66C31C68491C0,-1); ped=ok_ped and ped and ped.int or 0
                if ped==0 then safe_toast("INI: No ped"); spawn_state.ini_is_spawning=false; return end
                local ok_c,coords=pcall(invoker.call,0x3FEF770D40960D5A,ped,false); coords=ok_c and coords and coords.scr_vec3
                if not coords then safe_toast("INI: No coords"); spawn_state.ini_is_spawning=false; return end
                local ok_hd,hdg=pcall(invoker.call,0xE83A169BE1F8E88F,ped,false)
                local heading = ok_hd and hdg and hdg.flo or 0.0

                local sx = coords.x - math.sin(math.rad(heading)) * 5.0
                local sy = coords.y + math.cos(math.rad(heading)) * 5.0
                local sz = coords.z + (spawn_state.ini_spawn_in_air and 30.0 or 1.0)

                local parent_ent = 0
                local parent_info = nil
                local attachments = {}
                local all_ents = {}
                spawn_state.ini_last_attachments = {}

                -- Separate parent sections from attached sections
                -- Also find [Vehicle Mods] and [Vehicle Toggles] sections to attach to parent
                local parent_sections = {}
                local attach_sections = {}
                local vehicle_mods_section = nil
                local vehicle_toggles_section = nil
                for _,info in ipairs(parsed) do
                    if type(info)=="table" then
                        local sn = info._section_name or ""
                        if sn == "Vehicle Mods" or sn == "Mods" then
                            vehicle_mods_section = info
                        elseif sn == "Vehicle Toggles" or sn == "Toggles" then
                            vehicle_toggles_section = info
                        else
                            local h=get_model_hash(info)
                            if h then
                                if info.IsAttached==true then
                                    attach_sections[#attach_sections+1]={info=info,hash=h}
                                else
                                    parent_sections[#parent_sections+1]={info=info,hash=h}
                                end
                            end
                        end
                    end
                end
                -- Attach mods/toggles sections to first parent vehicle info
                if vehicle_mods_section and parent_sections[1] then
                    parent_sections[1].info._vehicle_mods_section = vehicle_mods_section
                end
                if vehicle_toggles_section and parent_sections[1] then
                    parent_sections[1].info._vehicle_toggles_section = vehicle_toggles_section
                end

                -- Spawn parents first
                for _,item in ipairs(parent_sections) do
                    local info=item.info
                    local ent=ini_spawn_entity(item.hash, sx, sy, sz, heading)
                    if ent~=0 then
                        -- Check entity type
                        local ok_v,iv=pcall(invoker.call,0x6AC7003FA6E5575E,ent); local is_veh=ok_v and iv and iv.bool
                        local ok_p,ip=pcall(invoker.call,0x524AC5ECEA15343E,ent); local is_ped=ok_p and ip and ip.bool

                        if is_veh then
                            apply_ini_vehicle_mods(ent, info, ini_type)
                        elseif is_ped then
                            apply_ped_mods_ini(ent, info)
                        end

                        if is_parent_section(info) then
                            parent_ent=ent; parent_info=info
                            pcall(invoker.call, 0x428CA6DBD1094446, ent, true)  -- freeze while attaching
                        end

                        local sn=info.SelfNumeration
                        if sn then all_ents[sn]=ent end
                        all_ents[#all_ents+1]=ent
                    end
                end

                -- Yield so vehicle settles, then spawn attachments
                util.yield(250)

                -- Spawn attached entities
                for _,item in ipairs(attach_sections) do
                    local info=item.info
                    local ent=ini_spawn_entity(item.hash, sx, sy, sz, heading)
                    if ent~=0 then
                        local ok_p,ip=pcall(invoker.call,0x524AC5ECEA15343E,ent); local is_ped=ok_p and ip and ip.bool
                        if is_ped then apply_ped_mods_ini(ent, info) end

                        apply_ini_entity_opts(ent, info)

                        -- Resolve attach target: by SelfNumeration/AttachNumeration, or parent
                        local attach_to_num = info.AttachNumeration
                        local target = (attach_to_num and all_ents[attach_to_num]) or parent_ent or all_ents[1] or 0

                        -- type_5: compute relative offset from world positions
                        local attach_info = info
                        if ini_type=="type_5" and parent_info then
                            attach_info = {}
                            for k,v in pairs(info) do attach_info[k]=v end
                            attach_info.X = (info.X or 0) - (parent_info.X or 0)
                            attach_info.Y = (info.Y or 0) - (parent_info.Y or 0)
                            attach_info.Z = (info.Z or 0) - (parent_info.Z or 0)
                        end

                        if target~=0 then
                            ini_attach(ent, target, attach_info, sx, sy, sz)
                        end

                        local sn=info.SelfNumeration
                        if sn then all_ents[sn]=ent end
                        all_ents[#all_ents+1]=ent
                        spawn_state.ini_last_attachments[#spawn_state.ini_last_attachments+1]=ent
                    end
                end

                -- Unfreeze parent
                if parent_ent~=0 then pcall(invoker.call, 0x428CA6DBD1094446, parent_ent, false) end

                spawn_state.ini_last_spawned = parent_ent~=0 and parent_ent or all_ents[1] or 0

                -- Apply user options to parent vehicle
                if spawn_state.ini_last_spawned~=0 then
                    local sv=spawn_state.ini_last_spawned
                    if spawn_state.ini_godmode   then pcall(invoker.call, 0x3882114BDE571AD4, sv, true) end
                    if spawn_state.ini_engine_on then pcall(invoker.call, 0x2497C4717C8B881E, sv, true, true, false) end
                    if spawn_state.ini_radio_off then
                        pcall(invoker.call, 0x3B988190C0AA6C0B, sv, false)
                        pcall(invoker.call, 0x1B9C0099CB942AC6, sv, "RADIO_OFF")
                    end
                    if spawn_state.ini_max_upgrade then
                        pcall(invoker.call, 0x1F2AA07F00B3217A, sv, 0)
                        for i=0,49 do
                            local ok_n,nm=pcall(invoker.call,0x33F2E3FE70EAAE1D,sv,i)
                            if ok_n and nm and nm.int and nm.int>0 then pcall(invoker.call,0x6AF0636DDEDCB6DD,sv,i,nm.int-1,false) end
                        end
                    end
                    if spawn_state.ini_invisible then
                        pcall(invoker.call, 0x44A0870B7E92D7C0, sv, 0, false)    -- SET_ENTITY_ALPHA(veh, 0, false)
                        pcall(invoker.call, 0xEA1C610A04DB6BBB, sv, false, false) -- SET_ENTITY_VISIBLE(false)
                    end
                    if spawn_state.ini_teleport then
                        util.yield(300)
                        pcall(invoker.call, 0xF75B0D629E1C063D, ped, sv, -1)
                    end
                end

                local n=#spawn_state.ini_last_attachments
                safe_toast("INI: Spawned "..entry.name..(n>0 and (" (+"..n.." attached)") or ""))
                spawn_state.ini_is_spawning=false
            end)
        end

        -- =====================================================================
        -- END INI SPAWNER CORE
        -- =====================================================================

        -- Left panel background
        draw_rect(left_x2, content_y, left_w2, content_h, C.sidebar, math.floor(5 * s))
        draw_rect(left_x2, content_y, left_w2, hdr_h, C.header, math.floor(5 * s))
        local ini_count = #spawn_state.ini_vehicles
        draw_text("INI Vehicles (" .. ini_count .. ")", left_x2 + math.floor(8 * s), content_y + math.floor(6 * s), UI.font_small, C.text)

        -- Search bar
        local srch_h6 = math.floor(30 * s)
        local srch_y6 = content_y + hdr_h + math.floor(4 * s)
        local srch_x6 = left_x2 + math.floor(6 * s)
        local srch_w6 = left_w2 - math.floor(12 * s)
        local s6_hov = is_mouse_in(srch_x6, srch_y6, srch_w6, srch_h6)
        if s6_hov and MOUSE.just_pressed then
            spawn_state.ini_search_focused = not spawn_state.ini_search_focused
        end
        if spawn_state.ini_search_focused and input and input.key then
            if input.key(0x08).just_pressed and #spawn_state.ini_search > 0 then
                spawn_state.ini_search = spawn_state.ini_search:sub(1, -2)
            end
            for code = 0x30, 0x39 do
                if input.key(code).just_pressed then spawn_state.ini_search = spawn_state.ini_search .. string.char(code) end
            end
            for code = 0x41, 0x5A do
                if input.key(code).just_pressed then spawn_state.ini_search = spawn_state.ini_search .. string.char(code):lower() end
            end
            if input.key(0x20).just_pressed then spawn_state.ini_search = spawn_state.ini_search .. " " end
        end
        draw_rect(srch_x6, srch_y6, srch_w6, srch_h6, (spawn_state.ini_search_focused or s6_hov) and C.widget_hover or C.widget_bg, math.floor(4 * s))
        if spawn_state.ini_search_focused then
            draw_rect(srch_x6, srch_y6 + srch_h6 - math.floor(2 * s), srch_w6, math.floor(2 * s), C.accent, 0)
        end
        if #spawn_state.ini_search == 0 then
            draw_text("Search INI files...", srch_x6 + math.floor(10 * s), srch_y6 + math.floor(8 * s), UI.font_small, color(100,100,100,180))
        else
            draw_text(spawn_state.ini_search .. (spawn_state.ini_search_focused and "_" or ""), srch_x6 + math.floor(10 * s), srch_y6 + math.floor(8 * s), UI.font_small, C.text)
        end

        -- Vehicle list
        local list_top6 = srch_y6 + srch_h6 + math.floor(6 * s)
        local list_h6   = content_h - hdr_h - srch_h6 - math.floor(16 * s)
        local item_h6   = math.floor(30 * s)
        local cat_h6    = math.floor(26 * s)
        local list_bot6 = list_top6 + list_h6

        -- Filter
        local ini_groups = {}
        for _, v in ipairs(spawn_state.ini_vehicles) do
            if not spawn_state.ini_search or spawn_state.ini_search == "" or v.name:lower():find(spawn_state.ini_search:lower(), 1, true) or (v.model_hash_hint and (spawn_state.hash_to_model[v.model_hash_hint] or ""):lower():find(spawn_state.ini_search:lower(), 1, true)) then
                local grp = v.subfolder or "Root"
                if not ini_groups[grp] then ini_groups[grp] = {} end
                table.insert(ini_groups[grp], v)
            end
        end
        local ini_sorted = {}
        for g in pairs(ini_groups) do ini_sorted[#ini_sorted+1] = g end
        table.sort(ini_sorted)

        -- Scroll height
        local ini_scroll_total = 0
        for _, g in ipairs(ini_sorted) do
            ini_scroll_total = ini_scroll_total + cat_h6 + math.floor(4 * s)
            if not spawn_state.ini_collapsed[g] then
                ini_scroll_total = ini_scroll_total + #ini_groups[g] * item_h6
            end
        end
        if is_mouse_in(left_x2, list_top6, left_w2, list_h6) then
            if MOUSE.scroll_up then spawn_state.ini_scroll = spawn_state.ini_scroll - math.floor(30 * s)
            elseif MOUSE.scroll_down then spawn_state.ini_scroll = spawn_state.ini_scroll + math.floor(30 * s) end
        end
        spawn_state.ini_scroll = math.max(0, math.min(spawn_state.ini_scroll, math.max(0, ini_scroll_total - list_h6)))

        draw_rect(left_x2, list_top6, left_w2, list_h6, C.sidebar, math.floor(4 * s))
        local dy6 = list_top6 - spawn_state.ini_scroll
        if ini_count == 0 then
            if not spawn_state.ini_loaded then
                draw_text("Click 'Scan Folder' to load INI files", left_x2 + math.floor(8 * s), list_top6 + math.floor(12 * s), UI.font_small, C.text_dim)
            else
                draw_text("No INI vehicles found.", left_x2 + math.floor(8 * s), list_top6 + math.floor(12 * s), UI.font_small, C.text_dim)
                draw_text("Expected: scripts\\Kyron\\Vehicles\\INI\\", left_x2 + math.floor(8 * s), list_top6 + math.floor(28 * s), UI.font_small, C.accent)
            end
        else
            for _, grp in ipairs(ini_sorted) do
                if dy6 + cat_h6 > list_top6 and dy6 < list_bot6 then
                    local clipped_cat_h6 = math.min(cat_h6, list_bot6 - dy6)
                    local gh = is_mouse_in(left_x2 + math.floor(4 * s), dy6, left_w2 - math.floor(8 * s), clipped_cat_h6)
                    draw_rect(left_x2 + math.floor(4 * s), dy6, left_w2 - math.floor(8 * s), clipped_cat_h6, gh and C.widget_hover or C.header, math.floor(4 * s))
                    if dy6 + math.floor(5 * s) < list_bot6 then
                        draw_text((spawn_state.ini_collapsed[grp] and ">" or "v") .. "  " .. grp .. " (" .. #ini_groups[grp] .. ")", left_x2 + math.floor(10 * s), dy6 + math.floor(5 * s), UI.font_small, C.text)
                    end
                    if gh and MOUSE.just_pressed then spawn_state.ini_collapsed[grp] = not spawn_state.ini_collapsed[grp] end
                end
                dy6 = dy6 + cat_h6 + math.floor(4 * s)
                if not spawn_state.ini_collapsed[grp] then
                    for _, v in ipairs(ini_groups[grp]) do
                        if dy6 + item_h6 > list_top6 and dy6 < list_bot6 then
                            local clipped_item_h6 = math.min(item_h6 - math.floor(4 * s), list_bot6 - dy6 - math.floor(2 * s))
                            if clipped_item_h6 > 0 then
                                local bx = left_x2 + math.floor(12 * s)
                                local bw = left_w2 - math.floor(20 * s)
                                local bh = is_mouse_in(bx, dy6 + math.floor(2 * s), bw, clipped_item_h6)
                                draw_rect(bx, dy6 + math.floor(2 * s), bw, clipped_item_h6, bh and C.widget_hover or C.widget_bg, math.floor(4 * s))
                                if dy6 + math.floor(8 * s) < list_bot6 then
                                    draw_text(v.name, bx + math.floor(8 * s), dy6 + math.floor(8 * s), UI.font_small, C.text)
                                end
                                if bh then
                                    -- INI entries: quick-parse model from first 512 bytes of file
                                    if not v._preview_hash and v.path then
                                        pcall(function()
                                            local f = io.open(v.path, "r")
                                            if f then
                                                local chunk = f:read(512); f:close()
                                                local ms = chunk and chunk:match("[Mm]odel%s*=%s*(%d+)")
                                                if ms then v._preview_hash = tonumber(ms) end
                                            end
                                        end)
                                    end
                                    if v._preview_hash then spawn_state.preview_hovered_model = v._preview_hash end
                                end
                                if bh and MOUSE.just_pressed then spawn_ini_vehicle(v) end
                            end
                        end
                        dy6 = dy6 + item_h6
                        if dy6 >= list_bot6 then break end
                    end
                end
                if dy6 >= list_bot6 then break end
            end
        end

        -- Right panel
        draw_rect(right_x2, content_y, right_w2, content_h, C.sidebar, math.floor(5 * s))
        local oh6 = math.floor(28 * s)
        draw_rect(right_x2, content_y, right_w2, oh6, C.header, math.floor(5 * s))
        draw_text("Spawn Options", right_x2 + math.floor(8 * s), content_y + math.floor(6 * s), UI.font_small, C.text)
        local oy6 = content_y + oh6 + math.floor(8 * s)
        local ox6 = right_x2 + math.floor(10 * s)
        local ow6 = right_w2 - math.floor(20 * s)
        local cb6 = math.floor(28 * s)

        -- Scan button (TOP, like Menyoo)
        local scan6_h = math.floor(32 * s)
        local scan6_hov = is_mouse_in(ox6, oy6, ow6, scan6_h)
        draw_rect(ox6, oy6, ow6, scan6_h, scan6_hov and C.accent or C.widget_bg, math.floor(4 * s))
        draw_text_centered(spawn_state.ini_loaded and "Rescan Folder" or "Scan Folder", ox6, oy6, ow6, scan6_h, UI.font_small, scan6_hov and color(255,255,255,255) or C.accent)
        if scan6_hov and MOUSE.just_pressed then
            -- Scan INI folder (same method as Menyoo XML scanner)
            spawn_state.ini_vehicles = {}
            spawn_state.ini_loaded = false

            if not (dirs and dirs.exists) then
                safe_toast("[Kyron] INI: dirs API not available")
                spawn_state.ini_loaded = true
            else
                -- Build candidate paths (same pattern as Menyoo XML)
                local ini_candidates = {}
                if paths and paths.script then
                    local s = paths.script
                    if not s:match("[/\\]$") then s = s .. "\\" end
                    table.insert(ini_candidates, s .. "Kyron\\Vehicles\\INI\\")
                    table.insert(ini_candidates, s .. "Kyron\\vehicles\\INI\\")
                    table.insert(ini_candidates, s .. "Vehicles\\INI\\")
                end
                if paths and paths.game then
                    local g = paths.game
                    if not g:match("[/\\]$") then g = g .. "\\" end
                    table.insert(ini_candidates, g .. "scripts\\Kyron\\Vehicles\\INI\\")
                end

                local ini_base_dir = nil
                for _, c in ipairs(ini_candidates) do
                    local ok, exists = pcall(dirs.exists, c)
                    if ok and exists then
                        ini_base_dir = c
                        break
                    end
                end

                if not ini_base_dir then
                    safe_toast("INI: Folder not found.\nExpected: Kyron\\Vehicles\\INI\\")
                    spawn_state.ini_loaded = true
                else
                    -- Helper: scan INI files in one folder (mirrors scan_xml_in_folder)
                    local function scan_ini_in_folder(folder, subfolder_label)
                        folder = folder:gsub("[/\\]?$", "\\")
                        if not dirs.exists(folder) then return end

                        -- Try all three variants just like the XML scanner
                        local ok_ini,  ini_files  = pcall(dirs.list, folder, "ini")
                        local ok_dini, dini_files  = pcall(dirs.list, folder, ".ini")
                        local ok_all,  all_files  = pcall(dirs.list, folder)

                        local files = nil
                        if ok_ini and ini_files and #ini_files > 0 then
                            files = ini_files
                        elseif ok_dini and dini_files and #dini_files > 0 then
                            files = dini_files
                        elseif ok_all and all_files and #all_files > 0 then
                            files = {}
                            for _, fp in ipairs(all_files) do
                                if fp:lower():match("%.ini$") then
                                    table.insert(files, fp)
                                end
                            end
                        end

                        if not files then return end
                        for _, fp in ipairs(files) do
                            local fname = fp:match("[/\\]([^/\\]+)%.ini$") or fp:match("([^/\\]+)%.ini$") or fp:match("[^/\\]+$")
                            if fname then
                                fname = fname:gsub("%.ini$", "")
                                -- Always construct guaranteed full absolute path (same fix as XML)
                                local full_path = folder .. fname .. ".ini"
                                local ini_model_hash = nil
                                pcall(function()
                                    if file and file.open then
                                        local fh = file.open(full_path, {})
                                        if fh and fh.valid and fh.text then
                                            local chunk = fh.text:sub(1, 4096)
                                            local ms = chunk:match("[Mm]odel%s*=%s*(%d+)")
                                                     or chunk:match("[Hh]ash%s*=%s*(%d+)")
                                            if ms then ini_model_hash = tonumber(ms) end
                                        end
                                    end
                                end)
                                table.insert(spawn_state.ini_vehicles, {
                                    name            = fname,
                                    path            = full_path,
                                    subfolder       = subfolder_label or "Root",
                                    model_hash_hint = ini_model_hash,
                                })
                            end
                        end
                    end

                    -- 1) Scan root INI files
                    scan_ini_in_folder(ini_base_dir, "Root")

                    -- 2) Read folders.txt via file.open (new Lexis API — io.open is path-restricted)
                    local ini_folders_txt = ini_base_dir .. "folders.txt"
                    local ini_loaded_from_txt = false
                    if file and file.open then
                        local fh = file.open(ini_folders_txt, {})
                        if fh and fh.valid and fh.text and fh.text ~= "" then
                            ini_loaded_from_txt = true
                            for line in fh.text:gmatch("[^\r\n]+") do
                                line = line:match("^%s*(.-)%s*$")
                                if line and line ~= "" and not line:match("^#") then
                                    scan_ini_in_folder(ini_base_dir .. line .. "\\", line)
                                end
                            end
                        end
                    end

                    -- 3) Fallback: dirs.scan for subdirectories if no folders.txt (added 5/25/2026)
                    if not ini_loaded_from_txt then
                        local ok_d, subdirs = pcall(dirs.scan, ini_base_dir)
                        if ok_d and subdirs then
                            for _, subdir in ipairs(subdirs) do
                                local dname = subdir:match("[/\\]([^/\\]+)[/\\]?$") or subdir
                                scan_ini_in_folder(subdir:gsub("[/\\]?$", "\\"), dname)
                            end
                        end
                    end

                    table.sort(spawn_state.ini_vehicles, function(a, b)
                        if a.subfolder ~= b.subfolder then return a.subfolder < b.subfolder end
                        return a.name:lower() < b.name:lower()
                    end)
                    spawn_state.ini_loaded = true
                    spawn_state.ini_collapsed = {}
                    local _seen_grps6 = {}
                    for _, v in ipairs(spawn_state.ini_vehicles) do
                        local g = v.subfolder or "Root"
                        if not _seen_grps6[g] then _seen_grps6[g] = true; spawn_state.ini_collapsed[g] = true end
                    end
                    local total6 = #spawn_state.ini_vehicles
                    if total6 > 0 then
                        safe_toast("INI: Loaded " .. total6 .. " files")
                    else
                        safe_toast("INI: No INI files found.\nFolder: " .. tostring(ini_base_dir))
                    end
                end
            end
        end
        oy6 = oy6 + scan6_h + math.floor(10 * s)

        -- Separator
        draw_rect(ox6, oy6, ow6, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
        oy6 = oy6 + math.floor(10 * s)

        local function ini_checkbox(label, key)
            local box6 = math.floor(18 * s)
            local rh6 = is_mouse_in(ox6, oy6, ow6, cb6)
            local box_y6 = oy6 + math.floor((cb6 - box6) / 2)
            draw_rect(ox6, box_y6, box6, box6, rh6 and C.widget_hover or C.widget_bg, math.floor(3 * s))
            if spawn_state[key] then
                draw_rect(ox6 + math.floor(3 * s), box_y6 + math.floor(3 * s), box6 - math.floor(6 * s), box6 - math.floor(6 * s), C.accent, math.floor(2 * s))
            end
            draw_text(label, ox6 + box6 + math.floor(8 * s), oy6 + math.floor(5 * s), UI.font_small, rh6 and C.text or C.text_dim)
            if rh6 and MOUSE.just_pressed then spawn_state[key] = not spawn_state[key] end
            oy6 = oy6 + cb6
        end
        ini_checkbox("Delete Old Vehicle",    "ini_delete_old")
        ini_checkbox("Teleport to Vehicle",   "ini_teleport")
        ini_checkbox("Auto Start Engine",     "ini_engine_on")
        ini_checkbox("Vehicle God Mode",      "ini_godmode")
        ini_checkbox("Radio Off",             "ini_radio_off")
        ini_checkbox("Spawn Aircraft in Air", "ini_spawn_in_air")
        ini_checkbox("Max Visual Upgrade",    "ini_max_upgrade")
        ini_checkbox("Invisible Vehicle",     "ini_invisible")

        oy6 = oy6 + math.floor(8 * s)
        draw_rect(ox6, oy6, ow6, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
        oy6 = oy6 + math.floor(10 * s)

        -- Delete last vehicle button
        local del6_h = math.floor(32 * s)
        local del6_hov = is_mouse_in(ox6, oy6, ow6, del6_h)
        draw_rect(ox6, oy6, ow6, del6_h, del6_hov and color(180,50,50,220) or C.widget_bg, math.floor(4 * s))
        draw_text_centered("Delete Last Vehicle", ox6, oy6, ow6, del6_h, UI.font_small, del6_hov and color(255,255,255,255) or color(220,80,80,255))
        if del6_hov and MOUSE.just_pressed then
            if spawn_state.ini_last_spawned and spawn_state.ini_last_spawned ~= 0 then
                for _, att in ipairs(spawn_state.ini_last_attachments or {}) do
                    if att and att ~= 0 then pcall(entities.delete, att) end
                end
                spawn_state.ini_last_attachments = {}
                pcall(entities.delete, spawn_state.ini_last_spawned)
                spawn_state.ini_last_spawned = nil
                safe_toast("INI: Last vehicle and all props deleted")
            else
                safe_toast("INI: No vehicle to delete")
            end
        end

    -- ─────────────────────────────────────────────────────────────────────
    -- TAB 7: JSON SPAWNER
    -- ─────────────────────────────────────────────────────────────────────
    elseif spawn_state.main_tab == 7 then
        local s = UI.scale
        -- NOTE: content_h and content_y come from the outer draw_spawn_tab scope
        -- (they already subtract maintab_h). Do NOT redefine content_h here.
        local hdr_h = math.floor(28 * s)
        local gap3 = math.floor(12 * s)
        local left_w3 = math.floor(300 * s)
        local right_w3 = ui_layout.content_w - left_w3 - gap3
        local left_x3  = ui_layout.content_x
        local right_x3 = ui_layout.content_x + left_w3 + gap3

        -- =====================================================================
        -- JSON SPAWNER CORE
        -- =====================================================================

        -- ── Minimal recursive JSON parser ─────────────────────────────────────
        local function json_parse(str)
            local pos=1
            local function skip_ws() while pos<=#str and str:sub(pos,pos):match("%s") do pos=pos+1 end end
            local function peek() return str:sub(pos,pos) end
            local parse_value
            local function parse_string()
                pos=pos+1; local r={}
                while pos<=#str do
                    local c=str:sub(pos,pos)
                    if c=='"' then pos=pos+1; break
                    elseif c=='\\' then
                        pos=pos+1; local e=str:sub(pos,pos)
                        if e=='"' then r[#r+1]='"' elseif e=='\\' then r[#r+1]='\\'
                        elseif e=='n' then r[#r+1]='\n' elseif e=='r' then r[#r+1]='\r'
                        elseif e=='t' then r[#r+1]='\t'
                        elseif e=='u' then r[#r+1]=string.char(tonumber(str:sub(pos+1,pos+4),16) or 63); pos=pos+4
                        else r[#r+1]=e end; pos=pos+1
                    else r[#r+1]=c; pos=pos+1 end
                end
                return table.concat(r)
            end
            local function parse_array()
                pos=pos+1; local a={}; skip_ws()
                if peek()==']' then pos=pos+1; return a end
                while pos<=#str do skip_ws(); a[#a+1]=parse_value(); skip_ws()
                    if peek()==',' then pos=pos+1 elseif peek()==']' then pos=pos+1; break end end
                return a
            end
            local function parse_object()
                pos=pos+1; local o={}; skip_ws()
                if peek()=='}' then pos=pos+1; return o end
                while pos<=#str do
                    skip_ws(); if peek()~='"' then break end
                    local k=parse_string(); skip_ws()
                    if peek()==':' then pos=pos+1 end; skip_ws()
                    o[k]=parse_value(); skip_ws()
                    if peek()==',' then pos=pos+1 elseif peek()=='}' then pos=pos+1; break end
                end
                return o
            end
            parse_value=function()
                skip_ws(); local c=peek()
                if c=='"' then return parse_string()
                elseif c=='{' then return parse_object()
                elseif c=='[' then return parse_array()
                elseif c=='t' then pos=pos+4; return true
                elseif c=='f' then pos=pos+5; return false
                elseif c=='n' then pos=pos+4; return nil
                else local ns=str:match("^%-?%d+%.%d+[eE][+-]?%d+",pos) or str:match("^%-?%d+[eE][+-]?%d+",pos) or str:match("^%-?%d+%.%d*",pos) or str:match("^%-?%d+",pos) or str:match("^%-?%.%d+",pos)
                    if ns then pos=pos+#ns; return tonumber(ns) end end
            end
            local ok,res=pcall(parse_value); return ok and res or nil
        end

        -- ── Format detection + converters ─────────────────────────────────────
        local function detect_json_fmt(d)
            if not d then return "unknown" end
            if d.type then return "constructor" end
            if d.base then return "jstand" end
            if d.craftlab then return "craftlab" end
            return "unknown"
        end

        local function convert_jstand(data)
            local r={type="VEHICLE",hash=data.base and data.base.model,children={},vehicle_attributes={}}
            local sd=data.savedata
            if sd then
                r.vehicle_attributes.mods=sd.mods or {}
                r.vehicle_attributes.paint={primary=sd.primaryColor,secondary=sd.secondaryColor,
                    extra_colors={pearlescent=sd.pearlColor,wheel=sd.wheelColor},
                    vehicle_custom_color={r=sd.customPrimaryColor and sd.customPrimaryColor.r,g=sd.customPrimaryColor and sd.customPrimaryColor.g,b=sd.customPrimaryColor and sd.customPrimaryColor.b,
                        r2=sd.customSecondaryColor and sd.customSecondaryColor.r,g2=sd.customSecondaryColor and sd.customSecondaryColor.g,b2=sd.customSecondaryColor and sd.customSecondaryColor.b}}
                r.vehicle_attributes.wheels={wheel_type=sd.wheelType,tire_smoke_color=sd.tireSmokeColor}
                r.vehicle_attributes.options={license_plate_text=sd.plateText,license_plate_type=sd.plateIndex,window_tint=sd.windowTint,bulletproof_tires=sd.bulletproofTires}
                if sd.neonEnabled then r.vehicle_attributes.neon={lights={left=sd.neonLeft,right=sd.neonRight,front=sd.neonFront,back=sd.neonBack},color=sd.neonColor} end
            end
            for _,v in ipairs(data.vehicles or {}) do table.insert(r.children,{type="VEHICLE",hash=v.model,offset=v.offset or {x=0,y=0,z=0},rotation=v.rotation or {x=0,y=0,z=0},options={bone_index=v.boneIndex or 0}}) end
            for _,v in ipairs(data.objects or {}) do table.insert(r.children,{type="OBJECT",hash=v.model,offset=v.offset or {x=0,y=0,z=0},rotation=v.rotation or {x=0,y=0,z=0},options={bone_index=v.boneIndex or 0}}) end
            for _,v in ipairs(data.peds   or {}) do table.insert(r.children,{type="PED",hash=v.model,offset=v.offset or {x=0,y=0,z=0},rotation=v.rotation or {x=0,y=0,z=0},ped_attributes=v.ped_attributes,options={bone_index=v.boneIndex or 0}}) end
            return r
        end

        local function convert_craftlab(data)
            if not data.craftlab or #data.craftlab==0 then return nil end
            local emap={}
            for _,item in ipairs(data.craftlab) do local e=item.entity; if e and e.unique_number then emap[e.unique_number]=e end end
            local root=nil
            for _,item in ipairs(data.craftlab) do local e=item.entity; if e and not e.is_attached and e.type==1 then root=e; break end end
            if not root then for _,item in ipairs(data.craftlab) do local e=item.entity; if e and e.type==1 then root=e; break end end end
            if not root and data.craftlab[1] then root=data.craftlab[1].entity end
            if not root then return nil end
            local tmap={[1]="VEHICLE",[2]="PED",[3]="OBJECT"}
            local function conv(e)
                local r={type=tmap[e.type] or "OBJECT",hash=e.model,children={},
                    options={is_visible=e.visible~=false,has_collision=e.collision~=false,is_invincible=e.invincible==true,is_frozen=e.freeze==true,alpha=e.alpha_level or 255}}
                if e.attach_data then
                    r.offset={x=e.attach_data.x or 0,y=e.attach_data.y or 0,z=e.attach_data.z or 0}
                    r.rotation={x=e.attach_data.pitch or 0,y=e.attach_data.roll or 0,z=e.attach_data.yaw or 0}
                    r.options.bone_index=e.attach_data.attached_to_bone or 0
                end
                if r.type=="VEHICLE" and e.vehicle_data then
                    local vd=e.vehicle_data
                    r.vehicle_attributes={mods={},
                        paint={primary=vd.primary_colour,secondary=vd.secondary_colour,extra_colors={pearlescent=vd.pearl_color,wheel=vd.wheel_color}},
                        wheels={wheel_type=vd.wheel_type},
                        options={license_plate_text=vd.number_plate_text,license_plate_type=vd.number_plate_text_index,window_tint=vd.window_tint,bulletproof_tires=not vd.tyres_can_burst},neon={}}
                    if vd.rgb_colors then
                        if vd.is_custom_primary_color then r.vehicle_attributes.paint.vehicle_custom_color={r=vd.rgb_colors.custom_primary_colour_r,g=vd.rgb_colors.custom_primary_colour_g,b=vd.rgb_colors.custom_primary_colour_b} end
                        if vd.is_custom_secondary_color then r.vehicle_attributes.paint.vehicle_custom_color=r.vehicle_attributes.paint.vehicle_custom_color or {}
                            r.vehicle_attributes.paint.vehicle_custom_color.r2=vd.rgb_colors.custom_secondary_colour_r
                            r.vehicle_attributes.paint.vehicle_custom_color.g2=vd.rgb_colors.custom_secondary_colour_g
                            r.vehicle_attributes.paint.vehicle_custom_color.b2=vd.rgb_colors.custom_secondary_colour_b end
                        r.vehicle_attributes.neon.color={r=vd.rgb_colors.neon_lights_colour_r,g=vd.rgb_colors.neon_lights_colour_g,b=vd.rgb_colors.neon_lights_colour_b}
                        r.vehicle_attributes.wheels.tire_smoke_color={r=vd.rgb_colors.tyre_smoke_colour_r,g=vd.rgb_colors.tyre_smoke_colour_g,b=vd.rgb_colors.tyre_smoke_colour_b}
                    end
                    if vd.neon then r.vehicle_attributes.neon.lights={left=vd.neon.is_enabled_0,right=vd.neon.is_enabled_1,front=vd.neon.is_enabled_2,back=vd.neon.is_enabled_3} end
                    if vd.mod_slot then for k,val in pairs(vd.mod_slot) do local mid=k:match("mod_index_(%d+)") or k:match("mod_toggle_(%d+)"); if mid then r.vehicle_attributes.mods["_"..mid]=val end end end
                end
                return r
            end
            local result=conv(root)
            local function find_children(pnum)
                local ch={}
                for _,item in ipairs(data.craftlab) do local e=item.entity
                    if e and e.is_attached and e.attach_data and e.attach_data.attached_to_number==pnum then
                        local c=conv(e); c.children=find_children(e.unique_number); table.insert(ch,c) end end
                return ch
            end
            result.children=find_children(root.unique_number)
            return result
        end

        -- ── Stream-in wait (CRITICAL for mods) ───────────────────────────────
        local function wait_streamed_in(veh)
            for _=1,50 do
                local ok,r=pcall(invoker.call,0x48B0AABB8E95D7F3,veh)
                if ok and r and r.bool then return end
                util.yield(100)
            end
        end

        -- ── Apply vehicle attributes ──────────────────────────────────────────
        local function apply_json_veh_attrs(veh, attrs)
            if not attrs or not veh or veh==0 then return end
            wait_streamed_in(veh)
            local mods=attrs.mods
            if mods then
                invoker.call(0x1F2AA07F00B3217A,veh,0)
                for k,v in pairs(mods) do
                    local idx=tonumber(k) or tonumber(tostring(k):match("_?(%d+)$"))
                    if idx then
                        if type(v)=="boolean" then pcall(invoker.call,0x772960328CE265C3,veh,idx,v)
                        elseif type(v)=="number" and v>=0 then pcall(invoker.call,0x6AF0636DDEDCB6DD,veh,idx,v,false) end
                    end
                end
            end
            local paint=attrs.paint
            if paint then
                local cc=paint.vehicle_custom_color
                if cc then
                    if cc.r and cc.g and cc.b then pcall(invoker.call,0x7141766F91D15BEA,veh,cc.r,cc.g,cc.b) end
                    if cc.r2 and cc.g2 and cc.b2 then pcall(invoker.call,0x36CED73BFED89754,veh,cc.r2,cc.g2,cc.b2) end
                elseif paint.primary~=nil then pcall(invoker.call,0x4F1D4BE3A7F24601,veh,paint.primary,paint.secondary or 0) end
                local ec=paint.extra_colors
                if ec then pcall(invoker.call,0x2036F561ADD12E33,veh,ec.pearlescent or 0,ec.wheel or 0) end
            end
            local neon=attrs.neon
            if neon then
                if neon.lights then local nl=neon.lights
                    pcall(invoker.call,0x2AA720E4287BF269,veh,0,nl.left==true)
                    pcall(invoker.call,0x2AA720E4287BF269,veh,1,nl.right==true)
                    pcall(invoker.call,0x2AA720E4287BF269,veh,2,nl.front==true)
                    pcall(invoker.call,0x2AA720E4287BF269,veh,3,nl.back==true) end
                if neon.color then local nc=neon.color
                    pcall(invoker.call,0x8E0A582209A62695,veh,type(nc)=="table" and (nc.r or 255) or 255,type(nc)=="table" and (nc.g or 255) or 255,type(nc)=="table" and (nc.b or 255) or 255) end
            end
            local wheels=attrs.wheels
            if wheels then
                if wheels.wheel_type~=nil then pcall(invoker.call,0x487EB21CC7295BA1,veh,wheels.wheel_type) end
                if wheels.tire_smoke_color then local ts=wheels.tire_smoke_color; pcall(invoker.call,0xB5BA80F839791C0F,veh,ts.r or 255,ts.g or 255,ts.b or 255) end
            end
            local opts=attrs.options
            if opts then
                if opts.license_plate_text then pcall(invoker.call,0x95A88F0B409CDA47,veh,opts.license_plate_text) end
                if opts.license_plate_type~=nil then pcall(invoker.call,0x9088EB5A43FFB0A1,veh,opts.license_plate_type) end
                if opts.window_tint~=nil then pcall(invoker.call,0x57C51E6BAD752696,veh,opts.window_tint) end
                if opts.bulletproof_tires then pcall(invoker.call,0xC98B4B2D9C8DA1EB,veh,false) end
            end
        end

        -- ── Apply ped attributes (components, props, scenario/anim, weapon) ──
        local function apply_json_ped_attrs(ped, attrs)
            if not attrs or not ped or ped==0 then return end
            -- Components
            local comps=attrs.components
            if comps then
                for k,c in pairs(comps) do
                    local cid=tonumber(k) or tonumber(tostring(k):match("_?(%d+)$"))
                    if cid then
                        local did=type(c)=="table" and (c.drawable or c[1] or 0) or 0
                        local tid=type(c)=="table" and (c.texture or c[2] or 0) or 0
                        pcall(invoker.call,0x262B14F48D29DE80,ped,cid,did,tid,0)
                    end
                end
            end
            -- Props
            local props=attrs.props
            if props then
                for k,p in pairs(props) do
                    local pid_slot=tonumber(k) or tonumber(tostring(k):match("_?(%d+)$"))
                    if pid_slot then
                        local did=type(p)=="table" and (p.drawable or p[1] or -1) or -1
                        local tid=type(p)=="table" and (p.texture or p[2] or 0) or 0
                        if did>=0 then pcall(invoker.call,0x93376B65A266EB5F,ped,pid_slot,did,tid,true,false)
                        else pcall(invoker.call,0x0943E5B8E078E76E,ped,pid_slot) end
                    end
                end
            end
            -- Weapon
            if attrs.current_weapon then
                local wh=tonumber(attrs.current_weapon) or 0
                if type(attrs.current_weapon)=="string" then
                    local ok,h=pcall(invoker.call,0xD24D37CC275948CC,attrs.current_weapon); wh=ok and h and h.int or 0
                end
                if wh~=0 then pcall(invoker.call,0xBF0FD6E56C964FCB,ped,wh,9999,false,true) end
            end
            -- Block events so the ped holds its animation
            if attrs.ignore_events or attrs.animation then
                pcall(invoker.call,0x9F0903C2172D7F43,ped,true)
            end
            -- Animation or scenario
            local anim=attrs.animation
            if anim then
                if anim.scenario then
                    pcall(invoker.call,0x142A02425FF02BD9,ped,anim.scenario,0,true)
                elseif anim.dictionary and anim.clip then
                    pcall(invoker.call,0xD3BD40951412FEF6,anim.dictionary)
                    local deadline2 = util.get_tick_count() + 2000
                    while true do
                        local ok,ld=pcall(invoker.call,0xD031A9162D01088C,anim.dictionary)
                        if ok and ld and ld.bool then break end
                        if util.get_tick_count() > deadline2 then break end
                        util.yield(0)
                    end
                    local flags = anim.loop == false and 0 or 1
                    pcall(invoker.call,0xEA47FE3719165B94,ped,anim.dictionary,anim.clip,8.0,1.0,-1,flags,1.0,false,false,false)
                end
            end
        end

        -- ── Spawn children + attach (Menyoo-exact pattern) ───────────────────
        local function spawn_children(children, parent_handle, spawn_x, spawn_y, spawn_z, spawned_list)
            if not children or #children==0 then return end
            for _,child in ipairs(children) do
                local ch=child.hash or child.model
                if not ch then goto cont end
                if type(ch)=="string" then local ok,h=pcall(invoker.call,0xD24D37CC275948CC,ch); ch=ok and h and h.int or 0 end
                if ch==0 then goto cont end

                local etype=child.type or "OBJECT"
                local offset=child.offset or {x=0,y=0,z=0}
                local rot=child.rotation or {x=0,y=0,z=0}
                local opts=child.options or {}
                local bone=opts.bone_index or 0

                if not request.model(ch) then goto cont end

                -- [v10 FIX] Use public-lobby safe helpers (script_host_object=false)
                local obj=0
                if etype=="VEHICLE" then
                    obj = _menyoo_spawn_veh(ch, spawn_x, spawn_y, spawn_z, rot.z or 0) or 0
                elseif etype=="PED" then
                    obj = _menyoo_spawn_ped(ch, spawn_x, spawn_y, spawn_z, rot.z or 0) or 0
                else
                    obj = _menyoo_spawn_obj(ch, spawn_x, spawn_y, spawn_z) or 0
                end
                pcall(invoker.call,0xE532F5D78798DAAB,ch)
                if obj==0 then goto cont end

                invoker.call(0xAD738C3085FE7E11,obj,true,true)   -- SET_ENTITY_AS_MISSION_ENTITY
                invoker.call(0x1A9205C1B9EE827F,obj,true,true)   -- SET_ENTITY_COLLISION


                if etype=="VEHICLE" and child.vehicle_attributes then apply_json_veh_attrs(obj,child.vehicle_attributes) end
                if etype=="PED" and child.ped_attributes then apply_json_ped_attrs(obj,child.ped_attributes) end

                if opts.is_invincible then pcall(invoker.call,0x3882114BDE571AD4,obj,true) end
                if opts.is_frozen     then pcall(invoker.call,0x428CA6DBD1094446,obj,true) end
                if opts.alpha and opts.alpha<255 then pcall(invoker.call,0x44A0870B7E92D7C0,obj,opts.alpha) end

                -- ATTACH_ENTITY_TO_ENTITY (16 args, Menyoo-exact)
                pcall(invoker.call,0x6B9BBD38AB0796DF,
                    obj,parent_handle,bone,
                    1.0*(offset.x or 0),1.0*(offset.y or 0),1.0*(offset.z or 0),
                    1.0*(rot.x or 0),1.0*(rot.y or 0),1.0*(rot.z or 0),
                    false,false,opts.has_collision~=false,false,2,true,false)

                pcall(invoker.call,0xEA1C610A04DB6BBB,obj,true,false)
                pcall(invoker.call,0x5927F96A78577363,obj,16960)  -- SET_ENTITY_LOD_DIST
                table.insert(spawned_list,obj)

                if child.children and #child.children>0 then
                    spawn_children(child.children,obj,spawn_x,spawn_y,spawn_z,spawned_list)
                end
                ::cont::
            end
        end

        -- ── Main JSON spawn ───────────────────────────────────────────────────
        local function json_spawn_vehicle(entry)
            if spawn_state.json_is_spawning then return end
            spawn_state.json_is_spawning=true

            util.create_job(function()
                local raw=nil
                pcall(function()
                    if file and file.open then
                        local fh = file.open(entry.path, {})
                        if fh and fh.valid and fh.text then raw = fh.text end
                    end
                end)
                if not raw or raw=="" then safe_toast("JSON: Cannot read: "..entry.name); spawn_state.json_is_spawning=false; return end

                local data=json_parse(raw)
                if not data then safe_toast("JSON: Parse failed: "..entry.name); spawn_state.json_is_spawning=false; return end

                local fmt=detect_json_fmt(data)
                if fmt=="jstand" then data=convert_jstand(data)
                elseif fmt=="craftlab" then data=convert_craftlab(data); if not data then safe_toast("JSON: No root: "..entry.name); spawn_state.json_is_spawning=false; return end
                elseif fmt=="unknown" then safe_toast("JSON: Unknown format: "..entry.name); spawn_state.json_is_spawning=false; return end

                -- ── Detect Constructor MAP (children have absolute position, not offsets) ──
                -- A Constructor map has always_spawn_at_position=true at root, OR
                -- the root type is OBJECT and children each have a "position" table with world coords.
                local is_map = data.always_spawn_at_position == true
                if not is_map and data.children and type(data.children) == "table" and data.children[1] then
                    local c1 = data.children[1]
                    is_map = (c1.position and type(c1.position) == "table" and c1.position.x ~= nil
                              and c1.offset == nil)  -- maps have position, not offset
                end

                if is_map then
                    -- ── MAP MODE: spawn every child at its own absolute world position ──
                    local model_cache = {}
                    local function map_request_model(hash)
                        if not hash or hash == 0 then return false end
                        if model_cache[hash] ~= nil then return model_cache[hash] end
                        if invoker.call(0x98A4EB5D89A0C952, hash).bool then
                            model_cache[hash] = true; return true
                        end
                        invoker.call(0x963D27A58DF860AC, hash)  -- REQUEST_MODEL
                        local deadline = util.get_tick_count() + 2000
                        while not invoker.call(0x98A4EB5D89A0C952, hash).bool do
                            if util.get_tick_count() > deadline then
                                model_cache[hash] = false; return false
                            end
                            util.yield(0)
                        end
                        model_cache[hash] = true; return true
                    end

                    if spawn_state.json_delete_old then
                        -- Delete previous map objects
                        for _, h in ipairs(spawn_state.json_map_spawned or {}) do
                            if h and h ~= 0 then pcall(entities.delete, h) end
                        end
                        spawn_state.json_map_spawned = {}
                        spawn_state.json_map_name = nil
                        -- Also clear vehicle-mode state
                        if spawn_state.json_last_spawned and spawn_state.json_last_spawned ~= 0 then
                            pcall(entities.delete, spawn_state.json_last_spawned)
                            spawn_state.json_last_spawned = nil
                        end
                        for _, h in ipairs(spawn_state.json_last_attachments or {}) do
                            if h and h ~= 0 then pcall(entities.delete, h) end
                        end
                        spawn_state.json_last_attachments = {}
                        util.yield(100)
                    end

                    local map_spawned = spawn_state.json_map_spawned
                    spawn_state.json_map_name = entry.name

                    local function spawn_map_entity(child)
                        if type(child) ~= "table" then return end
                        local etype = child.type or "OBJECT"
                        -- Skip non-spawnable types
                        if etype == "PARTICLE" then return end

                        local h = child.hash or child.model
                        if not h then return end
                        if type(h) == "string" then
                            local ok2, r2 = pcall(invoker.call, 0xD24D37CC275948CC, h)
                            h = ok2 and r2 and r2.int or 0
                        end
                        if type(h) == "number" and h < 0 then h = h + 4294967296 end
                        if not h or h == 0 then return end

                        local pos = child.position
                        if not pos or pos.x == nil then return end
                        local px, py, pz = pos.x, pos.y, pos.z

                        local wr = child.world_rotation or child.rotation or {}
                        local rx = wr.x or 0
                        local ry = wr.y or 0
                        local rz = wr.z or 0

                        local opts = child.options or {}

                        if not map_request_model(h) then return end

                        -- [v10 FIX] Use public-lobby safe helpers (script_host_object=false)
                        local ent = 0
                        if etype == "VEHICLE" then
                            ent = _menyoo_spawn_veh(h, px, py, pz, rz) or 0
                        elseif etype == "PED" then
                            ent = _menyoo_spawn_ped(h, px, py, pz, rz) or 0
                        else
                            ent = _menyoo_spawn_obj(h, px, py, pz) or 0
                        end
                        invoker.call(0xE532F5D78798DAAB, h)
                        if ent == 0 then return end

                        invoker.call(0xAD738C3085FE7E11, ent, true, true)  -- SET_ENTITY_AS_MISSION_ENTITY
                        -- Freeze FIRST, then place — frozen entities respect exact coords
                        invoker.call(0x428CA6DBD1094446, ent, true)
                        invoker.call(0x8524A8B0171D5E07, ent, 1.0*rx, 1.0*ry, 1.0*rz, 2, true)
                        -- Use SET_ENTITY_COORDS_NO_OFFSET (0x239A3351AC1DA385) with keepTasks=true
                        -- This respects the exact Z without snapping to ground
                        invoker.call(0x239A3351AC1DA385, ent, 1.0*px, 1.0*py, 1.0*pz, true, true, false)

                        if opts.is_invincible then invoker.call(0x3882114BDE571AD4, ent, true) end
                        if opts.alpha and opts.alpha < 255 then invoker.call(0x44A0870B7E92D7C0, ent, opts.alpha, false) end
                        if opts.is_visible == false then invoker.call(0xEA1C610A04DB6BBB, ent, false, false) end

                        -- Type-specific attributes (applied while frozen so position is locked)
                        if etype == "VEHICLE" and child.vehicle_attributes then
                            apply_json_veh_attrs(ent, child.vehicle_attributes)
                        elseif etype == "PED" and child.ped_attributes then
                            apply_json_ped_attrs(ent, child.ped_attributes)
                        end

                        table.insert(map_spawned, ent)

                        -- Recurse into sub-children (also use absolute position)
                        local sub = child.children
                        if type(sub) == "table" and #sub > 0 then
                            for _, sc in ipairs(sub) do
                                spawn_map_entity(sc)
                            end
                        end
                    end

                    safe_toast("JSON Map: Spawning " .. entry.name .. "...")
                    if data.children and type(data.children) == "table" then
                        for i, child in ipairs(data.children) do
                            spawn_map_entity(child)
                            if i % 10 == 0 then util.yield(0) end
                        end
                    end
                    safe_toast("JSON Map: Done! " .. #map_spawned .. " objects spawned from " .. entry.name)

                    if spawn_state.json_teleport and #map_spawned > 0 then
                        util.yield(300)
                        local first = map_spawned[1]
                        if first and first ~= 0 then
                            local ok_pos, pos2 = pcall(invoker.call, 0x3FEF770D40960D5A, first, true)
                            if ok_pos and pos2 and pos2.x then
                                local my_ped = invoker.call(0x43A66C31C68491C0, -1).int
                                if my_ped and my_ped ~= 0 then
                                    pcall(invoker.call, 0x06843DA7060A026B, my_ped, 1.0*pos2.x, 1.0*pos2.y, 1.0*(pos2.z + 2.0), false, false, false, true)
                                end
                            end
                        end
                    end

                    spawn_state.json_is_spawning = false
                    return
                end
                -- ── END MAP MODE ──

                local root_hash=data.hash or data.model
                if not root_hash then safe_toast("JSON: No model: "..entry.name); spawn_state.json_is_spawning=false; return end
                if type(root_hash)=="string" then local ok,h=pcall(invoker.call,0xD24D37CC275948CC,root_hash); root_hash=ok and h and h.int or 0 end
                if root_hash==0 then safe_toast("JSON: Bad hash: "..entry.name); spawn_state.json_is_spawning=false; return end

                if spawn_state.json_delete_old then
                    if spawn_state.json_last_spawned and spawn_state.json_last_spawned~=0 then pcall(entities.delete,spawn_state.json_last_spawned); spawn_state.json_last_spawned=nil end
                    for _,h in ipairs(spawn_state.json_last_attachments or {}) do pcall(entities.delete,h) end
                    spawn_state.json_last_attachments={}; util.yield(100)
                end

                local ok_ped,ped=pcall(invoker.call,0x43A66C31C68491C0,-1); ped=ok_ped and ped and ped.int or 0
                if ped==0 then safe_toast("JSON: No ped"); spawn_state.json_is_spawning=false; return end
                local ok_c,coords=pcall(invoker.call,0x3FEF770D40960D5A,ped,false); coords=ok_c and coords and coords.scr_vec3
                if not coords then safe_toast("JSON: No coords"); spawn_state.json_is_spawning=false; return end
                local ok_hd,hdg=pcall(invoker.call,0xE83A169BE1F8E88F,ped,false)
                local heading=ok_hd and hdg and hdg.flo or 0.0
                local spawn_x=coords.x-math.sin(math.rad(heading))*5.0
                local spawn_y=coords.y+math.cos(math.rad(heading))*5.0
                local spawn_z=coords.z+(spawn_state.json_spawn_in_air and 30.0 or 1.0)

                local root_type=data.type or "VEHICLE"
                if not request.model(root_hash) then safe_toast("JSON: Model load failed: "..entry.name); spawn_state.json_is_spawning=false; return end

                -- [v10 FIX] Use public-lobby safe helpers (script_host_object=false)
                local veh=0
                if root_type=="VEHICLE" then
                    veh = _menyoo_spawn_veh(root_hash, spawn_x, spawn_y, spawn_z, heading) or 0
                elseif root_type=="PED" then
                    veh = _menyoo_spawn_ped(root_hash, spawn_x, spawn_y, spawn_z, heading) or 0
                else
                    veh = _menyoo_spawn_obj(root_hash, spawn_x, spawn_y, spawn_z) or 0
                end
                invoker.call(0xE532F5D78798DAAB,root_hash)
                if veh==0 then safe_toast("JSON: Spawn failed: "..entry.name); spawn_state.json_is_spawning=false; return end

                spawn_state.json_last_spawned=veh
                spawn_state.json_last_attachments={}
                invoker.call(0xAD738C3085FE7E11,veh,true,true)
                invoker.call(0x1A9205C1B9EE827F,veh,true,true)  -- SET_ENTITY_COLLISION(veh, true, true)
                invoker.call(0x8E2C98D9CAF3DB09,veh,heading)
                -- Clear stolen flag and allow blend so others can actually drive
                if root_type=="VEHICLE" then
                    pcall(invoker.call,0x67B2C79AA7FF5738,veh,false)  -- SET_VEHICLE_IS_STOLEN false
                    pcall(invoker.call,0x9B8E5CC6B20562E9,veh,true)   -- NETWORK_SET_ENTITY_CAN_BLEND
                end


                if root_type=="VEHICLE" and data.vehicle_attributes then apply_json_veh_attrs(veh,data.vehicle_attributes) end
                if root_type=="PED"     and data.ped_attributes     then apply_json_ped_attrs(veh,data.ped_attributes)     end

                if spawn_state.json_godmode    then pcall(invoker.call,0x3882114BDE571AD4,veh,true) end
                if spawn_state.json_engine_on  then pcall(invoker.call,0x2497C4717C8B881E,veh,true,true,false) end
                if spawn_state.json_radio_off  then pcall(invoker.call,0x3B988190C0AA6C0B,veh,false); pcall(invoker.call,0x1B9C0099CB942AC6,veh,"RADIO_OFF") end
                if spawn_state.json_max_upgrade then
                    pcall(invoker.call,0x1F2AA07F00B3217A,veh,0)
                    for i=0,49 do local ok_n,nm=pcall(invoker.call,0x33F2E3FE70EAAE1D,veh,i)
                        if ok_n and nm and nm.int and nm.int>0 then pcall(invoker.call,0x6AF0636DDEDCB6DD,veh,i,nm.int-1,false) end end
                end
                if spawn_state.json_invisible then
                    pcall(invoker.call, 0x44A0870B7E92D7C0, veh, 0, false)    -- SET_ENTITY_ALPHA(veh, 0, false)
                    pcall(invoker.call, 0xEA1C610A04DB6BBB, veh, false, false) -- SET_ENTITY_VISIBLE(false)
                end

                util.yield(200)
                if data.children and #data.children>0 then
                    spawn_children(data.children,veh,spawn_x,spawn_y,spawn_z,spawn_state.json_last_attachments)
                end

                if spawn_state.json_teleport then util.yield(300); pcall(invoker.call,0xF75B0D629E1C063D,ped,veh,-1) end

                local n=#spawn_state.json_last_attachments
                safe_toast("JSON: Spawned "..entry.name..(n>0 and (" (+"..n.." attached)") or ""))
                spawn_state.json_is_spawning=false
            end)
        end

        -- =====================================================================
        -- END JSON SPAWNER CORE
        -- =====================================================================

        draw_rect(left_x3, content_y, left_w3, content_h, C.sidebar, math.floor(5 * s))
        draw_rect(left_x3, content_y, left_w3, hdr_h, C.header, math.floor(5 * s))
        local json_count = #spawn_state.json_vehicles
        draw_text("JSON Vehicles (" .. json_count .. ")", left_x3 + math.floor(8 * s), content_y + math.floor(6 * s), UI.font_small, C.text)

        local srch_h7 = math.floor(30 * s)
        local srch_y7 = content_y + hdr_h + math.floor(4 * s)
        local srch_x7 = left_x3 + math.floor(6 * s)
        local srch_w7 = left_w3 - math.floor(12 * s)
        local s7_hov = is_mouse_in(srch_x7, srch_y7, srch_w7, srch_h7)
        if s7_hov and MOUSE.just_pressed then
            spawn_state.json_search_focused = not spawn_state.json_search_focused
        end
        if spawn_state.json_search_focused and input and input.key then
            if input.key(0x08).just_pressed and #spawn_state.json_search > 0 then
                spawn_state.json_search = spawn_state.json_search:sub(1, -2)
            end
            for code = 0x30, 0x39 do
                if input.key(code).just_pressed then spawn_state.json_search = spawn_state.json_search .. string.char(code) end
            end
            for code = 0x41, 0x5A do
                if input.key(code).just_pressed then spawn_state.json_search = spawn_state.json_search .. string.char(code):lower() end
            end
            if input.key(0x20).just_pressed then spawn_state.json_search = spawn_state.json_search .. " " end
        end
        draw_rect(srch_x7, srch_y7, srch_w7, srch_h7, (spawn_state.json_search_focused or s7_hov) and C.widget_hover or C.widget_bg, math.floor(4 * s))
        if spawn_state.json_search_focused then
            draw_rect(srch_x7, srch_y7 + srch_h7 - math.floor(2 * s), srch_w7, math.floor(2 * s), C.accent, 0)
        end
        if #spawn_state.json_search == 0 then
            draw_text("Search JSON files...", srch_x7 + math.floor(10 * s), srch_y7 + math.floor(8 * s), UI.font_small, color(100,100,100,180))
        else
            draw_text(spawn_state.json_search .. (spawn_state.json_search_focused and "_" or ""), srch_x7 + math.floor(10 * s), srch_y7 + math.floor(8 * s), UI.font_small, C.text)
        end

        local list_top7 = srch_y7 + srch_h7 + math.floor(6 * s)
        local list_h7   = content_h - hdr_h - srch_h7 - math.floor(16 * s)
        local item_h7   = math.floor(30 * s)
        local cat_h7    = math.floor(26 * s)
        local list_bot7 = list_top7 + list_h7

        local json_groups = {}
        for _, v in ipairs(spawn_state.json_vehicles) do
            if not spawn_state.json_search or spawn_state.json_search == "" or v.name:lower():find(spawn_state.json_search:lower(), 1, true) or (v.model_hash_hint and (spawn_state.hash_to_model[v.model_hash_hint] or ""):lower():find(spawn_state.json_search:lower(), 1, true)) then
                local grp = v.subfolder or "Root"
                if not json_groups[grp] then json_groups[grp] = {} end
                table.insert(json_groups[grp], v)
            end
        end
        local json_sorted = {}
        for g in pairs(json_groups) do json_sorted[#json_sorted+1] = g end
        table.sort(json_sorted)

        local json_scroll_total = 0
        for _, g in ipairs(json_sorted) do
            json_scroll_total = json_scroll_total + cat_h7 + math.floor(4 * s)
            if not spawn_state.json_collapsed[g] then
                json_scroll_total = json_scroll_total + #json_groups[g] * item_h7
            end
        end
        if is_mouse_in(left_x3, list_top7, left_w3, list_h7) then
            if MOUSE.scroll_up then spawn_state.json_scroll = spawn_state.json_scroll - math.floor(30 * s)
            elseif MOUSE.scroll_down then spawn_state.json_scroll = spawn_state.json_scroll + math.floor(30 * s) end
        end
        spawn_state.json_scroll = math.max(0, math.min(spawn_state.json_scroll, math.max(0, json_scroll_total - list_h7)))

        draw_rect(left_x3, list_top7, left_w3, list_h7, C.sidebar, math.floor(4 * s))
        local dy7 = list_top7 - spawn_state.json_scroll
        if json_count == 0 then
            if not spawn_state.json_loaded then
                draw_text("Click 'Scan Folder' to load JSON files", left_x3 + math.floor(8 * s), list_top7 + math.floor(12 * s), UI.font_small, C.text_dim)
            else
                draw_text("No JSON vehicles found.", left_x3 + math.floor(8 * s), list_top7 + math.floor(12 * s), UI.font_small, C.text_dim)
                draw_text("Expected: scripts\\Kyron\\Vehicles\\JSON\\", left_x3 + math.floor(8 * s), list_top7 + math.floor(28 * s), UI.font_small, C.accent)
            end
        else
            for _, grp in ipairs(json_sorted) do
                if dy7 + cat_h7 > list_top7 and dy7 < list_bot7 then
                    local clipped_cat_h7 = math.min(cat_h7, list_bot7 - dy7)
                    local gh7 = is_mouse_in(left_x3 + math.floor(4 * s), dy7, left_w3 - math.floor(8 * s), clipped_cat_h7)
                    draw_rect(left_x3 + math.floor(4 * s), dy7, left_w3 - math.floor(8 * s), clipped_cat_h7, gh7 and C.widget_hover or C.header, math.floor(4 * s))
                    if dy7 + math.floor(5 * s) < list_bot7 then
                        draw_text((spawn_state.json_collapsed[grp] and ">" or "v") .. "  " .. grp .. " (" .. #json_groups[grp] .. ")", left_x3 + math.floor(10 * s), dy7 + math.floor(5 * s), UI.font_small, C.text)
                    end
                    if gh7 and MOUSE.just_pressed then spawn_state.json_collapsed[grp] = not spawn_state.json_collapsed[grp] end
                end
                dy7 = dy7 + cat_h7 + math.floor(4 * s)
                if not spawn_state.json_collapsed[grp] then
                    for _, v in ipairs(json_groups[grp]) do
                        if dy7 + item_h7 > list_top7 and dy7 < list_bot7 then
                            local clipped_item_h7 = math.min(item_h7 - math.floor(4 * s), list_bot7 - dy7 - math.floor(2 * s))
                            if clipped_item_h7 > 0 then
                                local bx7 = left_x3 + math.floor(12 * s)
                                local bw7 = left_w3 - math.floor(20 * s)
                                local bh7 = is_mouse_in(bx7, dy7 + math.floor(2 * s), bw7, clipped_item_h7)
                                draw_rect(bx7, dy7 + math.floor(2 * s), bw7, clipped_item_h7, bh7 and C.widget_hover or C.widget_bg, math.floor(4 * s))
                                if dy7 + math.floor(8 * s) < list_bot7 then
                                    draw_text(v.name, bx7 + math.floor(8 * s), dy7 + math.floor(8 * s), UI.font_small, C.text)
                                end
                                if bh7 then
                                    if v.hash then
                                        spawn_state.preview_hovered_model = v.hash
                                    elseif not v._preview_hash and v.path then
                                        pcall(function()
                                            local f = io.open(v.path, "r")
                                            if f then
                                                local chunk = f:read(1024); f:close()
                                                local hs = chunk and (chunk:match('"hash"%s*:%s*(-?%d+)') or chunk:match('"hash"%s*:%s*(%d+)'))
                                                if hs then v._preview_hash = tonumber(hs) end
                                            end
                                        end)
                                        if v._preview_hash then spawn_state.preview_hovered_model = v._preview_hash end
                                    elseif v._preview_hash then
                                        spawn_state.preview_hovered_model = v._preview_hash
                                    end
                                end
                                if bh7 and MOUSE.just_pressed then json_spawn_vehicle(v) end
                            end
                        end
                        dy7 = dy7 + item_h7
                        if dy7 >= list_bot7 then break end
                    end
                end
                if dy7 >= list_bot7 then break end
            end
        end

        -- Right panel
        draw_rect(right_x3, content_y, right_w3, content_h, C.sidebar, math.floor(5 * s))
        local oh7 = math.floor(28 * s)
        draw_rect(right_x3, content_y, right_w3, oh7, C.header, math.floor(5 * s))
        draw_text("Spawn Options", right_x3 + math.floor(8 * s), content_y + math.floor(6 * s), UI.font_small, C.text)
        local oy7 = content_y + oh7 + math.floor(8 * s)
        local ox7 = right_x3 + math.floor(10 * s)
        local ow7 = right_w3 - math.floor(20 * s)
        local cb7 = math.floor(28 * s)

        -- Scan button (TOP, like Menyoo)
        local scan7_h = math.floor(32 * s)
        local scan7_hov = is_mouse_in(ox7, oy7, ow7, scan7_h)
        draw_rect(ox7, oy7, ow7, scan7_h, scan7_hov and C.accent or C.widget_bg, math.floor(4 * s))
        draw_text_centered(spawn_state.json_loaded and "Rescan Folder" or "Scan Folder", ox7, oy7, ow7, scan7_h, UI.font_small, scan7_hov and color(255,255,255,255) or C.accent)
        if scan7_hov and MOUSE.just_pressed then
            -- Scan JSON folder (same method as Menyoo XML scanner)
            spawn_state.json_vehicles = {}
            spawn_state.json_loaded = false

            if not (dirs and dirs.exists) then
                safe_toast("[Kyron] JSON: dirs API not available")
                spawn_state.json_loaded = true
            else
                -- Build candidate paths (same pattern as Menyoo XML)
                local json_candidates = {}
                if paths and paths.script then
                    local s = paths.script
                    if not s:match("[/\\]$") then s = s .. "\\" end
                    table.insert(json_candidates, s .. "Kyron\\Vehicles\\Json\\")
                    table.insert(json_candidates, s .. "Kyron\\Vehicles\\JSON\\")
                    table.insert(json_candidates, s .. "Kyron\\vehicles\\Json\\")
                    table.insert(json_candidates, s .. "Vehicles\\Json\\")
                end
                if paths and paths.game then
                    local g = paths.game
                    if not g:match("[/\\]$") then g = g .. "\\" end
                    table.insert(json_candidates, g .. "scripts\\Kyron\\Vehicles\\Json\\")
                    table.insert(json_candidates, g .. "scripts\\Kyron\\Vehicles\\JSON\\")
                end

                local json_base_dir = nil
                for _, c in ipairs(json_candidates) do
                    local ok, exists = pcall(dirs.exists, c)
                    if ok and exists then
                        json_base_dir = c
                        break
                    end
                end

                if not json_base_dir then
                    safe_toast("JSON: Folder not found.\nExpected: Kyron\\Vehicles\\Json\\")
                    spawn_state.json_loaded = true
                else
                    -- Helper: scan JSON files in one folder (mirrors scan_xml_in_folder)
                    local function scan_json_in_folder(folder, subfolder_label)
                        folder = folder:gsub("[/\\]?$", "\\")
                        if not dirs.exists(folder) then return end

                        -- Try all three variants just like the XML scanner
                        local ok_json,  json_files  = pcall(dirs.list, folder, "json")
                        local ok_djson, djson_files = pcall(dirs.list, folder, ".json")
                        local ok_all,   all_files   = pcall(dirs.list, folder)

                        local files = nil
                        if ok_json and json_files and #json_files > 0 then
                            files = json_files
                        elseif ok_djson and djson_files and #djson_files > 0 then
                            files = djson_files
                        elseif ok_all and all_files and #all_files > 0 then
                            files = {}
                            for _, fp in ipairs(all_files) do
                                if fp:lower():match("%.json$") then
                                    table.insert(files, fp)
                                end
                            end
                        end

                        if not files then return end
                        for _, fp in ipairs(files) do
                            local fname = fp:match("[/\\]([^/\\]+)%.json$") or fp:match("([^/\\]+)%.json$") or fp:match("[^/\\]+$")
                            if fname then
                                fname = fname:gsub("%.json$", "")
                                -- Always construct guaranteed full absolute path (same fix as XML)
                                local full_path = folder .. fname .. ".json"
                                local json_model_hash = nil
                                pcall(function()
                                    if file and file.open then
                                        local fh = file.open(full_path, {})
                                        if fh and fh.valid and fh.text then
                                            local chunk = fh.text:sub(1, 4096)
                                            local hs = chunk:match('"hash"%s*:%s*(-?%d+)')
                                                     or chunk:match('"model"%s*:%s*(-?%d+)')
                                            if hs then json_model_hash = tonumber(hs) end
                                            if not json_model_hash then
                                                local bs = chunk:match('"base"%s*:%s*{[^}]*"model"%s*:%s*(-?%d+)')
                                                if bs then json_model_hash = tonumber(bs) end
                                            end
                                        end
                                    end
                                end)
                                table.insert(spawn_state.json_vehicles, {
                                    name            = fname,
                                    path            = full_path,
                                    subfolder       = subfolder_label or "Root",
                                    model_hash_hint = json_model_hash,
                                })
                            end
                        end
                    end

                    -- 1) Scan root JSON files
                    scan_json_in_folder(json_base_dir, "Root")

                    -- 2) Read folders.txt via file.open (new Lexis API — io.open is path-restricted)
                    local json_folders_txt = json_base_dir .. "folders.txt"
                    local json_loaded_from_txt = false
                    if file and file.open then
                        local fh = file.open(json_folders_txt, {})
                        if fh and fh.valid and fh.text and fh.text ~= "" then
                            json_loaded_from_txt = true
                            for line in fh.text:gmatch("[^\r\n]+") do
                                line = line:match("^%s*(.-)%s*$")
                                if line and line ~= "" and not line:match("^#") then
                                    scan_json_in_folder(json_base_dir .. line .. "\\", line)
                                end
                            end
                        end
                    end

                    -- 3) Fallback: dirs.scan for subdirectories if no folders.txt (added 5/25/2026)
                    if not json_loaded_from_txt then
                        local ok_d, subdirs = pcall(dirs.scan, json_base_dir)
                        if ok_d and subdirs then
                            for _, subdir in ipairs(subdirs) do
                                local dname = subdir:match("[/\\]([^/\\]+)[/\\]?$") or subdir
                                scan_json_in_folder(subdir:gsub("[/\\]?$", "\\"), dname)
                            end
                        end
                    end

                    table.sort(spawn_state.json_vehicles, function(a, b)
                        if a.subfolder ~= b.subfolder then return a.subfolder < b.subfolder end
                        return a.name:lower() < b.name:lower()
                    end)
                    spawn_state.json_loaded = true
                    spawn_state.json_collapsed = {}
                    local _seen_grps7 = {}
                    for _, v in ipairs(spawn_state.json_vehicles) do
                        local g = v.subfolder or "Root"
                        if not _seen_grps7[g] then _seen_grps7[g] = true; spawn_state.json_collapsed[g] = true end
                    end
                    local total7 = #spawn_state.json_vehicles
                    if total7 > 0 then
                        safe_toast("JSON: Loaded " .. total7 .. " files")
                    else
                        safe_toast("JSON: No JSON files found.\nFolder: " .. tostring(json_base_dir))
                    end
                end
            end
        end
        oy7 = oy7 + scan7_h + math.floor(10 * s)

        -- Separator
        draw_rect(ox7, oy7, ow7, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
        oy7 = oy7 + math.floor(10 * s)

        local function json_checkbox(label, key)
            local box7 = math.floor(18 * s)
            local rh7 = is_mouse_in(ox7, oy7, ow7, cb7)
            local box_y7 = oy7 + math.floor((cb7 - box7) / 2)
            draw_rect(ox7, box_y7, box7, box7, rh7 and C.widget_hover or C.widget_bg, math.floor(3 * s))
            if spawn_state[key] then
                draw_rect(ox7 + math.floor(3 * s), box_y7 + math.floor(3 * s), box7 - math.floor(6 * s), box7 - math.floor(6 * s), C.accent, math.floor(2 * s))
            end
            draw_text(label, ox7 + box7 + math.floor(8 * s), oy7 + math.floor(5 * s), UI.font_small, rh7 and C.text or C.text_dim)
            if rh7 and MOUSE.just_pressed then spawn_state[key] = not spawn_state[key] end
            oy7 = oy7 + cb7
        end
        json_checkbox("Delete Old Vehicle",    "json_delete_old")
        json_checkbox("Teleport to Vehicle",   "json_teleport")
        json_checkbox("Auto Start Engine",     "json_engine_on")
        json_checkbox("Vehicle God Mode",      "json_godmode")
        json_checkbox("Radio Off",             "json_radio_off")
        json_checkbox("Spawn Aircraft in Air", "json_spawn_in_air")
        json_checkbox("Max Visual Upgrade",    "json_max_upgrade")
        json_checkbox("Invisible Vehicle",     "json_invisible")

        oy7 = oy7 + math.floor(8 * s)
        draw_rect(ox7, oy7, ow7, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
        oy7 = oy7 + math.floor(10 * s)

        -- Delete last vehicle button
        local del7_h = math.floor(32 * s)
        local del7_hov = is_mouse_in(ox7, oy7, ow7, del7_h)
        draw_rect(ox7, oy7, ow7, del7_h, del7_hov and color(180,50,50,220) or C.widget_bg, math.floor(4 * s))
        draw_text_centered("Delete Last Vehicle", ox7, oy7, ow7, del7_h, UI.font_small, del7_hov and color(255,255,255,255) or color(220,80,80,255))
        if del7_hov and MOUSE.just_pressed then
            if spawn_state.json_last_spawned and spawn_state.json_last_spawned ~= 0 then
                for _, att in ipairs(spawn_state.json_last_attachments or {}) do
                    if att and att ~= 0 then pcall(entities.delete, att) end
                end
                spawn_state.json_last_attachments = {}
                pcall(entities.delete, spawn_state.json_last_spawned)
                spawn_state.json_last_spawned = nil
                safe_toast("JSON: Last vehicle and all props deleted")
            else
                safe_toast("JSON: No vehicle to delete")
            end
        end

        -- ── JSON Map controls (shown when a map is loaded) ──
        local jmap_count = #(spawn_state.json_map_spawned or {})
        if jmap_count > 0 or spawn_state.json_map_name then
            local oy7m = oy7 + del7_h + math.floor(12 * s)
            draw_rect(ox7, oy7m, ow7, math.floor(1 * s), C.separator or color(60,60,70,255), 0)
            oy7m = oy7m + math.floor(10 * s)

            local lbl7 = spawn_state.json_map_name or "Map"
            draw_text("Map: " .. lbl7 .. " (" .. jmap_count .. " obj)", ox7, oy7m, UI.font_small - 1, color(160,210,255,255))
            oy7m = oy7m + math.floor(20 * s)

            local tp7_h = math.floor(30 * s)
            local tp7_hov = is_mouse_in(ox7, oy7m, ow7, tp7_h)
            draw_rect(ox7, oy7m, ow7, tp7_h, tp7_hov and C.btn_hover or C.widget_bg, math.floor(4 * s))
            draw_text_centered("Teleport to Map", ox7, oy7m, ow7, tp7_h, UI.font_small, tp7_hov and C.text or C.text_dim)
            if tp7_hov and MOUSE.just_pressed then
                local first = (spawn_state.json_map_spawned or {})[1]
                if first and first ~= 0 then
                    local ok_p, p2 = pcall(invoker.call, 0x3FEF770D40960D5A, first, true)
                    if ok_p and p2 and p2.x then
                        local my_ped = invoker.call(0x43A66C31C68491C0, -1).int
                        if my_ped and my_ped ~= 0 then
                            pcall(invoker.call, 0x06843DA7060A026B, my_ped, 1.0*p2.x, 1.0*p2.y, 1.0*(p2.z + 2.0), false, false, false, true)
                            safe_toast("Teleported to map: " .. (spawn_state.json_map_name or ""))
                        end
                    end
                else
                    safe_toast("JSON: No map loaded")
                end
            end
            oy7m = oy7m + tp7_h + math.floor(6 * s)

            local dm7_h = math.floor(30 * s)
            local dm7_hov = is_mouse_in(ox7, oy7m, ow7, dm7_h)
            draw_rect(ox7, oy7m, ow7, dm7_h, dm7_hov and color(180,50,50,220) or C.widget_bg, math.floor(4 * s))
            draw_text_centered("Delete Map", ox7, oy7m, ow7, dm7_h, UI.font_small, dm7_hov and color(255,255,255,255) or color(200,80,80,255))
            if dm7_hov and MOUSE.just_pressed then
                local removed = 0
                for _, h in ipairs(spawn_state.json_map_spawned or {}) do
                    if h and h ~= 0 then pcall(entities.delete, h); removed = removed + 1 end
                end
                spawn_state.json_map_spawned = {}
                spawn_state.json_map_name = nil
                safe_toast("JSON Map deleted (" .. removed .. " objects removed)")
            end
        end

    end  -- end if/elseif tab chain
end  -- end draw_spawn_tab

    local function draw_heist_tab()
        local s = UI.scale
        local base_x = ui_layout.content_x
        local base_y = ui_layout.widget_y
        local total_w = ui_layout.content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- TWO columns: heist list (left) + options panel (right)
        local gap = math.floor(10 * s)
        local list_w = math.floor(160 * s)
        local panel_w = total_w - list_w - gap - math.floor(10 * s)

        -- LEFT: Heist Category List
        local list_x = base_x + math.floor(5 * s)
        local list_y = base_y

        local header_h = math.floor(24 * s)
        draw_rect(list_x, list_y, list_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Heists", list_x + math.floor(8 * s), list_y + math.floor(5 * s), UI.font_small, C.text)
        list_y = list_y + header_h + 2

        draw_rect(list_x, list_y, list_w, total_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local item_h = math.floor(36 * s)
        local py = list_y + math.floor(5 * s)

        for i, cat in ipairs(HEIST_CATEGORIES) do
            local is_selected = (heist_state.selected_category == i)
            local label = cat.icon .. "  " .. cat.name
            if selectable(label, is_selected, nil, list_x + 2, py, list_w - 4, item_h - 4) then
                heist_state.selected_category = i
                heist_state.scroll_offset = 0  -- Reset scroll when changing category
            end
            py = py + item_h
        end

        -- RIGHT: Options Panel
        local panel_x = list_x + list_w + gap
        local panel_y = base_y

        local selected_cat = HEIST_CATEGORIES[heist_state.selected_category]

        draw_rect(panel_x, panel_y, panel_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text(selected_cat.name .. " Options", panel_x + math.floor(8 * s), panel_y + math.floor(5 * s), UI.font_small, C.text)
        panel_y = panel_y + header_h + 2

        local panel_h = total_h - header_h - 2
        draw_rect(panel_x, panel_y, panel_w, panel_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Draw content for selected heist
        draw_heist_panel_content(panel_x, panel_y, panel_w, panel_h)
    end

