    -- =========================================================================
    -- CUSTOM MESSAGE EVENT HANDLER (Receives RGB messages from other players)
    -- =========================================================================
    util.create_thread(function()
        while true do
            -- Check for incoming script events (Lexis doesn't have built-in event listeners,
            -- so messages will display when sent by checking the event data structure)
            -- The actual event handling needs to be done via game hooks or polling

            -- NOTE: This is a placeholder - full implementation would require:
            -- 1. Hooking into game's script event system
            -- 2. Filtering for our magic ID (0x43525047)
            -- 3. Decoding the message and RGB values
            -- 4. Rendering the message on screen

            -- For now, the sending works and other players running THIS script
            -- will receive the events via the game's internal event system

            util.yield(1000)
        end
    end)

    -- Spectate system
    local spectate_state_ex = {active = false}

    -- Spectate background thread: runs EVERY frame while spectating to keep the
    -- ped protected. The original code only re-froze every 2 seconds which left a
    -- 2-second window each cycle where the ped could take damage, ragdoll, or die.
    util.create_thread(function()
        while true do
            if player_state.spectating_id then
                pcall(function()
                    local me = players and players.me and players.me()
                    local ped = me and me.ped
                    if ped and ped ~= 0 then
                        -- Keep frozen so the ped doesn't fall or drift
                        invoker.call(0x428CA6DBD1094446, ped, true)   -- FREEZE_ENTITY_POSITION
                        -- Make invincible so damage/bullets/explosions don't kill it
                        invoker.call(0x3882114BDE571AD4, ped, true)   -- SET_ENTITY_INVINCIBLE
                        -- Make invisible so NPCs and players can't target or shoot it
                        invoker.call(0xEA1C610A04DB6BBB, ped, false, false) -- SET_ENTITY_VISIBLE
                        -- Disable ragdoll so physics can't knock it over
                        invoker.call(0xB128377056A54E2A, ped, false)  -- SET_PED_CAN_RAGDOLL
                    end
                end)
            end
            util.yield(0)
        end
    end)

    local function stop_spectating()
        if player_state.spectating_id == nil then return end

        pcall(function()
            local me = players and players.me and players.me()
            local my_ped = me and me.ped

            if my_ped and my_ped ~= 0 then
                -- Disable spectator mode
                invoker.call(0x423DE3854BB50894, false, my_ped)  -- NETWORK_SET_IN_SPECTATOR_MODE

                -- Restore ped to normal state
                invoker.call(0x428CA6DBD1094446, my_ped, false)  -- FREEZE_ENTITY_POSITION off
                invoker.call(0x3882114BDE571AD4, my_ped, false)  -- SET_ENTITY_INVINCIBLE off
                invoker.call(0xEA1C610A04DB6BBB, my_ped, true, false) -- SET_ENTITY_VISIBLE on
                invoker.call(0xB128377056A54E2A, my_ped, true)   -- SET_PED_CAN_RAGDOLL on

                -- Restore position
                if player_state.spectate_saved_coords then
                    local c = player_state.spectate_saved_coords
                    invoker.call(0x239A3351AC1DA385, my_ped, c.x, c.y, c.z, false, false, false) -- SET_ENTITY_COORDS_NO_OFFSET
                    player_state.spectate_saved_coords = nil
                end
            end
        end)

        player_state.spectating_id = nil
        spectate_state_ex.active = false
    end

    local function start_spectating(target_id, target_ped)
        local me = players and players.me and players.me()
        if not me or not me.ped or not me.coords then return false end

        pcall(function()
            -- Save current position so we can restore it on stop
            player_state.spectate_saved_coords = {x = me.coords.x, y = me.coords.y, z = me.coords.z}

            -- Apply all protections immediately before enabling spectator mode
            -- so there is zero gap where the ped is unprotected
            invoker.call(0x428CA6DBD1094446, me.ped, true)        -- FREEZE_ENTITY_POSITION
            invoker.call(0x3882114BDE571AD4, me.ped, true)        -- SET_ENTITY_INVINCIBLE
            invoker.call(0xEA1C610A04DB6BBB, me.ped, false, false) -- SET_ENTITY_VISIBLE
            invoker.call(0xB128377056A54E2A, me.ped, false)       -- SET_PED_CAN_RAGDOLL

            -- Enable spectator mode (pass target ped, not player ID)
            invoker.call(0x423DE3854BB50894, true, target_ped)    -- NETWORK_SET_IN_SPECTATOR_MODE
        end)

        player_state.spectating_id = target_id
        spectate_state_ex.active = true
        return true
    end

    -- Helper for info panel rows - SEPARATE INFO PANEL outside main window (matching ClickUI PlayerInfo.lua)
    local function draw_info_row(label1, value1, label2, value2, x, y, w, font_size, pad, row_h)
        local half = w / 2
        local fs = font_size or UI.font_widget
        local p = pad or math.floor(10 * UI.scale)

        -- Left column: label + value (value right-aligned within left half)
        draw_text(label1, x + p, y, fs, C.overlay_text)

        -- Estimate text width for right-alignment
        local v1_str = tostring(value1)
        local v1_w = #v1_str * (fs * 0.55)
        draw_text(v1_str, x + half - v1_w - p, y, fs, C.overlay_text)

        -- Divider
        draw_text("|", x + half - 2, y - 2, fs, C.overlay_divider)

        -- Right column
        if label2 then
            draw_text(label2, x + half + p, y, fs, C.overlay_text)
            local v2_str = tostring(value2)
            local v2_w = #v2_str * (fs * 0.55)
            draw_text(v2_str, x + w - v2_w - p, y, fs, C.overlay_text)
        end

        return y + (row_h or math.floor(24 * UI.scale))
    end

    local function draw_player_tab()
        update_player_list()

        local s = UI.scale
        local base_x = ui_layout.content_x
        local base_y = ui_layout.widget_y
        local total_w = ui_layout.content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- TWO columns inside main window (player list + actions) - scaled properly
        local gap = math.floor(10 * s)
        local list_w = math.floor(280 * s)
        local action_w = total_w - list_w - gap - math.floor(10 * s)

        -- LEFT: Player List
        local list_x = base_x + math.floor(5 * s)
        local list_y = base_y
        local list_h = total_h

        local player_count = #player_state.player_list
        local header_h = math.floor(24 * s)
        draw_rect(list_x, list_y, list_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Online Players (" .. player_count .. "/32)", list_x + math.floor(8 * s), list_y + math.floor(5 * s), UI.font_small, C.text)
        list_y = list_y + header_h + 2

        draw_rect(list_x, list_y, list_w, list_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local item_h = math.floor(26 * s)
        local visible_items = math.floor((list_h - header_h - 2) / item_h)

        -- Handle mouse wheel scrolling for player list
        local list_hover = is_mouse_in(list_x, list_y, list_w, list_h - header_h - 2)
        if list_hover then
            if MOUSE.scroll_up then
                player_state.list_scroll = math.max(0, player_state.list_scroll - 1)
            elseif MOUSE.scroll_down then
                local max_scroll = math.max(0, player_count - visible_items)
                player_state.list_scroll = math.min(max_scroll, player_state.list_scroll + 1)
            end
        end

        local start_idx = math.max(1, player_state.list_scroll + 1)
        local end_idx = math.min(player_count, start_idx + visible_items - 1)

        local py = list_y + math.floor(3 * s)
        for i = start_idx, end_idx do
            local p = player_state.player_list[i]
            if p then
                local label = p.name .. " [" .. p.id .. "]"
                if player_state.selected_id == p.id then label = "> " .. label end
                if selectable(label, player_state.selected_id == p.id, p.tags, list_x + 2, py, list_w - 4, item_h - 2) then
                    local prev_id = player_state.selected_id
                    player_state.selected_id = p.id
                    if DEBUG.feature_debug and prev_id ~= p.id then
                        debug_info("PLAYER", string.format("Selected player: %s [ID: %d]", p.name or "Unknown", p.id))
                    end
                end
                py = py + item_h
            end
        end

        -- RIGHT: Actions panel
        local action_x = list_x + list_w + gap
        local action_y = base_y

        local new_sub_tab, tab_h = sub_tab_bar(player_state.sub_tabs, player_state.sub_tab, action_x, action_y, action_w)
        if new_sub_tab ~= player_state.sub_tab then
            player_state.scroll_offset = 0
        end
        player_state.sub_tab = new_sub_tab
        action_y = action_y + tab_h

        local action_panel_h = list_h - tab_h
        draw_rect(action_x, action_y, action_w, action_panel_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local action_clip = gui and gui.push_clip and vec2
        if action_clip then gui.push_clip(vec2(action_x, action_y), vec2(action_w, action_panel_h)) end

        local selected = get_selected_player()
        local ay = action_y + math.floor(8 * s) - player_state.scroll_offset
        local content_start_y = action_y + math.floor(8 * s)
        local btn_h = math.floor(28 * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)

        if not selected then
            draw_text("Select a player", action_x + math.floor(10 * s), ay, UI.font_widget, C.text_dim)
        else
            local btn_w = (action_w - side_pad * 3) / 2

            if player_state.sub_tab == 1 then
                -- GENERAL
                local is_spec = (player_state.spectating_id == selected.id)
                local cb_h = math.floor(26 * s)
                local new_spec = inline_toggle("Spectate Player", is_spec, action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                if new_spec ~= is_spec then
                    if is_spec then stop_spectating(); safe_toast("Stopped spectating")
                    else if start_spectating(selected.id, selected.ped) then safe_toast("Spectating " .. selected.name) end end
                end
                ay = ay + cb_h + btn_gap
                if small_button("Copy Name", action_x + side_pad, ay, btn_w, btn_h) then safe_toast("Name: " .. selected.name) end
                if small_button("Copy RID", action_x + side_pad * 2 + btn_w, ay, btn_w, btn_h) then safe_toast("RID: " .. tostring(selected.rockstar_id)) end
                ay = ay + btn_h + btn_gap

                -- Detected menu display
                local menu_label = nil  -- mod menu detection removed
                if menu_label then
                    draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, math.floor(24 * s), color(30, 20, 50, 180), math.floor(4 * s))
                    draw_text("  Menu: " .. menu_label, action_x + side_pad + math.floor(4 * s), ay + math.floor(5 * s), UI.font_small, color(180, 130, 255, 255))
                    ay = ay + math.floor(24 * s) + btn_gap
                end

                -- Add to Watchlist button
                do
                    local lname = (selected.name or ""):lower()
                    if KYRON_WATCHLIST[lname] then
                        draw_text("  ✓ On Watchlist (all attacks blocked)", action_x + side_pad, ay, UI.font_small, color(100, 220, 100, 220))
                        ay = ay + math.floor(18 * s) + btn_gap
                    else
                        if small_button("⛔  Add to Watchlist", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                            kyron_watchlist_add(selected.name or "")
                            safe_toast("[KYRON] Added to watchlist: " .. (selected.name or "?") .. "\nAll their attacks will be blocked.")
                        end
                        ay = ay + btn_h + btn_gap
                    end
                end

                -- CUSTOM MESSAGE SECTION
                ay = ay + math.floor(10 * s)
                draw_text("  Send Phone Message (to selected player)", action_x + side_pad, ay, UI.font_widget, C.accent)
                ay = ay + math.floor(18 * s)

                -- Message input box
                local input_h = math.floor(32 * s)
                local input_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, input_h)
                local bg_col = player_state.message_text_focused and C.widget_hover or (input_hover and C.widget_hover or C.widget_bg)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, input_h, bg_col, math.floor((UI.widget_rounding or 5) * s))
                -- Accent border when focused
                if player_state.message_text_focused then
                    local mx = action_x + side_pad
                    local mw = action_w - side_pad * 2
                    draw_rect(mx, ay, mw, math.floor(2 * s), C.accent, math.floor(6 * s))
                    draw_rect(mx, ay + input_h - math.floor(2 * s), mw, math.floor(2 * s), C.accent, math.floor(6 * s))
                    draw_rect(mx, ay, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
                    draw_rect(mx + mw - math.floor(2 * s), ay, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
                end

                -- Handle focus
                if input_hover and MOUSE.just_pressed then
                    player_state.message_text_focused = true
                elseif MOUSE.just_pressed and not input_hover then
                    player_state.message_text_focused = false
                end

                -- Handle keyboard input
                if player_state.message_text_focused and input and input.key then
                    if input.key(0x08).just_pressed and #player_state.message_text > 0 then
                        player_state.message_text = player_state.message_text:sub(1, -2)
                    end
                    for code = 0x30, 0x39 do
                        if input.key(code).just_pressed then
                            player_state.message_text = player_state.message_text .. string.char(code)
                        end
                    end
                    local shift_pressed = input.key(0x10).pressed
                    for code = 0x41, 0x5A do
                        if input.key(code).just_pressed then
                            player_state.message_text = player_state.message_text .. (shift_pressed and string.char(code) or string.char(code):lower())
                        end
                    end
                    if input.key(0x20).just_pressed then player_state.message_text = player_state.message_text .. " " end
                    if input.key(0xBD).just_pressed then player_state.message_text = player_state.message_text .. "-" end
                    if input.key(0xBB).just_pressed then player_state.message_text = player_state.message_text .. "=" end
                    if input.key(0xBC).just_pressed then player_state.message_text = player_state.message_text .. "," end
                    if input.key(0xBE).just_pressed then player_state.message_text = player_state.message_text .. "." end
                    if input.key(0xBF).just_pressed then player_state.message_text = player_state.message_text .. "/" end
                    if input.key(0xBA).just_pressed then player_state.message_text = player_state.message_text .. ":" end
                    if input.key(0xDE).just_pressed then player_state.message_text = player_state.message_text .. "'" end
                    if input.key(0xC0).just_pressed then player_state.message_text = player_state.message_text .. "`" end
                    if input.key(0xBD).just_pressed and shift_pressed then player_state.message_text = player_state.message_text .. "_" end
                end

                -- Display text
                if player_state.message_text ~= "" then
                    local display_text = player_state.message_text .. (player_state.message_text_focused and "_" or "")
                    draw_text(display_text, action_x + side_pad + math.floor(10 * s), ay + math.floor(8 * s), UI.font_small, C.text)
                else
                    draw_text("Type your message...", action_x + side_pad + math.floor(10 * s), ay + math.floor(8 * s), UI.font_small, color(100,100,100,180))
                end
                ay = ay + input_h + btn_gap

                -- Send button
                if small_button(" > Send Message", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if player_state.message_text ~= "" then
                        -- Send to selected player (phone message via NETWORK_SEND_TEXT_MESSAGE)
                        if selected then
                            -- Don't send to yourself (causes crash)
                            if selected.id == player_state.my_id then
                                safe_toast("Cannot send message to yourself!")
                            else
                                pcall(function()
                                    -- Use NETWORK_SEND_TEXT_MESSAGE (shows as phone message)
                                    local success = invoker.call(0x3A214F2EC889B100, player_state.message_text, selected.gamer_handle)
                                    if success and success.bool then
                                        safe_toast("Message sent to " .. selected.name)
                                    else
                                        safe_toast("Failed to send message (player may have blocked messages)")
                                    end
                                end)
                            end
                        else
                            safe_toast("Select a player first!")
                        end

                        -- Don't reset message so user can re-send if needed
                    else
                        safe_toast("Enter a message first")
                    end
                end
                ay = ay + btn_h + btn_gap

            elseif player_state.sub_tab == 2 then
                -- TELEPORT
                if small_button("Teleport To Player", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.coords and N.SET_ENTITY_COORDS_NO_OFFSET then
                        local me = players and players.me and players.me()
                        if me then
                            local entity = (me.vehicle and me.vehicle ~= 0) and me.vehicle or me.ped
                            if entity then
                                pcall(N.SET_ENTITY_COORDS_NO_OFFSET, entity, selected.coords.x, selected.coords.y, selected.coords.z, false, false, false)
                                safe_toast("Teleported to " .. selected.name)
                            end
                        end
                    else
                        safe_toast("Teleport not available")
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Teleport Above", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.coords and N.SET_ENTITY_COORDS_NO_OFFSET then
                        local me = players and players.me and players.me()
                        if me then
                            local entity = (me.vehicle and me.vehicle ~= 0) and me.vehicle or me.ped
                            if entity then
                                pcall(N.SET_ENTITY_COORDS_NO_OFFSET, entity, selected.coords.x, selected.coords.y, selected.coords.z + 10, false, false, false)
                                safe_toast("Teleported above " .. selected.name)
                            end
                        end
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Teleport Into Vehicle", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.vehicle and selected.vehicle ~= 0 then
                        local me = players and players.me and players.me()
                        if me and me.ped and N.SET_ENTITY_COORDS_NO_OFFSET then
                            -- Teleport to vehicle location
                            pcall(N.SET_ENTITY_COORDS_NO_OFFSET, me.ped, selected.coords.x, selected.coords.y, selected.coords.z, false, false, false)
                            -- Wait a moment then put in vehicle
                            util.yield(100)
                            -- TASK_WARP_PED_INTO_VEHICLE (0x9A7D091411C5F684) - seat -1 = driver
                            if invoker and invoker.call then
                                pcall(function()
                                    invoker.call(0x9A7D091411C5F684, me.ped, selected.vehicle, -1)
                                end)
                            end
                            safe_toast("Teleported into " .. selected.name .. "'s vehicle")
                        end
                    else
                        safe_toast(selected.name .. " is not in a vehicle")
                    end
                end

            elseif player_state.sub_tab == 3 then
                -- FRIENDLY
                if small_button("Give All Weapons", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.ped and N.GIVE_WEAPON_TO_PED and N.GET_HASH_KEY then
                        local weapons = {"WEAPON_PISTOL", "WEAPON_SMG", "WEAPON_ASSAULTRIFLE", "WEAPON_SNIPERRIFLE", "WEAPON_RPG"}
                        for _, w in ipairs(weapons) do
                            local hash = N.GET_HASH_KEY(w)
                            if hash and hash ~= 0 then
                                pcall(N.GIVE_WEAPON_TO_PED, selected.ped, hash, 9999, false, true)
                            end
                        end
                        safe_toast("Gave weapons to " .. selected.name)
                    else
                        safe_toast("Cannot give weapons")
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Give Max Health", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.ped and N.SET_ENTITY_HEALTH then
                        pcall(N.SET_ENTITY_HEALTH, selected.ped, 328, 0)
                        safe_toast("Gave health to " .. selected.name)
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Give Armor", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.ped and N.SET_PED_ARMOUR then
                        pcall(N.SET_PED_ARMOUR, selected.ped, 100)
                        safe_toast("Gave armor to " .. selected.name)
                    end
                end
                ay = ay + btn_h + btn_gap

                -- =====================================================
                -- BODYGUARD
                -- =====================================================
                do
                    if not player_state.bg_states then player_state.bg_states = {} end
                    if not player_state.bg_states[selected.id] then
                        player_state.bg_states[selected.id] = {
                            bodyguards = {},
                            spawn_amount = 1,
                            preset_idx = 1,
                            weapon_idx = 1,
                            invincible = false,
                            open = false,
                        }
                    end
                    local bg = player_state.bg_states[selected.id]

                    local bg_presets = {
                        {name="Private Mercenaries", models={0x613E626C,0x5076A73B,0xB3F3EE34}, weapon=0x83BF0278},
                        {name="High-Level Security",  models={0xF161D212,0x2930C1AB,0x55FE9B46}, weapon=0x2B5EF5EC},
                        {name="Ballas OGs",           models={0x231AF63F,0xABEF0004,0xDB41B4EF}, weapon=0x1B06D571},
                        {name="Families OGs",         models={0x33A464E5,0xE83B93B7,0x84302B09}, weapon=0x1B06D571},
                        {name="Vagos Esses",          models={0x837B64DE,0x5AA42C21,0x964D12DC}, weapon=0x1B06D571},
                        {name="Lost MC",              models={0x32B11CDC,0x4F46D607,0xFD5537DE}, weapon=0x1B06D571},
                        {name="Armenian Mobsters",    models={0xE7714013,0xFDA94268,0xF1E823A2}, weapon=0x1B06D571},
                        {name="Cartel Sicarios",      models={0x995B3F9F,0x7ED5AD78,0xE6AC74A4}, weapon=0xBFEFFF6D},
                        {name="Bad Bitches",          models={0x28ABF95, 0x81441B71,0xAEEA76B5}, weapon=0x2BE6766B},
                        {name="Law: FIB",             models={0xEDBC7546,0x7B8B434B,0x5CDEF405}, weapon=0x1B06D571},
                        {name="Law: LSPD",            models={0x5E3DA4A4,0x15F8700D,0x5E3DA4A4}, weapon=0x1B06D571},
                        {name="Law: SWAT",            models={0x8D8F1B10,0x8D8F1B10,0x8D8F1B10}, weapon=0x2B5EF5EC},
                    }

                    local bg_weapons = {
                        {name="Default (Preset)",       hash=0},
                        {name="Railgun",                hash=joaat("weapon_railgun")},
                        {name="Minigun",                hash=joaat("weapon_minigun")},
                        {name="RPG",                    hash=joaat("weapon_rpg")},
                        {name="Combat MG",              hash=joaat("weapon_combatmg")},
                        {name="Tactical SMG",           hash=joaat("weapon_tecpistol")},
                        {name="Micro SMG",              hash=joaat("weapon_microsmg")},
                        {name="Mini SMG",               hash=joaat("weapon_minismg")},
                        {name="Machine Pistol",         hash=joaat("weapon_machinepistol")},
                        {name="AP Pistol",              hash=joaat("weapon_appistol")},
                        {name="Pistol Mk II",           hash=joaat("weapon_pistol_mk2")},
                        {name="Combat Pistol",          hash=joaat("weapon_combatpistol")},
                        {name="Pistol .50",             hash=joaat("weapon_pistol50")},
                        {name="Heavy Revolver",         hash=joaat("weapon_revolver")},
                        {name="Heavy Revolver Mk II",   hash=joaat("weapon_revolver_mk2")},
                        {name="Navy Revolver",          hash=joaat("weapon_navyrevolver")},
                        {name="Double Action Revolver", hash=joaat("weapon_doubleaction")},
                        {name="Up-n-Atomizer",          hash=joaat("weapon_raypistol")},
                        {name="Stun Gun",               hash=joaat("weapon_stungun")},
                    }

                    -- Bodyguard dropdown header
                    local bg_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h or math.floor(26*s))
                    local cb_h2 = math.floor(26 * s)
                    draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, cb_h2, bg_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                    local bg_arrow = bg.open and "v" or ">"
                    draw_text(bg_arrow .. " Bodyguard", action_x + side_pad + math.floor(6 * s), ay + (cb_h2 - UI.font_small) / 2, UI.font_small, C.text)
                    if bg_hover and MOUSE.just_pressed then bg.open = not bg.open end
                    ay = ay + cb_h2 + math.floor(2 * s)

                    if bg.open then
                        local ind = math.floor(20 * s)
                        local iw  = action_w - side_pad * 2 - ind
                        local btn_h2 = math.floor(22 * s)

                        -- Cycle unit preset
                        if small_button("Unit: " .. bg_presets[bg.preset_idx].name, action_x + side_pad + ind, ay, iw, btn_h2) then
                            bg.preset_idx = (bg.preset_idx % #bg_presets) + 1
                            safe_toast("Unit: " .. bg_presets[bg.preset_idx].name)
                        end
                        ay = ay + btn_h2 + math.floor(2 * s)

                        -- Cycle weapon
                        if not bg.weapon_idx then bg.weapon_idx = 1 end
                        local wname = bg_weapons[bg.weapon_idx].name
                        if small_button("Weapon: " .. wname, action_x + side_pad + ind, ay, iw, btn_h2) then
                            bg.weapon_idx = (bg.weapon_idx % #bg_weapons) + 1
                            safe_toast("Weapon: " .. bg_weapons[bg.weapon_idx].name)
                        end
                        ay = ay + btn_h2 + math.floor(2 * s)

                        -- Spawn amount -/+
                        if small_button("Amount: " .. bg.spawn_amount .. "  [-]", action_x + side_pad + ind, ay, iw / 2 - math.floor(2*s), btn_h2) then
                            bg.spawn_amount = math.max(1, bg.spawn_amount - 1)
                        end
                        if small_button("[+]", action_x + side_pad + ind + iw / 2, ay, iw / 2, btn_h2) then
                            bg.spawn_amount = math.min(10, bg.spawn_amount + 1)
                        end
                        ay = ay + btn_h2 + math.floor(2 * s)

                        -- Spawn Bodyguards
                        if small_button("Spawn Bodyguards", action_x + side_pad + ind, ay, iw, btn_h2) then
                            if selected.ped then
                                local sel_ped   = selected.ped
                                local preset    = bg_presets[bg.preset_idx]
                                local amount    = bg.spawn_amount
                                local invinc    = bg.invincible
                                local wsel      = bg_weapons[bg.weapon_idx or 1]
                                local use_weapon = (wsel and wsel.hash ~= 0) and wsel.hash or preset.weapon
                                util.create_job(function()
                                    local UNARMED = 0xA2719263
                                    -- Get or create group on the TARGET ped so guards follow them
                                    local group = PED.GET_PED_GROUP_INDEX(sel_ped)
                                    if group == 0 then
                                        group = PED.CREATE_GROUP(0)
                                        PED.SET_PED_AS_GROUP_LEADER(sel_ped, group)
                                    end
                                    PED.SET_GROUP_FORMATION(group, 0)
                                    PED.SET_GROUP_SEPARATION_RANGE(group, 16960)
                                    local pos = selected.coords
                                    if not pos then return end
                                    local heading = ENTITY.GET_ENTITY_HEADING(sel_ped)
                                    for i = 1, amount do
                                        local mdl = preset.models[math.random(1, #preset.models)]
                                        local rad = math.rad(heading)
                                        local ox = -math.sin(rad) * (2.0 + i * 1.5)
                                        local oy =  math.cos(rad) * (2.0 + i * 1.5)
                                        local ped = entities.create_ped(4, mdl, {x=pos.x+ox, y=pos.y+oy, z=pos.z}, heading)
                                        if ped and ped ~= 0 then
                                            -- Combat config flags
                                            PED.SET_PED_CONFIG_FLAG(ped, 2,   true)
                                            PED.SET_PED_CONFIG_FLAG(ped, 43,  true)
                                            PED.SET_PED_CONFIG_FLAG(ped, 140, false)
                                            PED.SET_PED_CONFIG_FLAG(ped, 141, true)
                                            PED.SET_PED_CONFIG_FLAG(ped, 179, true)
                                            PED.SET_PED_CONFIG_FLAG(ped, 249, true)
                                            PED.SET_PED_CONFIG_FLAG(ped, 402, true)
                                            PED.SET_PED_CONFIG_FLAG(ped, 443, true)
                                            -- Combat ability
                                            PED.SET_PED_COMBAT_ABILITY(ped, 2)
                                            PED.SET_PED_COMBAT_MOVEMENT(ped, 2)
                                            PED.SET_PED_COMBAT_RANGE(ped, 2)
                                            PED.SET_PED_ACCURACY(ped, 100)
                                            PED.SET_PED_COMBAT_ATTRIBUTES(ped, 5,  true)
                                            PED.SET_PED_COMBAT_ATTRIBUTES(ped, 46, true)
                                            PED.SET_PED_FLEE_ATTRIBUTES(ped, 0, false)
                                            -- Weapon: always give it drawn and ready
                                            WEAPON.GIVE_WEAPON_TO_PED(ped, use_weapon, 9999, false, true)
                                            WEAPON.SET_CURRENT_PED_WEAPON(ped, use_weapon, true)
                                            WEAPON.SET_PED_INFINITE_AMMO_CLIP(ped, true)
                                            PED.SET_PED_CAN_SWITCH_WEAPON(ped, true)
                                            -- Group: member of target's group so they follow target
                                            PED.SET_PED_AS_GROUP_MEMBER(ped, group)
                                            PED.SET_PED_NEVER_LEAVES_GROUP(ped, true)
                                            ENTITY.SET_ENTITY_INVINCIBLE(ped, invinc)
                                            table.insert(bg.bodyguards, ped)
                                        end
                                        util.yield(100)
                                    end
                                    safe_toast("Spawned " .. amount .. " " .. preset.name)
                                end)
                            end
                        end
                        ay = ay + btn_h2 + math.floor(2 * s)

                        -- Invincibility toggle
                        local new_invinc = inline_toggle("Invincible", bg.invincible, action_x + side_pad + ind, ay, iw, cb_h2)
                        if new_invinc ~= bg.invincible then
                            bg.invincible = new_invinc
                            for _, ped in ipairs(bg.bodyguards) do
                                if invoker.call(0x7239B21A38F536BA, ped).bool then
                                    invoker.call(0x3882114BDE571AD4, ped, new_invinc)  -- SET_ENTITY_INVINCIBLE
                                end
                            end
                            safe_toast("Bodyguards " .. (new_invinc and "Invincible" or "Mortal"))
                        end
                        ay = ay + cb_h2 + math.floor(2 * s)

                        -- Delete All
                        if small_button("Delete All Bodyguards", action_x + side_pad + ind, ay, iw, btn_h2) then
                            for _, ped in ipairs(bg.bodyguards) do
                                pcall(function()
                                    if invoker.call(0x7239B21A38F536BA, ped).bool then
                                        invoker.call(0xAE3CBE5BF394C9C9, ped)
                                    end
                                end)
                            end
                            bg.bodyguards = {}
                            safe_toast("Bodyguards deleted")
                        end
                        ay = ay + btn_h2 + math.floor(2 * s)
                    end
                end

            elseif player_state.sub_tab == 4 then
                -- TROLLING
                local troll = get_troll_state(selected.id)
                local player_obj = get_player_object(selected.id)

                -- ── v10 Troll Spawn Helpers (no host/script-host required) ──────────────────
                -- Primary path: spawn.* API (Lexis v10) with script_host_object=false.
                -- Fallback: raw native with bScriptHostObj=false + networkise_entity().
                -- ALL trolling spawns must go through these helpers, never the raw natives
                -- directly with bScriptHostObj=true or bNetMissionPed=true.
                local function _ts_veh(hash, x, y, z, hdg)
                    if spawn and type(spawn.vehicle) == "function" then
                        local ok, r = pcall(spawn.vehicle, hash, scr_vec3(x,y,z), hdg, true, false)
                        if ok and r and r ~= 0 then return r end
                    end
                    -- fallback: bScriptHostObj=false
                    local res = invoker.call(0xAF35D0D2583051B0, hash, x, y, z, hdg, true, false, false)
                    local h = res and res.int or 0
                    if h ~= 0 then networkise_entity(h) end
                    return h ~= 0 and h or nil
                end
                local function _ts_ped(ptype, hash, x, y, z, hdg)
                    if spawn and type(spawn.ped) == "function" then
                        local ok, r = pcall(spawn.ped, hash, scr_vec3(x,y,z), hdg, true, false)
                        if ok and r and r ~= 0 then return r end
                    end
                    -- fallback: bNetMissionPed=false
                    local res = invoker.call(0xD49F9B0955C367DE, ptype, hash, x, y, z, hdg, true, false)
                    local h = res and res.int or 0
                    if h ~= 0 then networkise_entity(h) end
                    return h ~= 0 and h or nil
                end
                local function _ts_obj(hash, x, y, z)
                    if spawn and type(spawn.object) == "function" then
                        local ok, r = pcall(spawn.object, hash, scr_vec3(x,y,z), true, false)
                        if ok and r and r ~= 0 then return r end
                    end
                    -- fallback: bScriptHostObj=false
                    local res = invoker.call(0x509D5878EB39E842, hash, x, y, z, true, false, false)
                    local h = res and res.int or 0
                    if h ~= 0 then networkise_entity(h) end
                    return h ~= 0 and h or nil
                end
                -- ── End helpers ──────────────────────────────────────────────────────────────

                local cb_h = math.floor(26 * s)
                local box_size = math.floor(16 * s)

                -- One-Shot Attacks Dropdown
                local attack_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, cb_h, attack_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                local attack_arrow = (troll.attack_trolls_open or false) and "v" or ">"
                draw_text(attack_arrow .. " One-Shot Attacks", action_x + side_pad + math.floor(6 * s), ay + (cb_h - UI.font_small) / 2, UI.font_small, C.text)
                if attack_hover and MOUSE.just_pressed then
                    troll.attack_trolls_open = not (troll.attack_trolls_open or false)
                end
                ay = ay + cb_h + btn_gap

                if troll.attack_trolls_open then
                    -- Kill Player (button - instant action)
                    if small_button("Kill Player", action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), btn_h) then
                        if selected.ped and N.SET_ENTITY_HEALTH then N.SET_ENTITY_HEALTH(selected.ped, 0, 0); safe_toast("Killed") end
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- God Mode Killer (button - spawns Rhino on target, explodes it, cleans up after 8s)
                    if small_button("God Mode Killer", action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), btn_h) then
                        local selected_id = selected.id
                        util.create_job(function()
                            -- Get target ped via GET_PLAYER_PED (0x43A66C31C68491C0)
                            local target_ped = invoker.call(0x43A66C31C68491C0, selected_id).int
                            if not target_ped or target_ped == 0 then
                                safe_toast("[Kyron] God Mode Killer: target not found")
                                return
                            end

                            -- Get fresh target coords via GET_ENTITY_COORDS (0x3FEF770D40960D5A)
                            local coords = invoker.call(0x3FEF770D40960D5A, target_ped, true)
                            if not coords or not coords.scr_vec3 then
                                safe_toast("[Kyron] God Mode Killer: could not get coords")
                                return
                            end
                            local tx = coords.scr_vec3.x
                            local ty = coords.scr_vec3.y
                            local tz = coords.scr_vec3.z

                            -- Resolve rhino hash via GET_HASH_KEY (0xD24D37CC275948CC)
                            local rhino_hash = invoker.call(0xD24D37CC275948CC, "rhino").int

                            -- IS_MODEL_IN_CDIMAGE (0x35B9E0803292B641) + IS_MODEL_VALID (0xC0296A2EDF545E92)
                            local in_cd  = invoker.call(0x35B9E0803292B641, rhino_hash)
                            local is_valid = invoker.call(0xC0296A2EDF545E92, rhino_hash)
                            if not (in_cd and in_cd.bool) or not (is_valid and is_valid.bool) then
                                safe_toast("[Kyron] God Mode Killer: Rhino model invalid")
                                return
                            end

                            -- REQUEST_MODEL (0x963D27A58DF860AC)
                            invoker.call(0x963D27A58DF860AC, rhino_hash)
                            local load_start = util.get_tick_count()
                            -- HAS_MODEL_LOADED (0x98A4EB5D89A0C952)
                            while not invoker.call(0x98A4EB5D89A0C952, rhino_hash).bool do
                                if util.get_tick_count() - load_start > 5000 then
                                    safe_toast("[Kyron] God Mode Killer: model load timeout")
                                    return
                                end
                                util.yield(0)
                            end

                            -- Spawn Rhino slightly above player so it drops onto them
                            -- CREATE_VEHICLE (0xAF35D0D2583051B0)
                            local rhino = _ts_veh(rhino_hash, tx, ty, tz + 3.0, 0.0)
                            -- SET_MODEL_AS_NO_LONGER_NEEDED (0xE532F5D78798DAAB)
                            invoker.call(0xE532F5D78798DAAB, rhino_hash)

                            if not rhino or rhino == 0 then
                                safe_toast("[Kyron] God Mode Killer: failed to spawn Rhino")
                                return
                            end

                            -- Networkise and take ownership
                            invoker.call(0x06FAACD625D80CAA, rhino)  -- NETWORK_REGISTER_ENTITY_AS_NETWORKED
                            invoker.call(0xAD738C3085FE7E11, rhino, true, true)  -- SET_ENTITY_AS_MISSION_ENTITY
                            local netId_r = invoker.call(0xA11700682F3AD45C, rhino).int  -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
                            if netId_r and netId_r ~= 0 then
                                invoker.call(0xE05E81A888FA63C8, netId_r, true)   -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
                                invoker.call(0x299EEB23175895FC, netId_r, false)  -- SET_NETWORK_ID_CAN_MIGRATE false (keep control)
                            end
                            for _ = 1, 15 do
                                local has = invoker.call(0x01BF60A500E28887, rhino)  -- NETWORK_HAS_CONTROL_OF_ENTITY
                                if has and has.bool then break end
                                invoker.call(0xB69317BF5E782347, rhino)  -- NETWORK_REQUEST_CONTROL_OF_ENTITY
                                util.yield(50)
                            end

                            -- Slam it down onto the player with downward velocity
                            invoker.call(0x1C99BB7B6E96D16F, rhino, 0.0, 0.0, -50.0)  -- SET_ENTITY_VELOCITY

                            -- Wait for it to land
                            util.yield(100)

                            -- Force ragdoll BEFORE explosion to bypass no-ragdoll protection
                            invoker.call(0xB128377056A54E2A, target_ped, true)       -- SET_PED_CAN_RAGDOLL
                            invoker.call(0xD86D101FCFD00A4B, target_ped, 0)          -- CLEAR_RAGDOLL_BLOCKING_FLAGS
                            invoker.call(0xAE99FB955581844A, target_ped, 10000, 10000, 0, true, true, false)  -- SET_PED_TO_RAGDOLL

                            -- EXPLODE_VEHICLE (0xBA71116ADF5B514C)
                            invoker.call(0xBA71116ADF5B514C, rhino, true, false)

                            safe_toast("[Kyron] God Mode Killer: BOOM! Cleaning up in 8s...")

                            -- Wait 8 seconds then clean up wreckage
                            util.yield(8000)

                            pcall(function()
                                local exists = invoker.call(0x7239B21A38F536BA, rhino)  -- DOES_ENTITY_EXIST
                                if not (exists and exists.bool) then return end
                                invoker.call(0xAD738C3085FE7E11, rhino, true, true)  -- SET_ENTITY_AS_MISSION_ENTITY
                                for _ = 1, 15 do
                                    local has = invoker.call(0x01BF60A500E28887, rhino)  -- NETWORK_HAS_CONTROL_OF_ENTITY
                                    if has and has.bool then break end
                                    invoker.call(0xB69317BF5E782347, rhino)  -- NETWORK_REQUEST_CONTROL_OF_ENTITY
                                    util.yield(50)
                                end
                                -- Teleport wreckage to deep ocean
                                invoker.call(0x06843DA7060A026B, rhino, 4500.0, -5000.0, -200.0, false, false, false, false)  -- SET_ENTITY_COORDS
                                local netId_c = invoker.call(0xA11700682F3AD45C, rhino).int
                                if netId_c and netId_c ~= 0 then
                                    invoker.call(0x299EEB23175895FC, netId_c, true)   -- SET_NETWORK_ID_CAN_MIGRATE true
                                    invoker.call(0xE05E81A888FA63C8, netId_c, false)  -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES false
                                end
                            end)
                        end)
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Launch Into Sky (exact copy from testtrollscript)
                    local new_launch = inline_toggle("Launch Into Sky", troll.launch_sky, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_launch ~= troll.launch_sky then
                        troll.launch_sky = new_launch
                        if new_launch and selected.ped then
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.launch_sky = false
                                    return
                                end
                                local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z

                                local entity = selected.ped
                                local veh_result = invoker.call(0x9A9112A0FE9A4713, selected.ped, false)  -- GET_VEHICLE_PED_IS_IN
                                if veh_result and veh_result.int and veh_result.int ~= 0 then
                                    if request_control(veh_result.int) then
                                        entity = veh_result.int
                                    end
                                end

                                invoker.call(0x06843DA7060A026B, entity, px, py, pz + 2500.0, false, false, false, false)  -- SET_ENTITY_COORDS
                                safe_toast("Target launched to space!")
                                troll.launch_sky = false
                            end)
                        elseif not new_launch then
                            troll.launch_sky = false
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- TP to Ocean (button - instant action)
                    if small_button("TP to Ocean", action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), btn_h) then
                        if player_obj and player_obj.teleport then pcall(function() player_obj:teleport(vec3(4500, 8000, 0)) end); safe_toast("Ocean TP") end
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Spawn Clones (toggle - loops while active)
                    local new_spawn_clones = inline_toggle("Spawn Clones", troll.spawn_clones, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_spawn_clones ~= troll.spawn_clones then
                        troll.spawn_clones = new_spawn_clones
                        if new_spawn_clones and selected.ped then
                            local sid = {}
                            troll.spawn_clones_sid = sid
                            local selected_id = selected.id
                            util.create_thread(function()
                                while troll.spawn_clones and troll.spawn_clones_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped then
                                        local clone = invoker.call(0xEF29A16337FACADB, target_ped, false, false, true).int
                                        if clone and clone ~= 0 then
                                            networkise_entity(clone)
                                            pcall(function()
                                                invoker.call(0xF166E48407BAC484, clone, target_ped, 0, 16)
                                            end)
                                        end
                                    else
                                        break
                                    end
                                    util.yield(1000)
                                end
                                troll.spawn_clones = false
                            end)
                            safe_toast("Spawn Clones: ON")
                        elseif not new_spawn_clones then
                            troll.spawn_clones_sid = nil
                            safe_toast("Spawn Clones: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)
                end

                -- Force Teleport Dropdown
                local ftp_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, cb_h, ftp_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                local ftp_arrow = (troll.force_tp_open or false) and "v" or ">"
                draw_text(ftp_arrow .. " Force Teleport", action_x + side_pad + math.floor(6 * s), ay + (cb_h - UI.font_small) / 2, UI.font_small, C.text)
                if ftp_hover and MOUSE.just_pressed then
                    troll.force_tp_open = not (troll.force_tp_open or false)
                end
                ay = ay + cb_h + btn_gap

                if troll.force_tp_open then
                    local ftp_w = action_w - side_pad * 2 - math.floor(20 * s)
                    local ftp_x = action_x + side_pad + math.floor(20 * s)

                    -- helper: teleport and toast, or warn
                    local function ftp(dest_vec, label)
                        local pobj = get_player_object(selected.id)
                        if pobj and pobj.teleport then
                            pcall(function() pobj:teleport(dest_vec) end)
                            safe_toast(label)
                        else
                            safe_toast("[Kyron] Force TP: player object unavailable")
                        end
                    end

                    -- Sandy Shores Airfield (open outdoor, always works)
                    if small_button("Sandy Shores Airfield", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(1747.0, 3273.0, 41.0), "Sent to Sandy Shores Airfield!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Zancudo Army Base (restricted zone, jets attack them)
                    if small_button("Send to Zancudo Base", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(-2047.0, 3132.0, 32.0), "Sent to Fort Zancudo!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Top of Mount Chiliad
                    if small_button("Send to Chiliad", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(500.0, 5604.0, 797.0), "Sent to Mount Chiliad!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- North Yankton (off map, freezes movement)
                    if small_button("Send to North Yankton", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(3452.0, -5270.0, 10.0), "Sent to North Yankton!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Deep ocean off map
                    if small_button("Send to Ocean", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(4500.0, 8000.0, 0.0), "Sent to ocean!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- High sky drop (long fall)
                    if small_button("Send to Sky", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(0.0, 0.0, 2000.0), "Sent to sky!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Under map void
                    if small_button("Send Under Map", ftp_x, ay, ftp_w, btn_h) then
                        ftp(vec3(0.0, 0.0, -250.0), "Sent under map!")
                    end
                    ay = ay + btn_h + math.floor(2 * s)
                end

                -- Vehicle Trolls Dropdown
                local veh_trolls_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, cb_h, veh_trolls_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                local v_arrow = (troll.veh_trolls_open or false) and "v" or ">"
                draw_text(v_arrow .. " Vehicle Trolls", action_x + side_pad + math.floor(6 * s), ay + (cb_h - UI.font_small) / 2, UI.font_small, C.text)
                if veh_trolls_hover and MOUSE.just_pressed then
                    troll.veh_trolls_open = not (troll.veh_trolls_open or false)
                end
                ay = ay + cb_h + btn_gap

                if troll.veh_trolls_open then
                    -- Lock Doors (toggle - loops to keep locked)
                    local new_lock = inline_toggle("Lock Doors", troll.lock_doors, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_lock ~= troll.lock_doors then
                        troll.lock_doors = new_lock
                        if new_lock then
                            local sid = {}
                            troll.lock_doors_sid = sid
                            local selected_id = selected.id
                            util.create_thread(function()
                                while troll.lock_doors and troll.lock_doors_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped then
                                        local veh = invoker.call(0x9A9112A0FE9A4713, target_ped, false)
                                        if veh and veh.int and veh.int ~= 0 and request_control(veh.int) then
                                            invoker.call(0xB664292EAECF7FA6, veh.int, 4)  -- Lock doors
                                        end
                                    end
                                    util.yield(500)
                                end
                                troll.lock_doors = false
                            end)
                            safe_toast("Lock Doors: ON")
                        else
                            troll.lock_doors_sid = nil
                            safe_toast("Lock Doors: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- Kill Engine (toggle - loops to keep dead)
                    local new_kill = inline_toggle("Kill Engine", troll.kill_engine, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_kill ~= troll.kill_engine then
                        troll.kill_engine = new_kill
                        if new_kill then
                            local sid = {}
                            troll.kill_engine_sid = sid
                            local selected_id = selected.id
                            util.create_thread(function()
                                while troll.kill_engine and troll.kill_engine_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped then
                                        local veh = invoker.call(0x9A9112A0FE9A4713, target_ped, false)
                                        if veh and veh.int and veh.int ~= 0 and request_control(veh.int) then
                                            invoker.call(0x45F6D8EEF34ABEF1, veh.int, -1.0)  -- SET_VEHICLE_ENGINE_HEALTH
                                            invoker.call(0x2497C4717C8B881A, veh.int, false, true, true)  -- SET_VEHICLE_ENGINE_ON (off)
                                        end
                                    end
                                    util.yield(500)
                                end
                                troll.kill_engine = false
                            end)
                            safe_toast("Kill Engine: ON")
                        else
                            troll.kill_engine_sid = nil
                            safe_toast("Kill Engine: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ INVISIBLE STALKER CAR (toggle - loop) ============
                    local stalker_active = (troll.stalker_car_toggle or false)
                    local new_stalker = inline_toggle("Invisible Stalker Car", stalker_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_stalker ~= stalker_active then
                        troll.stalker_car_toggle = new_stalker
                        if new_stalker and selected.ped then
                            local sid = {}
                            troll.stalker_car_sid = sid
                            local selected_id = selected.id
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.stalker_car_toggle = false
                                    return
                                end
                                local tx, ty, tz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                local heading_result = invoker.call(0xE83A3E3557A56640, selected.ped)
                                local heading = heading_result and heading_result.float or 0.0

                                local car_hash = joaat("zentorno")
                                local driver_hash = joaat("s_m_y_marine_01")
                                request.model(car_hash)
                                request.model(driver_hash)
                                util.yield(200)

                                -- Spawn car 40m behind target
                                local rad = math.rad(heading)
                                local sx = tx - math.sin(rad) * 40.0
                                local sy = ty - math.cos(rad) * 40.0

                                local car = _ts_veh(car_hash, sx, sy, tz, heading)
                                if not car or car == 0 then
                                    troll.stalker_car_toggle = false
                                    return
                                end
                                networkise_entity(car)

                                local driver = _ts_ped(29, driver_hash, sx, sy, tz, 0.0)
                                if driver and driver ~= 0 then
                                    networkise_entity(driver)
                                    invoker.call(0xF75B0D629E1C063D, driver, car, -1)  -- SET_PED_INTO_VEHICLE
                                end

                                -- Make car and driver invisible
                                invoker.call(0xEA1C610A04DB6BBB, car, false, 0)  -- SET_ENTITY_VISIBLE
                                invoker.call(0xEA1C610A04DB6BBB, driver, false, 0)  -- SET_ENTITY_VISIBLE
                                -- Make both invincible
                                invoker.call(0x3882114BA7B7E164, car, true)  -- SET_ENTITY_INVINCIBLE
                                invoker.call(0x3882114BA7B7E164, driver, true)
                                invoker.call(0x2497C4717C8B881A, car, true, true, false)  -- ENGINE ON
                                -- Driver settings
                                invoker.call(0xB195FFA8042FC5C3, driver, 1.0)  -- SET_DRIVER_ABILITY
                                invoker.call(0xA731F608CA104E3C, driver, 1.0)  -- SET_DRIVER_AGGRESSIVENESS
                                invoker.call(0x9F8AA94D6D97DBF4, driver, true)  -- BLOCKING
                                invoker.call(0x971D38760FBC02EF, driver, true)  -- KEEP_TASK

                                troll.stalker_car_entity = car
                                troll.stalker_driver_entity = driver

                                invoker.call(0x4AD96EE8E9A3C880, car_hash)
                                invoker.call(0x4AD96EE8E9A3C880, driver_hash)
                                safe_toast("Invisible Stalker: Active!")

                                -- Loop: keep retasking driver to chase target
                                while troll.stalker_car_toggle and troll.stalker_car_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped and car and driver then
                                        -- TASK_VEHICLE_MISSION_PED_TARGET: missionType 7 = ram
                                        invoker.call(0x9454528DF15D657A, driver, car, target_ped, 7, 200.0, 786468, 5.0, 5.0, true)
                                    end
                                    util.yield(3000)
                                end

                                -- Cleanup on toggle off
                                pcall(function()
                                    if car and invoker.call(0x7239B21A38F536BA, car).bool then
                                        invoker.call(0xAD738C3085FE7E11, car, true, true)
                                        invoker.call(0xAE3CBE5BF394C9C9, car)
                                    end
                                end)
                                pcall(function()
                                    if driver and invoker.call(0x7239B21A38F536BA, driver).bool then
                                        invoker.call(0xAD738C3085FE7E11, driver, true, true)
                                        invoker.call(0xAE3CBE5BF394C9C9, driver)
                                    end
                                end)
                                troll.stalker_car_entity = nil
                                troll.stalker_driver_entity = nil
                                troll.stalker_car_toggle = false
                            end)
                        else
                            troll.stalker_car_sid = nil
                            safe_toast("Invisible Stalker: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ CAR MAGNET (auto-reset) ============
                    local magnet_active = (troll.car_magnet_toggle or false)
                    local new_magnet = inline_toggle("Car Magnet", magnet_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_magnet ~= magnet_active then
                        troll.car_magnet_toggle = new_magnet
                        if new_magnet and selected.ped then
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.car_magnet_toggle = false
                                    return
                                end
                                local tx, ty, tz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z

                                local car_hash = joaat("adder")
                                local driver_hash = joaat("s_m_y_marine_01")
                                request.model(car_hash)
                                request.model(driver_hash)
                                util.yield(200)

                                -- Spawn 6 cars in a circle 50m away with drivers that ram target
                                for i = 1, 6 do
                                    local angle = (i * 60) * (math.pi / 180)
                                    local sx = tx + math.cos(angle) * 50.0
                                    local sy = ty + math.sin(angle) * 50.0
                                    local dx = tx - sx
                                    local dy = ty - sy
                                    local aim_heading = math.deg(math.atan(dx, dy))

                                    local car = _ts_veh(car_hash, sx, sy, tz, aim_heading)
                                    if car and car ~= 0 then
                                        networkise_entity(car)
                                        invoker.call(0x2497C4717C8B881A, car, true, true, false)  -- ENGINE ON

                                        -- Spawn driver
                                        local driver = _ts_ped(29, driver_hash, sx, sy, tz, 0.0)
                                        if driver and driver ~= 0 then
                                            networkise_entity(driver)
                                            invoker.call(0xF75B0D629E1C063D, driver, car, -1)  -- SET_PED_INTO_VEHICLE
                                            invoker.call(0xB195FFA8042FC5C3, driver, 1.0)  -- SET_DRIVER_ABILITY
                                            invoker.call(0xA731F608CA104E3C, driver, 1.0)  -- SET_DRIVER_AGGRESSIVENESS
                                            invoker.call(0x9F8AA94D6D97DBF4, driver, true)  -- BLOCKING
                                            -- TASK_VEHICLE_MISSION_PED_TARGET: missionType 7 = ram
                                            invoker.call(0x9454528DF15D657A, driver, car, selected.ped, 7, 500.0, 786468, 5.0, 5.0, true)
                                        end
                                    end
                                    util.yield(300)
                                end

                                invoker.call(0x4AD96EE8E9A3C880, car_hash)
                                invoker.call(0x4AD96EE8E9A3C880, driver_hash)
                                safe_toast("CAR MAGNET! Incoming!")
                                troll.car_magnet_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ DRIVE FOR FRIEND ============
                    -- Lets YOU control your friend's vehicle while they stay inside as passenger.
                    -- Uses: lock their net migration once, then apply your inputs every frame.
                    local dff_active = (troll.drive_for_friend_toggle or false)
                    local new_dff = inline_toggle("Drive For Friend", dff_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    ay = ay + cb_h + math.floor(2 * s)
                    if dff_active then
                        troll.drive_for_friend_speed = vehicle_slider(
                            "Drive For Friend Speed",
                            troll.drive_for_friend_speed or 40, 1, 100,
                            action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), s
                        )
                        ay = ay + math.floor(42 * s)
                    end
                    if new_dff ~= dff_active then
                        troll.drive_for_friend_toggle = new_dff
                        if new_dff then
                            local sid = {}
                            troll.drive_for_friend_sid = sid
                            local selected_id = selected.id
                            local speed_setting = troll.drive_for_friend_speed or 40
                            util.create_thread(function()
                                -- ── PHASE 1: find friend's vehicle (with yields outside pcall) ──
                                local target_veh = 0
                                local find_attempts = 0
                                while troll.drive_for_friend_toggle and troll.drive_for_friend_sid == sid do
                                    find_attempts = find_attempts + 1
                                    if find_attempts > 100 then
                                        -- gave up after ~5s
                                        safe_toast("Drive For Friend: friend not in a vehicle!")
                                        troll.drive_for_friend_toggle = false
                                        troll.drive_for_friend_sid = nil
                                        return
                                    end

                                    local found_ped = nil
                                    pcall(function()
                                        if players and players.list then
                                            for _, p in ipairs(players.list()) do
                                                if p and p.id == selected_id and p.ped and p.ped ~= 0 then
                                                    found_ped = p.ped
                                                end
                                            end
                                        end
                                    end)

                                    if found_ped then
                                        local veh_res = invoker.call(0x9A9112A0FE9A4713, found_ped, false)  -- GET_VEHICLE_PED_IS_IN
                                        local v = veh_res and veh_res.int or 0
                                        if v and v ~= 0 then
                                            -- confirm they are in the driver seat
                                            local seat_res = invoker.call(0xBB40DD2270B65366, v, -1, false)  -- GET_PED_IN_VEHICLE_SEAT seat -1 = driver
                                            if seat_res and seat_res.int == found_ped then
                                                target_veh = v
                                                break
                                            end
                                        end
                                    end
                                    util.yield(50)
                                end

                                if target_veh == 0 then return end

                                -- ── PHASE 2: take network control once (request_control uses yield safely here) ──
                                local got_control = false
                                pcall(function()
                                    -- Ensure networked
                                    local is_net = invoker.call(0xC7827959479DCC78, target_veh)
                                    if not is_net or not is_net.bool then
                                        invoker.call(0x06FAACD625D80CAA, target_veh)
                                    end
                                    -- Lock migration so game doesn't hand control back to the driver player
                                    local nid_r = invoker.call(0xA11700682F3AD45C, target_veh)
                                    if nid_r and nid_r.int and nid_r.int ~= 0 then
                                        invoker.call(0xE05E81A888FA63C8, nid_r.int, true)   -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
                                        invoker.call(0x299EEB23175895FC, nid_r.int, false)  -- SET_NETWORK_ID_CAN_MIGRATE = false (WE keep control)
                                    end
                                    invoker.call(0xAD738C3085FE7E11, target_veh, true, true) -- SET_ENTITY_AS_MISSION_ENTITY
                                end)

                                -- request control (has its own yields, safe here outside the drive loop)
                                for _ = 1, 20 do
                                    local has = invoker.call(0x01BF60A500E28887, target_veh)
                                    if has and has.bool then
                                        got_control = true
                                        break
                                    end
                                    invoker.call(0xB69317BF5E782347, target_veh)  -- NETWORK_REQUEST_CONTROL_OF_ENTITY
                                    util.yield(50)
                                end

                                if not got_control then
                                    safe_toast("Drive For Friend: couldn't get vehicle control!")
                                    troll.drive_for_friend_toggle = false
                                    troll.drive_for_friend_sid = nil
                                    return
                                end

                                safe_toast("Drive For Friend: ON! Use WASD/controller to drive.")

                                -- ── PHASE 3: noclip-style drive loop ──
                                -- Copied exactly from working noclip vehicle code.
                                -- We own position directly via SET_ENTITY_COORDS each frame.
                                -- WASD moves relative to YOUR camera direction.
                                -- Collision off on their vehicle so it doesn't bounce/stop.

                                -- Get initial position of their vehicle
                                local pos_x, pos_y, pos_z = 0.0, 0.0, 0.0
                                local ic = invoker.call(0x3FEF770D40960D5A, target_veh, true)  -- GET_ENTITY_COORDS
                                if ic and ic.scr_vec3 then
                                    pos_x = ic.scr_vec3.x or 0.0
                                    pos_y = ic.scr_vec3.y or 0.0
                                    pos_z = ic.scr_vec3.z or 0.0
                                end

                                -- Disable collision so the vehicle doesn't get blocked
                                invoker.call(0x1A9205C1B9EE827F, target_veh, false, false)  -- SET_ENTITY_COLLISION off
                                invoker.call(0x4A13F96B24F7A558, target_veh, true)           -- SET_VEHICLE_GRAVITY off
                                invoker.call(0x4A4722448F18EEF5, target_veh, false)           -- SET_ENTITY_HAS_GRAVITY off

                                local accel_vel = {w=0, s=0, a=0, d=0, up=0, dn=0}
                                -- Map the 1-100 speed slider to a noclip-style position-delta
                                -- max. Old hardcoded value was 0.6 (~equivalent to slider 40).
                                local speed_clamped = math.max(1, math.min(100, speed_setting))
                                local MAX_SPEED = 0.05 + (3.0 - 0.05) * (speed_clamped - 1) / 99
                                local recontrol_timer = 0

                                while troll.drive_for_friend_toggle and troll.drive_for_friend_sid == sid do

                                    -- LMB stops Drive For Friend without reopening the menu
                                    local lmb_pressed = invoker.call(0x91AEF906BCA88877, 0, 24) -- IS_DISABLED_CONTROL_JUST_PRESSED, 24 = attack/LMB
                                    if lmb_pressed and lmb_pressed.bool then
                                        troll.drive_for_friend_toggle = false
                                        break
                                    end

                                    -- Re-assert control every 60 frames
                                    recontrol_timer = recontrol_timer + 1
                                    if recontrol_timer >= 60 then
                                        recontrol_timer = 0
                                        invoker.call(0xB69317BF5E782347, target_veh)
                                    end

                                    -- Keep collision off and gravity off every frame (game resets them)
                                    invoker.call(0x4A4722448F18EEF5, target_veh, false)
                                    invoker.call(0x4A13F96B24F7A558, target_veh, true)
                                    invoker.call(0x2497C4717C8B881E, target_veh, true, true, false)  -- engine on

                                    -- Get YOUR camera rotation (same as noclip)
                                    local cam_rot = invoker.call(0x837765A25378F0BB, 2)  -- GET_GAMEPLAY_CAM_ROT
                                    if cam_rot and cam_rot.scr_vec3 then
                                        local pitch       = cam_rot.scr_vec3.x or 0.0
                                        local heading     = cam_rot.scr_vec3.z or 0.0
                                        local pitch_rad   = math.rad(pitch)
                                        local heading_rad = math.rad(heading)

                                        local accel = math.max(0.002, MAX_SPEED * 0.05)

                                        -- Read keys exactly like noclip does (IS_DISABLED_CONTROL_PRESSED)
                                        -- 32=W, 33=S, 34=A, 35=D, 22=Shift(up), 36=Ctrl(down)
                                        local w_down = invoker.call(0xF3A21BCD95725A4A, 0, 32).bool
                                        local s_down = invoker.call(0xF3A21BCD95725A4A, 0, 33).bool
                                        local a_down = invoker.call(0xF3A21BCD95725A4A, 0, 34).bool
                                        local d_down = invoker.call(0xF3A21BCD95725A4A, 0, 35).bool
                                        local up_down  = invoker.call(0xF3A21BCD95725A4A, 0, 22).bool  -- Shift = go up
                                        local dn_down  = invoker.call(0xF3A21BCD95725A4A, 0, 36).bool  -- Ctrl  = go down

                                        -- Accelerate or reset each axis (exact noclip logic)
                                        accel_vel.w  = w_down  and math.min(accel_vel.w  + accel, MAX_SPEED) or 0
                                        accel_vel.s  = s_down  and math.min(accel_vel.s  + accel, MAX_SPEED) or 0
                                        accel_vel.a  = a_down  and math.min(accel_vel.a  + accel, MAX_SPEED) or 0
                                        accel_vel.d  = d_down  and math.min(accel_vel.d  + accel, MAX_SPEED) or 0
                                        accel_vel.up = up_down and math.min(accel_vel.up + accel, MAX_SPEED) or 0
                                        accel_vel.dn = dn_down and math.min(accel_vel.dn + accel, MAX_SPEED) or 0

                                        -- Move position (exact noclip math)
                                        if w_down then
                                            pos_x = pos_x - math.sin(heading_rad) * math.cos(pitch_rad) * accel_vel.w
                                            pos_y = pos_y + math.cos(heading_rad) * math.cos(pitch_rad) * accel_vel.w
                                            pos_z = pos_z + math.sin(pitch_rad) * accel_vel.w
                                        end
                                        if s_down then
                                            pos_x = pos_x + math.sin(heading_rad) * math.cos(pitch_rad) * accel_vel.s
                                            pos_y = pos_y - math.cos(heading_rad) * math.cos(pitch_rad) * accel_vel.s
                                            pos_z = pos_z - math.sin(pitch_rad) * accel_vel.s
                                        end
                                        if a_down then
                                            pos_x = pos_x - math.cos(heading_rad) * accel_vel.a
                                            pos_y = pos_y - math.sin(heading_rad) * accel_vel.a
                                        end
                                        if d_down then
                                            pos_x = pos_x + math.cos(heading_rad) * accel_vel.d
                                            pos_y = pos_y + math.sin(heading_rad) * accel_vel.d
                                        end
                                        if up_down then pos_z = pos_z + accel_vel.up end
                                        if dn_down then pos_z = pos_z - accel_vel.dn end

                                        -- Apply position + face camera heading (exact noclip)
                                        invoker.call(0x239A3351AC1DA385, target_veh,
                                            pos_x, pos_y, pos_z,
                                            false, false, false)                  -- SET_ENTITY_COORDS_NO_OFFSET: no ground-snap
                                        invoker.call(0x428CA6DBD1094446, target_veh, true)           -- FREEZE_ENTITY_POSITION: lock physics between frames
                                        invoker.call(0x1C99BB7B6E96D16F, target_veh, 0.0, 0.0, 0.0) -- zero velocity so no drift
                                        invoker.call(0xAB54A438726D25D5, target_veh, 0.0)            -- SET_VEHICLE_FORWARD_SPEED 0
                                        invoker.call(0x8E2530AA8ADA980E, target_veh, heading)        -- face camera direction
                                    end

                                    util.yield(0)
                                end

                                -- ── CLEANUP: hand the vehicle back to physics + the friend's client ──
                                -- Order matters here. Previously position was unfrozen first while
                                -- still mission-owned with no ground snap, so the vehicle stayed
                                -- floating wherever it was left (often mid-air) and never gave up
                                -- ownership, so the friend's client had no authority to move it.
                                invoker.call(0xB69317BF5E782347, target_veh)                -- NETWORK_REQUEST_CONTROL_OF_ENTITY: make sure control isn't stale/contested right before release
                                invoker.call(0x4A13F96B24F7A558, target_veh, false)         -- SET_VEHICLE_GRAVITY on
                                invoker.call(0x4A4722448F18EEF5, target_veh, true)          -- SET_ENTITY_HAS_GRAVITY on
                                invoker.call(0x1A9205C1B9EE827F, target_veh, true, true)    -- collision back on
                                invoker.call(0x49733E92263139D1, target_veh, 0)             -- SET_VEHICLE_ON_GROUND_PROPERLY: snap to ground if left mid-air
                                invoker.call(0x428CA6DBD1094446, target_veh, false)         -- FREEZE_ENTITY_POSITION off (after collision/gravity/ground snap)
                                -- Every frame while driving ended on exactly 0 velocity / 0 forward speed,
                                -- which leaves the vehicle's physics/network sim with no motion to hand
                                -- off — give it a small real nudge instead of a dead stop so the engine
                                -- and wheels have something to pick back up from.
                                invoker.call(0x1C99BB7B6E96D16F, target_veh, 0.0, 0.0, -0.5) -- SET_ENTITY_VELOCITY: small downward nudge to wake physics
                                invoker.call(0xAB54A438726D25D5, target_veh, 1.0)            -- SET_VEHICLE_FORWARD_SPEED: tiny nonzero nudge (not a hard stop)

                                pcall(function()
                                    invoker.call(0xAD738C3085FE7E11, target_veh, false, true) -- SET_ENTITY_AS_MISSION_ENTITY(false): release our ownership claim
                                    local nid_r = invoker.call(0xA11700682F3AD45C, target_veh)
                                    if nid_r and nid_r.int and nid_r.int ~= 0 then
                                        invoker.call(0x299EEB23175895FC, nid_r.int, true)   -- SET_NETWORK_ID_CAN_MIGRATE = true so control can flow back
                                    end
                                end)

                                safe_toast("Drive For Friend: OFF - control returned!")
                                troll.drive_for_friend_toggle = false
                                troll.drive_for_friend_sid = nil
                            end)
                        else
                            troll.drive_for_friend_sid = nil
                            safe_toast("Drive For Friend: OFF")
                        end
                    end
                    ay = ay + cb_h + btn_gap

                    -- ============ SEND SUS MECHANIC (one-shot) ============
                    local sus_mech_active = (troll.sus_mechanic_toggle or false)
                    local new_sus_mech = inline_toggle("Send Sus Mechanic", sus_mech_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_sus_mech ~= sus_mech_active then
