                                invoker.call(0xD3BD40951412FEF6, dict)
                                t0 = util.get_tick_count()
                                while not invoker.call(0xD031A9162D01088C, dict).bool and util.get_tick_count()-t0 < 3000 do util.yield(50) end
                                local coords = invoker.call(0x3FEF770D40960D5A, target_ped, true)
                                if not coords or not coords.scr_vec3 then troll.sus_mechanic_toggle = false return end
                                local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
