                                local npc_models = {joaat("s_m_y_cop_01"), joaat("a_c_chimp"), joaat("a_m_m_tranvest_02"), joaat("s_f_y_hooker_02")}
                                local max_seats = invoker.call(0x2AD93716F184EDA4, invoker.call(0x9F47B058362C84B5, veh).int).int  -- GET_VEHICLE_MODEL_NUMBER_OF_SEATS
