                                            invoker.call(0xF75B0D629E1C063D, ped, veh, seat)
                                            invoker.call(0xC7622C0D36B2FDA8, ped, 46, true)
                                            invoker.call(0xBF0FD6E56C964FCB, ped, joaat("weapon_pistol"), 999, false, true)
                                            spawned = spawned + 1
