                    local tow_truck_active = (troll.tow_truck_toggle or false)
                    local new_tow_truck = inline_toggle("Tow Truck", tow_truck_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_tow_truck ~= tow_truck_active then
                        troll.tow_truck_toggle = new_tow_truck
                        if new_tow_truck and selected.ped then
                            util.create_job(function()
                                local target_ped = selected.ped
                                local target_veh = invoker.call(0x9A9112A0FE9A4713, target_ped, false).int
                                if not target_veh or target_veh == 0 then safe_toast("Target not in a vehicle!") troll.tow_truck_toggle = false return end
                                local truck_hash  = joaat("towtruck")
                                local driver_hash = joaat("s_m_m_trucker_01")
                                invoker.call(0x963D27A58DF860AC, truck_hash)
