                                while (not invoker.call(0x98A4EB5D89A0C952, truck_hash).bool or not invoker.call(0x98A4EB5D89A0C952, driver_hash).bool) and util.get_tick_count()-t0 < 4000 do util.yield(50) end
                                local coords = invoker.call(0x3FEF770D40960D5A, target_ped, true)
                                if not coords or not coords.scr_vec3 then troll.tow_truck_toggle = false return end
                                local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                local heading = invoker.call(0xE83A3E3557A56640, target_ped).float or 0.0
                                local rad = math.rad(heading)
                                local sx = px + math.cos(rad) * 8.0
