                                local truck  = _ts_veh(truck_hash, sx, sy, pz, heading)
                                local driver = _ts_ped(28, driver_hash, sx, sy, pz, 0.0)
                                if truck and truck ~= 0 and driver and driver ~= 0 then
                                    networkise_entity(truck)
