                                    invoker.call(0xF75B0D629E1C063D, driver, truck, -1)
                                    invoker.call(0x3882114BA7B7E164, truck,  true)
                                    invoker.call(0x3882114BA7B7E164, driver, true)
                                    invoker.call(0x9F8AA94D6D97DBF4, driver, true)
                                    if request_control(target_veh) then
