                    -- Dancing Lesters Toggle (auto-reset)
                    local dancing_lesters_active = (troll.dancing_lesters_toggle or false)
                    local new_dancing_lesters = inline_toggle("Dancing Lesters", dancing_lesters_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_dancing_lesters ~= dancing_lesters_active then
                        troll.dancing_lesters_toggle = new_dancing_lesters
                        if new_dancing_lesters and selected.ped then
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)  -- GET_ENTITY_COORDS
                                local heading = invoker.call(0xE83A3E3557A56640, selected.ped)  -- GET_ENTITY_HEADING
                                if not coords or not coords.scr_vec3 or not heading then return end
                                heading = heading.float or 0.0

                                local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                local lester_hash = joaat("cs_lestercrest")
                                local anim_dict = "anim@amb@nightclub@dancers@crowddance_groups@hi_intensity"

                                request.model(lester_hash)
                                -- REQUEST_ANIM_DICT (0xD3BD40951412FEF6)
                                invoker.call(0xD3BD40951412FEF6, anim_dict)
                                util.yield(100)

                                -- Spawn all Lesters first
                                local lesters = {}
                                for i = -3, 3 do
                                    local rad = math.rad(heading)
                                    local spawn_x = px + (math.sin(-rad) * i * 1.5) + (math.sin(-rad) * 5.0)
                                    local spawn_y = py + (math.cos(-rad) * i * 1.5) + (math.cos(-rad) * 5.0)
                                    local spawn_z = pz

                                    -- CREATE_PED (0xD49F9B0955C367DE)
                                    local lester = _ts_ped(26, lester_hash, spawn_x, spawn_y, spawn_z, 0.0)
                                    if lester and lester ~= 0 then
