                                    local heading = invoker.call(0xE83A3E3557A56640, target_ped).float or 0.0
                                    local rad = math.rad(heading)
                                    local attacker = _ts_ped(26, hash, px - math.sin(rad)*4, py + math.cos(rad)*4, pz, 0.0)
                                    if attacker and attacker ~= 0 then
                                        networkise_entity(attacker)
                                        invoker.call(0xC7622C0D36B2FDA8, attacker, 46, true)
                                        invoker.call(0x57E40F35034AE6EF, attacker, 2)
                                        invoker.call(0xBF0FD6E56C964FCB, attacker, joaat("weapon_dagger"), 1, false, true)
                                        invoker.call(0xF166E48407BAC484, attacker, target_ped, 0, 16)
                                        safe_toast("Zombie sent!")
                                    end
                                    invoker.call(0x4AD96EE8E9A3C880, hash)
                                end)
                            end
                        end
                        ay = ay + bh + math.floor(2 * s)

                        -- Juggernaut Attacker
                        if small_button("Juggernaut Attacker", action_x + side_pad + ind, ay, iw, bh) then
                            if selected.ped then
                                util.create_job(function()
                                    local target_ped = selected.ped
                                    local hash = joaat("u_m_y_juggernaut_01")
                                    invoker.call(0x963D27A58DF860AC, hash)
                                    local t0 = util.get_tick_count()
                                    while not invoker.call(0x98A4EB5D89A0C952, hash).bool and util.get_tick_count()-t0 < 3000 do util.yield(50) end
                                    local coords = invoker.call(0x3FEF770D40960D5A, target_ped, true)
                                    if not coords or not coords.scr_vec3 then return end
                                    local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                    local heading = invoker.call(0xE83A3E3557A56640, target_ped).float or 0.0
                                    local rad = math.rad(heading)
                                    local attacker = _ts_ped(28, hash, px - math.sin(rad)*6, py + math.cos(rad)*6, pz, 0.0)
                                    if attacker and attacker ~= 0 then
