                                        invoker.call(0x6B76DC1F3AE6E6A3, attacker, 2500, 0)      -- SET_ENTITY_HEALTH
                                        invoker.call(0x4E3A0CC40F35C9BF, attacker, 100)           -- SET_PED_ARMOUR
                                        invoker.call(0xC7622C0D36B2FDA8, attacker, 46, true)
                                        invoker.call(0xBF0FD6E56C964FCB, attacker, joaat("weapon_minigun"), 9999, false, true)
                                        invoker.call(0xF166E48407BAC484, attacker, target_ped, 0, 16)
                                        safe_toast("Juggernaut sent!")
                                    end
                                    invoker.call(0x4AD96EE8E9A3C880, hash)
                                end)
                            end
                        end
                        ay = ay + bh + math.floor(2 * s)
                    end
                end  -- special_attackers do block

                -- =====================================================
                -- KIDNAP DROPDOWN (inside sub_tab == 4)
                -- =====================================================
                do
                    local cb_h2 = math.floor(26 * s)
