                                        invoker.call(0x9F8AA94D6D97DBF4, driver, true)             -- SET_BLOCKING_OF_NON_TEMPORARY_EVENTS
                                        invoker.call(0x3882114BA7B7E164, van,    true)             -- SET_ENTITY_INVINCIBLE
