                                            invoker.call(0xE2A2AA2F659D77A7, driver, van,
                                                math.random(-2000,2000)*1.0, math.random(-2000,2000)*1.0, 0.0,
                                                100.0, 1.0, van_hash, 786996, 5.0, -1.0)
                                            safe_toast("Van kidnap incoming!")
                                        else
                                            safe_delete_entity(van)
                                            safe_delete_entity(driver)
                                        end
                                    end
                                    invoker.call(0x4AD96EE8E9A3C880, van_hash)
                                    invoker.call(0x4AD96EE8E9A3C880, driver_hash)
                                end)
                            end
                        end
                        ay = ay + bh + math.floor(2 * s)

