                        if small_button("Cargobob Kidnap", action_x + side_pad + ind, ay, iw, bh) then
                            if selected.ped then
                                local sel_id = selected.id
                                util.create_job(function()
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == sel_id then target_ped = p.ped break end
                                        end
