                                    invoker.call(0x963D27A58DF860AC, pilot_hash)
                                    local t0 = util.get_tick_count()
                                    while (not invoker.call(0x98A4EB5D89A0C952, heli_hash).bool or not invoker.call(0x98A4EB5D89A0C952, pilot_hash).bool) and util.get_tick_count()-t0 < 4000 do util.yield(50) end
                                    local coords = invoker.call(0x3FEF770D40960D5A, target_ped, true)
                                    if not coords or not coords.scr_vec3 then return end
                                    local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                    local heading = invoker.call(0xE83A3E3557A56640, target_ped).float or 0.0
                                    local heli  = _ts_veh(heli_hash, px, py, pz, heading)
                                    local pilot = _ts_ped(29, pilot_hash, px, py, pz, 0.0)
                                    if heli and heli ~= 0 and pilot and pilot ~= 0 then
