                                        networkise_entity(pilot)
                                        invoker.call(0xF75B0D629E1C063D, pilot, heli, -1)
                                        invoker.call(0xA178472EBB8AE60D, heli)                     -- SET_HELI_BLADES_FULL_SPEED
                                        invoker.call(0x2497C4717C8B881A, heli, true, true, false)   -- SET_VEHICLE_ENGINE_ON
                                        invoker.call(0x3882114BA7B7E164, heli,  true)
                                        invoker.call(0x3882114BA7B7E164, pilot, true)
                                        invoker.call(0x9F8AA94D6D97DBF4, pilot, true)
                                        invoker.call(0x70A2D1137C8ED7C9, pilot, 0, false)           -- SET_PED_FLEE_ATTRIBUTES
                                        invoker.call(0xC7622C0D36B2FDA8, pilot, 46, true)
                                        invoker.call(0x428CA6DBD1094446, heli, true)
                                        util.yield(2000)
                                        invoker.call(0x428CA6DBD1094446, heli, false)
                                        -- TASK_HELI_MISSION: fly to random spot at high altitude
