    -- Dynamic config directory (works for anyone)
    -- ============================================================
    --  AUTO-SAVE / AUTO-LOAD  (saves EVERYTHING)
    --  Hardcoded path - no runtime path resolution that can fail.
    --  Simple key=value format - no JSON parsing.
    --  Saves every 20 seconds automatically, always on.
    -- ============================================================
    local SAVE_PATH = "C:\\Users\\Administrator\\Lexis\\Grand Theft Auto V\\scripts\\Kyron\\Config\\kyron_autosave.txt"

    -- keep get_config_dir for other parts of the script that use it
    local function get_config_dir()
        return "C:\\Users\\Administrator\\Lexis\\Grand Theft Auto V\\scripts\\Kyron\\Config"
    end

    local function autosave_write()
        local ok, f = pcall(io.open, SAVE_PATH, "w")
        if not ok or not f then
            safe_toast("[KYRON] AutoSave FAILED - check path:\n" .. SAVE_PATH)
            return
        end
        local b = function(v) return v and "1" or "0" end
        local n = function(v, d) return tostring(v ~= nil and v or d) end

        -- SELF / PLAYER
        f:write("god_mode="                  .. b(demo.god_mode)                             .. "\n")
        f:write("no_ragdoll="                .. b(demo.no_ragdoll)                           .. "\n")
        f:write("never_wanted="              .. b(demo.never_wanted)                         .. "\n")
        f:write("super_jump="                .. b(demo.super_jump)                           .. "\n")
        f:write("fast_run="                  .. b(demo.fast_run)                             .. "\n")
