        f:write("auto_script_host="          .. b(demo.auto_script_host)                     .. "\n")
        f:write("ghost_org="                 .. b(self_state.ghost_org)                      .. "\n")
        f:write("veh_thrower="               .. b(self_state.veh_thrower_enabled)            .. "\n")
        f:write("context_menu="              .. b(self_state.context_menu_enabled)           .. "\n")
        f:write("far_pov="                   .. b(self_state.far_pov_enabled)                .. "\n")
        f:write("noclip_speed="              .. n(noclip_state.speed, 1.0)                   .. "\n")
        f:write("noclip_keybind="            .. n(noclip_state.keybind, "null")              .. "\n")

        -- VEHICLE
        f:write("veh_god_mode="              .. b(vehicle_state.god_mode)                    .. "\n")
        f:write("veh_invisible="             .. b(vehicle_state.invisible)                   .. "\n")
        f:write("veh_bulletproof="           .. b(vehicle_state.bulletproof_tires)           .. "\n")
        f:write("veh_super_grip="            .. b(vehicle_state.super_grip)                  .. "\n")
        f:write("veh_instant_brake="         .. b(vehicle_state.instant_brake)               .. "\n")
        f:write("veh_drift_mode="            .. b(vehicle_state.drift_mode)                  .. "\n")
        f:write("veh_horn_boost="            .. b(vehicle_state.horn_boost)                  .. "\n")
        f:write("veh_horn_speed_boost="      .. b(vehicle_state.horn_speed_boost)            .. "\n")
        f:write("veh_rainbow_paint="         .. b(vehicle_state.rainbow_paint)               .. "\n")
        f:write("veh_rainbow_headlights="    .. b(vehicle_state.rainbow_headlights)          .. "\n")
        f:write("veh_livery_cycler="         .. b(vehicle_state.livery_cycler)               .. "\n")
        f:write("veh_paint_cycler="          .. b(vehicle_state.paint_cycler)                .. "\n")
