    local function autosave_read()
        local f = io.open(SAVE_PATH, "r")
        if not f then return end
        local data = {}
        for line in f:lines() do
            local k, v = line:match("^([^=]+)=(.*)$")
            if k and v then data[k] = v end
        end
        f:close()
        if not next(data) then return end

        local function gb(key)
            local v = data[key]
            if v == "1" then return true elseif v == "0" then return false end
            return nil
        end
        local function gn(key)
            return data[key] and tonumber(data[key]) or nil
        end

        local v

        -- SELF / PLAYER
        v=gb("god_mode");             if v~=nil then demo.god_mode=v end
        v=gb("no_ragdoll");           if v~=nil then demo.no_ragdoll=v end
        v=gb("never_wanted");         if v~=nil then demo.never_wanted=v end
        v=gb("super_jump");           if v~=nil then demo.super_jump=v end
        v=gb("fast_run");             if v~=nil then demo.fast_run=v end
        v=gn("run_speed");            if v~=nil then demo.run_speed=v end
        v=gb("invisibility");         if v~=nil then demo.invisibility=v end
        v=gb("off_the_radar");        if v~=nil then demo.off_the_radar=v end
        v=gb("auto_waypoint_tp");     if v~=nil then demo.auto_waypoint_tp=v end
        v=gb("auto_script_host");     if v~=nil then demo.auto_script_host=v end
        v=gb("ghost_org");            if v~=nil then self_state.ghost_org=v end
        v=gb("veh_thrower");          if v~=nil then self_state.veh_thrower_enabled=v end
        v=gb("context_menu");         if v~=nil then self_state.context_menu_enabled=v end
        v=gb("far_pov");              if v~=nil then self_state.far_pov_enabled=v end
        v=gn("noclip_speed");         if v~=nil then noclip_state.speed=v end
        v=gn("noclip_keybind");       if v~=nil then noclip_state.keybind=v end

        -- VEHICLE
        v=gb("veh_god_mode");            if v~=nil then vehicle_state.god_mode=v end
        v=gb("veh_invisible");           if v~=nil then vehicle_state.invisible=v end
        v=gb("veh_bulletproof");         if v~=nil then vehicle_state.bulletproof_tires=v end
        v=gb("veh_super_grip");          if v~=nil then vehicle_state.super_grip=v end
        v=gb("veh_instant_brake");       if v~=nil then vehicle_state.instant_brake=v end
