        v=gb("hide_other_spawns");       if v~=nil then settings_state.hide_other_spawns=v end

        -- MODDER OVERLAY
        v=gb("modder_overlay")
        if v~=nil then
            UI.modder_overlay_enabled = v
            player_state.modder_overlay_enabled = v
            modder_overlay.enabled = v
