    local function draw_ui_tab()
        local s = UI.scale
        local base_x = ui_layout.content_x
        local base_y = ui_layout.widget_y
        local total_w = ui_layout.content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- Sub-tab bar
        local new_sub_tab, tab_h = sub_tab_bar(ui_state.sub_tabs, ui_state.sub_tab, base_x + math.floor(5 * s), base_y, total_w - math.floor(10 * s))
        if new_sub_tab ~= ui_state.sub_tab then
            ui_state.scroll_offset = 0  -- Reset scroll on tab change
        end
        ui_state.sub_tab = new_sub_tab
        base_y = base_y + tab_h

        local panel_x = base_x + math.floor(5 * s)
        local panel_y = base_y
        local panel_w = total_w - math.floor(10 * s)
        local panel_h = total_h - tab_h

        draw_rect(panel_x, panel_y, panel_w, panel_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local side_pad = math.floor((UI.padding or 10) * s)
        local usable_w = panel_w - side_pad * 2
        local slider_w = usable_w
        local slider_h = math.floor((UI.slider_h or 24) * s)
        local settings_h = math.floor(48 * s)  -- settings_slider height
        local btn_h = math.floor((UI.button_h or 32) * s)
        local scrollbar_w = math.floor(6 * s)

        -- Initialize all UI values if not set
        if not UI.accent_r then UI.accent_r, UI.accent_g, UI.accent_b = 114, 137, 218 end
        if not UI.widget_bg_r then UI.widget_bg_r, UI.widget_bg_g, UI.widget_bg_b = 40, 40, 46 end
        if not UI.font_header then UI.font_header = 16 end
        if not UI.font_tab then UI.font_tab = 14 end
        if not UI.font_widget then UI.font_widget = 12 end
        if not UI.font_small then UI.font_small = 10 end
        if not UI.padding then UI.padding = 5 end
        if not UI.item_spacing then UI.item_spacing = 6 end
        if not UI.widget_rounding then UI.widget_rounding = 5 end
        if not UI.button_h then UI.button_h = 32 end
        if not UI.slider_h then UI.slider_h = 24 end

        -- Calculate content height for scrolling
        local content_h = 0
        if ui_state.sub_tab == 1 then
            -- Colors tab: 8 color pickers (Accent, BG, Sidebar, Header, Text, TextDim, WidgetBG, WidgetHover)
            local color_picker_h = 20 + (slider_h + 4) * 3 + 8 + 30 + 8 + btn_h + 16  -- Title + 3 RGB sliders + spacing + preview + button
            content_h = math.floor((color_picker_h * 7 + (color_picker_h + (slider_h + 4)) + 100) * s)  -- 7 RGB + 1 RGBA
        elseif ui_state.sub_tab == 2 then
            -- Fonts & Layout: Font Sizes (4) + Component Sizes (4) + Spacing (4) + Visual (4) + Notif (3) + button
            content_h = math.floor((24 + 4*settings_h + 8 + 24 + 4*settings_h + 8 + 24 + 4*settings_h + 8 + 24 + 4*settings_h + 8 + 24 + 3*settings_h + 8 + btn_h + 100) * s)
        else
            -- Config tab
            content_h = math.floor((24 + 24 + btn_h + 8 + btn_h + 50) * s)
        end

        local scroll_needed = content_h > panel_h
        local max_scroll = scroll_needed and math.max(0, content_h - panel_h + math.floor(20 * s)) or 0

        -- Handle scroll input
        if is_mouse_in(panel_x, panel_y, panel_w, panel_h) and scroll_needed then
            local scroll_amt = math.floor(40 * s)
            if MOUSE.scroll_up then
                ui_state.scroll_offset = math.max(0, ui_state.scroll_offset - scroll_amt)
            elseif MOUSE.scroll_down then
                ui_state.scroll_offset = math.min(max_scroll, ui_state.scroll_offset + scroll_amt)
            end
        end

        -- Clipping
        local clip_top = panel_y
        local clip_bottom = panel_y + panel_h
        local ly = panel_y + math.floor(8 * s) - ui_state.scroll_offset

        -- COLORS TAB
        if ui_state.sub_tab == 1 then
            -- Initialize all color values
            if not UI.accent_r then UI.accent_r, UI.accent_g, UI.accent_b = 114, 137, 218 end
            if not UI.bg_r then UI.bg_r, UI.bg_g, UI.bg_b, UI.bg_a = 24, 24, 29, 250 end
            if not UI.sidebar_r then UI.sidebar_r, UI.sidebar_g, UI.sidebar_b = 18, 18, 22 end
            if not UI.header_r then UI.header_r, UI.header_g, UI.header_b = 14, 14, 18 end
            if not UI.text_r then UI.text_r, UI.text_g, UI.text_b = 240, 240, 245 end
            if not UI.text_dim_r then UI.text_dim_r, UI.text_dim_g, UI.text_dim_b = 140, 140, 155 end
            if not UI.widget_bg_r then UI.widget_bg_r, UI.widget_bg_g, UI.widget_bg_b = 40, 40, 46 end
            if not UI.widget_hover_r then UI.widget_hover_r, UI.widget_hover_g, UI.widget_hover_b = 55, 55, 62 end

            -- Accent Color
            if ly + 20*s > clip_top and ly < clip_bottom then
                draw_text("Accent Color", panel_x + side_pad, ly, UI.font_small, C.accent)
            end
            ly = ly + math.floor(20 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.accent_r = improved_slider("accent_r", UI.accent_r, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(255, 0, 0, 200))
            end
            ly = ly + slider_h + math.floor(4 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.accent_g = improved_slider("accent_g", UI.accent_g, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(0, 255, 0, 200))
            end
            ly = ly + slider_h + math.floor(4 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.accent_b = improved_slider("accent_b", UI.accent_b, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(0, 0, 255, 200))
            end
            ly = ly + slider_h + math.floor(8 * s)

            if ly + 30*s > clip_top and ly < clip_bottom then
                draw_rect(panel_x + side_pad, ly, slider_w, math.floor(30 * s), color(UI.accent_r, UI.accent_g, UI.accent_b, 255), math.floor((UI.widget_rounding or 5) * s))
            end
            ly = ly + math.floor(38 * s)

            if ly + btn_h > clip_top and ly < clip_bottom then
                if small_button("Apply Accent", panel_x + side_pad, ly, slider_w, btn_h) then
                    C.accent = color(UI.accent_r, UI.accent_g, UI.accent_b, 255)
                    C.tab_active = color(UI.accent_r, UI.accent_g, UI.accent_b, 255)
                    C.checkbox_on = color(UI.accent_r, UI.accent_g, UI.accent_b, 255)
                    safe_toast("Accent Applied!")
                end
            end
            ly = ly + btn_h + math.floor(16 * s)

            -- Background
            if ly + 20*s > clip_top and ly < clip_bottom then
                draw_text("Background", panel_x + side_pad, ly, UI.font_small, C.accent)
            end
            ly = ly + math.floor(20 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.bg_r = improved_slider("bg_r", UI.bg_r, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(255, 0, 0, 200))
            end
            ly = ly + slider_h + math.floor(4 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.bg_g = improved_slider("bg_g", UI.bg_g, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(0, 255, 0, 200))
            end
            ly = ly + slider_h + math.floor(4 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.bg_b = improved_slider("bg_b", UI.bg_b, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(0, 0, 255, 200))
            end
            ly = ly + slider_h + math.floor(4 * s)

            if ly + slider_h > clip_top and ly < clip_bottom then
                UI.bg_a = improved_slider("bg_a", UI.bg_a, 0, 255, panel_x + side_pad, ly, slider_w, slider_h, color(255, 255, 255, 200))
            end
            ly = ly + slider_h + math.floor(8 * s)

            if ly + 30*s > clip_top and ly < clip_bottom then
                draw_rect(panel_x + side_pad, ly, slider_w, math.floor(30 * s), color(UI.bg_r, UI.bg_g, UI.bg_b, UI.bg_a), math.floor((UI.widget_rounding or 5) * s))
            end
            ly = ly + math.floor(38 * s)

            if ly + btn_h > clip_top and ly < clip_bottom then
                if small_button("Apply Background", panel_x + side_pad, ly, slider_w, btn_h) then
                    C.bg = color(UI.bg_r, UI.bg_g, UI.bg_b, UI.bg_a)
                    safe_toast("Background Applied!")
                end
            end
            ly = ly + btn_h + math.floor(16 * s)

            -- Sidebar
            if ly + 20*s > clip_top and ly < clip_bottom then
