-- FIXED CONFIG SAVE (using same pattern as vehicle save)
if small_button("Save Full Config", panel_x + side_pad, ly, usable_w, btn_h) then
    local config = {
        ui = {
            x = UI.x, y = UI.y, w = UI.w, h = UI.h, scale = UI.scale,
