        ly = ly + btn_h + btn_gap

        local old_bdv = settings_state.block_destroy_vehicle
        if prot_vis() then settings_state.block_destroy_vehicle = inline_toggle("Block Destroy Vehicle Event", settings_state.block_destroy_vehicle, panel_x + side_pad, ly, usable_w, btn_h) end
        if settings_state.block_destroy_vehicle ~= old_bdv then safe_toast("Block Destroy Vehicle Event: " .. (settings_state.block_destroy_vehicle and "ON" or "OFF")) end
        ly = ly + btn_h + btn_gap

        local old_bfe = settings_state.block_fire_event
        if prot_vis() then settings_state.block_fire_event = inline_toggle("Block FIRE_EVENT Crash", settings_state.block_fire_event, panel_x + side_pad, ly, usable_w, btn_h) end
        if settings_state.block_fire_event ~= old_bfe then safe_toast("Block FIRE_EVENT Crash: " .. (settings_state.block_fire_event and "ON" or "OFF")) end
        ly = ly + btn_h + btn_gap

        local old_bpcs = settings_state.block_player_cam_sync
        if prot_vis() then settings_state.block_player_cam_sync = inline_toggle("Block Player Camera Sync Crash", settings_state.block_player_cam_sync, panel_x + side_pad, ly, usable_w, btn_h) end
        if settings_state.block_player_cam_sync ~= old_bpcs then safe_toast("Block Player Camera Sync Crash: " .. (settings_state.block_player_cam_sync and "ON" or "OFF")) end
        ly = ly + btn_h + btn_gap

        local old_bsf = settings_state.block_sync_flood
        if prot_vis() then settings_state.block_sync_flood = inline_toggle("Block Sync Flood (FPS Drop Attack)", settings_state.block_sync_flood, panel_x + side_pad, ly, usable_w, btn_h) end
        if settings_state.block_sync_flood ~= old_bsf then safe_toast("Block Sync Flood: " .. (settings_state.block_sync_flood and "ON" or "OFF")) end
        ly = ly + btn_h + btn_gap

        local old_hos = settings_state.hide_other_spawns
        if prot_vis() then settings_state.hide_other_spawns = inline_toggle("Hide Other Players Spawns (Crash Prevention)", settings_state.hide_other_spawns, panel_x + side_pad, ly, usable_w, btn_h) end
        if settings_state.hide_other_spawns ~= old_hos then safe_toast("Hide Other Spawns: " .. (settings_state.hide_other_spawns and "ON" or "OFF")) end
        ly = ly + btn_h + btn_gap

        local old_shield = settings_state.shield
        if prot_vis() then settings_state.shield = inline_toggle("Shield (Deep Packet Protection)", settings_state.shield, panel_x + side_pad, ly, usable_w, btn_h) end
        if settings_state.shield and not old_shield then

            local function shield_get_name(sender)
                local ok, name = pcall(function() return invoker.call(0x7718D2E2060837D2, sender).str end)
                if ok and name and #name > 0 then return name end
                return "Player " .. tostring(sender)
            end

            -- Red on-screen alert queue for protection events
            self_state.shield_alert_queue = self_state.shield_alert_queue or {}
            self_state.shield_alert_show_until = self_state.shield_alert_show_until or 0

            local function shield_alert(category, attacker, detail)
                local timestamp = os.date("%Y-%m-%d %H:%M:%S")
                local msg = timestamp .. " Protections: " .. category .. " from " .. attacker
                if detail and #detail > 0 then msg = msg .. " (" .. detail .. ")" end
                print(msg)

                -- Red notification via notify API
                pcall(function()
                    if notify and notify.push then
                        local icon = (notify.icon.warning and notify.icon.warning)
                                  or (notify.icon.error   and notify.icon.error)
                                  or (notify.icon.info    and notify.icon.info)
                        notify.push("⚠ KYRON SHIELD", "BLOCKED: " .. category .. "\nAttacker: " .. attacker, {
                            time = 6000,
                            icon = icon,
                            color = color and color(220, 30, 30, 255) or nil,
                        })
                    end
                end)

                -- Queue for red on-screen overlay
                local alert_text = "⚠  " .. category
                local sub_text   = "From: " .. attacker .. (detail and #detail > 0 and "  |  " .. detail or "")
                local queue = self_state.shield_alert_queue
                queue[#queue + 1] = { title = alert_text, sub = sub_text, born = os.clock() }
                if #queue > 5 then table.remove(queue, 1) end
            end

            -- Draw red shield alerts on screen (called every frame inside draw_ui)
            local function draw_shield_alerts()
                if not (self_state.shield_alert_queue and #self_state.shield_alert_queue > 0) then return end
                if not (gui and gui.rect and gui.text and vec2 and color) then return end
                local now = os.clock()
                local alive = {}
                for i = 1, #self_state.shield_alert_queue do
                    if now - self_state.shield_alert_queue[i].born < 6.0 then
                        alive[#alive + 1] = self_state.shield_alert_queue[i]
                    end
                end
                self_state.shield_alert_queue = alive
                if #alive == 0 then return end

                local sw = screen_w or 1920
                local sh = screen_h or 1080
                local box_w = math.floor(sw * 0.32)
                local box_h = math.floor(sh * 0.072)
                local pad   = math.floor(sh * 0.012)
                local bx    = sw - box_w - math.floor(sw * 0.012)

                for i = 1, #alive do
                    local alert = alive[i]
                    local age   = now - alert.born
                    local alpha = 255
                    if age > 4.5 then alpha = math.floor(255 * (1.0 - (age - 4.5) / 1.5)) end
                    if alpha < 0 then alpha = 0 end

                    local by = math.floor(sh * 0.04) + (i - 1) * (box_h + pad)

                    -- Red background
                    local bg = gui.rect(vec2(bx, by), vec2(box_w, box_h))
                    bg:filled(); bg:color(color(160, 18, 18, math.floor(alpha * 0.88))); bg:rounding(6); bg:draw()

                    -- Bright red left accent bar
                    local bar = gui.rect(vec2(bx, by), vec2(4, box_h))
                    bar:filled(); bar:color(color(255, 50, 50, alpha)); bar:rounding(2); bar:draw()

                    -- Title text
                    local t = gui.text(alert.title)
                    t:position(vec2(bx + 12, by + math.floor(box_h * 0.1)))
                    t:scale(math.floor(sh * 0.016))
                    t:color(color(255, 200, 200, alpha))
                    t:draw()

                    -- Sub text
                    local s = gui.text(alert.sub)
                    s:position(vec2(bx + 12, by + math.floor(box_h * 0.52)))
                    s:scale(math.floor(sh * 0.012))
                    s:color(color(255, 160, 160, math.floor(alpha * 0.85)))
                    s:draw()
                end
            end
            self_state.draw_shield_alerts = draw_shield_alerts

            self_state.shield_blocked_events = {
                [160]="K-Script Remote Crash",[6]="GIVE_CONTROL_EVENT Crash",[157]="CEO Transaction Kick",
                [168]="Script Event Crash",[86]="Freeze Player",[106]="Kick From CEO",
                [62]="Force Mission",[125]="Chaos Mode Crash",
                [85]="FIRE_EVENT Crash",
            }

            self_state.shield_blocked_models = {
                [0x1286B147]=true,[0xD2800BD6]=true,[0xFD707EDE]=true,[0x505603B9]=true,
                [0x1E41B223]=true,[0xBE086EFD]=true,[0x9CA95F7E]=true,
                [0x00000000]=true,[0xFFFFFFFF]=true,[0xDEADBEEF]=true,[0xBADF00D]=true,
                [0x15F27762]=true, -- NET_OBJ_TYPE_PLANE crash model (2026-02-23, maryusicabaa)
                -- Plane/aircraft crash models used in vehicle takeover → plane-spawn crash (2026-02-25, wyq225)
                [0x39D6B540]=true, -- Hydra
                [0xAA699BB6]=true, -- Lazer
                [0x8704B4DC]=true, -- Cuban800
                [0xFCF5C362]=true, -- Cargoplane
                [0x44B5A4BB]=true, -- Titan
                [0x97E50B70]=true, -- Bombushka
                [0xF8F4B8CD]=true, -- Besra
                [0xD7278283]=true, -- Nimbus
                [0xAD3B3CC1]=true, -- Molotok
                [0x1A82798B]=true, -- Starling
                [0x4D1FCB1E]=true, -- Pyro
                [0x97EF5396]=true, -- Nokota
                [0x97C62D0B]=true, -- Volatol
                [0x3D6AAA23]=true, -- Alkonost
            }

            self_state.shield_blocked_script_hashes = {
                [0xEDB26815]="K-Script SCRIPTED_GAME_EVENT Crash",
                [0x5D7BB983]="K-Script Session Crash (Cherax payload)",
                [0x36E852EB]="K-Script SGE Crash",
                [0xC6751F5E]="Enhanced Edition SGE Crash (MyGBibuatM)",
            }

            self_state.request_control_tracker = {}
            self_state.sge_spam_tracker = {}
            self_state.sync_flood_tracker = {}  -- Per-sender sync packet rate limiter

            local sid = {}
            self_state.shield_sid = sid
            util.create_thread(function()
                while settings_state.shield and self_state.shield_sid == sid do util.yield(0) end
            end)

            function on_script_event(sender, event_id, event_data)
                if not settings_state.shield then return end
                local name = shield_get_name(sender)
                if self_state.shield_blocked_events and self_state.shield_blocked_events[event_id] then
                    shield_alert("Crash attempt blocked", name, "Script Event ID " .. tostring(event_id) .. " (" .. self_state.shield_blocked_events[event_id] .. ")")
                    return false
                end
                if settings_state.block_kscript_sge and event_data then
                    for _, idx in ipairs({1,2}) do
                        local raw = event_data[idx]
                        if raw then
                            local uhash = raw & 0xFFFFFFFF
                            if self_state.shield_blocked_script_hashes and self_state.shield_blocked_script_hashes[uhash] then
                                shield_alert("K-Script crash blocked", name, self_state.shield_blocked_script_hashes[uhash] .. " hash=0x" .. string.format("%X", uhash))
                                return false
                            end
                        end
                    end
                    local n = event_data and #event_data or 0
                    if n >= 4 and event_data[n] and (event_data[n] & 0xFFFFFFFF) == 0xBF800000 then
                        shield_alert("K-Script crash blocked", name, "Float fingerprint 0xBF800000 in arg[" .. n .. "]"); return false
                    end
                    if event_data[2]==11 and event_data[3]==522239 then shield_alert("K-Script crash blocked", name, "SGE pattern (11/522239)"); return false end
                    -- FIRE_EVENT crash (seen 2026-02-23, sender maryusicabaa)
                    -- Fingerprint: arg[0]=0xA94AF7A5, arg[2]=524269, arg[4]=63
                    if settings_state.block_fire_event then
                        if event_data[1] and (event_data[1] & 0xFFFFFFFF)==0xA94AF7A5 and event_data[3]==524269 then
                            shield_alert("FIRE_EVENT crash blocked", name, "FIRE_EVENT payload hash=0xA94AF7A5"); return false
                        end
                        if event_data[3] and event_data[3]==524269 and event_data[5] and event_data[5]==63 then
                            shield_alert("FIRE_EVENT crash blocked", name, "FIRE_EVENT payload (524269/63 pattern)"); return false
                        end
                    end
                    if event_data[1]==0 and event_data[2]==842 and event_data[3]==20 then shield_alert("K-Script crash blocked", name, "Cherax SGE pattern (0/842/20)"); return false end
                    if event_data[1]==6 and event_data[3]==20 then shield_alert("K-Script crash blocked", name, "REMOTE_SCRIPT_LEAVE_EVENT pattern (6/*/20)"); return false end
                    if event_data[2]==1048576 and event_data[3]==877157602 then shield_alert("K-Script crash blocked", name, "K-Script_Sponsor SGE pattern"); return false end
                end
                if settings_state.block_sge_catchall and event_data then
                    local n = #event_data
                    local now = os.clock()
                    self_state.sge_spam_tracker = self_state.sge_spam_tracker or {}
                    local track = self_state.sge_spam_tracker[sender]
                    if not track then self_state.sge_spam_tracker[sender] = {count=1,t=now}
                    elseif now - track.t < 1.0 then
                        track.count = track.count + 1
                        if track.count > 8 then shield_alert("SGE spam blocked", name, "Rapid-fire " .. track.count .. " events/sec"); return false end
                    else self_state.sge_spam_tracker[sender] = {count=1,t=now} end
                    if n <= 2 and event_data[1] then
                        local v = event_data[1] & 0xFFFFFFFF
                        if v > 0x10000000 and v ~= 0xFFFFFFFF and v ~= 0xDEADBEEF then
                            shield_alert("SGE catch-all blocked", name, "Anomalous short SGE arg[1]=0x" .. string.format("%X", v)); return false
                        end
                    end
                end
            end

            function on_network_script_leave_event(sender, event_data)
                if not (settings_state.shield and settings_state.block_kscript_sge) then return end
                local name = shield_get_name(sender)
                if event_data then
                    for _, idx in ipairs({1,2}) do
                        local raw = event_data[idx]
                        if raw then
                            local uhash = raw & 0xFFFFFFFF
                            if self_state.shield_blocked_script_hashes and self_state.shield_blocked_script_hashes[uhash] then
                                shield_alert("REMOTE_SCRIPT_LEAVE_EVENT blocked", name, self_state.shield_blocked_script_hashes[uhash]); return false
                            end
                        end
                    end
                    local n = #event_data
                    if n >= 4 and event_data[n] and (event_data[n] & 0xFFFFFFFF) == 0xBF800000 then
                        shield_alert("REMOTE_SCRIPT_LEAVE_EVENT blocked", name, "Float fingerprint 0xBF800000"); return false
                    end
                end
            end

            function on_give_control_event(sender, event_data)
                if not settings_state.shield then return end
                local name = shield_get_name(sender)
                -- Block known GIVE_CONTROL_EVENT crash payload (2026-02-23, maryusicabaa)
                -- Fingerprint: arg[0]=0xBC70D7F5, arg[2]=577, arg[4]=7521
                if event_data then
                    if event_data[1] and (event_data[1] & 0xFFFFFFFF) == 0xBC70D7F5 then
                        shield_alert("GIVE_CONTROL crash blocked", name, "Payload hash=0xBC70D7F5"); return false
                    end
                    if event_data[3] and event_data[3] == 577 and event_data[5] and event_data[5] == 7521 then
                        shield_alert("GIVE_CONTROL crash blocked", name, "Payload pattern (577/7521)"); return false
                    end
                    -- Generic: arg[0] suspiciously large (overflow attack)
                    if event_data[1] then
                        local v = event_data[1] & 0xFFFFFFFF
                        if v > 0xF0000000 and v ~= 0xFFFFFFFF then
                            shield_alert("GIVE_CONTROL crash blocked", name, "Overflow arg[0]=0x"..string.format("%X",v)); return false
                        end
                    end
                end
            end

            function on_object_sync_requested(sender, object_type, object_flags, object_data, extra_data)
                if not settings_state.shield then return end
                local model = object_data and object_data.model
                local name = shield_get_name(sender)
                local is_create = object_data and object_data.create

                -- Sync flood rate limiter (FPS drop / object spam crash protection)
                -- Global limit: 15 total sync packets/sec per sender
                -- Per-type limits: 8 peds/sec, 8 vehicles/sec, 8 objects/sec
                -- (type ids: 1=Ped, 3=Automobile, 4=Bike, 5=Boat, 6=Heli, 7=Plane, 8=Object, 9=Vehicle, 14=Trailer)
                if settings_state.block_sync_flood then
                    local now = os.clock()
                    self_state.sync_flood_tracker = self_state.sync_flood_tracker or {}
                    local t = self_state.sync_flood_tracker[sender]
                    if not t then
                        self_state.sync_flood_tracker[sender] = {
                            count = 1, window_start = now, blocked = false,
                            ped_count = 0, veh_count = 0, obj_count = 0,
                        }
                    else
                        if now - t.window_start >= 1.0 then
                            t.count = 1
                            t.window_start = now
                            t.blocked = false
                            t.ped_count = 0
                            t.veh_count = 0
                            t.obj_count = 0
                        else
                            t.count = t.count + 1
                            -- Per-type counters
                            if object_type == 1 then
                                t.ped_count = (t.ped_count or 0) + 1
                            elseif object_type == 3 or object_type == 4 or object_type == 5 or object_type == 6 or object_type == 7 or object_type == 9 or object_type == 14 then
                                t.veh_count = (t.veh_count or 0) + 1
                            elseif object_type == 8 then
                                t.obj_count = (t.obj_count or 0) + 1
                            end
                            -- Check limits
                            local reason = nil
                            if t.count > 15 then
                                reason = t.count .. " total sync/sec (limit 15)"
                            elseif (t.ped_count or 0) > 8 then
                                reason = t.ped_count .. " ped syncs/sec (limit 8) - ped spam attack"
                            elseif (t.veh_count or 0) > 8 then
                                reason = t.veh_count .. " vehicle syncs/sec (limit 8) - vehicle spam attack"
                            elseif (t.obj_count or 0) > 8 then
                                reason = t.obj_count .. " object syncs/sec (limit 8) - object spam attack"
                            end
                            if reason and not t.blocked then
                                t.blocked = true
                                shield_alert("Sync flood BLOCKED", name, reason)
                            end
                            if t.blocked then return false end
                        end
                    end
                end
                -- NET_OBJ_TYPE_AUTOMOBILE crash (type 3) — Create:No forced sync crash vector (2026-02-25, tiger900ugo)
                if settings_state.block_vehicle_sync and object_type == 3 then
                    if model then
                        local umodel = model & 0xFFFFFFFF
                        if self_state.shield_blocked_models and self_state.shield_blocked_models[umodel] then
                            shield_alert("Automobile sync crash blocked", name, "Blacklisted model 0x"..string.format("%X",umodel)..(is_create==false and " (Create:No)" or "")); return false
                        end
                        if is_create == false then
                            shield_alert("Automobile sync crash blocked", name, "NET_OBJ_TYPE_AUTOMOBILE Create:No forced sync 0x"..string.format("%X",umodel)); return false
                        end
                    else shield_alert("Automobile sync crash blocked", name, "NET_OBJ_TYPE_AUTOMOBILE null model"); return false end
                end
                if settings_state.block_heli_sync and object_type == 6 then
                    if model then
                        local umodel = model & 0xFFFFFFFF
                        if self_state.shield_blocked_models and self_state.shield_blocked_models[umodel] then shield_alert("Heli sync crash blocked", name, "NET_OBJ_TYPE_HELI model 0x"..string.format("%X",umodel)); return false end
                        if extra_data and extra_data.from_join_request then shield_alert("Heli sync crash blocked", name, "NET_OBJ_TYPE_HELI via CMsgJoinRequest"); return false end
                        if umodel > 0xF0000000 and umodel ~= 0xFFFFFFFF then shield_alert("Heli sync crash blocked", name, "NET_OBJ_TYPE_HELI invalid model 0x"..string.format("%X",umodel)); return false end
                    else shield_alert("Heli sync crash blocked", name, "NET_OBJ_TYPE_HELI null model"); return false end
                end
                if settings_state.block_vehicle_sync and (object_type==7 or object_type==9 or object_type==14) then
                    local tname = ({[7]="BOAT",[9]="PLANE",[14]="TRAILER"})[object_type]
                    if model then
                        local umodel = model & 0xFFFFFFFF
                        if self_state.shield_blocked_models and self_state.shield_blocked_models[umodel] then shield_alert("Vehicle sync crash blocked", name, "NET_OBJ_TYPE_"..tname.." blacklisted 0x"..string.format("%X",umodel)); return false end
                        if extra_data and extra_data.from_join_request then shield_alert("Vehicle sync crash blocked", name, "NET_OBJ_TYPE_"..tname.." via CMsgJoinRequest"); return false end
                        if umodel > 0xF0000000 and umodel ~= 0xFFFFFFFF then shield_alert("Vehicle sync crash blocked", name, "NET_OBJ_TYPE_"..tname.." invalid model"); return false end
                        -- Block Create:No plane/boat/trailer sync from non-host (crash vector seen 2026-02-23)
                        if is_create == false then shield_alert("Vehicle sync crash blocked", name, "NET_OBJ_TYPE_"..tname.." Create:No forced sync 0x"..string.format("%X",umodel)); return false end
                    else shield_alert("Vehicle sync crash blocked", name, "NET_OBJ_TYPE_"..tname.." null model"); return false end
                end
                -- Blocked model check fires for ALL vehicle/object types (not just type 2)
                -- because the Lexis API type IDs may not exactly match GTA's NET_OBJ_TYPE enum.
                -- This catches 3602674979 (GINandYhy / _-The-Most-God-_ automobile crash tool).
                if model and self_state.shield_blocked_models then
                    local umodel = model & 0xFFFFFFFF
                    if self_state.shield_blocked_models[umodel] then
                        shield_alert("Blocked model sync", name, "type="..tostring(object_type).." model 0x"..string.format("%X",umodel)..(is_create==false and " (Create:No)" or " (Create:Yes)")); return false
                    end
                end
                if model and self_state.shield_blocked_models then
                    local umodel = model & 0xFFFFFFFF
                    if self_state.shield_blocked_models[umodel] then shield_alert("Crash attempt", name, "NS type="..tostring(object_type).." model 0x"..string.format("%X",umodel)); return false end
                    if umodel < 0x1000 and object_type ~= 0 then shield_alert("Crash attempt", name, "NS invalid model 0x"..string.format("%X",umodel)); return false end
                end
                -- NET_OBJ_TYPE_PLAYER crash (seen 2026-02-23, sender HasHimali121)
                -- Malicious CPlayerCameraDataNode injection via player sync
                if object_type==4 and settings_state.block_player_cam_sync then
                    -- Block known crash model hashes on NET_OBJ_TYPE_PLAYER syncs (2026-02-25, mcaketzyp)
                    if model and self_state.shield_blocked_models then
                        local umodel = model & 0xFFFFFFFF
                        if self_state.shield_blocked_models[umodel] then
                            shield_alert("Player sync crash blocked", name, "Blacklisted model 0x"..string.format("%X",umodel).." in NET_OBJ_TYPE_PLAYER (Create:"..(is_create==false and "No" or "Yes")..")"); return false
                        end
                    end
                    if object_data and object_data.nodes then
                        for _, node in ipairs(object_data.nodes) do
                            if type(node)=="string" and node:find("CPlayerCameraDataNode") then
                                shield_alert("Player sync crash blocked", name, "Malicious CPlayerCameraDataNode in NET_OBJ_TYPE_PLAYER"); return false
                            end
                        end
                    end
                end
                if object_type==3 then
                    local tc = 0
                    if object_data and object_data.nodes then for _,node in ipairs(object_data.nodes) do if type(node)=="string" and node:find("TaskSpecific") then tc=tc+1 end end end
                    if tc >= 7 then shield_alert("Task flood blocked", name, tc.."x CPedTaskSpecificDataNode"..(is_create==false and " (Create:No)" or "")); return false end
                    if model and self_state.shield_blocked_models then
                        local umodel = model & 0xFFFFFFFF
                        if self_state.shield_blocked_models[umodel] then shield_alert("Task flood blocked", name, "NET_OBJ_TYPE_PED blacklisted 0x"..string.format("%X",umodel)); return false end
                    end
                end
                if object_type==0 and (not model or (model & 0xFFFFFFFF)==0) then shield_alert("Crash attempt", name, "NS model 0 spam"); return false end
            end

            function on_task_flood_detected(sender)
                if not settings_state.shield then return end
                shield_alert("Crash attempt", shield_get_name(sender), "Task Flood"); return false
            end

            function on_explosion_event(sender, x, y, z, explosion_type, f_damage)
                if not settings_state.shield then return end
                if f_damage and f_damage > 10000 then shield_alert("Crash attempt", shield_get_name(sender), "NE explosion damage "..tostring(f_damage)); return false end
                if self_state.shield_last_ns_sender and self_state.shield_last_ns_sender==sender then shield_alert("Crash attempt", shield_get_name(sender), "NE EXPLOSION_EVENT combo"); return false end
            end

            function on_player_card_stat_event(sender, event_data)
                if not (settings_state.shield and settings_state.block_card_stat_event) then return end
                local name = shield_get_name(sender)
                if event_data then
                    if event_data[1]==800157557 then shield_alert("PLAYER_CARD_STAT_EVENT blocked", name, "Known crash payload"); return false end
                    local sv = event_data[4]
                    if sv and (sv > 0x7FFFFFFF or sv < -0x7FFFFFFF) then shield_alert("PLAYER_CARD_STAT_EVENT blocked", name, "Overflow stat "..tostring(sv)); return false end
                end
            end

            function on_sge_enhanced_event(sender, event_data)
                if not (settings_state.shield and settings_state.block_sge_enhanced) then return end
                local name = shield_get_name(sender)
                if event_data then
                    if event_data[1] and (event_data[1] & 0xFFFFFFFF)==0xC6751F5E then shield_alert("Enhanced SGE crash blocked", name, "hash=0xC6751F5E"); return false end
                    if event_data[2]==26 and event_data[3]==989853695 then shield_alert("Enhanced SGE crash blocked", name, "Fingerprint (26/989853695/0)"); return false end
                end
            end

            function on_request_control_event(sender, entity_id)
                if not (settings_state.shield and settings_state.block_request_control) then return end
                local now = os.clock()
                self_state.request_control_tracker = self_state.request_control_tracker or {}
                local track = self_state.request_control_tracker[sender]
                if not track then
                    self_state.request_control_tracker[sender] = {count=1, t=now, blocked=false}
                    return false  -- block all REQUEST_CONTROL from non-local senders when shield is on
                end
                -- Already permanently blocked this session
                if track.blocked then
                    return false
                end
                if now - track.t < 2.0 then
                    track.count = track.count + 1
                    -- After 3 attempts in 2 seconds, permanently block + alert (2026-02-25, wyq225 plane crash)
                    if track.count >= 3 then
                        track.blocked = true
                        shield_alert("Vehicle takeover blocked", shield_get_name(sender),
                            track.count .. " REQUEST_CONTROL attempts — auto-blocked for session (plane spawn crash vector)")
                        return false
                    end
                else
                    self_state.request_control_tracker[sender] = {count=1, t=now, blocked=false}
                end
                return false  -- always block REQUEST_CONTROL when shield is on
            end

            function on_report_myself_event(sender, event_data)
                if not (settings_state.shield and settings_state.block_report_myself) then return end
                shield_alert("REPORT_MYSELF_EVENT blocked", shield_get_name(sender), "Remote player state corruption"); return false
            end

            function on_destroy_personal_vehicle_event(sender, event_data)
                if not (settings_state.shield and settings_state.block_destroy_vehicle) then return end
                shield_alert("Destroy Vehicle Event blocked", shield_get_name(sender), "Remote vehicle destruction"); return false
            end

            -- REMOTE_SCRIPT_INFO_EVENT crash (seen 2026-02-25, sender Foreverywhere)
            -- Payload: 800157557 1 402653177 -1140092619 4432
            -- Hash 800157557 is a known crash payload delivered via REMOTE_SCRIPT_INFO_EVENT
            function on_remote_script_info_event(sender, event_data)
                if not settings_state.shield then return end
                local name = shield_get_name(sender)
                if event_data then
                    local h = event_data[1]
                    if h == 800157557 then
                        shield_alert("REMOTE_SCRIPT_INFO_EVENT blocked", name, "Known crash payload 800157557"); return false
                    end
                    -- Block any payload hash that is in the blocked script events table
                    if h and BLOCKED_SCRIPT_EVENTS and BLOCKED_SCRIPT_EVENTS[h] then
                        shield_alert("REMOTE_SCRIPT_INFO_EVENT blocked", name, BLOCKED_SCRIPT_EVENTS[h]); return false
                    end
                end
            end

            safe_toast("Shield: ON")
        elseif not settings_state.shield and old_shield then
            self_state.shield_sid = nil
            self_state.shield_blocked_events = nil
            self_state.shield_blocked_models = nil
            self_state.shield_blocked_script_hashes = nil
            -- Background thread: hide + no-collide entities spawned by other players
            -- Runs every 500ms, uses safe grid-scan (GET_CLOSEST_PED/VEHICLE) instead of
            -- GET_NEARBY_PEDS which crashes GTA Enhanced. Hides networked entities that
            -- are not owned by any real player so they can't render-crash you.
            util.create_thread(function()
                local sid = self_state.shield_sid
                local hidden = {}
                -- Grid offsets to probe around player (covers ~150m radius)
                local grid = {
                    {0,0},{20,0},{-20,0},{0,20},{0,-20},
                    {40,0},{-40,0},{0,40},{0,-40},
                    {30,30},{-30,30},{30,-30},{-30,-30},
                    {60,0},{-60,0},{0,60},{0,-60},
                    {50,50},{-50,50},{50,-50},{-50,-50},
                    {80,0},{-80,0},{0,80},{0,-80},
                }
                while settings_state.shield and self_state.shield_sid == sid do
                    if settings_state.hide_other_spawns then
                        pcall(function()
                            local my_ped = invoker.call(0x43A66C31C68491C0).int -- PLAYER_PED_ID
                            if not my_ped or my_ped == 0 then return end
                            local cx = invoker.call(0x3FEF770D40960D5A, my_ped, false).vec3
                            if not cx then return end
                            local px, py, pz = cx.x, cx.y, cx.z

                            -- Build set of all real player peds so we never hide them
                            local player_peds = {}
                            for i = 0, 31 do
                                local ok, active = pcall(invoker.call, 0x490A0C2BB8DA3FA5, i) -- NETWORK_IS_PARTICIPANT_ACTIVE
                                if ok and active and active.bool then
                                    local ok2, pp = pcall(invoker.call, 0x43A66C31C68491C0, i) -- GET_PLAYER_PED
                                    if ok2 and pp and pp.int and pp.int ~= 0 then
                                        player_peds[pp.int] = true
                                    end
                                end
                            end

                            local seen = {}

                            -- Scan for peds via safe grid probe
                            for _, off in ipairs(grid) do
                                local ok, pr = pcall(invoker.call, 0x57AB4A3080B91165,
                                    1.0*(px+off[1]), 1.0*(py+off[2]), 1.0*pz, 80.0, 1, 1)
                                if ok and pr and pr.int and pr.int ~= 0 then
                                    local ped = pr.int
                                    if not seen[ped] and ped ~= my_ped and not player_peds[ped] then
                                        seen[ped] = true
                                        -- Only hide networked (other-player-spawned) peds
                                        local ok2, nl = pcall(invoker.call, 0x0991549DE4D64762, ped) -- NETWORK_GET_ENTITY_IS_LOCAL
                                        local is_net = ok2 and nl and not nl.bool
                                        if is_net and not hidden[ped] then
                                            pcall(invoker.call, 0xEA1C610A04DB6BBB, ped, false, false) -- SET_ENTITY_VISIBLE false
                                            pcall(invoker.call, 0xA53ED5520C07654A, my_ped, ped, false) -- SET_ENTITY_NO_COLLISION_ENTITY
                                            hidden[ped] = true
                                        end
                                    end
                                end
                            end

                            -- Scan for vehicles via safe grid probe
                            for _, off in ipairs(grid) do
                                local ok, vr = pcall(invoker.call, 0xF73EB622C4F1689B,
                                    1.0*(px+off[1]), 1.0*(py+off[2]), 1.0*pz, 80.0, 0, 70)
                                if ok and vr and vr.int and vr.int ~= 0 then
                                    local veh = vr.int
                                    if not seen[veh] then
                                        seen[veh] = true
                                        local ok2, nl = pcall(invoker.call, 0x0991549DE4D64762, veh)
                                        local is_net = ok2 and nl and not nl.bool
                                        if is_net and not hidden[veh] then
                                            -- Don't hide vehicles a real player is sitting in
                                            local has_player = false
                                            for pp, _ in pairs(player_peds) do
                                                local ok3, iv = pcall(invoker.call, 0xF3139A2EBF7F2B7D, pp) -- GET_VEHICLE_PED_IS_IN
                                                if ok3 and iv and iv.int == veh then has_player = true; break end
                                            end
                                            if not has_player then
                                                pcall(invoker.call, 0xEA1C610A04DB6BBB, veh, false, false) -- SET_ENTITY_VISIBLE false
                                                pcall(invoker.call, 0xA53ED5520C07654A, my_ped, veh, false) -- SET_ENTITY_NO_COLLISION_ENTITY
                                                hidden[veh] = true
                                            end
                                        end
                                    end
                                end
                            end
                        end)
                    end
                    util.yield(500)
                end
                -- Cleanup: restore visibility when shield turns off
                pcall(function()
                    for ent, _ in pairs(hidden) do
                        pcall(invoker.call, 0xEA1C610A04DB6BBB, ent, true, false)
                    end
                end)
            end)

            self_state.shield_last_ns_sender = nil
            self_state.sge_spam_tracker = nil
            self_state.request_control_tracker = nil
            self_state.sync_flood_tracker = nil
            on_script_event = nil
            on_network_script_leave_event = nil
            on_give_control_event = nil
            on_object_sync_requested = nil
            on_task_flood_detected = nil
            on_explosion_event = nil
            on_player_card_stat_event = nil
            on_sge_enhanced_event = nil
            on_request_control_event = nil
            on_report_myself_event = nil
            on_destroy_personal_vehicle_event = nil
            on_remote_script_info_event = nil
            safe_toast("Shield: OFF")
        end
        ly = ly + btn_h + btn_gap
    end

    -- =========================================================================
    local function draw_settings_tab()
        local s = UI.scale
        local base_x = ui_layout.content_x
        local base_y = ui_layout.widget_y
        local total_w = ui_layout.content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- Sub-tab bar
        local new_sub_tab, tab_h = sub_tab_bar(settings_state.sub_tabs, settings_state.sub_tab, base_x + math.floor(5 * s), base_y, total_w - math.floor(10 * s))
        settings_state.sub_tab = new_sub_tab
        base_y = base_y + tab_h

        -- Content area (standard layout for all tabs)
        local panel_x = base_x + math.floor(5 * s)
        local panel_y = base_y
        local panel_w = total_w - math.floor(10 * s)
        local panel_h = total_h - tab_h

        draw_rect(panel_x, panel_y, panel_w, panel_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local side_pad = math.floor((UI.padding or 10) * s)
        local item_gap = math.floor((UI.item_spacing or 6) * s)
        local section_gap = math.floor((UI.section_gap or 14) * s)
        local usable_w = panel_w - side_pad * 2

        -- Build items list based on sub-tab
        local items = {}

        local function add_section(title)
            table.insert(items, {type = "section", text = title})
        end

        local function add_slider_item(label, key, min, max, step)
            table.insert(items, {type = "slider", text = label, key = key, min = min, max = max, step = step or 1})
        end

        local function add_checkbox_item(label, key)
            table.insert(items, {type = "checkbox", text = label, key = key})
        end

        local function add_button_item(label, action)
            table.insert(items, {type = "button", text = label, action = action})
        end

        -- ==================== GENERAL ====================
        if settings_state.sub_tab == 1 then
            add_section("Menu Position")
            add_slider_item("Menu X Position", "x", 0, screen_w - UI.w, 10)
            add_slider_item("Menu Y Position", "y", 0, screen_h - UI.h, 10)

            add_section("Menu Behavior")
            -- allow_movement always enabled (no toggle needed)

            add_section("Menu Appearance")
            add_slider_item("Menu Transparency", "menu_transparency", 0, 100, 1)

            add_section("Actions")
            add_button_item("Center Menu", function()
                UI.x = math.floor((screen_w - UI.w) / 2)
                UI.y = math.floor((screen_h - UI.h) / 2)
                safe_toast("Menu Centered!")
            end)
            add_button_item("Reset Position", function()
                UI.x = 170
                UI.y = 100
                safe_toast("Position Reset!")
            end)

            add_section("Modder Detection Overlay")
            add_checkbox_item("Show Modder Overlay", "modder_overlay_enabled")

            add_section("Config Save/Load")
            add_button_item("Save Full Config", function()
                local config = {
                    ui = {
                        x = UI.x, y = UI.y, w = UI.w, h = UI.h,
                        font_header = UI.font_header, font_tab = UI.font_tab,
                        font_widget = UI.font_widget, font_small = UI.font_small,
                        padding = UI.padding, item_spacing = UI.item_spacing,
                        widget_rounding = UI.widget_rounding,
                        accent_r = UI.accent_r, accent_g = UI.accent_g, accent_b = UI.accent_b,
                        bg_r = UI.bg_r, bg_g = UI.bg_g, bg_b = UI.bg_b, bg_a = UI.bg_a
                    },
                    features = {
                        self = {
                            god_mode = demo.god_mode, invisibility = demo.invisibility,
                            off_the_radar = demo.off_the_radar, super_jump = demo.super_jump,
                            fast_run = demo.fast_run, no_ragdoll = demo.no_ragdoll,
                            noclip = demo.noclip
                        },
                        vehicle = {
                            god_mode = vehicle_state.god_mode, invisible = vehicle_state.invisible,
                            super_brake = vehicle_state.super_brake, drift_mode = vehicle_state.drift_mode,
                            horn_boost = vehicle_state.horn_boost, bulletproof_tires = vehicle_state.bulletproof_tires
                        }
                    },
                    timestamp = os.date("%Y-%m-%d %H:%M:%S")
                }

                -- Manual JSON serialization
                local function val_to_json(v)
                    if type(v) == "boolean" then
                        return v and "true" or "false"
                    elseif type(v) == "number" then
                        return tostring(v)
                    else
                        return '"' .. tostring(v):gsub('"', '\\"') .. '"'
                    end
                end

                local json_str = '{\n  "ui": {\n'
                for k, v in pairs(config.ui) do
                    json_str = json_str .. '    "' .. k .. '": ' .. val_to_json(v) .. ',\n'
                end
                json_str = json_str:gsub(',\n$', '\n') .. '  },\n  "features": {\n    "self": {\n'
                for k, v in pairs(config.features.self) do
                    json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v) .. ',\n'
                end
                json_str = json_str:gsub(',\n$', '\n') .. '    },\n    "vehicle": {\n'
                for k, v in pairs(config.features.vehicle) do
                    json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v) .. ',\n'
                end
                json_str = json_str:gsub(',\n$', '\n') .. '    }\n  },\n  "timestamp": "' .. config.timestamp .. '"\n}'

                -- Save using Lexis file.open API
                local save_path = get_config_dir() .. "\\kyron_config.json"
                if file and file.open then
                    pcall(function()
                        local f = file.open(save_path, {create_if_not_exists=true, append=false})
                        if f and f.valid then
                            f.text = json_str
                            if f.close then pcall(f.close, f) elseif f.Close then pcall(f.Close, f) end
                            safe_toast("Config Saved!")
                        else
                            safe_toast("Failed to save!")
                        end
                    end)
                else
                    safe_toast("File API not available!")
                end
            end)
            add_button_item("Load Full Config", function()
                local save_path = get_config_dir() .. "\\kyron_config.json"
                if file and file.open then
                    local ok_open, f = pcall(file.open, save_path, {create_if_not_exists=false, append=false})
                    if ok_open and f and f.valid then
                        local json_str = f.text
                        if f.close then pcall(f.close, f) elseif f.Close then pcall(f.Close, f) end

                        if json_str and json_str ~= "" then
                            -- Manual JSON parsing
                            local function extract_val(key, section)
                                section = section or ""
                                local full_key = section ~= "" and (section .. '": {[^}]*"' .. key) or key
                                local num = json_str:match('"' .. full_key .. '"%s*:%s*(%-?%d+%.?%d*)')
                                if num then return tonumber(num) end
                                local bool = json_str:match('"' .. full_key .. '"%s*:%s*(%a+)')
                                if bool == "true" then return true elseif bool == "false" then return false end
                                local str = json_str:match('"' .. full_key .. '"%s*:%s*"([^"]*)"')
                                if str then return str end
                                return nil
                            end

                            UI.x = extract_val("x", "ui") or UI.x
                            UI.y = extract_val("y", "ui") or UI.y
                            UI.w = extract_val("w", "ui") or UI.w
                            UI.h = extract_val("h", "ui") or UI.h
                            UI.font_header = extract_val("font_header", "ui") or UI.font_header
                            UI.font_tab = extract_val("font_tab", "ui") or UI.font_tab

                            local ar = extract_val("accent_r", "ui")
                            if ar then
                                UI.accent_r, UI.accent_g, UI.accent_b = ar, extract_val("accent_g", "ui"), extract_val("accent_b", "ui")
                                C.accent = color(UI.accent_r, UI.accent_g, UI.accent_b, 255)
                            end

                            local gm = extract_val("god_mode", "self")
                            if gm ~= nil then demo.god_mode = gm end
                            local inv = extract_val("invisibility", "self")
                            if inv ~= nil then demo.invisibility = inv end
                            local otr = extract_val("off_the_radar", "self")
                            if otr ~= nil then demo.off_the_radar = otr end
                            local sj = extract_val("super_jump", "self")
                            if sj ~= nil then demo.super_jump = sj end
                            local fr = extract_val("fast_run", "self")
                            if fr ~= nil then demo.fast_run = fr end
                            local nr = extract_val("no_ragdoll", "self")
                            if nr ~= nil then demo.no_ragdoll = nr end
                            local nc = extract_val("noclip", "self")
                            if nc ~= nil then demo.noclip = nc end
                            local nspd2 = extract_val("noclip_speed", "self")
                            if nspd2 ~= nil then noclip_state.speed = nspd2 end
                            local nkb2 = extract_val("noclip_keybind", "self")
                            if nkb2 ~= nil and nkb2 ~= 0 then noclip_state.keybind = nkb2 end
                            local asv2 = extract_val("auto_save", "self")
                            if asv2 ~= nil then settings_state.auto_save = asv2 end

                            local vgm = extract_val("god_mode", "vehicle")
                            if vgm ~= nil then vehicle_state.god_mode = vgm end
                            local vinv = extract_val("invisible", "vehicle")
                            if vinv ~= nil then vehicle_state.invisible = vinv end
                            local vsb = extract_val("super_brake", "vehicle")
                            if vsb ~= nil then vehicle_state.super_brake = vsb end
                            local vdm = extract_val("drift_mode", "vehicle")
                            if vdm ~= nil then vehicle_state.drift_mode = vdm end
                            local vhb = extract_val("horn_boost", "vehicle")
                            if vhb ~= nil then vehicle_state.horn_boost = vhb end
                            local vbt = extract_val("bulletproof_tires", "vehicle")
                            if vbt ~= nil then vehicle_state.bulletproof_tires = vbt end

                            safe_toast("Config Loaded!")
                        else
                            safe_toast("Config file is empty!")
                        end
                    else
                        safe_toast("Config file not found!")
                    end
                else
                    safe_toast("File API not available!")
                end
            end)

        -- ==================== LAYOUT ====================
        elseif settings_state.sub_tab == 2 then
            add_section("Menu Dimensions")
            add_slider_item("Menu Width", "w", 500, 1200, 10)
            add_slider_item("Menu Height", "h", 400, 900, 10)

            add_section("Header & Sidebar")
            add_slider_item("Header Height", "header_h", 18, 40, 1)
            add_slider_item("Sidebar Width", "sidebar_w", 50, 120, 2)

            add_section("Content")
            add_slider_item("Item Height", "item_h", 28, 60, 2)
            add_slider_item("SubTab Height", "subtab_h", 22, 45, 1)

        -- ==================== THEME ====================
        elseif settings_state.sub_tab == 3 then
            add_section("Presets")
            add_button_item("Default Theme", function()
