                C.tab_active = color(65, 105, 225, 255)
                C.text = color(220, 230, 255, 255)
                safe_toast("Dark Blue Theme Applied!")
            end)
            add_button_item("Purple Theme", function()
                C.bg = color(25, 18, 35, 250)
                C.header = color(18, 12, 25, 255)
                C.sidebar = color(20, 14, 28, 255)
                C.accent = color(147, 112, 219, 255)
                C.tab_active = color(147, 112, 219, 255)
                C.text = color(240, 235, 255, 255)
                safe_toast("Purple Theme Applied!")
