                C.sidebar = color(14, 24, 18, 255)
                C.accent = color(46, 204, 113, 255)
                C.tab_active = color(46, 204, 113, 255)
                C.text = color(230, 255, 240, 255)
                safe_toast("Green Theme Applied!")
