                C.bg = color(30, 18, 20, 250)
                C.header = color(22, 12, 14, 255)
                C.sidebar = color(25, 14, 16, 255)
                C.accent = color(231, 76, 60, 255)
                C.tab_active = color(231, 76, 60, 255)
                C.text = color(255, 235, 235, 255)
                safe_toast("Red Theme Applied!")
            end)
