                C.bg = color(28, 25, 18, 250)
                C.header = color(20, 18, 12, 255)
                C.sidebar = color(24, 21, 14, 255)
                C.accent = color(255, 193, 7, 255)
                C.tab_active = color(255, 193, 7, 255)
                C.text = color(255, 250, 230, 255)
                safe_toast("Gold Theme Applied!")
            end)

