        elseif settings_state.sub_tab == 4 then
            add_section("Console Window")
            add_button_item(DEBUG.show_console and "Hide Debug Console" or "Show Debug Console", function()
                DEBUG.show_console = not DEBUG.show_console
                debug_info("UI", DEBUG.show_console and "Debug console shown" or "Debug console hidden")
            end)

            add_section("Debug Controls")
            add_checkbox_item("Enable Debug System", "debug_enabled")
            add_checkbox_item("Show Timestamps", "debug_timestamps")
            add_checkbox_item("Show Memory", "debug_memory")
            add_checkbox_item("Show Performance", "debug_performance")
            add_checkbox_item("Auto Scroll Logs", "debug_auto_scroll")

            add_section("Feature Debugging")
            add_checkbox_item("Enable Feature Debug (VERBOSE!)", "debug_feature_debug")

            add_section("Log Level")
            add_slider_item("Min Log Level (1=ALL, 4=ERROR ONLY)", "debug_log_level", 1, 4, 1)

            add_section("Actions")
            add_button_item("Clear Logs", function()
                debug_clear_logs()
                safe_toast("Logs cleared!")
            end)
            add_button_item("Clear Performance Stats", function()
                debug_clear_perf()
                safe_toast("Performance stats cleared!")
            end)
            add_button_item("Force Garbage Collection", function()
                collectgarbage("collect")
                debug_log_memory("After GC")
                safe_toast("GC performed!")
            end)
            add_button_item("Log Memory Now", function()
                debug_log_memory("Manual Check")
            end)
            add_button_item("Test All Log Levels", function()
                debug_debug("TEST", "This is a DEBUG message")
                debug_info("TEST", "This is an INFO message")
                debug_warn("TEST", "This is a WARNING message")
                debug_error("TEST", "This is an ERROR message")
            end)

            add_button_item("Test Noclip Prerequisites", function()
                debug_info("DIAG", "=== Noclip Diagnostic Test ===")

                -- Test ped
                local ped = invoker.call(0xD80958FC74E988A6, -1).int
                debug_info("DIAG", string.format("Ped ID: %s", tostring(ped)))

                -- Test player object
                local me = players and players.me and players.me()
                debug_info("DIAG", string.format("Player object: %s", me and "Valid" or "NIL"))

                -- Test coords
                if me and me.coords then
                    debug_info("DIAG", string.format("Player coords: %.2f, %.2f, %.2f", me.coords.x, me.coords.y, me.coords.z))
                else
                    debug_error("DIAG", "Player coords are NIL!")
                end

                -- Test camera
                local heading = invoker.call(0x743607648ADD4587)
                local pitch = invoker.call(0x3A6867B4845BEDA2)
                debug_info("DIAG", string.format("Camera heading: %s", heading and heading.float or "NIL"))
                debug_info("DIAG", string.format("Camera pitch: %s", pitch and pitch.float or "NIL"))

                -- Test vec3
                local test_vec = vec3(1.0, 2.0, 3.0)
                debug_info("DIAG", string.format("vec3 test: %s", test_vec and "OK" or "FAILED"))

                debug_info("DIAG", "=== End Diagnostic ===")
                safe_toast("Diagnostic complete - check console!")
            end)

            add_section("Info")
            local fps = debug_get_fps()
            local mem_kb = collectgarbage("count")
            local log_count = DEBUG.log_count
            add_button_item(string.format("FPS: %.1f | Memory: %dKB | Logs: %d", fps, math.floor(mem_kb), log_count), function() end)

            -- Sync UI state with debug config
            if UI.debug_enabled ~= nil then DEBUG.enabled = UI.debug_enabled end
            if UI.debug_timestamps ~= nil then DEBUG.show_timestamp = UI.debug_timestamps end
            if UI.debug_memory ~= nil then DEBUG.show_memory = UI.debug_memory end
            if UI.debug_performance ~= nil then DEBUG.show_performance = UI.debug_performance end
            if UI.debug_auto_scroll ~= nil then DEBUG.auto_scroll = UI.debug_auto_scroll end
            if UI.debug_feature_debug ~= nil then DEBUG.feature_debug = UI.debug_feature_debug end
            if UI.debug_log_level ~= nil then DEBUG.log_level = math.floor(UI.debug_log_level) end

            -- Initialize if not set
            if UI.debug_enabled == nil then UI.debug_enabled = DEBUG.enabled end
            if UI.debug_timestamps == nil then UI.debug_timestamps = DEBUG.show_timestamp end
            if UI.debug_memory == nil then UI.debug_memory = DEBUG.show_memory end
            if UI.debug_performance == nil then UI.debug_performance = DEBUG.show_performance end
            if UI.debug_auto_scroll == nil then UI.debug_auto_scroll = DEBUG.auto_scroll end
            if UI.debug_feature_debug == nil then UI.debug_feature_debug = DEBUG.feature_debug end
            if UI.debug_log_level == nil then UI.debug_log_level = DEBUG.log_level end

        -- (Protections moved to dedicated Protection tab in the main sidebar)
        end

        -- Calculate total content height
        local total_content_h = 0
        for _, item in ipairs(items) do
            if item.type == "section" then
                total_content_h = total_content_h + math.floor(22 * s) + section_gap
            elseif item.type == "slider" then
                total_content_h = total_content_h + math.floor(42 * s) + item_gap
            else
                total_content_h = total_content_h + math.floor(32 * s) + item_gap
            end
        end

        -- Check if scrolling needed
        local content_area_h = panel_h - math.floor(16 * s)
        local needs_scroll = total_content_h > content_area_h
        local max_scroll = math.max(0, total_content_h - content_area_h + math.floor(30 * s))

        -- Reset scroll when changing sub-tab
        settings_state.scroll_offset = math.max(0, math.min(settings_state.scroll_offset, max_scroll))

        -- Handle mouse wheel scroll
        if is_mouse_in(panel_x, panel_y, panel_w, panel_h) and needs_scroll then
            local scroll_amt = math.floor(50 * s)
            if MOUSE.scroll_up then
                settings_state.scroll_offset = math.max(0, settings_state.scroll_offset - scroll_amt)
            elseif MOUSE.scroll_down then
                settings_state.scroll_offset = math.min(max_scroll, settings_state.scroll_offset + scroll_amt)
            end
        end

        -- Draw items with scroll offset
        local ly = panel_y + math.floor(8 * s) - settings_state.scroll_offset
        local clip_top = panel_y + math.floor(4 * s)
        local clip_bottom = panel_y + panel_h - math.floor(8 * s)

        -- Initialize color sliders if needed
        if not UI.accent_r then
            UI.accent_r = 114
            UI.accent_g = 137
            UI.accent_b = 218
        end

        for _, item in ipairs(items) do
            local item_h_current = math.floor(32 * s)
            if item.type == "section" then
                item_h_current = math.floor(22 * s)
            elseif item.type == "slider" then
                item_h_current = math.floor(42 * s)
            end

            -- Only draw if visible
            if ly + item_h_current > clip_top and ly < clip_bottom then
                if item.type == "section" then
                    draw_text(item.text, panel_x + side_pad, ly + math.floor(3 * s), UI.font_small, C.accent)
                    ly = ly + item_h_current + section_gap
                elseif item.type == "slider" then
                    local current_val = UI[item.key] or 0
                    local new_val, h = settings_slider(item.text, current_val, item.min, item.max, item.step, panel_x + side_pad, ly, usable_w, s)
                    UI[item.key] = new_val
                    ly = ly + h + item_gap
                elseif item.type == "checkbox" then
                    local cb_h = math.floor(28 * s)
                    UI[item.key] = inline_toggle(item.text, UI[item.key] or false, panel_x + side_pad, ly, usable_w, cb_h)
                    ly = ly + cb_h + item_gap
                elseif item.type == "button" then
                    if small_button(item.text, panel_x + side_pad, ly, usable_w, math.floor(32 * s)) then
                        if item.action then pcall(item.action) end
                    end
                    ly = ly + math.floor(32 * s) + item_gap
                end
            else
                -- Skip but advance
                if item.type == "section" then
                    ly = ly + item_h_current + section_gap
                elseif item.type == "slider" then
                    ly = ly + math.floor(42 * s) + item_gap
                else
                    ly = ly + math.floor(32 * s) + item_gap
                end
            end
        end

        -- Scroll shadows
        if needs_scroll then
            local shadow_h = math.floor(8 * s)
            if settings_state.scroll_offset > 0 then
                draw_rect(panel_x, panel_y, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            if settings_state.scroll_offset < max_scroll then
                draw_rect(panel_x, panel_y + panel_h - shadow_h, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
        end

        -- Draw scrollbar if needed
        if needs_scroll then
            local sb_w = math.floor(4 * s)
            local sb_x = panel_x + panel_w - sb_w - math.floor(1 * s)
            local sb_h = panel_h - math.floor(10 * s)
            local thumb_h = math.max(math.floor(30 * s), sb_h * (content_area_h / total_content_h))
            local thumb_y = panel_y + math.floor(5 * s) + (sb_h - thumb_h) * (settings_state.scroll_offset / max_scroll)

            draw_rect(sb_x, panel_y + math.floor(5 * s), sb_w, sb_h, C.checkbox_off, math.floor(2 * s))
            draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(2 * s))

            -- Scrollbar drag
            if is_mouse_in(sb_x - math.floor(5 * s), panel_y, sb_w + math.floor(10 * s), panel_h) and MOUSE.pressed then
                local rel_y = MOUSE.y - panel_y - math.floor(5 * s) - thumb_h / 2
                local scroll_pct = rel_y / (sb_h - thumb_h)
                settings_state.scroll_offset = math.max(0, math.min(max_scroll, scroll_pct * max_scroll))
            end
        end
    end

    -- =========================================================================
    -- MAIN UI DRAW
    -- =========================================================================

    local function draw_ui()
        if not UI.open then return end

        -- ── 3D Vehicle Preview functions (defined here so locals don't count toward outer scope) ──
        local function cleanup_vehicle_preview()
        if spawn_state.preview_veh and spawn_state.preview_veh ~= 0 then
            pcall(function()
                invoker.call(0xAD738C3085FE7E11, spawn_state.preview_veh, false, false) -- release mission entity
                invoker.call(0xEA1C610A04DB6BBB, spawn_state.preview_veh, false, false) -- hide first
                invoker.call(0x3C3C9A0E1EC4AABA, spawn_state.preview_veh, 1)             -- SET_ENTITY_AS_NO_LONGER_NEEDED
                entities.delete(spawn_state.preview_veh)
            end)
        end
        spawn_state.preview_veh   = nil
        spawn_state.preview_model = nil
        spawn_state.preview_rotation = 0.0
    end

        local function update_vehicle_preview(hovered_model_hash)
        if not hovered_model_hash then
            -- Nothing hovered this frame — destroy preview
            if spawn_state.preview_veh then cleanup_vehicle_preview() end
            return
        end

        local ped_r = invoker.call(0x43A66C31C68491C0, -1)
        local ped   = ped_r and ped_r.int or 0
        if ped == 0 then return end

        local pos_r = invoker.call(0x3FEF770D40960D5A, ped, true)
        if not pos_r or not pos_r.scr_vec3 then return end
        local px, py, pz = pos_r.scr_vec3.x, pos_r.scr_vec3.y, pos_r.scr_vec3.z
        -- Use gameplay camera Z rotation (yaw) so preview follows where player is LOOKING
        local cam_rot_r = invoker.call(0x837765A25378F0BB, 2)
        local cam_v3 = cam_rot_r and (cam_rot_r.vec3 or cam_rot_r.scr_vec3)
        local h = cam_v3 and cam_v3.z or nil
        -- Fall back to ped heading if camera rotation unavailable
        if not h then
            local hdg_r = invoker.call(0xE83A169C1F547683, ped)
            h = (hdg_r and hdg_r.float) or 0.0
        end
        local rad = math.rad(h)
        -- Forward vector in GTA V: forward = (-sin(rad), cos(rad))
        -- Place preview 7m directly in front of where camera is pointing, centered
        local pvx = px - math.sin(rad) * 7.0
        local pvy = py + math.cos(rad) * 7.0
        local pvz = pz

        -- If model changed, destroy old and spawn new in a job (needs yield for model load)
        if hovered_model_hash ~= spawn_state.preview_model then
            cleanup_vehicle_preview()
            spawn_state.preview_model = hovered_model_hash
            local spawn_hash = hovered_model_hash
            local spawn_pvx, spawn_pvy, spawn_pvz, spawn_h = pvx, pvy, pvz, h

            util.create_job(function()
                -- Load model (raw, works for addon vehicles too)
                invoker.call(0x963D27A58DF860AC, spawn_hash)
                local t = 0
                while t < 30 do
                    local r = invoker.call(0x98A4EB5D89A0C952, spawn_hash)
                    if r and r.bool then break end
                    util.yield(50); t = t + 1
                end
                local ok = invoker.call(0x98A4EB5D89A0C952, spawn_hash)
                if not ok or not ok.bool then return end
                -- Abort if model changed while loading
                if spawn_state.preview_model ~= spawn_hash then
                    invoker.call(0xE532F5D78798DAAB, spawn_hash)
                    return
                end

                local veh = invoker.call(0xAF35D0D2583051B0,
                    spawn_hash, spawn_pvx, spawn_pvy, spawn_pvz, spawn_h + 90.0, false, false, false).int
                invoker.call(0xE532F5D78798DAAB, spawn_hash)

                if not veh or veh == 0 then return end

                invoker.call(0xAD738C3085FE7E11, veh, true, true)   -- SET_ENTITY_AS_MISSION_ENTITY
                invoker.call(0x428CA6DBD1094446, veh, true)          -- FREEZE_ENTITY_POSITION
                invoker.call(0x3882114BDE571AD4, veh, true)          -- SET_ENTITY_INVINCIBLE
                invoker.call(0x1CF38D529D7441D9, veh, false, false)  -- SET_ENTITY_COLLISION off
                invoker.call(0xEA1C610A04DB6BBB, veh, true, false)   -- SET_ENTITY_VISIBLE
                pcall(function() invoker.call(0x2497C4717C8B881E, veh, false, false, false) end) -- engine off
                pcall(function() invoker.call(0x3B988190C0AA6C0B, veh, false) end) -- radio off
                pcall(function() invoker.call(0x1B9C0099CB942AC6, veh, "RADIO_OFF") end)

                -- Only store if still same model (user didn't move to another)
                if spawn_state.preview_model == spawn_hash then
                    spawn_state.preview_veh = veh
                    spawn_state.preview_rotation = spawn_h + 90.0
                else
                    -- Already moved on, delete immediately
                    pcall(entities.delete, veh)
                end
            end)
        end

        -- Each frame: rotate and reposition to stay in front of player
        if spawn_state.preview_veh and spawn_state.preview_veh ~= 0 then
            pcall(function()
                if not invoker.call(0x7239B21A38F536BA, spawn_state.preview_veh).bool then
                    spawn_state.preview_veh = nil; return
                end
                spawn_state.preview_rotation = (spawn_state.preview_rotation + 1.2) % 360.0
                invoker.call(0x8E2530AA8ADA980E, spawn_state.preview_veh, spawn_state.preview_rotation)
                invoker.call(0x06843DA7060A026B, spawn_state.preview_veh, pvx, pvy, pvz, false, false, false, true)
            end)
        end
    end

        -- Reset preview hover state each frame (tabs will set it if hovered)
        spawn_state.preview_hovered_model = nil

        -- Disable conflicting controls while menu is open
        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int
        local in_veh = invoker.call(0x9A9112A0FE9A4713, player_ped, false)
        if in_veh and (in_veh.int or in_veh.ent or 0) ~= 0 then
            -- Disable radio wheel and music controls in vehicle
            invoker.call(0xFE99B66D079CF6BC, 0, 19, true) -- VehicleRadioWheel
            invoker.call(0xFE99B66D079CF6BC, 0, 85, true) -- VehicleNextRadio (scroll up)
            invoker.call(0xFE99B66D079CF6BC, 0, 84, true) -- VehiclePrevRadio (scroll down)
            invoker.call(0xFE99B66D079CF6BC, 0, 81, true) -- VehicleRadioWheelUD
            invoker.call(0xFE99B66D079CF6BC, 0, 82, true) -- VehicleRadioWheelLR
        end
        -- Disable weapon scroll/select for everyone
        invoker.call(0xFE99B66D079CF6BC, 0, 14, true) -- Mouse wheel down
        invoker.call(0xFE99B66D079CF6BC, 0, 15, true) -- Mouse wheel up
        invoker.call(0xFE99B66D079CF6BC, 0, 99, true) -- Next weapon
        invoker.call(0xFE99B66D079CF6BC, 0, 100, true) -- Prev weapon
        invoker.call(0xFE99B66D079CF6BC, 0, 27, true) -- Phone

        -- Note: update_input() is called in main loop, don't call it here again

        local s = UI.scale
        local x, y, w, h = UI.x, UI.y, UI.w, UI.h

        -- Window dragging
        if is_mouse_in(x, y, w, UI.header_h) then
            if MOUSE.just_pressed and not UI.dragging then
                UI.dragging = true
                UI.drag_ox = MOUSE.x - x
                UI.drag_oy = MOUSE.y - y
            end
        end

        if UI.dragging then
            if MOUSE.pressed then
                UI.x = MOUSE.x - UI.drag_ox
                UI.y = MOUSE.y - UI.drag_oy
                UI.x = math.max(0, math.min(screen_w - w, UI.x))
                UI.y = math.max(0, math.min(screen_h - h, UI.y))
            else
                UI.dragging = false
            end
        end

        -- Update local vars after drag
        x, y = UI.x, UI.y

        -- Window resizing (bottom-right corner drag)
        local resize_handle_size = math.floor(16 * s)
        local resize_x = x + w - resize_handle_size
        local resize_y = y + h - resize_handle_size

        if is_mouse_in(resize_x, resize_y, resize_handle_size, resize_handle_size) then
            if MOUSE.just_pressed and not UI.resizing then
                UI.resizing = true
                UI.resize_ox = MOUSE.x - w
                UI.resize_oy = MOUSE.y - h
            end
        end

        if UI.resizing then
            if MOUSE.pressed then
                local new_w = MOUSE.x - UI.resize_ox
                local new_h = MOUSE.y - UI.resize_oy
                UI.w = math.max(UI.min_w, math.min(UI.max_w, new_w))
                UI.h = math.max(UI.min_h, math.min(UI.max_h, new_h))

                -- Update scale factor dynamically based on new size
                local base_w = 760
                local base_h = 600
                local scale_x = UI.w / base_w
                local scale_y = UI.h / base_h
                UI.scale = math.min(scale_x, scale_y)
                s = UI.scale

                -- Update all scaled UI elements
                UI.header_h = math.floor(24 * s)
                UI.sidebar_w = math.floor(64 * s)
                UI.padding = math.floor(5 * s)
                UI.item_h = math.floor(40 * s)
                UI.font_header = math.floor(17 * s)
                UI.font_tab = math.floor(15 * s)
                UI.font_widget = math.floor(14 * s)
                UI.font_small = math.floor(13 * s)
                UI.font_tiny = math.floor(11 * s)
                UI.widget_rounding = math.floor(6 * s)
                UI.subtab_h = math.floor(30 * s)
            else
                UI.resizing = false
            end
        end

        -- Update local vars after resize
        w, h = UI.w, UI.h

        -- Background with rounded corners
        draw_rect(x, y, w, h, C.bg, math.floor(8 * s))

        -- Wallpaper: loaded lazily on first draw via gui.load_image (same as Aurox AIO)
        -- Place Kyron_wallpaper.png in: scripts\Kyron\kyron_ui\Kyron_wallpaper.png
        try_load_wallpaper()
        if wallpaper_tex and gui and gui.image and vec2 then
            local wp_x = x + UI.sidebar_w
            local wp_y = y + UI.header_h
            local wp_w = w - UI.sidebar_w
            local wp_h = h - UI.header_h
            if gui.push_clip then gui.push_clip(vec2(wp_x, wp_y), vec2(wp_w, wp_h)) end
            gui.image(wallpaper_tex, vec2(wp_x, wp_y), vec2(wp_w, wp_h), color(255, 255, 255, 255))
            if gui.pop_clip then gui.pop_clip() end
        end

        -- Draw resize handle (visual indicator in bottom-right corner)
        if not UI.resizing then
            draw_rect(resize_x + math.floor(8 * s), resize_y + math.floor(8 * s), resize_handle_size - math.floor(8 * s), resize_handle_size - math.floor(8 * s), C.accent, 0)
        else
            draw_rect(resize_x + math.floor(6 * s), resize_y + math.floor(6 * s), resize_handle_size - math.floor(6 * s), resize_handle_size - math.floor(6 * s), C.text, 0)
        end

        -- Header
        draw_rect(x, y, w, UI.header_h, C.header, math.floor(8 * s))
        draw_text("KYRON", x + math.floor(15 * s), y + math.floor(4 * s), UI.font_header, C.text)

        -- Sidebar
        local sidebar_y = y + UI.header_h
        local sidebar_h = h - UI.header_h
        draw_rect(x, sidebar_y, UI.sidebar_w, sidebar_h, C.sidebar)

        -- Tabs (with proper scaling)
        local tab_h = math.floor(40 * s)
        local btn_margin = math.floor(6 * s)
        local btn_rounding = math.floor(6 * s)

        for i, name in ipairs(TABS) do
            local ty = sidebar_y + btn_margin + (i - 1) * (tab_h + math.floor(4 * s))
            local tx = x + btn_margin
            local tw = UI.sidebar_w - btn_margin * 2
            local is_active = (UI.active_tab == i)
            local is_hover = is_mouse_in(tx, ty, tw, tab_h)

            if is_active then
                draw_rect(tx, ty, tw, tab_h, C.tab_active, btn_rounding)
            elseif is_hover then
                draw_rect(tx, ty, tw, tab_h, C.tab_hover, btn_rounding)
            else
                draw_rect(tx, ty, tw, tab_h, C.tab_inactive, btn_rounding)
            end

            -- Center text in button
            draw_text_centered(name, tx, ty, tw, tab_h, UI.font_tab, is_active and C.text or C.text_dim)

            if is_hover and MOUSE.just_pressed then
                -- Clean up preview clone when switching away from Self tab
                if UI.active_tab == 1 and i ~= 1 then
                    cleanup_preview_clone()
                end
                UI.active_tab = i
            end
        end

        -- Content area
        local cx = x + UI.sidebar_w
        local cy = y + UI.header_h
        local cw = w - UI.sidebar_w
        local ch = h - UI.header_h

        begin_content(cx, cy + math.floor(8 * s), cw)

        if UI.active_tab == 1 then
            draw_self_tab()
        elseif UI.active_tab == 2 then
            draw_player_tab()
        elseif UI.active_tab == 3 then
            draw_network_tab()
        elseif UI.active_tab == 4 then
            draw_online_tab()
        elseif UI.active_tab == 5 then
            draw_protection_tab()
        elseif UI.active_tab == 6 then
            draw_weapon_tab()
        elseif UI.active_tab == 7 then
            draw_spawn_tab()
        elseif UI.active_tab == 8 then
            draw_vehicle_tab()
        elseif UI.active_tab == 9 then
            draw_model_tab()
        elseif UI.active_tab == 10 then
            draw_heist_tab()
        elseif UI.active_tab == 11 then
            draw_ui_tab()
        elseif UI.active_tab == 12 then
            draw_settings_tab()
        else
            draw_placeholder_tab(TABS[UI.active_tab])
        end

        -- Footer hint removed

        -- Update 3D vehicle preview based on what was hovered this frame
        update_vehicle_preview(spawn_state.preview_hovered_model)
    end

    -- =========================================================================
    -- TOGGLE FUNCTION
    -- =========================================================================

    local function toggle_menu()
        UI.open = not UI.open
        if UI.open then
            safe_toast("KYRON Opened")
            debug_info("UI", "Menu opened")
            pcall(MissileRuntime.on_menu_open)
        else
            -- Clean up preview clone when closing menu
            cleanup_preview_clone()
            pcall(cleanup_vehicle_preview)  -- Clean up 3D vehicle preview
            debug_info("UI", "Menu closed")
            pcall(MissileRuntime.on_menu_close)
        end
    end

    -- =========================================================================
    -- MAIN LOOP
    -- =========================================================================

    local input_key = input.key
    local TOGGLE_KEY = 0xBB  -- = (legacy fallback)
    local TOGGLE_KEY_ALT = 0x77  -- F8 (legacy fallback)
    local DEBUG_CONSOLE_KEY = 0x70  -- F1

    -- Initialize natives
    util.yield(0)
    local natives_ok = init_natives()
    if natives_ok then
        safe_toast("KYRON Loaded!\nWaiting for keybind setup...")
        debug_info("SYSTEM", "Natives initialized successfully")
    else
        safe_toast("KYRON Loaded (limited)\nNatives not available")
        debug_warn("SYSTEM", "Natives failed to initialize")
    end

    -- Auto-load saved settings from last session
    pcall(autosave_read)

    debug_info("SYSTEM", "Starting main loop")

    while true do
        local ok, err = xpcall(function()
            -- Update frame time for FPS tracking
            debug_update_frame_time()

            -- Update input
            update_input()

            -- First-time keybind setup
            if keybind.show_setup then
                -- Draw setup window inline
                local res = game.resolution()
                local w, h = 450, 220
                local x, y = (res.x - w) / 2, (res.y - h) / 2
                draw_rect(x - 2, y - 2, w + 4, h + 4, color(114, 137, 218, 200), 8)
                draw_rect(x, y, w, h, color(25, 20, 35, 240), 6)
                draw_rect(x, y, w, 50, color(114, 137, 218, 255), 6)
                draw_text("SET MENU KEYBIND", x + w/2 - 110, y + 15, 18.0, color(255, 255, 255, 255))
                draw_text("Press any key to set menu open/close key", x + w/2 - 160, y + 80, 15.0, color(255, 255, 255, 255))
                draw_text("(Recommended: F9, F10, Insert, =, etc.)", x + w/2 - 150, y + 110, 12.0, color(200, 200, 200, 255))
                draw_text("[ Waiting for key press... ]", x + w/2 - 105, y + 145, 13.0, color(114, 137, 218, 255))

                -- Wait 30 frames before listening to keys
                keybind.startup_frames = keybind.startup_frames + 1

                if keybind.startup_frames >= 30 then
                    -- Listen for key press (exclude WASD and left shift)
                    for key_code = 0x08, 0xFF do
                        -- Skip movement keys: W=0x57, A=0x41, S=0x53, D=0x44, Left Shift=0x10
                        if key_code ~= 0x57 and key_code ~= 0x41 and key_code ~= 0x53 and key_code ~= 0x44 and key_code ~= 0x10 then
                            if input_key(key_code) and input_key(key_code).just_released then
                                local key_name = keybind.key_names[key_code] or string.format("Key 0x%X", key_code)
                                keybind.menu_key = key_code
                                keybind.configured = true
                                safe_toast("Menu keybind set to: " .. key_name)
                                safe_toast("Press " .. key_name .. " to open/close menu!")
                                keybind.show_setup = false
                                break
                            end
                        end
                    end
                end
            else
                -- Normal menu toggle (use custom keybind or fallback to = and F8)
                if keybind.configured and keybind.menu_key and input_key(keybind.menu_key).just_released then
                    toggle_menu()
                elseif input_key(TOGGLE_KEY).just_released or input_key(TOGGLE_KEY_ALT).just_released then
                    toggle_menu()
                end
                -- Noclip keybind toggle
                if noclip_state.keybind_capturing then
                    -- Capture mode: listen for any key release, ESC cancels
                    for kc = 0x08, 0xFF do
                        if input_key(kc) and input_key(kc).just_released then
                            if kc == 0x1B then
                                noclip_state.keybind_capturing = false
                                safe_toast("Noclip keybind: cancelled")
                            else
                                noclip_state.keybind = kc
                                noclip_state.keybind_capturing = false
                                local kn = keybind.key_names[kc] or string.format("0x%X", kc)
                                safe_toast("Noclip keybind set to: " .. kn)
                            end
                            break
                        end
                    end
                elseif noclip_state.keybind then
                    if input_key(noclip_state.keybind) and input_key(noclip_state.keybind).just_released then
                        demo.noclip = not demo.noclip
                        safe_toast("Noclip: " .. (demo.noclip and "ON" or "OFF"))
                    end
                end

                -- Backtick (`) key 0xC0: toggle crash cam
                local backtick = input_key(0xC0)
                if backtick and backtick.just_released then
                    set_crash_cam(not kyron_crash_cam.active)
                    safe_toast("[Kyron] Crash Cam: " .. (kyron_crash_cam.active and "ON" or "OFF"))
                end
            end

            -- No Hesi points now auto-reset on crash (see vehicle thread)

            -- Cursor (show only when main menu is open, never for context menu)
            if input.show_cursor then
                input.show_cursor(UI.open)
            end

            -- Disable game controls when context menu is active (separate from main menu)
            if self_state.context_menu_active then
                -- Block: attack, melee, weapon wheel, scroll weapon cycle, aim
                local ctx_block = {
                    24,   -- Attack (LMB / RT)
                    25,   -- Aim (RMB / LT)
                    69,   -- Melee Attack Light
                    70,   -- Melee Attack Heavy
                    92,   -- Melee Attack Alternate
                    140,  -- Melee Attack
                    141,  -- Melee Attack 2
                    142,  -- Melee Attack 3
                    157,  -- Select Weapon / Weapon Wheel (TAB)
                    14,   -- Next Weapon
                    15,   -- Prev Weapon
                    241,  -- Scroll Weapon Up
                    242,  -- Scroll Weapon Down
                }
                for _, ctrl in ipairs(ctx_block) do
                    pcall(function() invoker.call(0xFE99B66D079CF6BC, 0, ctrl, true) end)
                    pcall(function() invoker.call(0xFE99B66D079CF6BC, 1, ctrl, true) end)
                end
            end

            -- Disable game controls when menu is open (ZODIAC method)
            if UI.open then
                -- Movement/look/drive controls that should stay enabled when allow_movement is on
                -- Controls that are ALWAYS kept on (never disabled regardless of menu state)
                -- Includes WASD on foot AND all vehicle drive controls
                local always_on = {
                    [30] = true, [31] = true, [32] = true, [33] = true,  -- WASD on foot
                    [71] = true, [72] = true,  -- Vehicle accelerate / brake (W/S in vehicle)
                    [59] = true, [60] = true,  -- Vehicle steer left/right (A/D in vehicle)
                    [63] = true, [64] = true,  -- Vehicle look left/right
                    [75] = true,               -- Exit vehicle
                    [37] = true,               -- Sprint
                }
                local controls_to_disable = {
                    0, 1, 2, 3, 4, 5, 6, 25, 34, 35,
                    44, 45, 47, 58, 140, 141, 142, 143,
                    257, 258, 261, 262, 263, 264, 265, 266, 267, 268, 27,
                    -- Weapon wheel + scroll-to-change-weapon
                    14, 15,   -- Next/Prev weapon
                    157,      -- SelectWeapon (hold TAB = weapon wheel)
                    241, 242  -- Scroll up/down (would cycle weapons / open wheel)
                }
                -- Disable for both control groups 0 and 1
                for group = 0, 1 do
                    for _, control in ipairs(controls_to_disable) do
                        if not always_on[control] then
                            pcall(function() invoker.call(0xFE99B66D079CF6BC, group, control, true) end)
                        end
                    end
                end
            end

            -- Draw UI (with performance tracking)
            if UI.open then
                debug_mark_start("draw_ui")
                draw_ui()
                debug_mark_end("draw_ui")
            end

            -- Draw modder overlay (always visible when enabled)
            -- Sync toggle from Settings > General into both overlay state vars
            if UI.modder_overlay_enabled ~= nil then
                player_state.modder_overlay_enabled = UI.modder_overlay_enabled
                modder_overlay.enabled = UI.modder_overlay_enabled
            end
            pcall(draw_modder_overlay)

            -- Spectate detection (runs every frame, toasts on new spectators)
            -- Draw red shield alerts (always visible, even when menu is closed)
            if self_state and self_state.draw_shield_alerts then
                pcall(self_state.draw_shield_alerts)
            end

            -- ============ MODDER OVERLAY + SPECTATE-ME DETECTION ============



            -- ── Modder overlay draw (live, rebuilt every frame from players.list()) ──
            if player_state.modder_overlay_enabled then
                pcall(function()
                    if not game or not game.resolution then return end
                    local res = game.resolution()
                    local sw = res.x or 1920
                    local sh = res.y or 1080
                    local s  = sh / 1080

                    -- Collect modders LIVE every frame using Lexis players.list() API
                    -- p.modder = Lexis native flag; also flag god mode, insane rank/money
                    local me_id = players and players.me and players.me().id or -1
                    local modders = {}
                    if players and players.list then
                        for _, p in ipairs(players.list()) do
                            if p and p.id ~= me_id then
                                local reasons = {}
                                if p.modder            then reasons[#reasons+1] = "Flagged" end
                                if p.rank and p.rank >= 1000 then reasons[#reasons+1] = "Rank "..p.rank end
                                if p.cash and p.cash > 500000000 then reasons[#reasons+1] = "$"..math.floor(p.cash/1e6).."M cash" end
                                if p.bank and p.bank > 500000000 then reasons[#reasons+1] = "$"..math.floor(p.bank/1e6).."M bank" end
                                if #reasons > 0 then
                                    modders[#modders+1] = {
                                        name    = p.name or "Unknown",
                                        reasons = table.concat(reasons, "  |  "),
                                        god     = p.modder,
                                    }
                                end
                            end
                        end
                    end

                    -- Overlay dimensions
                    local ov_w   = math.floor(340 * s)
                    local name_h = math.floor(20 * s)   -- name row height
                    local rsn_h  = math.floor(14 * s)   -- reason row height
                    local row_h  = name_h + rsn_h + math.floor(4 * s)
                    local pad    = math.floor(8  * s)
                    local hdr_h  = math.floor(28 * s)
                    local ov_h   = hdr_h + pad + (#modders > 0 and #modders or 1) * (row_h + math.floor(4 * s)) + pad
                    local ov_x   = math.floor(player_state.modder_overlay_x * (sw - ov_w))
                    local ov_y   = math.floor(player_state.modder_overlay_y * (sh - ov_h))

                    -- Background
                    draw_rect(ov_x - 2, ov_y - 2, ov_w + 4, ov_h + 4, color(114, 137, 218, 180), math.floor(8 * s))
                    draw_rect(ov_x, ov_y, ov_w, ov_h, color(18, 18, 22, 220), math.floor(7 * s))

                    -- Header
                    draw_rect(ov_x, ov_y, ov_w, hdr_h, color(14, 14, 18, 230), math.floor(7 * s))
                    local count_txt = #modders > 0 and ("  ⚠ Detected Modders (" .. #modders .. ")") or "  ⚠ Detected Modders"
                    draw_text(count_txt, ov_x + pad, ov_y + math.floor((hdr_h - 15) / 2), math.floor(14 * s), color(114, 137, 218, 255))

                    local ry = ov_y + hdr_h + pad

                    if #modders == 0 then
                        draw_text("  No modders detected", ov_x + pad, ry, math.floor(13 * s), color(140, 140, 155, 255))
                    else
                        for _, m in ipairs(modders) do
                            -- Row background
                            draw_rect(ov_x + math.floor(4 * s), ry, ov_w - math.floor(8 * s), row_h, color(40, 40, 46, 140), math.floor(5 * s))

                            -- Name — larger font (16px scaled)
                            local name_col = m.god and color(255, 60, 60, 255) or color(255, 110, 110, 255)
                            draw_text(m.name, ov_x + pad + math.floor(4 * s), ry + math.floor(3 * s), math.floor(16 * s), name_col)

                            -- Reasons below name — smaller dimmed text
                            local reason = m.reasons
                            if #reason > 40 then reason = reason:sub(1, 40) .. "..." end
                            draw_text(reason, ov_x + pad + math.floor(4 * s), ry + math.floor(3 * s) + name_h, math.floor(11 * s), color(180, 150, 80, 220))

                            ry = ry + row_h + math.floor(4 * s)
                        end
                    end

                    -- Drag handle: click header to drag overlay
                    if is_mouse_in(ov_x, ov_y, ov_w, hdr_h) then
                        if MOUSE.just_pressed then
                            player_state.modder_overlay_dragging = true
                            player_state.modder_overlay_drag_ox = MOUSE.x - ov_x
                            player_state.modder_overlay_drag_oy = MOUSE.y - ov_y
                        end
                    end
                    if player_state.modder_overlay_dragging then
                        if MOUSE.pressed then
                            local nx = MOUSE.x - player_state.modder_overlay_drag_ox
                            local ny = MOUSE.y - player_state.modder_overlay_drag_oy
                            player_state.modder_overlay_x = math.max(0, math.min(1, nx / (sw - ov_w)))
                            player_state.modder_overlay_y = math.max(0, math.min(1, ny / (sh - ov_h)))
                        else
                            player_state.modder_overlay_dragging = false
                        end
                    end
                end)
            end

            -- ============ ONLINE TAB FEATURES (in main loop like ZODIAC) ============

            -- Time Override (using natives table)
            if online_state and online_state.time_override then
                pcall(natives.NETWORK_OVERRIDE_CLOCK_TIME, online_state.time_hour or 12, online_state.time_minute or 0, online_state.time_second or 0)
            end

            -- Freeze Time (using natives table)
            if online_state and online_state.freeze_time then
                local hour = online_state.time_hour or 12
                pcall(natives.SET_CLOCK_TIME, hour, 0, 0)
            end

            -- Suppress NPC vehicle spawns every frame when traffic removal is active
            if online_state and online_state.remove_all_traffic then
                pcall(function()
                    invoker.call(0x245A6883D966D537, 0.0) -- SET_VEHICLE_DENSITY_MULTIPLIER_THIS_FRAME
                    invoker.call(0xB3B3359379FE77D3, 0.0) -- SET_RANDOM_VEHICLE_DENSITY_MULTIPLIER_THIS_FRAME
                    invoker.call(0xEAE6DCC7EEE3DB1D, 0.0) -- SET_PARKED_VEHICLE_DENSITY_MULTIPLIER_THIS_FRAME
                    invoker.call(0x90B6DA738A9A25DA, 0.0) -- SET_AMBIENT_VEHICLE_RANGE_MULTIPLIER_THIS_FRAME
                end)
            end

        end, debug.traceback)

        if not ok then
            safe_toast("Error: " .. tostring(err))
            debug_error("SYSTEM", "Main loop error", tostring(err))
        end

        -- Auto-save every ~600 frames (~20 seconds), always on, no gate
        if not _autosave_tick then _autosave_tick = 0 end
        _autosave_tick = _autosave_tick + 1
        if _autosave_tick >= 600 then
            _autosave_tick = 0
            pcall(autosave_write)
        end

        util.yield(0)
    end
end)

-- =========================================================================
-- KYRON WATCHLIST MONITOR THREAD
-- Polls every 2s: alerts when a watchlisted player joins, applies
-- anti-freeze counter (force-refreshes ped flags) when a flood is detected.
-- =========================================================================
util.create_thread(function()
    local known_in_session = {}  -- [player_id] = name

    while true do
        pcall(function()
            if not (players and players.list) then return end

            local current = {}
            for _, p in ipairs(players.list()) do
                if p and p.name then
                    local lname = p.name:lower()
                    current[p.id] = lname

                    -- Watchlisted player detected joining
                    if KYRON_WATCHLIST[lname] and not known_in_session[p.id] then
                        known_in_session[p.id] = p.name
                        kyron_watch_state.alerted[p.id]    = nil  -- reset so alert fires again
                        kyron_watch_state.se_count[p.id]   = 0
                        safe_toast("[KYRON] ⛔ WATCHLIST: " .. p.name .. " joined your session!\nAll their attacks are being blocked.")
                        protection_log("WATCHLIST JOIN: " .. p.name .. " id=" .. tostring(p.id))
                    end
                end
            end

            -- Clear players who left
            for pid in pairs(known_in_session) do
                if not current[pid] then
                    local gone_name = known_in_session[pid] or "unknown"
                    known_in_session[pid] = nil
                    kyron_watch_state.alerted[pid]  = nil
                    kyron_watch_state.se_count[pid] = nil
                    safe_toast("[KYRON] ✓ " .. gone_name .. " left the session.")
                    protection_log("WATCHLIST LEFT: " .. gone_name)
                end
            end

            -- Anti-freeze counter: if a flood was detected in last 5s, keep
            -- re-applying god-mode ped flags so the engine doesn't lock you up
            if kyron_watch_state.freeze_hit then
                local elapsed = os.clock() - (kyron_watch_state.freeze_tick or 0)
                if elapsed < 5.0 then
                    pcall(function()
                        -- Re-apply invincibility and clear any forced task
                        local ped_r = invoker.call(0x43A66C31C68491C0, -1)
                        local ped = ped_r and ped_r.int or 0
                        if ped and ped ~= 0 then
                            invoker.call(0xE3E2A1DEC4360F9B, ped, 1, 1)  -- SET_PED_INVINCIBLE (via flag)
                            invoker.call(0xEB3CA8E4CB938BD3, ped)          -- CLEAR_ALL_TASKS (breaks freeze)
                            invoker.call(0xAC4EF23D6739EFA7, ped, false)   -- SET_PED_FREEZED_POSITION_AND_ROTATION
                        end
                    end)
                else
                    kyron_watch_state.freeze_hit = false
                end
            end
        end)

        util.yield(2000)
    end
end)

-- =========================================================================
-- TRAFFIC REMOVAL THREAD
-- Full request_control defined locally so it works outside the draw thread.
-- Networkises each vehicle, takes ownership, then teleports to ocean.
-- =========================================================================
util.create_thread(function()

    local function traffic_request_control(entity)
        if not entity or entity == 0 then return false end
        local exists = invoker.call(0x7239B21A38F536BA, entity) -- DOES_ENTITY_EXIST
        if not exists or not exists.bool then return false end

        -- Ensure entity is networked
        local is_net = invoker.call(0xC7827959479DCC78, entity) -- NETWORK_GET_ENTITY_IS_NETWORKED
        if not is_net or not is_net.bool then
            invoker.call(0x06FAACD625D80CAA, entity) -- NETWORK_REGISTER_ENTITY_AS_NETWORKED
            util.yield(100)
        end

        -- Get net ID and lock migration so we can take control
        local netId = invoker.call(0xA11700682F3AD45C, entity) -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
        if netId and netId.int and netId.int ~= 0 then
            invoker.call(0xE05E81A888FA63C8, netId.int, true)  -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
            invoker.call(0x299EEB23175895FC, netId.int, false) -- SET_NETWORK_ID_CAN_MIGRATE (disable migration)
        end

        -- Flag as mission entity to force network authority handoff
        invoker.call(0xAD738C3085FE7E11, entity, true, true) -- SET_ENTITY_AS_MISSION_ENTITY

        -- Retry loop
        for _ = 1, 15 do
            local has = invoker.call(0x01BF60A500E28887, entity) -- NETWORK_HAS_CONTROL_OF_ENTITY
            if has and has.bool then return true end
            invoker.call(0xB69317BF5E782347, entity) -- NETWORK_REQUEST_CONTROL_OF_ENTITY
            util.yield(50)
        end

        local final = invoker.call(0x01BF60A500E28887, entity)
        return final and final.bool or false
    end

    while true do
        if online_state and online_state.remove_all_traffic then
            if pools and pools.vehicle and game and game.guid_from_entity then
                local veh_list = {}
                pcall(function()
                    for _, addr in ipairs(pools.vehicle()) do
                        local ok_h, veh = pcall(game.guid_from_entity, addr)
                        if ok_h and veh and veh ~= 0 then
                            table.insert(veh_list, veh)
                        end
                    end
                end)

                for _, veh in ipairs(veh_list) do
                    if not (online_state and online_state.remove_all_traffic) then break end

                    pcall(function()
                        local exists = invoker.call(0x7239B21A38F536BA, veh) -- DOES_ENTITY_EXIST
                        if not exists or not exists.bool then return end

                        -- Skip if any real player is seated
                        for seat = -1, 7 do
                            local occ = invoker.call(0xBB40DD2270B65366, veh, seat, false) -- GET_PED_IN_VEHICLE_SEAT
                            if occ and occ.int and occ.int ~= 0 then
                                local is_p = invoker.call(0x12534C348C6CB68B, occ.int) -- IS_PED_A_PLAYER
                                if is_p and is_p.bool then return end
                            end
                        end

                        -- Take ownership then teleport into deep ocean off the map
                        if traffic_request_control(veh) then
                            invoker.call(0x06843DA7060A026B, veh, 4500.0, -5000.0, -200.0, false, false, false, false) -- SET_ENTITY_COORDS
                        end
                    end)

                    util.yield(0)
                end
            end
            util.yield(200)
        else
            util.yield(500)
        end
    end
end)
